init();

async function init() {
  try {
    setProjectChromeEnabled(false);
    state.projectCenter = await loadProjectCenter();
    refs.loadingState.classList.add("is-hidden");
    refs.errorState.classList.add("is-hidden");
    openProjectCenter({ keepStatus: true });
  } catch (error) {
    setSaveStatus("载入失败", true);
    refs.loadingState.classList.add("is-hidden");
    refs.errorState.classList.remove("is-hidden");
    refs.errorMessage.textContent = error.message;
    console.error(error);
  }
}

async function loadProjectCenter() {
  const response = await fetch(API_PROJECT_CENTER);

  if (!response.ok) {
    throw new Error(`读取项目列表失败，状态码 ${response.status}`);
  }

  const result = await response.json();
  return {
    activeProjectId: result.activeProjectId ?? null,
    projects: Array.isArray(result.projects) ? result.projects : [],
  };
}

async function loadProjectData() {
  const response = await fetch(API_PROJECT_DATA);
  let bundle = null;
  try {
    bundle = await response.json();
  } catch (error) {
    bundle = null;
  }

  if (!response.ok || bundle?.ok === false) {
    const loadError = new Error(bundle?.error ?? `读取项目数据失败，状态码 ${response.status}`);
    loadError.recovery = bundle?.recovery ?? null;
    throw loadError;
  }

  const project = bundle.project ?? {};
  const chapters = bundle.chapters ?? [];
  const assetList = bundle.assets?.assets ?? [];
  const characters = bundle.characters?.characters ?? [];
  const variables = bundle.variables?.variables ?? [];
  const scenes = [];
  const scenesById = new Map();
  const chaptersById = new Map();
  const assetsById = new Map(assetList.map((asset) => [asset.id, asset]));
  const charactersById = new Map(characters.map((character) => [character.id, character]));
  const variablesById = new Map(variables.map((variable) => [variable.id, variable]));

  chapters.forEach((chapter) => {
    chaptersById.set(chapter.chapterId, chapter);
    (chapter.scenes ?? []).forEach((scene) => {
      scenes.push({
        ...scene,
        chapterId: chapter.chapterId,
        chapterName: chapter.name,
      });
      scenesById.set(scene.id, {
        ...scene,
        chapterId: chapter.chapterId,
        chapterName: chapter.name,
      });
    });
  });

  const assetUsage = buildAssetUsageMap({
    chapters,
    characters,
    charactersById,
  });

  return {
    project,
    currentProject: bundle.currentProject ?? null,
    history: bundle.history ?? null,
    sessionRecovery: bundle.sessionRecovery ?? null,
    chapters,
    chaptersById,
    scenes,
    scenesById,
    assetList,
    assetsById,
    characters,
    charactersById,
    variables,
    variablesById,
    assetUsage,
  };
}

function setProjectChromeEnabled(enabled) {
  refs.projectNavButtons.forEach((button) => {
    button.disabled = !enabled;
  });
}

function getSafeProjectSessionRecovery(recovery = state.projectSessionRecovery) {
  if (!recovery || typeof recovery !== "object") {
    return {
      noticeActive: false,
      lastUnexpectedExitAt: "",
      lastUnexpectedExitStartedAt: "",
      lastEndedReason: "",
      message: "",
    };
  }

  return {
    noticeActive: Boolean(recovery.noticeActive),
    lastUnexpectedExitAt: String(recovery.lastUnexpectedExitAt ?? "").trim(),
    lastUnexpectedExitStartedAt: String(recovery.lastUnexpectedExitStartedAt ?? "").trim(),
    lastEndedReason: String(recovery.lastEndedReason ?? "").trim(),
    message: String(recovery.message ?? "").trim(),
  };
}

function getSafeProjectHistory(history = state.projectHistory) {
  if (!history || typeof history !== "object") {
    return {
      totalSnapshots: 0,
      currentIndex: -1,
      canUndo: false,
      canRedo: false,
      currentSnapshot: null,
      previousSnapshot: null,
      nextSnapshot: null,
      recentSnapshots: [],
      timelineSnapshots: [],
    };
  }

  return {
    totalSnapshots: Number(history.totalSnapshots ?? 0),
    currentIndex: Number(history.currentIndex ?? -1),
    canUndo: Boolean(history.canUndo),
    canRedo: Boolean(history.canRedo),
    currentSnapshot: history.currentSnapshot ?? null,
    previousSnapshot: history.previousSnapshot ?? null,
    nextSnapshot: history.nextSnapshot ?? null,
    recentSnapshots: Array.isArray(history.recentSnapshots) ? history.recentSnapshots : [],
    timelineSnapshots: Array.isArray(history.timelineSnapshots) ? history.timelineSnapshots : [],
  };
}

function getHistorySnapshotByIndex(targetIndex, history = state.projectHistory) {
  const safeHistory = getSafeProjectHistory(history);
  const numericIndex = Number(targetIndex);
  if (Number.isNaN(numericIndex)) {
    return null;
  }
  return safeHistory.timelineSnapshots.find((snapshot) => Number(snapshot.index) === numericIndex) ?? null;
}

function getHistoryKindLabel(kind) {
  if (kind === "manual") {
    return "手动检查点";
  }
  if (kind === "baseline") {
    return "项目基线";
  }
  return "自动快照";
}

function getHistoryKindTone(kind) {
  if (kind === "manual") {
    return "good";
  }
  if (kind === "baseline") {
    return "soft";
  }
  return "warn";
}

function getSafeHistoryFilterMode(value) {
  return ["all", "manual", "auto", "baseline", "current"].includes(value) ? value : "all";
}

function getHistoryFilterLabel(value) {
  const labels = {
    all: "全部版本",
    manual: "只看检查点",
    auto: "只看自动快照",
    baseline: "只看基线",
    current: "只看当前版本",
  };
  return labels[getSafeHistoryFilterMode(value)] ?? labels.all;
}

function getHistoryChangeKindLabel(kind) {
  if (kind === "created") {
    return "新增";
  }
  if (kind === "removed") {
    return "移除";
  }
  return "改动";
}

function getFilteredHistorySnapshots(history = state.projectHistory) {
  const safeHistory = getSafeProjectHistory(history);
  const query = String(state.historySearchQuery ?? "").trim().toLowerCase();
  const filterMode = getSafeHistoryFilterMode(state.historyFilterMode);

  return (safeHistory.timelineSnapshots ?? []).filter((snapshot) => {
    if (filterMode === "manual" && snapshot.kind !== "manual") {
      return false;
    }
    if (filterMode === "auto" && snapshot.kind !== "auto") {
      return false;
    }
    if (filterMode === "baseline" && snapshot.kind !== "baseline") {
      return false;
    }
    if (filterMode === "current" && !snapshot.isCurrent) {
      return false;
    }
    if (!query) {
      return true;
    }

    const haystack = [snapshot.label, getHistoryKindLabel(snapshot.kind), formatDate(snapshot.createdAt)]
      .filter(Boolean)
      .join(" ")
      .toLowerCase();
    return haystack.includes(query);
  });
}

function renderHistorySnapshotCard(snapshot, options = {}) {
  if (!snapshot) {
    return "";
  }

  const isCompact = options.compact === true;
  const isCurrent = Boolean(snapshot.isCurrent);
  const canRestore = options.allowRestore !== false && !isCurrent;
  const canRelabel = options.allowRelabel !== false;
  const title = String(snapshot.label ?? "未命名快照").trim() || "未命名快照";
  const metaLabel = `${getHistoryKindLabel(snapshot.kind)} · 第 ${Number(snapshot.index ?? 0) + 1} 份`;

  return `
    <article class="history-card ${isCurrent ? "is-current" : ""} ${snapshot.kind === "manual" ? "is-manual" : ""} ${
      snapshot.kind === "baseline" ? "is-baseline" : ""
    }">
      <div class="history-card-top">
        <div class="history-card-title">
          <div class="pill-row">
            <span class="issue-tag ${getDashboardTaskToneClass(getHistoryKindTone(snapshot.kind))}">${escapeHtml(
              getHistoryKindLabel(snapshot.kind)
            )}</span>
            ${isCurrent ? '<span class="issue-tag is-good">当前版本</span>' : ""}
          </div>
          <strong>${escapeHtml(title)}</strong>
        </div>
        <span class="history-card-time">${escapeHtml(formatDate(snapshot.createdAt))}</span>
      </div>
      <div class="history-card-meta">${escapeHtml(metaLabel)}</div>
      <div class="history-card-actions">
        ${
          canRestore
            ? `<button class="toolbar-button ${isCompact ? "" : "toolbar-button-primary"}" data-action="restore-project-history" data-history-index="${Number(
                snapshot.index ?? -1
              )}">
                恢复到这里
              </button>`
            : '<button class="toolbar-button" type="button" disabled>当前就在这里</button>'
        }
        ${
          canRelabel
            ? `<button class="toolbar-button" data-action="rename-project-history-snapshot" data-history-index="${Number(
                snapshot.index ?? -1
              )}">
                改备注
              </button>`
            : ""
        }
      </div>
    </article>
  `;
}

function renderHistoryTimeline(history = state.projectHistory, options = {}) {
  const safeHistory = getSafeProjectHistory(history);
  const snapshots = options.filteredSnapshots ?? getFilteredHistorySnapshots(history);

  if (snapshots.length === 0) {
    return safeHistory.totalSnapshots > 0
      ? '<div class="history-empty">当前筛选下还没有命中的快照，可以换个关键词或切回“全部版本”。</div>'
      : '<div class="history-empty">这个项目还没有可显示的快照时间线。</div>';
  }

  return snapshots
    .map((snapshot) => renderHistorySnapshotCard(snapshot, options))
    .join("");
}

function formatHistoryRestorePreview(preview) {
  if (!preview || typeof preview !== "object") {
    return "恢复后会把项目回到你选中的那个时间点。";
  }

  const changedFileCount = Number(preview.changedFileCount ?? 0);
  if (changedFileCount <= 0) {
    return "当前版本和目标版本没有差异。";
  }

  const changedItems = Array.isArray(preview.changedItems) ? preview.changedItems : [];
  const detailLines = changedItems
    .slice(0, 6)
    .map((item) => `- ${item.label ?? item.path ?? "未知内容"}（${getHistoryChangeKindLabel(item.kind)}）`);
  const hiddenCount = Math.max(changedItems.length - detailLines.length, 0);
  return [
    `恢复后会影响 ${changedFileCount} 处内容。`,
    detailLines.length > 0 ? "" : null,
    ...detailLines,
    hiddenCount > 0 ? `- 另外还有 ${hiddenCount} 处变化` : null,
  ]
    .filter(Boolean)
    .join("\n");
}

function updateErrorRecoveryState(history = state.projectHistory) {
  if (!refs.errorRecoveryState || !refs.errorRecoveryMessage || !refs.historyRestoreButton) {
    return;
  }

  const safeHistory = getSafeProjectHistory(history);
  const canRestore = safeHistory.canUndo;
  const currentLabel = safeHistory.currentSnapshot?.label ?? "当前版本";
  const previousLabel = safeHistory.previousSnapshot?.label ?? "上个版本";
  refs.errorRecoveryState.classList.toggle("is-hidden", safeHistory.totalSnapshots === 0);
  refs.errorRecoveryMessage.textContent =
    safeHistory.totalSnapshots === 0
      ? "如存在可用的自动保存版本，这里会显示恢复入口。"
      : canRestore
        ? `已经找到 ${safeHistory.totalSnapshots} 份自动快照。当前停在「${currentLabel}」，可以尝试恢复到「${previousLabel}」。`
        : `已经找到 ${safeHistory.totalSnapshots} 份自动快照，但当前已经是最早版本「${currentLabel}」。`;

  if (refs.errorRecoverButton) {
    refs.errorRecoverButton.disabled = !canRestore;
  }

  if (refs.errorRecoveryTimeline) {
    refs.errorRecoveryTimeline.innerHTML =
      safeHistory.totalSnapshots > 0 ? renderHistoryTimeline(safeHistory, { compact: true, allowRelabel: false }) : "";
  }
}

function showFatalProjectLoadError(error) {
  refs.loadingState.classList.add("is-hidden");
  refs.projectCenterState.classList.add("is-hidden");
  refs.appMain.classList.add("is-hidden");
  refs.errorState.classList.remove("is-hidden");
  refs.errorMessage.textContent = error?.message ?? "当前还没有可显示的错误信息。";
  state.data = null;
  state.validation = null;
  state.lastExportResult = null;
  state.projectHistory = error?.recovery ?? null;
  state.projectSessionRecovery = null;
  setProjectChromeEnabled(false);
  updateErrorRecoveryState();
  updateTopbar();
  setSaveStatus("项目载入失败", true);
}

function handleProjectLoadFailure(error, fallbackMessage) {
  if (error?.recovery) {
    showFatalProjectLoadError(error);
    showToast("项目打开失败，但已经找到可恢复的自动快照", "error");
    return true;
  }

  setSaveStatus(fallbackMessage, true);
  showToast(fallbackMessage, "error");
  return false;
}

async function maybePromptProjectRecovery(data = state.data) {
  if (!data?.project?.projectId) {
    return;
  }

  const recovery = getSafeProjectSessionRecovery(data.sessionRecovery ?? state.projectSessionRecovery);
  const history = getSafeProjectHistory(data.history ?? state.projectHistory);
  const previousSnapshot =
    history.previousSnapshot ?? getHistorySnapshotByIndex(Number(history.currentIndex) - 1, history);
  const promptKey = `${data.project.projectId}:${recovery.lastUnexpectedExitAt || recovery.lastUnexpectedExitStartedAt || "none"}`;

  if (!recovery.noticeActive || !previousSnapshot || state.historyRecoveryPromptKey === promptKey) {
    return;
  }

  state.historyRecoveryPromptKey = promptKey;
  const shouldRestore = await confirmRestoreProjectHistorySnapshot(previousSnapshot, {
    introText: "检测到上次可能没有正常退出。是否恢复到上次安全点？",
  });

  if (shouldRestore) {
    await applyProjectHistoryAction("restore", {
      targetIndex: Number(previousSnapshot.index ?? history.currentIndex - 1),
      snapshotLabel: previousSnapshot.label ?? "上次安全点",
      acknowledgeRecoveryNotice: true,
    });
    return;
  }

  showToast("稍后仍可在首页的项目安全网中恢复到上次安全点");
}

