function hydrateProjectRuntime(data) {
  resetProjectScopedUiState();
  state.data = data;
  state.projectHistory = data.history ?? null;
  state.projectSessionRecovery = data.sessionRecovery ?? null;
  if (data.currentProject?.projectId) {
    state.projectCenter.activeProjectId = data.currentProject.projectId;
  }
  state.previewPlayback = loadStoredPreviewPlaybackSettings(data.project);
  applyEditorUiTheme(state.previewPlayback.uiThemeMode);
  state.previewAutoResume = loadStoredPreviewAutoResume(data.project);
  state.previewReadHistory = loadStoredPreviewReadHistory(data.project);
  state.previewSaveSlots = loadStoredPreviewSaveSlots(data.project);
  state.previewQuickSave = loadStoredPreviewQuickSave(data.project);
  state.recentWorkspaceItems = loadStoredRecentWorkspaceItems(data.project);
  state.validation = runValidation(data);
  updateErrorRecoveryState(null);
  initializeSelection(data);
  renderAll();
  void maybePromptProjectRecovery(data);
}

function clearLoadedProjectState() {
  resetProjectScopedUiState();
  state.data = null;
  state.validation = null;
  state.lastExportResult = null;
  state.projectHistory = null;
  state.projectSessionRecovery = null;
  updateErrorRecoveryState(null);
}

function isCurrentProjectBlank() {
  return Boolean(state.data) && state.data.chapters.length === 0 && state.data.scenes.length === 0;
}

function getBlankProjectStarterDefaults() {
  return {
    chapterName: "第一章 开场",
    firstSceneName: "第一场 相遇",
  };
}

function getStarterKitDefaults() {
  return {
    characterName: "女主角",
    backgroundName: "第一场背景",
    bgmName: "开场 BGM",
  };
}

function getStarterKitOverview(data = state.data) {
  const safeData = data ?? {};
  const assetList = safeData.assetList ?? [];
  const characters = safeData.characters ?? [];
  const hasScenes = (safeData.scenes?.length ?? 0) > 0;
  const missingCharacter = characters.length === 0;
  const missingBackground = !assetList.some((asset) => asset.type === "background");
  const missingBgm = !assetList.some((asset) => asset.type === "bgm");
  const missingLabels = [];

  if (missingCharacter) {
    missingLabels.push("第一个角色");
  }

  if (missingBackground) {
    missingLabels.push("第一张背景");
  }

  if (missingBgm) {
    missingLabels.push("第一首 BGM");
  }

  return {
    hasScenes,
    missingCharacter,
    missingBackground,
    missingBgm,
    missingLabels,
    needsStarterKit: hasScenes && missingLabels.length > 0,
  };
}

function renderStarterKitPanel(context = "dashboard") {
  const overview = getStarterKitOverview();
  if (!overview.needsStarterKit) {
    return "";
  }

  const defaults = getStarterKitDefaults();
  const contextCopy = {
    dashboard: "当前项目已经有章节骨架，下一步适合补齐角色、背景和 BGM 的基础条目。",
    story: "当前剧情已经可以继续写入，补齐角色、背景和 BGM 后，预览和演出会更完整。",
    assets: "这里可以生成“背景 / 立绘 / BGM”的起步条目，后续再替换成正式素材文件。",
    characters: "先补齐第一个角色骨架后，台词归属、立绘表情和语音整理会更完整。",
  };

  return `
    <section class="detail-card starter-kit-panel">
      <div class="panel-heading">
        <h3>第二步起步骨架</h3>
        <span class="badge badge-soft">补齐基础条目</span>
      </div>
      <div class="starter-kit-grid">
        <article class="starter-kit-card is-primary">
          <span class="eyebrow">当前进度</span>
          <strong>补齐角色与基础素材</strong>
          <p>${escapeHtml(contextCopy[context] ?? contextCopy.dashboard)}</p>
          <div class="scene-card-tags">
            ${overview.missingLabels
              .map((label) => `<span class="issue-tag warn-text">待补：${escapeHtml(label)}</span>`)
              .join("")}
          </div>
          <div class="pill-row">
            ${overview.missingCharacter ? `<span class="pill">角色默认名：${escapeHtml(defaults.characterName)}</span>` : ""}
            ${overview.missingBackground ? `<span class="pill">背景默认名：${escapeHtml(defaults.backgroundName)}</span>` : ""}
            ${overview.missingBgm ? `<span class="pill">BGM 默认名：${escapeHtml(defaults.bgmName)}</span>` : ""}
          </div>
          <div class="action-row">
            <button class="toolbar-button toolbar-button-primary" type="button" data-action="create-starter-kit">
              一键生成起步骨架
            </button>
            <button class="toolbar-button" type="button" data-action="create-starter-kit-custom">
              自定义名字再生成
            </button>
          </div>
        </article>
        <article class="starter-kit-card">
          <span class="eyebrow">生成内容</span>
          <ul class="blank-project-step-list">
            ${overview.missingCharacter ? "<li>生成一个角色骨架，并自动带一张默认立绘条目。</li>" : ""}
            ${overview.missingBackground ? "<li>生成第一张背景条目，方便你后面直接替换成真实图片。</li>" : ""}
            ${overview.missingBgm ? "<li>生成第一首 BGM 条目，后面导入音乐时不用再从零建分类。</li>" : ""}
          </ul>
          <div class="detail-meta">此操作只会补齐条目骨架，不会改动现有剧情内容。</div>
        </article>
      </div>
    </section>
  `;
}

