function renderDashboardTaskActions(actions = []) {
  return actions
    .slice(0, 2)
    .map((action, index) => renderQuickActionButton(action, index === 0))
    .join("");
}

function renderQuickActionButton(action, emphasized = false) {
  const className = `toolbar-button${emphasized ? " toolbar-button-primary" : ""}`;
  const label = escapeHtml(action.label ?? "去处理");
  const datasetMarkup = Object.entries(action.dataset ?? {})
    .map(([key, value]) => ` data-${key}="${escapeHtml(String(value ?? ""))}"`)
    .join("");

  if (action.href) {
    return `
      <a
        class="${className}"
        href="${escapeHtml(action.href)}"
        target="_blank"
        rel="noreferrer"
      >
        ${label}
      </a>
    `;
  }

  if (action.action === "open-scene-from-map" || action.action === "preview-scene-from-map") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="${action.action}"
        data-scene-id="${escapeHtml(action.sceneId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "open-character-line") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="open-character-line"
        data-scene-id="${escapeHtml(action.sceneId ?? "")}"
        data-block-id="${escapeHtml(action.blockId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "preview-story-location") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="preview-story-location"
        data-scene-id="${escapeHtml(action.sceneId ?? "")}"
        data-block-id="${escapeHtml(action.blockId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "open-dashboard-character") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="open-dashboard-character"
        data-character-id="${escapeHtml(action.characterId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "open-script-chapter-scene") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="open-script-chapter-scene"
        data-chapter-id="${escapeHtml(action.chapterId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "open-asset-from-issue") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="open-asset-from-issue"
        data-asset-id="${escapeHtml(action.assetId ?? "")}"
      >
        ${label}
      </button>
    `;
  }

  if (action.action === "switch-screen") {
    return `
      <button
        type="button"
        class="${className}"
        data-action="switch-screen"
        data-screen="${escapeHtml(action.screen ?? "dashboard")}"
      >
        ${label}
      </button>
    `;
  }

  return `
    <button
      type="button"
      class="${className}"
      data-action="${escapeHtml(action.action ?? "")}"
      ${datasetMarkup}
    >
      ${label}
    </button>
  `;
}

function getDashboardTaskToneClass(tone) {
  if (tone === "danger") {
    return "danger-text";
  }
  if (tone === "warn") {
    return "warn-text";
  }
  if (tone === "good") {
    return "good-text";
  }
  return "";
}

function buildSceneRouteOverview() {
  const entrySceneId = state.data.project.entrySceneId;
  const incomingCounts = new Map();
  const brokenRoutes = [];
  const effectBlockTypes = new Set([
    "particle_effect",
    "screen_shake",
    "screen_flash",
    "screen_fade",
    "camera_zoom",
    "camera_pan",
    "screen_filter",
    "depth_blur",
  ]);
  const validationSceneIndex = buildRouteValidationSceneIndex();

  const chapters = state.data.chapters.map((chapter, chapterIndex) => {
    const sceneNodes = (chapter.sceneOrder ?? [])
      .map((sceneId, sceneIndex) => {
        const scene = state.data.scenesById.get(sceneId);
        if (!scene) {
          return null;
        }

        const routes = collectSceneRoutes(scene);
        return {
          id: scene.id,
          name: scene.name,
          status: getSafeSceneStatus(scene.status),
          priority: getSafeScenePriority(scene.priority),
          notes: String(scene.notes ?? "").trim(),
          chapterId: chapter.chapterId,
          chapterName: chapter.name,
          chapterIndex,
          sceneIndex,
          blockCount: scene.blocks?.length ?? 0,
          dialogueCount: (scene.blocks ?? []).filter((block) => block.type === "dialogue").length,
          narrationCount: (scene.blocks ?? []).filter((block) => block.type === "narration").length,
          choiceCount: (scene.blocks ?? []).filter((block) => block.type === "choice").length,
          conditionCount: (scene.blocks ?? []).filter((block) => block.type === "condition").length,
          routes,
          isEntry: scene.id === entrySceneId,
          ...buildRouteSceneProduction(scene, effectBlockTypes, validationSceneIndex.get(scene.id)),
        };
      })
      .filter(Boolean);

    return {
      chapterId: chapter.chapterId,
      name: chapter.name,
      chapterIndex,
      scenes: sceneNodes,
      production: buildRouteChapterProduction(sceneNodes),
    };
  });

  const nodes = chapters.flatMap((chapter) => chapter.scenes);

  nodes.forEach((node) => {
    node.routes.forEach((route) => {
      if (route.targetExists) {
        incomingCounts.set(route.targetSceneId, (incomingCounts.get(route.targetSceneId) ?? 0) + 1);
      } else {
        brokenRoutes.push(route);
      }
    });
  });

  nodes.forEach((node) => {
    const validRoutes = node.routes.filter((route) => route.targetExists);
    node.incomingCount = incomingCounts.get(node.id) ?? 0;
    node.branchTargetCount = new Set(validRoutes.map((route) => route.targetSceneId)).size;
    node.brokenRouteCount = node.routes.length - validRoutes.length;
    node.isOrphan = !node.isEntry && node.incomingCount === 0;
    node.isEnding = validRoutes.length === 0;
  });

  const alerts = [
    ...brokenRoutes.map((route) => ({
      sceneId: route.sourceSceneId,
      sceneName: route.sourceSceneName,
      label: "坏链",
      tone: "danger",
      message: `${route.shortLabel} 指向了一个不存在的场景。`,
      meta: `${route.meta} -> ${route.targetSceneName}`,
    })),
    ...nodes
      .filter((node) => node.isOrphan)
      .map((node) => ({
        sceneId: node.id,
        sceneName: node.name,
        label: "孤立",
        tone: "warn",
        message: "目前没有任何分支、跳转或条件会走到这个场景。",
        meta: "如果这不是隐藏路线，可从别的场景补一条入口。",
      })),
    ...nodes
      .filter((node) => node.isEnding && !node.isEntry)
      .map((node) => ({
        sceneId: node.id,
        sceneName: node.name,
        label: "收束",
        tone: "soft",
        message: "这个场景没有继续跳往别处的路线。",
        meta: "如果它就是结局或章节收尾，那现在这样完全没问题。",
      })),
  ].sort((left, right) => getRouteAlertPriority(left.tone) - getRouteAlertPriority(right.tone));

  return {
    chapters,
    nodes,
    alerts,
    metrics: {
      entrySceneName: state.data.scenesById.get(entrySceneId)?.name ?? "未设置",
      branchingScenes: nodes.filter((node) => node.branchTargetCount > 1).length,
      endingScenes: nodes.filter((node) => node.isEnding).length,
      orphanScenes: nodes.filter((node) => node.isOrphan).length,
      brokenRoutes: brokenRoutes.length,
    },
  };
}

function buildRouteValidationSceneIndex() {
  const sceneIndex = new Map();

  function bumpIssue(sceneId, tone) {
    if (!sceneId) {
      return;
    }

    const entry = sceneIndex.get(sceneId) ?? { errorCount: 0, warningCount: 0 };
    if (tone === "error") {
      entry.errorCount += 1;
    } else {
      entry.warningCount += 1;
    }
    sceneIndex.set(sceneId, entry);
  }

  state.validation.errors.forEach((issue) => {
    const context = issue?.context;
    if (context?.type === "story" || context?.type === "scene") {
      bumpIssue(context.sceneId, "error");
    }
  });

  state.validation.warnings.forEach((issue) => {
    const context = issue?.context;
    if (context?.type === "story" || context?.type === "scene") {
      bumpIssue(context.sceneId, "warning");
    }
  });

  return sceneIndex;
}

function buildRouteSceneProduction(scene, effectBlockTypes, issueCounts = null) {
  const blocks = scene.blocks ?? [];
  const dialogueBlocks = blocks.filter((block) => block.type === "dialogue");
  const hasStoryContent = blocks.some((block) => ["dialogue", "narration", "choice"].includes(block.type));
  const hasBackground = blocks.some((block) => block.type === "background" && block.assetId);
  const hasMusic = blocks.some((block) => block.type === "music_play" && block.assetId);
  const hasEffects = blocks.some((block) => effectBlockTypes.has(block.type));
  const missingVoiceCount = dialogueBlocks.filter((block) => !block.voiceAssetId).length;
  const voicedDialogueCount = Math.max(dialogueBlocks.length - missingVoiceCount, 0);
  const voiceProgress =
    dialogueBlocks.length > 0 ? getDashboardProgressPercent(voicedDialogueCount, dialogueBlocks.length) : 100;
  const baseScore =
    (hasStoryContent ? 34 : 0) +
    (hasBackground ? 18 : 0) +
    (hasMusic ? 12 : 0) +
    (hasEffects ? 15 : 0) +
    (hasStoryContent ? Math.round((voiceProgress / 100) * 21) : 0);
  const errorCount = issueCounts?.errorCount ?? 0;
  const warningCount = issueCounts?.warningCount ?? 0;
  const issuePenalty = Math.min(24, errorCount * 10 + warningCount * 4);
  const completionScore = clamp(baseScore - issuePenalty, 0, 100);

  return {
    hasStoryContent,
    hasBackground,
    hasMusic,
    hasEffects,
    missingVoiceCount,
    voicedDialogueCount,
    voiceProgress,
    completionScore,
    errorCount,
    warningCount,
  };
}

function buildRouteChapterProduction(sceneNodes) {
  if (!sceneNodes.length) {
    return {
      averageCompletion: 0,
      readyCount: 0,
      missingBackgroundCount: 0,
      missingVoiceSceneCount: 0,
      flatSceneCount: 0,
      issueSceneCount: 0,
    };
  }

  return {
    averageCompletion: Math.round(
      sceneNodes.reduce((sum, node) => sum + (node.completionScore ?? 0), 0) / sceneNodes.length
    ),
    readyCount: sceneNodes.filter((node) => (node.completionScore ?? 0) >= 80).length,
    missingBackgroundCount: sceneNodes.filter((node) => node.hasStoryContent && !node.hasBackground).length,
    missingVoiceSceneCount: sceneNodes.filter((node) => node.missingVoiceCount > 0).length,
    flatSceneCount: sceneNodes.filter((node) => node.hasStoryContent && !node.hasEffects).length,
    issueSceneCount: sceneNodes.filter((node) => (node.errorCount ?? 0) > 0 || (node.warningCount ?? 0) > 0).length,
  };
}

function buildRouteSceneProductionNotes(node) {
  const notes = [];

  if (!node.hasStoryContent) {
    notes.push("正文未开始");
  }

  if (node.hasStoryContent && !node.hasBackground) {
    notes.push("缺背景");
  }

  if (node.hasStoryContent && !node.hasMusic) {
    notes.push("缺 BGM");
  }

  if (node.missingVoiceCount > 0) {
    notes.push(`缺语音 ${node.missingVoiceCount} 句`);
  }

  if (node.hasStoryContent && !node.hasEffects) {
    notes.push("演出偏素");
  }

  if ((node.errorCount ?? 0) > 0) {
    notes.push(`结构错误 ${node.errorCount}`);
  } else if ((node.warningCount ?? 0) > 0) {
    notes.push(`提醒 ${node.warningCount}`);
  }

  if (notes.length === 0) {
    notes.push("可以继续抛光");
  }

  return notes.slice(0, 4);
}

function collectSceneRoutes(scene) {
  const routes = [];

  (scene.blocks ?? []).forEach((block, blockIndex) => {
    if (block.type === "jump") {
      routes.push(
        createSceneRoute(scene, {
          blockIndex,
          routeKind: "jump",
          targetSceneId: block.targetSceneId,
          label: "直接跳转",
          shortLabel: "跳转",
          meta: `第 ${blockIndex + 1} 张卡片`,
        })
      );
    }

    if (block.type === "choice") {
      (block.options ?? []).forEach((option, optionIndex) => {
        routes.push(
          createSceneRoute(scene, {
            blockIndex,
            routeKind: "choice",
            targetSceneId: option.gotoSceneId,
            label: truncateText(option.text || `选项 ${optionIndex + 1}`, 20),
            shortLabel: "选项",
            meta: `第 ${blockIndex + 1} 张卡片 / 选项 ${optionIndex + 1}`,
          })
        );
      });
    }

    if (block.type === "condition") {
      (block.branches ?? []).forEach((branch, branchIndex) => {
        routes.push(
          createSceneRoute(scene, {
            blockIndex,
            routeKind: "condition",
            targetSceneId: branch.gotoSceneId,
            label: summarizeConditionBranchForRoute(branch),
            shortLabel: "条件",
            meta: `第 ${blockIndex + 1} 张卡片 / 条件分支 ${branchIndex + 1}`,
          })
        );
      });

      routes.push(
        createSceneRoute(scene, {
          blockIndex,
          routeKind: "fallback",
          targetSceneId: block.elseGotoSceneId,
          label: "都不满足时",
          shortLabel: "否则",
          meta: `第 ${blockIndex + 1} 张卡片 / 否则`,
        })
      );
    }
  });

  return routes;
}

function createSceneRoute(scene, config) {
  const targetScene = state.data.scenesById.get(config.targetSceneId);

  return {
    id: `${scene.id}-${config.blockIndex}-${config.routeKind}-${config.targetSceneId ?? "missing"}-${config.meta}`,
    sourceSceneId: scene.id,
    sourceSceneName: scene.name,
    targetSceneId: config.targetSceneId ?? "",
    targetSceneName: targetScene?.name ?? (config.targetSceneId || "未设置目标"),
    targetExists: Boolean(targetScene),
    routeKind: config.routeKind,
    label: config.label,
    shortLabel: config.shortLabel,
    meta: config.meta,
  };
}

function summarizeConditionBranchForRoute(branch) {
  const rules = (branch.when ?? [])
    .map((rule) => {
      const variableName = state.data.variablesById.get(rule.variableId)?.name ?? rule.variableId;
      const operatorLabel =
        getConditionOperators(rule.variableId).find(([value]) => value === getSafeConditionOperator(rule.variableId, rule.operator))?.[1] ??
        rule.operator ??
        "等于";
      return `${variableName} ${operatorLabel} ${formatVariableValue(rule.variableId, rule.value)}`;
    })
    .filter(Boolean);

  if (rules.length === 0) {
    return "满足条件时";
  }

  return truncateText(rules.join(" 且 "), 28);
}

function getRouteAlertPriority(tone) {
  if (tone === "danger") {
    return 0;
  }
  if (tone === "warn") {
    return 1;
  }
  return 2;
}

function renderRouteMetricCard(label, value, hint) {
  return `
    <article class="route-metric-card">
      <span>${escapeHtml(label)}</span>
      <strong>${escapeHtml(String(value))}</strong>
      <small>${escapeHtml(hint)}</small>
    </article>
  `;
}

function renderRouteMapBoard(routeOverview) {
  if ((routeOverview.chapters ?? []).length === 0) {
    return renderEmpty("当前项目还没有章节，路线图会在你建好章节后自动出现。");
  }

  const safeFilter = getSafeRouteMapFilter(state.dashboardRouteFilter);
  const filteredChapters = routeOverview.chapters
    .map((chapter) => ({
      ...chapter,
      visibleScenes: (chapter.scenes ?? []).filter((node) => doesRouteNodeMatchFilter(node, safeFilter)),
    }))
    .filter((chapter) => chapter.visibleScenes.length > 0);

  if (filteredChapters.length === 0) {
    return renderEmpty(`当前没有命中“${getRouteMapFilterLabel(safeFilter)}”的场景。可以切回全部，或者先继续写一点内容。`);
  }

  return `
    <div class="route-map-board">
      ${filteredChapters
        .map(
          (chapter) => `
            <section class="route-column">
              <div class="route-column-header">
                <strong>${escapeHtml(chapter.name)}</strong>
                <span>${chapter.visibleScenes.length}/${chapter.scenes.length} 个场景 · 推进 ${chapter.production.averageCompletion}%</span>
              </div>
              <div class="route-column-progress">
                <span class="issue-tag good-text">完成度 ${chapter.production.averageCompletion}%</span>
                <span class="issue-tag ${chapter.production.missingBackgroundCount > 0 ? "warn-text" : ""}">
                  缺背景 ${chapter.production.missingBackgroundCount}
                </span>
                <span class="issue-tag ${chapter.production.missingVoiceSceneCount > 0 ? "warn-text" : ""}">
                  缺语音 ${chapter.production.missingVoiceSceneCount}
                </span>
                <span class="issue-tag ${chapter.production.flatSceneCount > 0 ? "" : "good-text"}">
                  演出偏素 ${chapter.production.flatSceneCount}
                </span>
                <span class="issue-tag ${chapter.production.issueSceneCount > 0 ? "danger-text" : "good-text"}">
                  问题场景 ${chapter.production.issueSceneCount}
                </span>
              </div>
              <div class="route-node-stack">
                ${
                  chapter.visibleScenes.length === 0
                    ? renderEmpty("这一章暂时还没有场景。")
                    : chapter.visibleScenes.map((node) => renderRouteSceneCard(node)).join("")
                }
              </div>
            </section>
          `
        )
        .join("")}
    </div>
  `;
}

function renderRouteSceneCard(node) {
  const badges = [];
  const productionNotes = buildRouteSceneProductionNotes(node);
  const planningBadges = renderScenePlanningBadges(node);
  const quickButtons = renderScenePlanningQuickButtons(node);

  if (node.isEntry) {
    badges.push('<span class="issue-tag good-text">入口</span>');
  }

  if ((node.errorCount ?? 0) > 0) {
    badges.push(`<span class="issue-tag danger-text">错误 ${node.errorCount}</span>`);
  }

  if ((node.warningCount ?? 0) > 0) {
    badges.push(`<span class="issue-tag warn-text">提醒 ${node.warningCount}</span>`);
  }

  if (node.brokenRouteCount > 0) {
    badges.push(`<span class="issue-tag danger-text">坏链 ${node.brokenRouteCount}</span>`);
  }

  if (node.isOrphan) {
    badges.push('<span class="issue-tag warn-text">孤立</span>');
  }

  if (node.isEnding) {
    badges.push('<span class="issue-tag">收束</span>');
  }

  if (node.branchTargetCount > 1) {
    badges.push(`<span class="issue-tag good-text">分叉 ${node.branchTargetCount}</span>`);
  }

  const routeListMarkup =
    node.routes.length === 0
      ? '<div class="route-empty-note">这个场景没有继续跳往别的场景的卡片。</div>'
      : `
          <div class="route-link-list">
            ${node.routes
              .map(
                (route) => `
                  <button
                    type="button"
                    class="route-link-chip route-link-chip-${route.routeKind} ${route.targetExists ? "" : "is-broken"}"
                    ${route.targetExists ? `data-action="open-scene-from-map" data-scene-id="${route.targetSceneId}"` : "disabled"}
                    title="${escapeHtml(`${route.meta} -> ${route.targetSceneName}`)}"
                  >
                    <span>${escapeHtml(route.shortLabel)}</span>
                    <strong>${escapeHtml(route.label)}</strong>
                    <small>${escapeHtml(route.targetSceneName)}</small>
                  </button>
                `
              )
              .join("")}
          </div>
        `;

  return `
    <article class="route-scene-card ${node.id === state.selectedSceneId ? "is-selected" : ""}">
      <div class="route-scene-head">
        <div>
          <div class="route-scene-order">场景 ${node.sceneIndex + 1}</div>
          <h3>${escapeHtml(node.name)}</h3>
        </div>
        <div class="route-badge-row">
          ${badges.join("") || '<span class="issue-tag">普通节点</span>'}
        </div>
      </div>
      <div class="route-scene-meta">
        ${node.blockCount} 张卡片 · ${node.dialogueCount} 句台词 · ${node.choiceCount} 个选项 ·
        ${node.conditionCount} 次判断 · 来路 ${node.incomingCount} 条
      </div>
      <div class="route-scene-progress">
        <div class="route-scene-progress-head">
          <strong>制作完成度 ${node.completionScore}%</strong>
          <span>语音 ${node.voiceProgress}%</span>
        </div>
        <div class="route-scene-progress-track">
          <span class="route-scene-progress-fill" style="width:${node.completionScore}%;"></span>
        </div>
      </div>
      <div class="route-scene-status-row">
        ${planningBadges}
        ${productionNotes
          .map((note) => `<span class="issue-tag ${/错误/.test(note) ? "danger-text" : /缺|提醒/.test(note) ? "warn-text" : ""}">${escapeHtml(note)}</span>`)
          .join("")}
      </div>
      ${quickButtons}
      ${node.notes ? `<div class="route-scene-note">${escapeHtml(truncateText(node.notes, 84))}</div>` : ""}
      ${routeListMarkup}
      <div class="route-scene-actions">
        <button type="button" class="toolbar-button toolbar-button-primary" data-action="open-scene-from-map" data-scene-id="${node.id}">
          继续写这里
        </button>
        <button type="button" class="toolbar-button" data-action="preview-scene-from-map" data-scene-id="${node.id}">
          从这里试玩
        </button>
      </div>
    </article>
  `;
}

function renderRouteAlerts(routeOverview) {
  const alerts = routeOverview.alerts.slice(0, 8);

  if (alerts.length === 0) {
    return renderEmpty("目前没有明显的路线结构提醒，说明这份模板至少在连接关系上还算顺。");
  }

  return `
    <div class="list-stack">
      ${alerts
        .map(
          (alert) => `
            <article class="route-alert-card ${alert.tone === "danger" ? "is-danger" : alert.tone === "warn" ? "is-warn" : ""}">
              <div class="route-alert-top">
                <span class="issue-tag ${alert.tone === "danger" ? "danger-text" : alert.tone === "warn" ? "warn-text" : ""}">
                  ${escapeHtml(alert.label)}
                </span>
                <button type="button" class="toolbar-button" data-action="open-scene-from-map" data-scene-id="${alert.sceneId}">
                  打开场景
                </button>
              </div>
              <strong>${escapeHtml(alert.sceneName)}</strong>
              <p>${escapeHtml(alert.message)}</p>
              <div class="detail-meta">${escapeHtml(alert.meta)}</div>
            </article>
          `
        )
        .join("")}
    </div>
  `;
}

function getSafeDashboardSearchMode(mode) {
  return Object.prototype.hasOwnProperty.call(DASHBOARD_SEARCH_MODE_LABELS, mode) ? mode : "all";
}

function getDashboardSearchModeLabel(mode) {
  return DASHBOARD_SEARCH_MODE_LABELS[getSafeDashboardSearchMode(mode)] ?? DASHBOARD_SEARCH_MODE_LABELS.all;
}

function getSafeRouteMapFilter(mode) {
  return Object.prototype.hasOwnProperty.call(ROUTE_MAP_FILTER_LABELS, mode) ? mode : "all";
}

function getRouteMapFilterLabel(mode) {
  return ROUTE_MAP_FILTER_LABELS[getSafeRouteMapFilter(mode)] ?? ROUTE_MAP_FILTER_LABELS.all;
}

function getSafeSceneStatus(value) {
  return Object.prototype.hasOwnProperty.call(SCENE_STATUS_LABELS, value) ? value : "drafting";
}

function getSceneStatusLabel(value) {
  return SCENE_STATUS_LABELS[getSafeSceneStatus(value)] ?? SCENE_STATUS_LABELS.drafting;
}

function getSafeScenePriority(value) {
  return Object.prototype.hasOwnProperty.call(SCENE_PRIORITY_LABELS, value) ? value : "normal";
}

function getScenePriorityLabel(value) {
  return SCENE_PRIORITY_LABELS[getSafeScenePriority(value)] ?? SCENE_PRIORITY_LABELS.normal;
}

function getSceneStatusToneClass(status) {
  const safeStatus = getSafeSceneStatus(status);
  if (safeStatus === "ready") {
    return "good-text";
  }
  if (safeStatus === "polishing") {
    return "warn-text";
  }
  return "";
}

function getScenePriorityToneClass(priority) {
  const safePriority = getSafeScenePriority(priority);
  if (safePriority === "rush") {
    return "danger-text";
  }
  if (safePriority === "focus") {
    return "warn-text";
  }
  return "";
}

function getSceneQuickButtonToneClass(kind, value) {
  if (kind === "status") {
    return getSafeSceneStatus(value) === "ready" ? "is-good" : "is-soft";
  }

  const safePriority = getSafeScenePriority(value);
  if (safePriority === "rush") {
    return "is-danger";
  }
  if (safePriority === "focus") {
    return "is-warn";
  }
  if (safePriority === "parked") {
    return "is-muted";
  }
  return "is-soft";
}

function renderScenePlanningBadges(scene) {
  if (!scene) {
    return "";
  }

  return `
    <span class="issue-tag ${getSceneStatusToneClass(scene.status)}">状态：${escapeHtml(
      getSceneStatusLabel(scene.status)
    )}</span>
    <span class="issue-tag ${getScenePriorityToneClass(scene.priority)}">优先级：${escapeHtml(
      getScenePriorityLabel(scene.priority)
    )}</span>
  `;
}

function renderScenePlanningQuickButtons(scene) {
  if (!scene) {
    return "";
  }

  const buttons = [
    {
      action: "toggle-scene-priority",
      key: "scenePriority",
      value: "rush",
      label: "马上处理",
      active: getSafeScenePriority(scene.priority) === "rush",
      kind: "priority",
    },
    {
      action: "toggle-scene-priority",
      key: "scenePriority",
      value: "focus",
      label: "优先处理",
      active: getSafeScenePriority(scene.priority) === "focus",
      kind: "priority",
    },
    {
      action: "toggle-scene-status",
      key: "sceneStatus",
      value: "ready",
      label: "可试玩",
      active: getSafeSceneStatus(scene.status) === "ready",
      kind: "status",
    },
    {
      action: "toggle-scene-priority",
      key: "scenePriority",
      value: "parked",
      label: "先放一放",
      active: getSafeScenePriority(scene.priority) === "parked",
      kind: "priority",
    },
  ];

  return `
    <div class="scene-planning-quick-row">
      ${buttons
        .map(
          (button) => `
            <button
              type="button"
              class="scene-planning-quick-button ${getSceneQuickButtonToneClass(button.kind, button.value)} ${
                button.active ? "is-active" : ""
              }"
              data-action="${button.action}"
              data-scene-id="${escapeHtml(scene.id)}"
              data-${button.key}="${button.value}"
            >
              ${escapeHtml(button.label)}
            </button>
          `
        )
        .join("")}
    </div>
  `;
}

function doesRouteNodeMatchFilter(node, filterMode = state.dashboardRouteFilter) {
  const safeFilter = getSafeRouteMapFilter(filterMode);

  if (safeFilter === "all") {
    return true;
  }

  if (safeFilter === "issues") {
    return (node.errorCount ?? 0) > 0 || (node.warningCount ?? 0) > 0 || (node.brokenRouteCount ?? 0) > 0;
  }

  if (safeFilter === "missing_background") {
    return node.hasStoryContent && !node.hasBackground;
  }

  if (safeFilter === "missing_music") {
    return node.hasStoryContent && !node.hasMusic;
  }

  if (safeFilter === "missing_voice") {
    return (node.missingVoiceCount ?? 0) > 0;
  }

  if (safeFilter === "flat") {
    return node.hasStoryContent && !node.hasEffects;
  }

  if (safeFilter === "empty") {
    return !node.hasStoryContent;
  }

  if (safeFilter === "ready") {
    return (node.completionScore ?? 0) >= 80;
  }

  return true;
}

function getRouteMapFilterCount(routeOverview, filterMode) {
  return (routeOverview.nodes ?? []).filter((node) => doesRouteNodeMatchFilter(node, filterMode)).length;
}

function renderRouteMapFilterBar(routeOverview) {
  const safeFilter = getSafeRouteMapFilter(state.dashboardRouteFilter);
  const filters = [
    ["all", "全部", routeOverview.nodes.length],
    ["issues", "有问题", getRouteMapFilterCount(routeOverview, "issues")],
    ["missing_background", "缺背景", getRouteMapFilterCount(routeOverview, "missing_background")],
    ["missing_music", "缺 BGM", getRouteMapFilterCount(routeOverview, "missing_music")],
    ["missing_voice", "缺语音", getRouteMapFilterCount(routeOverview, "missing_voice")],
    ["flat", "演出偏素", getRouteMapFilterCount(routeOverview, "flat")],
    ["empty", "未开写", getRouteMapFilterCount(routeOverview, "empty")],
    ["ready", "完成度高", getRouteMapFilterCount(routeOverview, "ready")],
  ];

  return `
    <div class="route-filter-head">
      <span class="panel-note">${
        safeFilter === "all"
          ? "可以按制作状态快速缩小到最需要处理的场景。"
          : `当前只看：${escapeHtml(getRouteMapFilterLabel(safeFilter))}`
      }</span>
    </div>
    <div class="asset-tag-chip-row route-filter-bar">
      ${filters
        .map(
          ([mode, label, count]) => `
            <button
              type="button"
              class="asset-tag-chip ${safeFilter === mode ? "is-active" : ""}"
              data-action="set-route-map-filter"
              data-route-filter="${mode}"
            >
              <span>${escapeHtml(label)}</span>
              <strong>${count}</strong>
            </button>
          `
        )
        .join("")}
    </div>
  `;
}

function resetStoryBlockFilters() {
  state.storyBlockSearchQuery = "";
  state.storyBlockTypeFilter = "all";
  state.storyBlockIssueFilter = "all";
}

function focusStoryBlockFilters({
  typeFilter = "all",
  issueFilter = "all",
  searchQuery = "",
  statusText = "当前场景卡片筛选已更新",
  toastText = "",
} = {}) {
  state.storyBlockSearchQuery = typeof searchQuery === "string" ? searchQuery : "";
  state.storyBlockTypeFilter = getSafeStoryBlockTypeFilter(typeFilter);
  state.storyBlockIssueFilter = getSafeStoryBlockIssueFilter(issueFilter);
  renderStoryScreen();
  setSaveStatus(statusText);
  if (toastText) {
    showToast(toastText);
  }
}

function getSafeStoryBlockTypeFilter(value) {
  return Object.prototype.hasOwnProperty.call(STORY_BLOCK_TYPE_FILTER_LABELS, value) ? value : "all";
}

function getStoryBlockTypeFilterLabel(value) {
  return STORY_BLOCK_TYPE_FILTER_LABELS[getSafeStoryBlockTypeFilter(value)] ?? STORY_BLOCK_TYPE_FILTER_LABELS.all;
}

function getSafeStoryBlockIssueFilter(value) {
  return Object.prototype.hasOwnProperty.call(STORY_BLOCK_ISSUE_FILTER_LABELS, value) ? value : "all";
}

function getStoryBlockIssueFilterLabel(value) {
  return STORY_BLOCK_ISSUE_FILTER_LABELS[getSafeStoryBlockIssueFilter(value)] ?? STORY_BLOCK_ISSUE_FILTER_LABELS.all;
}

function getStoryBlockGroup(type) {
  if (type === "dialogue" || type === "narration" || type === "choice") {
    return "story";
  }

  if (type === "jump" || type === "variable_set" || type === "variable_add" || type === "condition") {
    return "logic";
  }

  return "effect";
}

function getStoryBlockGroupLabel(type) {
  const group = getStoryBlockGroup(type);
  if (group === "story") {
    return "正文";
  }
  if (group === "logic") {
    return "逻辑";
  }
  return "演出";
}

function getBlockExpressionAssetId(block) {
  if (block.type !== "dialogue" && block.type !== "character_show") {
    return "";
  }

  const characterId = block.speakerId ?? block.characterId;
  const character = state.data.charactersById.get(characterId);
  const expression = character?.expressions?.find((item) => item.id === block.expressionId);
  return expression?.spriteAssetId ?? "";
}

function isRawVariableValueMatchingType(variable, value) {
  if (!variable) {
    return false;
  }

  if (variable.type === "number") {
    return typeof value === "number" && Number.isFinite(value);
  }

  if (variable.type === "boolean") {
    return typeof value === "boolean";
  }

  return typeof value === "string";
}

function isConditionOperatorAllowedForVariable(variable, operator) {
  const safeOperator = String(operator ?? "==").trim() || "==";
  if (["==", "=", "!="].includes(safeOperator)) {
    return true;
  }
  if ([">", ">=", "<", "<="].includes(safeOperator)) {
    return variable?.type === "number";
  }
  return false;
}

function hasVariableReferenceIssue(
  variableId,
  { expectedType = null, value = null, validateValue = false, operator = null } = {}
) {
  const variable = state.data.variablesById.get(variableId);
  if (!variable) {
    return true;
  }

  if (expectedType && variable.type !== expectedType) {
    return true;
  }

  if (validateValue && !isRawVariableValueMatchingType(variable, value)) {
    return true;
  }

  if (operator !== null && !isConditionOperatorAllowedForVariable(variable, operator)) {
    return true;
  }

  return false;
}

function blockHasVariableLogicIssue(block) {
  if (block.type === "variable_set") {
    return hasVariableReferenceIssue(block.variableId, {
      value: block.value,
      validateValue: true,
    });
  }

  if (block.type === "variable_add") {
    return hasVariableReferenceIssue(block.variableId, {
      expectedType: "number",
      value: block.value,
      validateValue: true,
    });
  }

  if (block.type === "choice") {
    return (block.options ?? []).some((option) =>
      (option.effects ?? []).some((effect) => {
        if (effect.type === "variable_add") {
          return hasVariableReferenceIssue(effect.variableId, {
            expectedType: "number",
            value: effect.value,
            validateValue: true,
          });
        }
        if (effect.type === "variable_set") {
          return hasVariableReferenceIssue(effect.variableId, {
            value: effect.value,
            validateValue: true,
          });
        }
        return true;
      })
    );
  }

  if (block.type === "condition") {
    return (block.branches ?? []).some((branch) =>
      (branch.when ?? []).some((rule) =>
        hasVariableReferenceIssue(rule.variableId, {
          value: rule.value,
          validateValue: true,
          operator: rule.operator,
        })
      )
    );
  }

  return false;
}

function getStoryBlockIssueItems(block) {
  const items = [];
  const pushIssue = (key, label, toneClass = "warn-text") => {
    if (!items.some((item) => item.key === key)) {
      items.push({ key, label, toneClass });
    }
  };

  if (block.type === "dialogue" && !block.voiceAssetId) {
    pushIssue("missing_voice", "待绑语音");
  }

  if (
    ((block.type === "dialogue" || block.type === "narration") && isReadableTextLong(block.text)) ||
    (block.type === "choice" &&
      ((block.options ?? []).length > VN_CHOICE_MANY_OPTIONS ||
        (block.options ?? []).some((option) => String(option.text ?? "").trim().length > VN_CHOICE_LONG_WARNING_LENGTH)))
  ) {
    pushIssue("too_long", "偏长文本");
  }

  const assetIdsToCheck = [];
  if (["background", "music_play", "sfx_play", "video_play"].includes(block.type)) {
    assetIdsToCheck.push(block.assetId);
  }
  if (block.type === "particle_effect" && getSafeParticleAction(block.action) !== "stop" && block.assetId) {
    assetIdsToCheck.push(block.assetId);
  }
  const expressionAssetId = getBlockExpressionAssetId(block);
  if (expressionAssetId) {
    assetIdsToCheck.push(expressionAssetId);
  }

  if (
    assetIdsToCheck.some((assetId) => {
      if (!assetId) {
        return true;
      }
      const asset = state.data.assetsById.get(assetId);
      return !asset || !asset.fileExists;
    })
  ) {
    pushIssue("missing_asset", "待补素材");
  }

  if (block.type === "jump" && !state.data.scenesById.has(block.targetSceneId)) {
    pushIssue("broken_target", "跳转待修", "danger-text");
  }

  if (
    block.type === "choice" &&
    (block.options ?? []).some((option) => option.gotoSceneId && !state.data.scenesById.has(option.gotoSceneId))
  ) {
    pushIssue("broken_target", "跳转待修", "danger-text");
  }

  if (
    block.type === "condition" &&
    (
      !state.data.scenesById.has(block.elseGotoSceneId) ||
      (block.branches ?? []).some((branch) => branch.gotoSceneId && !state.data.scenesById.has(branch.gotoSceneId))
    )
  ) {
    pushIssue("broken_target", "跳转待修", "danger-text");
  }

  if (blockHasVariableLogicIssue(block)) {
    pushIssue("variable_logic", "变量待修", "danger-text");
  }

  return items;
}

function getSafeStorySceneTreeFilter(value) {
  return Object.prototype.hasOwnProperty.call(STORY_SCENE_TREE_FILTER_LABELS, value) ? value : "all";
}

function getStorySceneTreeFilterLabel(value) {
  return STORY_SCENE_TREE_FILTER_LABELS[getSafeStorySceneTreeFilter(value)] ?? STORY_SCENE_TREE_FILTER_LABELS.all;
}

function getSafeCharacterFilterMode(value) {
  return Object.prototype.hasOwnProperty.call(CHARACTER_FILTER_LABELS, value) ? value : "all";
}

function getCharacterFilterLabel(value) {
  return CHARACTER_FILTER_LABELS[getSafeCharacterFilterMode(value)] ?? CHARACTER_FILTER_LABELS.all;
}

function getSafePreviewIssueFilterMode(value) {
  return Object.prototype.hasOwnProperty.call(PREVIEW_ISSUE_FILTER_LABELS, value) ? value : "all";
}

function getPreviewIssueFilterLabel(value) {
  return PREVIEW_ISSUE_FILTER_LABELS[getSafePreviewIssueFilterMode(value)] ?? PREVIEW_ISSUE_FILTER_LABELS.all;
}

function getSafePreviewSceneFilterMode(value) {
  return Object.prototype.hasOwnProperty.call(PREVIEW_SCENE_FILTER_LABELS, value) ? value : "all";
}

function getPreviewSceneFilterLabel(value) {
  return PREVIEW_SCENE_FILTER_LABELS[getSafePreviewSceneFilterMode(value)] ?? PREVIEW_SCENE_FILTER_LABELS.all;
}

function resetCharacterFilters() {
  state.characterSearchQuery = "";
  state.characterFilterMode = "all";
}

function hasActiveCharacterFilter() {
  return Boolean((state.characterSearchQuery ?? "").trim()) ||
    getSafeCharacterFilterMode(state.characterFilterMode) !== "all";
}

function resetStorySceneTreeFilters() {
  state.storySceneTreeSearchQuery = "";
  state.storySceneTreeFilter = "all";
}

function hasActiveStorySceneTreeFilter() {
  return Boolean((state.storySceneTreeSearchQuery ?? "").trim()) ||
    getSafeStorySceneTreeFilter(state.storySceneTreeFilter) !== "all";
}

function buildStorySceneTreeSearchText(sceneNode) {
  const parts = [
    sceneNode.chapterName,
    sceneNode.name,
    sceneNode.notes,
    getSceneStatusLabel(sceneNode.status),
    getScenePriorityLabel(sceneNode.priority),
    buildRouteSceneProductionNotes(sceneNode).join(" "),
    sceneNode.isEntry ? "入口场景" : "",
    sceneNode.isOrphan ? "孤立场景" : "",
    sceneNode.isEnding ? "收束场景" : "",
    sceneNode.brokenRouteCount > 0 ? `坏链 ${sceneNode.brokenRouteCount}` : "",
  ];

  return normalizeDashboardSearchQuery(parts.filter(Boolean).join(" "));
}

function matchesStorySceneTreeFilter(sceneNode, filterMode) {
  const safeFilter = getSafeStorySceneTreeFilter(filterMode);

  if (safeFilter === "focus") {
    return ["rush", "focus"].includes(getSafeScenePriority(sceneNode.priority));
  }

  if (safeFilter === "ready") {
    return getSafeSceneStatus(sceneNode.status) === "ready";
  }

  if (safeFilter === "notes") {
    return Boolean(String(sceneNode.notes ?? "").trim());
  }

  if (safeFilter === "issues") {
    return (
      (sceneNode.brokenRouteCount ?? 0) > 0 ||
      (sceneNode.errorCount ?? 0) > 0 ||
      (sceneNode.warningCount ?? 0) > 0 ||
      sceneNode.isOrphan ||
      buildRouteSceneProductionNotes(sceneNode).some((note) => note !== "可以继续抛光")
    );
  }

  return true;
}

function buildStorySceneTreeOverview(routeOverview) {
  const filterMode = getSafeStorySceneTreeFilter(state.storySceneTreeFilter);
  const terms = getDashboardSearchTerms(state.storySceneTreeSearchQuery);

  const chapters = (routeOverview.chapters ?? [])
    .map((chapter) => {
      const chapterSearchText = normalizeDashboardSearchQuery(chapter.name);
      const chapterMatchesQuery = terms.length > 0 && terms.every((term) => chapterSearchText.includes(term));
      const scenes = (chapter.scenes ?? []).filter((sceneNode) => {
        if (!matchesStorySceneTreeFilter(sceneNode, filterMode)) {
          return false;
        }

        if (!terms.length) {
          return true;
        }

        if (chapterMatchesQuery) {
          return true;
        }

        const searchText = buildStorySceneTreeSearchText(sceneNode);
        return terms.every((term) => searchText.includes(term));
      });

      return {
        ...chapter,
        filteredScenes: scenes,
      };
    })
    .filter((chapter) => chapter.filteredScenes.length > 0);

  const visibleSceneIds = new Set(
    chapters.flatMap((chapter) => chapter.filteredScenes.map((sceneNode) => sceneNode.id))
  );

  return {
    chapters,
    totalSceneCount: routeOverview.nodes?.length ?? 0,
    visibleSceneCount: visibleSceneIds.size,
    totalChapterCount: routeOverview.chapters?.length ?? 0,
    visibleChapterCount: chapters.length,
    hiddenSelectedScene:
      Boolean(state.selectedSceneId) &&
      (routeOverview.nodes?.some((node) => node.id === state.selectedSceneId) ?? false) &&
      !visibleSceneIds.has(state.selectedSceneId),
  };
}

function countScenesForStorySceneTreeFilter(routeOverview, filterMode) {
  return (routeOverview.nodes ?? []).filter((sceneNode) =>
    matchesStorySceneTreeFilter(sceneNode, filterMode)
  ).length;
}

function renderStorySceneTreeFilterBar(routeOverview) {
  const filterModes = ["all", "focus", "ready", "issues", "notes"];

  return filterModes
    .map((mode) => {
      const count =
        mode === "all"
          ? routeOverview.nodes?.length ?? 0
          : countScenesForStorySceneTreeFilter(routeOverview, mode);
      return `
        <button
          type="button"
          class="asset-tag-chip ${getSafeStorySceneTreeFilter(state.storySceneTreeFilter) === mode ? "is-active" : ""}"
          data-action="set-story-scene-tree-filter"
          data-scene-tree-filter="${mode}"
        >
          <span>${escapeHtml(getStorySceneTreeFilterLabel(mode))}</span>
          <strong>${count}</strong>
        </button>
      `;
    })
    .join("");
}

function renderStorySceneTreeSummary(overview) {
  const activeLabels = [];

  if ((state.storySceneTreeSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.storySceneTreeSearchQuery.trim()}`);
  }

  if (getSafeStorySceneTreeFilter(state.storySceneTreeFilter) !== "all") {
    activeLabels.push(`视角：${getStorySceneTreeFilterLabel(state.storySceneTreeFilter)}`);
  }

  return `
    <div class="story-filter-summary-main">
      <strong>命中 ${overview.visibleSceneCount}/${overview.totalSceneCount} 个场景 · ${overview.visibleChapterCount}/${overview.totalChapterCount} 个章节</strong>
      <span class="panel-note">项目树会优先显示当前搜索结果</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有项目树筛选，正在显示全部章节和场景。</span>'
      }
      ${
        overview.hiddenSelectedScene
          ? '<span class="issue-tag warn-text">当前正在编辑的场景被项目树筛选隐藏了，右侧内容不会丢。</span>'
          : ""
      }
    </div>
  `;
}

function buildStoryBlockSearchText(block, scene) {
  const summary = getBlockSummary(block, scene);
  const parts = [
    scene?.chapterName,
    scene?.name,
    BLOCK_LABELS[block.type] ?? block.type,
    summary.title,
    summary.meta,
    getStoryBlockGroupLabel(block.type),
    getStoryBlockIssueItems(block)
      .map((item) => item.label)
      .join(" "),
  ];

  if (block.type === "dialogue" || block.type === "narration") {
    parts.push(block.text);
  }

  if (block.type === "choice") {
    parts.push((block.options ?? []).map((option) => option.text).join(" "));
    parts.push(
      (block.options ?? [])
        .map((option) => state.data.scenesById.get(option.gotoSceneId)?.name ?? option.gotoSceneId)
        .join(" ")
    );
  }

  if (block.type === "video_play") {
    parts.push(block.title);
    parts.push(state.data.assetsById.get(block.assetId)?.name ?? block.assetId);
  }

  if (block.type === "credits_roll") {
    parts.push(block.title);
    parts.push(block.subtitle);
    parts.push(getCreditsLines(block.lines).join(" "));
  }

  if (block.type === "jump") {
    parts.push(state.data.scenesById.get(block.targetSceneId)?.name ?? block.targetSceneId);
  }

  if (block.type === "variable_set" || block.type === "variable_add") {
    parts.push(state.data.variablesById.get(block.variableId)?.name ?? block.variableId);
  }

  if (block.type === "condition") {
    parts.push(state.data.scenesById.get(block.elseGotoSceneId)?.name ?? block.elseGotoSceneId);
    parts.push(
      (block.branches ?? [])
        .map((branch) => state.data.scenesById.get(branch.gotoSceneId)?.name ?? branch.gotoSceneId)
        .join(" ")
    );
    parts.push(
      (block.branches ?? [])
        .flatMap((branch) => branch.when ?? [])
        .map((rule) => state.data.variablesById.get(rule.variableId)?.name ?? rule.variableId)
        .join(" ")
    );
  }

  return normalizeDashboardSearchQuery(parts.filter(Boolean).join(" "));
}

function getFilteredStoryBlocks(scene) {
  const blocks = scene?.blocks ?? [];
  const typeFilter = getSafeStoryBlockTypeFilter(state.storyBlockTypeFilter);
  const issueFilter = getSafeStoryBlockIssueFilter(state.storyBlockIssueFilter);
  const terms = getDashboardSearchTerms(state.storyBlockSearchQuery);

  return blocks.filter((block) => {
    const group = getStoryBlockGroup(block.type);
    const issueItems = getStoryBlockIssueItems(block);

    if (typeFilter === "dialogue" && block.type !== "dialogue") {
      return false;
    }

    if (typeFilter === "choice" && block.type !== "choice") {
      return false;
    }

    if (typeFilter === "video" && block.type !== "video_play") {
      return false;
    }

    if (
      typeFilter !== "all" &&
      typeFilter !== "dialogue" &&
      typeFilter !== "choice" &&
      typeFilter !== "video" &&
      group !== typeFilter
    ) {
      return false;
    }

    if (issueFilter === "any" && issueItems.length === 0) {
      return false;
    }

    if (issueFilter !== "all" && issueFilter !== "any" && !issueItems.some((item) => item.key === issueFilter)) {
      return false;
    }

    if (!terms.length) {
      return true;
    }

    const haystack = buildStoryBlockSearchText(block, scene);
    return terms.every((term) => haystack.includes(term));
  });
}

function hasActiveStoryBlockFilter() {
  return Boolean((state.storyBlockSearchQuery ?? "").trim()) ||
    getSafeStoryBlockTypeFilter(state.storyBlockTypeFilter) !== "all" ||
    getSafeStoryBlockIssueFilter(state.storyBlockIssueFilter) !== "all";
}

function canDragStoryBlocks(scene = getSelectedScene()) {
  return Boolean(scene) && (scene.blocks?.length ?? 0) > 1 && !hasActiveStoryBlockFilter();
}

function renderStoryBlockFilterSummary(scene, visibleBlocks, allBlocks, selectedBlock) {
  const activeLabels = [];
  const dragEnabled = canDragStoryBlocks(scene);

  if ((state.storyBlockSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.storyBlockSearchQuery.trim()}`);
  }

  if (getSafeStoryBlockTypeFilter(state.storyBlockTypeFilter) !== "all") {
    activeLabels.push(`类型：${getStoryBlockTypeFilterLabel(state.storyBlockTypeFilter)}`);
  }

  if (getSafeStoryBlockIssueFilter(state.storyBlockIssueFilter) !== "all") {
    activeLabels.push(`问题：${getStoryBlockIssueFilterLabel(state.storyBlockIssueFilter)}`);
  }

  const storyCount = visibleBlocks.filter((block) => getStoryBlockGroup(block.type) === "story").length;
  const effectCount = visibleBlocks.filter((block) => getStoryBlockGroup(block.type) === "effect").length;
  const logicCount = visibleBlocks.filter((block) => getStoryBlockGroup(block.type) === "logic").length;
  const hiddenSelected = Boolean(selectedBlock) && !visibleBlocks.some((block) => block.id === selectedBlock.id);

  return `
    <div class="story-filter-summary-main">
      <strong>${escapeHtml(scene.name)} · 命中 ${visibleBlocks.length}/${allBlocks.length} 张卡片</strong>
      <span class="panel-note">正文 ${storyCount} · 演出 ${effectCount} · 逻辑 ${logicCount}</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有额外筛选，正在显示这个场景的全部卡片。</span>'
      }
      ${
        hiddenSelected
          ? '<span class="issue-tag warn-text">当前选中的卡片被筛选隐藏了，右侧仍然显示它的设置。</span>'
          : ""
      }
      ${
        allBlocks.length > 1
          ? `<span class="issue-tag ${dragEnabled ? "good-text" : "warn-text"}">${
              dragEnabled ? "现在可以直接拖拽卡片改顺序。" : "当前有筛选，先清空筛选后再拖拽排序。"
            }</span>`
          : ""
      }
    </div>
  `;
}

function renderStoryBlockIssueBadges(block) {
  const badges = [
    `<span class="issue-tag">${escapeHtml(getStoryBlockGroupLabel(block.type))}</span>`,
    ...getStoryBlockIssueItems(block).map(
      (item) => `<span class="issue-tag ${item.toneClass}">${escapeHtml(item.label)}</span>`
    ),
  ];

  return `<div class="block-card-tags">${badges.join("")}</div>`;
}

function normalizeDashboardSearchQuery(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function getDashboardSearchTerms(value) {
  const query = normalizeDashboardSearchQuery(value);
  return query ? query.split(" ").filter(Boolean) : [];
}

function buildDashboardSearchOverview() {
  const query = state.dashboardSearchQuery ?? "";
  const normalizedQuery = normalizeDashboardSearchQuery(query);
  const terms = getDashboardSearchTerms(query);
  const scenes = [];
  const characters = [];
  const lines = [];

  const pushIfMatch = (bucket, config) => {
    const score = scoreDashboardSearchMatch(config.primaryText, config.searchFields, normalizedQuery, terms);
    if (score < 0) {
      return;
    }
    bucket.push({
      ...config,
      score,
    });
  };

  state.data.characters.forEach((character) => {
    const stats = buildCharacterDialogueStats(character.id);
    pushIfMatch(characters, {
      resultType: "character",
      title: character.displayName,
      snippet: character.bio || `台词 ${stats.totalLines} 句，待配音 ${stats.missingVoiceCount} 句。`,
      meta: `${getPositionLabel(character.defaultPosition)} · ${character.expressions.length} 个表情 · 语音覆盖 ${stats.voiceCoverage}%`,
      primaryText: character.displayName,
      searchFields: [
        character.displayName,
        character.bio,
        character.id,
        stats.topExpressions.map(([name]) => name).join(" "),
      ],
      characterId: character.id,
    });
  });

  state.data.chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      const blocks = scene.blocks ?? [];
      const firstReadableBlock = blocks.find((block) =>
        ["dialogue", "narration", "choice"].includes(block.type)
      );
      const firstReadableText =
        firstReadableBlock?.type === "choice"
          ? (firstReadableBlock.options ?? []).map((option) => option.text).join(" / ")
          : firstReadableBlock?.text ?? "";

      pushIfMatch(scenes, {
        resultType: "scene",
        title: scene.name,
        snippet: firstReadableText
          ? `开头内容：${truncateText(firstReadableText, 44)}`
          : "这个场景暂时还没有正文卡片。",
        meta: `${chapter.name} · ${blocks.length} 张卡片`,
        primaryText: scene.name,
        searchFields: [scene.name, scene.id, chapter.name, firstReadableText],
        sceneId: scene.id,
      });

      blocks.forEach((block, blockIndex) => {
        if (block.type === "dialogue") {
          const speakerName =
            state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId ?? "角色";
          pushIfMatch(lines, {
            resultType: "line",
            lineType: "dialogue",
            title: `${speakerName}：${truncateText(block.text || "这句台词还没填正文。", 34)}`,
            snippet: block.text || "这句台词还没填正文。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张 · ${
              block.voiceAssetId ? "已绑语音" : "待绑语音"
            }`,
            primaryText: `${speakerName} ${block.text ?? ""}`,
            searchFields: [speakerName, block.text, scene.name, chapter.name, block.voiceAssetId],
            sceneId: scene.id,
            blockId: block.id,
            speakerId: block.speakerId,
          });
        } else if (block.type === "narration") {
          pushIfMatch(lines, {
            resultType: "line",
            lineType: "narration",
            title: `旁白：${truncateText(block.text || "这句旁白还没填正文。", 34)}`,
            snippet: block.text || "这句旁白还没填正文。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张 · 旁白`,
            primaryText: block.text ?? "",
            searchFields: [block.text, scene.name, chapter.name, "旁白"],
            sceneId: scene.id,
            blockId: block.id,
          });
        } else if (block.type === "choice") {
          const optionText = (block.options ?? []).map((option) => option.text).join(" / ");
          pushIfMatch(lines, {
            resultType: "line",
            lineType: "choice",
            title: `选项：${truncateText(optionText || "这个选项还没写文案。", 34)}`,
            snippet: optionText || "这个选项还没写文案。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张 · 选项`,
            primaryText: optionText,
            searchFields: [optionText, scene.name, chapter.name, "选项"],
            sceneId: scene.id,
            blockId: block.id,
          });
        }
      });
    });
  });

  const sortByScore = (left, right) => right.score - left.score || left.title.localeCompare(right.title, "zh-CN");
  scenes.sort(sortByScore);
  characters.sort(sortByScore);
  lines.sort(sortByScore);
  const hasQuery = terms.length > 0;

  return {
    query,
    normalizedQuery,
    mode: getSafeDashboardSearchMode(state.dashboardSearchMode),
    counts: {
      scenes: hasQuery ? scenes.length : state.data.scenes.length,
      characters: hasQuery ? characters.length : state.data.characters.length,
      lines: hasQuery ? lines.length : countSearchableStoryBlocks(),
    },
    scenes,
    characters,
    lines,
    suggestions: getDashboardSearchSuggestions(),
  };
}

function scoreDashboardSearchMatch(primaryText, searchFields, normalizedQuery, terms) {
  if (!terms.length) {
    return -1;
  }

  const haystack = normalizeDashboardSearchQuery(searchFields.filter(Boolean).join(" "));
  if (!terms.every((term) => haystack.includes(term))) {
    return -1;
  }

  const primary = normalizeDashboardSearchQuery(primaryText);
  let score = 0;

  if (normalizedQuery && primary.startsWith(normalizedQuery)) {
    score += 18;
  } else if (normalizedQuery && primary.includes(normalizedQuery)) {
    score += 10;
  } else if (normalizedQuery && haystack.includes(normalizedQuery)) {
    score += 5;
  }

  score += terms.reduce(
    (total, term) => total + (primary.includes(term) ? 4 : haystack.includes(term) ? 1 : 0),
    0
  );

  return score;
}

function getDashboardSearchSuggestions() {
  const suggestions = [];
  const seen = new Set();

  function pushSuggestion(label) {
    const nextLabel = String(label ?? "").trim();
    const key = normalizeDashboardSearchQuery(nextLabel);
    if (!nextLabel || !key || seen.has(key)) {
      return;
    }
    seen.add(key);
    suggestions.push(nextLabel);
  }

  state.data.characters.slice(0, 3).forEach((character) => pushSuggestion(character.displayName));
  state.data.scenes.slice(0, 3).forEach((scene) => pushSuggestion(scene.name));

  for (const scene of state.data.scenes) {
    const block = (scene.blocks ?? []).find((item) => item.type === "dialogue" || item.type === "narration");
    const text = String(block?.text ?? "").trim();
    if (text) {
      pushSuggestion(truncateText(text, 8));
    }
    if (suggestions.length >= 8) {
      break;
    }
  }

  return suggestions.slice(0, 8);
}

function renderDashboardSearchPanel() {
  const input = document.getElementById("dashboardSearchInput");
  const filterBar = document.getElementById("dashboardSearchFilterBar");
  const summary = document.getElementById("dashboardSearchSummary");
  const results = document.getElementById("dashboardSearchResults");

  if (!filterBar || !summary || !results) {
    return;
  }

  const overview = buildDashboardSearchOverview();

  if (input && input.value !== state.dashboardSearchQuery) {
    input.value = state.dashboardSearchQuery;
  }

  filterBar.innerHTML = renderDashboardSearchFilterBar(overview);
  summary.innerHTML = renderDashboardSearchSummary(overview);
  results.innerHTML = renderDashboardSearchResults(overview);
}

function renderDashboardSearchFilterBar(overview) {
  const modes = [
    ["all", "全部", overview.counts.scenes + overview.counts.characters + overview.counts.lines],
    ["scenes", "场景", overview.counts.scenes],
    ["characters", "角色", overview.counts.characters],
    ["lines", "台词", overview.counts.lines],
  ];

  return modes
    .map(
      ([mode, label, count]) => `
        <button
          type="button"
          class="asset-tag-chip ${overview.mode === mode ? "is-active" : ""}"
          data-action="set-dashboard-search-mode"
          data-search-mode="${mode}"
        >
          <span>${label}</span>
          <strong>${count}</strong>
        </button>
      `
    )
    .join("");
}

function renderDashboardSearchSummary(overview) {
  if (!overview.normalizedQuery) {
    return `
      ${renderRouteMetricCard("搜索状态", "等待输入", "输一个词，下面就会立刻给你结果")}
      ${renderRouteMetricCard("场景总数", state.data.scenes.length, "支持按场景名和章节名查")}
      ${renderRouteMetricCard("角色总数", state.data.characters.length, "支持按角色名和简介查")}
      ${renderRouteMetricCard("正文卡片", countSearchableStoryBlocks(), "台词、旁白、选项都能查")}
    `;
  }

  const totalCount = overview.counts.scenes + overview.counts.characters + overview.counts.lines;
  return `
    ${renderRouteMetricCard("当前关键词", overview.query, "输入即检索")}
    ${renderRouteMetricCard("命中总数", totalCount, "所有分类加起来的结果")}
    ${renderRouteMetricCard("场景命中", overview.counts.scenes, "能直接打开场景或试玩")}
    ${renderRouteMetricCard("角色命中", overview.counts.characters, "能直接跳到角色页")}
    ${renderRouteMetricCard("台词命中", overview.counts.lines, "能直接定位到具体卡片")}
  `;
}

function renderDashboardSearchResults(overview) {
  if (!overview.normalizedQuery) {
    return renderDashboardSearchSuggestions(overview.suggestions);
  }

  const totalCount = overview.counts.scenes + overview.counts.characters + overview.counts.lines;
  if (totalCount === 0) {
    return renderEmpty(`没有找到和“${overview.query}”有关的场景、角色或台词。可以试试搜章节名、角色名或更短的关键字。`);
  }

  const sections = [];
  const limitByMode = overview.mode === "all" ? 6 : 18;

  if (overview.mode === "all" || overview.mode === "scenes") {
    sections.push(renderDashboardSearchSection("场景结果", overview.scenes, limitByMode));
  }

  if (overview.mode === "all" || overview.mode === "characters") {
    sections.push(renderDashboardSearchSection("角色结果", overview.characters, limitByMode));
  }

  if (overview.mode === "all" || overview.mode === "lines") {
    sections.push(renderDashboardSearchSection("台词和选项", overview.lines, limitByMode));
  }

  return sections.filter(Boolean).join("") || renderEmpty("这个筛选下暂时没有结果。");
}

function renderDashboardSearchSuggestions(suggestions) {
  return `
    <article class="detail-card">
      <strong>可以直接试试这些词</strong>
      <p class="helper-text">点击后会自动填入搜索框。项目内容变多时，可用来快速定位剧情。</p>
      <div class="asset-tag-chip-row">
        ${suggestions
          .map(
            (item) => `
              <button
                type="button"
                class="asset-tag-chip asset-preset-tag-chip"
                data-action="apply-dashboard-search-sample"
                data-query="${escapeHtml(item)}"
              >
                ${escapeHtml(item)}
              </button>
            `
          )
          .join("")}
      </div>
    </article>
  `;
}

function renderDashboardSearchSection(title, items, limit) {
  if (!items.length) {
    return "";
  }

  const visibleItems = items.slice(0, limit);
  const hiddenCount = Math.max(items.length - visibleItems.length, 0);

  return `
    <div class="search-result-section">
      <div class="chapter-divider">${escapeHtml(title)} · ${items.length} 条</div>
      <div class="list-stack compact-list">
        ${visibleItems.map((item) => renderDashboardSearchResultCard(item)).join("")}
      </div>
      ${hiddenCount > 0 ? `<div class="helper-text">还有 ${hiddenCount} 条结果没有展开。把筛选切到这个分类，会看得更全。</div>` : ""}
    </div>
  `;
}

function renderDashboardSearchResultCard(item) {
  if (item.resultType === "scene") {
    return `
      <article class="search-result-card">
        <div class="search-result-top">
          <span class="issue-tag good-text">场景</span>
          <span class="search-result-meta">${escapeHtml(item.meta)}</span>
        </div>
        <strong>${escapeHtml(item.title)}</strong>
        <p>${escapeHtml(item.snippet)}</p>
        <div class="search-result-actions">
          <button type="button" class="toolbar-button toolbar-button-primary" data-action="open-scene-from-map" data-scene-id="${item.sceneId}">
            打开场景
          </button>
          <button type="button" class="toolbar-button" data-action="preview-scene-from-map" data-scene-id="${item.sceneId}">
            直接试玩
          </button>
        </div>
      </article>
    `;
  }

  if (item.resultType === "character") {
    return `
      <article class="search-result-card">
        <div class="search-result-top">
          <span class="issue-tag">角色</span>
          <span class="search-result-meta">${escapeHtml(item.meta)}</span>
        </div>
        <strong>${escapeHtml(item.title)}</strong>
        <p>${escapeHtml(item.snippet)}</p>
        <div class="search-result-actions">
          <button type="button" class="toolbar-button toolbar-button-primary" data-action="open-dashboard-character" data-character-id="${item.characterId}">
            打开角色页
          </button>
        </div>
      </article>
    `;
  }

  const lineTag =
    item.lineType === "dialogue" ? "台词" : item.lineType === "narration" ? "旁白" : "选项";
  const toneClass = item.lineType === "dialogue" ? "good-text" : item.lineType === "choice" ? "warn-text" : "";

  return `
    <article class="search-result-card">
      <div class="search-result-top">
        <span class="issue-tag ${toneClass}">${lineTag}</span>
        <span class="search-result-meta">${escapeHtml(item.meta)}</span>
      </div>
      <strong>${escapeHtml(item.title)}</strong>
      <p>${escapeHtml(truncateText(item.snippet, 96))}</p>
      <div class="search-result-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-primary"
          data-action="open-character-line"
          data-scene-id="${item.sceneId}"
          data-block-id="${item.blockId}"
        >
          定位到卡片
        </button>
      </div>
    </article>
  `;
}

function countSearchableStoryBlocks() {
  return state.data.scenes.reduce(
    (total, scene) =>
      total +
      (scene.blocks ?? []).filter((block) =>
        ["dialogue", "narration", "choice"].includes(block.type)
      ).length,
    0
  );
}

function renderStoryScreen() {
  const scene = getSelectedScene();
  const isBlankProject = isCurrentProjectBlank();
  const starterKitPanel = !isBlankProject ? renderStarterKitPanel("story") : "";
  const routeOverview = buildSceneRouteOverview();
  const sceneRouteNode = scene ? routeOverview.nodes.find((node) => node.id === scene.id) ?? null : null;
  const sceneTreeOverview = buildStorySceneTreeOverview(routeOverview);
  const blocks = scene?.blocks ?? [];
  const visibleBlocks = getFilteredStoryBlocks(scene);
  const canDragBlocks = canDragStoryBlocks(scene);
  const blockIndexMap = new Map(blocks.map((block, index) => [block.id, index]));
  const selectedBlock = getSelectedBlock();
  const selectedIndex = Math.max(
    blocks.findIndex((block) => block.id === state.selectedBlockId),
    0
  );

  if (refs.storyBlockSearchInput && refs.storyBlockSearchInput.value !== state.storyBlockSearchQuery) {
    refs.storyBlockSearchInput.value = state.storyBlockSearchQuery;
  }

  if (refs.storySceneTreeSearchInput && refs.storySceneTreeSearchInput.value !== state.storySceneTreeSearchQuery) {
    refs.storySceneTreeSearchInput.value = state.storySceneTreeSearchQuery;
  }

  if (refs.storyBlockTypeSelect) {
    refs.storyBlockTypeSelect.value = getSafeStoryBlockTypeFilter(state.storyBlockTypeFilter);
  }

  if (refs.storyBlockIssueSelect) {
    refs.storyBlockIssueSelect.value = getSafeStoryBlockIssueFilter(state.storyBlockIssueFilter);
  }

  if (refs.storyBlockClearButton) {
    refs.storyBlockClearButton.disabled =
      !state.storyBlockSearchQuery &&
      getSafeStoryBlockTypeFilter(state.storyBlockTypeFilter) === "all" &&
      getSafeStoryBlockIssueFilter(state.storyBlockIssueFilter) === "all";
  }

  if (refs.storyEditorModeHint) {
    refs.storyEditorModeHint.innerHTML = isBlankProject ? "" : renderStoryEditorModeBanner(scene);
    refs.storyEditorModeHint.classList.toggle("is-hidden", isBlankProject);
  }

  if (refs.creativeAssistantPanel) {
    refs.creativeAssistantPanel.innerHTML = isBlankProject
      ? renderCreativeAssistantBlankPanel()
      : renderCreativeAssistantPanel(scene, selectedBlock);
  }

  if (refs.storySceneTreeFilterBar) {
    refs.storySceneTreeFilterBar.innerHTML = renderStorySceneTreeFilterBar(routeOverview);
  }

  if (refs.storySceneTreeSummary) {
    refs.storySceneTreeSummary.innerHTML = renderStorySceneTreeSummary(sceneTreeOverview);
  }

  if (refs.storySceneTreeClearButton) {
    refs.storySceneTreeClearButton.disabled = !hasActiveStorySceneTreeFilter();
  }

  refs.storySceneMeta.textContent = isBlankProject
    ? "先创建第一章和第一场景，再开始写剧情"
    : scene
    ? `${scene.chapterName} · ${scene.name} · 共 ${blocks.length} 张卡片${
        visibleBlocks.length !== blocks.length ? ` · 当前命中 ${visibleBlocks.length} 张` : ""
      }`
    : "还没有场景";

  if (refs.storyBlockFilterSummary) {
    refs.storyBlockFilterSummary.innerHTML = isBlankProject
      ? renderBlankStoryWorkspacePanel()
      : scene
      ? renderStoryBlockFilterSummary(scene, visibleBlocks, blocks, selectedBlock)
      : renderEmpty("先从左边选一个场景，再开始筛剧情卡片。");
  }

  if (refs.storyScenePlanner) {
    refs.storyScenePlanner.innerHTML = isBlankProject
      ? renderBlankProjectStarterPanel("story")
      : scene
      ? `${starterKitPanel}${renderStoryScenePlanner(scene, sceneRouteNode)}`
      : renderEmpty("先从左边选一个场景，再写场景便签和制作计划。");
  }

  refs.storySceneTree.innerHTML = isBlankProject
    ? renderEmpty("这里会在你创建第一章以后，自动长出章节树和场景树。")
    : renderSceneTree(state.selectedSceneId, "select-scene", {
        routeOverview,
        useStoryFilters: true,
        sceneTreeOverview,
      });
  refs.storyBlockList.innerHTML = isBlankProject
    ? renderBlankProjectStarterPanel("story")
    : blocks.length === 0
      ? renderEmpty("这个场景还没有卡片。")
      : visibleBlocks.length === 0
        ? renderEmpty("这个筛选下没有命中的卡片。可换一个关键词，或点击上面的“清空筛选”。")
        : visibleBlocks
          .map((block) =>
            renderBlockCard(
              block,
              scene,
              blockIndexMap.get(block.id) ?? 0,
              block.id === state.selectedBlockId,
              canDragBlocks
            )
          )
          .join("");

  refs.storyBlockDetails.innerHTML = isBlankProject
    ? renderBlankStoryWorkspacePanel()
    : selectedBlock
    ? renderBlockPanel(selectedBlock, scene, selectedIndex)
    : scene
      ? renderEmpty("这个场景还没有卡片。可以先点上面的按钮加一张台词、旁白或选项。")
      : renderEmpty("先从左边选一个场景，再点中一张卡片。");
}

function renderAssetsScreen() {
  const visibleAssets = getVisibleAssets();
  const duplicateOverview = buildAssetDuplicateOverview();
  const starterKitPanel = renderStarterKitPanel("assets");
  const isAdvancedMode = isAdvancedEditorMode();
  const voiceMatchTargets = getVoicePlaceholderTargetAssets();
  const shouldPreserveSelectedType =
    state.assetFilterMode !== "all" ||
    Boolean(state.assetSearchQuery.trim()) ||
    Boolean(state.assetTagFilter) ||
    state.assetFavoriteOnly;
  const assetsOfType = visibleAssets.filter((asset) => asset.type === state.selectedAssetType);
  const selectedAsset =
    visibleAssets.find((asset) => asset.id === state.selectedAssetId) ??
    assetsOfType[0] ??
    (!shouldPreserveSelectedType ? visibleAssets[0] : null) ??
    null;

  if (selectedAsset && selectedAsset.type !== state.selectedAssetType) {
    state.selectedAssetType = selectedAsset.type;
  }
  state.selectedAssetId = selectedAsset?.id ?? null;
  const fullSelectedTypeAssets = state.data.assetList.filter((asset) => asset.type === state.selectedAssetType);
  const selectedTypeAssets = visibleAssets.filter((asset) => asset.type === state.selectedAssetType);
  const currentCheckedIds = getCurrentCheckedAssetIds();
  const totalCheckedCount = getCheckedAssetIds().length;
  const hiddenCheckedCount = Math.max(totalCheckedCount - currentCheckedIds.length, 0);
  const searchSummary = getAssetFilterSummary();
  const selectedTypeGapSummary = getAssetTypeGapSummaryText(state.selectedAssetType, fullSelectedTypeAssets, state.data, duplicateOverview);
  const selectionSummary =
    totalCheckedCount > 0
      ? ` · 当前勾选 ${currentCheckedIds.length} 个${
          hiddenCheckedCount > 0 ? `（另有 ${hiddenCheckedCount} 个在别的分类或筛选外）` : ""
        }`
      : "";

  refs.assetListMeta.textContent = isAdvancedMode
    ? `${getAssetTypeLabel(state.selectedAssetType)} · ${
        selectedTypeAssets.length
      } 个文件${selectionSummary} · ${selectedTypeGapSummary} · ${searchSummary}`
    : `${getAssetTypeLabel(state.selectedAssetType)} · ${selectedTypeAssets.length} 个素材 · ${
        currentCheckedIds.length > 0 ? `当前勾选 ${currentCheckedIds.length} 个 · ` : ""
      }${selectedTypeGapSummary}`;

  if (refs.assetFilterToggleButton) {
    refs.assetFilterToggleButton.textContent =
      state.assetFilterMode === "unused" ? "恢复显示全部素材" : "只看未使用素材";
    refs.assetFilterToggleButton.classList.toggle(
      "toolbar-button-primary",
      state.assetFilterMode === "unused"
    );
  }

  if (refs.assetImportDropzone) {
    refs.assetImportDropzone.innerHTML = `
      <strong>把文件拖到这里</strong>
      <p>${
        state.selectedAssetType === "voice" && voiceMatchTargets.length > 0
          ? `当前已选中 ${voiceMatchTargets.length} 个待导入语音条目。可优先点击上面的“批量匹配语音文件”，系统会按文件名自动尝试绑定。`
          : `默认会导入到：${escapeHtml(getAssetTypeLabel(state.selectedAssetType))}。一次拖入多种类型文件时，也可使用上面的“智能导入”。`
      }</p>
    `;
  }

  if (refs.assetSearchInput && refs.assetSearchInput.value !== state.assetSearchQuery) {
    refs.assetSearchInput.value = state.assetSearchQuery;
  }

  if (refs.assetSearchClearButton) {
    refs.assetSearchClearButton.disabled =
      !state.assetSearchQuery &&
      !state.assetTagFilter &&
      !state.assetFavoriteOnly &&
      state.assetFilterMode === "all";
  }

  if (refs.assetSortSelect && refs.assetSortSelect.value !== state.assetSortMode) {
    refs.assetSortSelect.value = state.assetSortMode;
  }

  if (refs.assetGapBoard) {
    refs.assetGapBoard.innerHTML = isAdvancedMode
      ? `${starterKitPanel}${renderAssetGapBoard(duplicateOverview)}`
      : `${starterKitPanel}${renderBeginnerAssetsGuide(selectedAsset, duplicateOverview)}`;
  }

  if (refs.assetTagFilterBar) {
    refs.assetTagFilterBar.innerHTML = isAdvancedMode ? renderAssetTagFilterBar(selectedTypeAssets) : "";
  }

  if (refs.assetPresetTagBar) {
    refs.assetPresetTagBar.innerHTML = isAdvancedMode
      ? renderAssetPresetTagBar(selectedAsset, currentCheckedIds)
      : "";
  }

  if (refs.assetFavoriteFilterButton) {
    refs.assetFavoriteFilterButton.textContent = state.assetFavoriteOnly ? "恢复全部收藏状态" : "只看收藏";
    refs.assetFavoriteFilterButton.classList.toggle("toolbar-button-primary", state.assetFavoriteOnly);
  }

  if (refs.assetBulkAddButton) {
    refs.assetBulkAddButton.disabled = selectedTypeAssets.length === 0;
  }

  if (refs.assetBulkRemoveButton) {
    refs.assetBulkRemoveButton.disabled = selectedTypeAssets.length === 0;
  }

  if (refs.assetBulkDeleteButton) {
    refs.assetBulkDeleteButton.disabled = currentCheckedIds.length === 0;
    refs.assetBulkDeleteButton.textContent =
      currentCheckedIds.length > 0
        ? `删掉勾选未使用 (${currentCheckedIds.length})`
        : "删掉勾选未使用";
  }

  if (refs.matchVoiceFilesButton) {
    const canMatchVoiceFiles = state.selectedAssetType === "voice" && voiceMatchTargets.length > 0;
    refs.matchVoiceFilesButton.disabled = !canMatchVoiceFiles;
    refs.matchVoiceFilesButton.textContent =
      state.selectedAssetType !== "voice"
        ? "切到语音分类后可匹配"
        : voiceMatchTargets.length > 0
          ? `批量匹配语音文件 (${voiceMatchTargets.length})`
          : "当前没有待导入语音";
  }

  if (refs.replaceAssetButton) {
    refs.replaceAssetButton.disabled = !selectedAsset;
  }

  if (refs.deleteAssetButton) {
    refs.deleteAssetButton.disabled = !selectedAsset;
  }

  refs.assetTypeList.innerHTML = renderAssetTypeList(visibleAssets, duplicateOverview);
  refs.assetGrid.innerHTML =
    selectedTypeAssets.length === 0
      ? renderEmpty(getAssetEmptyMessage())
      : selectedTypeAssets
          .map((asset) => renderAssetCard(asset, asset.id === selectedAsset?.id, duplicateOverview.infoByAssetId.get(asset.id)))
          .join("");
  const voiceMatchReviewPanel = renderVoiceMatchReviewPanel();
  refs.assetDetails.innerHTML = selectedAsset
    ? `${voiceMatchReviewPanel}${renderAssetDetails(selectedAsset, duplicateOverview)}`
    : voiceMatchReviewPanel || renderEmpty(getAssetEmptyMessage("当前没有可查看的素材。"));
}

function getSafeCharacterPresentationMode(mode) {
  return Object.prototype.hasOwnProperty.call(CHARACTER_PRESENTATION_MODE_LABELS, mode) ? mode : "sprite";
}

function getCharacterPresentation(character) {
  const raw = character?.presentation ?? {};
  const mode = getSafeCharacterPresentationMode(raw.mode);
  return {
    mode,
    fallbackSpriteAssetId: raw.fallbackSpriteAssetId || character?.defaultSpriteId || "",
    live2d: {
      modelAssetId: raw.live2d?.modelAssetId || "",
      idleMotion: raw.live2d?.idleMotion || "",
      blink: raw.live2d?.blink !== false,
      breath: raw.live2d?.breath !== false,
      lipSync: raw.live2d?.lipSync !== false,
      cursorTracking: Boolean(raw.live2d?.cursorTracking),
    },
    model3d: {
      modelAssetId: raw.model3d?.modelAssetId || "",
      idleAnimation: raw.model3d?.idleAnimation || "",
      cameraPreset: raw.model3d?.cameraPreset || "portrait",
      lightingPreset: raw.model3d?.lightingPreset || "studio",
    },
  };
}

function getCharacterPresentationModeLabel(character) {
  const presentation = getCharacterPresentation(character);
  return CHARACTER_PRESENTATION_MODE_LABELS[presentation.mode] ?? CHARACTER_PRESENTATION_MODE_LABELS.sprite;
}

function getCharacterPresentationPrimaryAssetId(character) {
  const presentation = getCharacterPresentation(character);
  if (presentation.mode === "live2d") {
    return presentation.live2d.modelAssetId || presentation.fallbackSpriteAssetId || character?.defaultSpriteId || "";
  }
  if (presentation.mode === "model3d") {
    return presentation.model3d.modelAssetId || presentation.fallbackSpriteAssetId || character?.defaultSpriteId || "";
  }
  return presentation.fallbackSpriteAssetId || character?.defaultSpriteId || "";
}

function collectCharacterPresentationAssetIds(character) {
  const presentation = getCharacterPresentation(character);
  const assetIds = [
    presentation.fallbackSpriteAssetId,
    presentation.live2d.modelAssetId,
    presentation.model3d.modelAssetId,
  ];
  (character?.expressions ?? []).forEach((expression) => {
    (expression.layerAssetIds ?? []).forEach((assetId) => assetIds.push(assetId));
  });
  return Array.from(new Set(assetIds.filter(Boolean)));
}

function getCharacterPresentationStatus(character) {
  const presentation = getCharacterPresentation(character);
  const primaryAssetId = getCharacterPresentationPrimaryAssetId(character);
  const primaryAsset = primaryAssetId ? state.data.assetsById.get(primaryAssetId) : null;
  const expectedType =
    presentation.mode === "live2d" ? "live2d" : presentation.mode === "model3d" ? "model3d" : "sprite";

  if (presentation.mode === "sprite" || presentation.mode === "layered_sprite") {
    const expressionCount = character?.expressions?.length ?? 0;
    const layeredCount = (character?.expressions ?? []).filter((expression) => (expression.layerAssetIds ?? []).length > 0).length;
    return {
      tone: primaryAsset ? "good-text" : "warn-text",
      label: primaryAsset ? `${expressionCount} 个表情可用` : "缺少兜底立绘",
      detail:
        presentation.mode === "layered_sprite"
          ? `已配置 ${layeredCount}/${expressionCount} 个差分图层；Runtime 会优先使用普通立绘兜底。`
          : "普通立绘模式稳定、兼容性最好，适合作为所有高级模型的兜底方案。",
    };
  }

  if (!primaryAsset) {
    return {
      tone: "warn-text",
      label: `还没绑定${getAssetTypeLabel(expectedType)}`,
      detail: `可以先导入 ${getAssetTypeLabel(expectedType)} 素材，再在这里绑定；正式 Runtime 会继续用兜底立绘。`,
    };
  }

  return {
    tone: primaryAsset.fileExists ? "good-text" : "warn-text",
    label: primaryAsset.fileExists ? `${primaryAsset.name} 已绑定` : `${primaryAsset.name} 待导入文件`,
    detail:
      presentation.mode === "live2d"
        ? "Live2D 配置会保存眨眼、呼吸、口型同步和视线跟随开关；完整渲染层会按这个结构接入。"
        : "3D 配置会保存模型、待机动作、镜头和灯光预设；后续原生渲染层会按这个结构迁移。",
  };
}

function getCharacterExpressionBindingStatus(expression) {
  const layerCount = (expression?.layerAssetIds ?? []).length;
  const live2dCount = [expression?.live2dExpression, expression?.live2dMotion].filter(Boolean).length;
  const model3dCount = [expression?.model3dExpression, expression?.model3dAnimation].filter(Boolean).length;
  if (layerCount || live2dCount || model3dCount) {
    return {
      tone: "good-text",
      label: `${layerCount} 图层 / ${live2dCount} Live2D / ${model3dCount} 3D`,
    };
  }
  return {
    tone: "",
    label: "沿用普通立绘",
  };
}

function getCharacterPresentationReadinessTone(score) {
  if (score >= 85) {
    return "good-text";
  }
  if (score >= 55) {
    return "warn-text";
  }
  return "danger-text";
}

function getCharacterAssetHealth(assetId, expectedTypes = []) {
  const cleanAssetId = String(assetId ?? "").trim();
  if (!cleanAssetId) {
    return {
      ok: false,
      fileOk: false,
      typeOk: false,
      label: "未绑定",
      detail: "还没有选择素材。",
      asset: null,
    };
  }

  const asset = state.data.assetsById.get(cleanAssetId);
  if (!asset) {
    return {
      ok: false,
      fileOk: false,
      typeOk: false,
      label: "素材不存在",
      detail: `找不到素材 ID：${cleanAssetId}`,
      asset: null,
    };
  }

  const typeOk = expectedTypes.length === 0 || expectedTypes.includes(asset.type);
  const fileOk = Boolean(asset.fileExists);
  return {
    ok: typeOk && fileOk,
    fileOk,
    typeOk,
    label: asset.name || cleanAssetId,
    detail: [
      getAssetTypeLabel(asset.type),
      fileOk ? "文件已导入" : "文件待导入",
      typeOk ? "" : `期望 ${expectedTypes.map((type) => getAssetTypeLabel(type)).join(" / ")}`,
    ]
      .filter(Boolean)
      .join(" · "),
    asset,
  };
}

function isExpressionMappedForPresentationMode(expression, mode) {
  if (!expression) {
    return false;
  }
  if (mode === "layered_sprite") {
    return (expression.layerAssetIds ?? []).length > 0 || Boolean(expression.spriteAssetId);
  }
  if (mode === "live2d") {
    return Boolean(expression.live2dExpression || expression.live2dMotion);
  }
  if (mode === "model3d") {
    return Boolean(expression.model3dExpression || expression.model3dAnimation);
  }
  return Boolean(expression.spriteAssetId);
}

function buildCharacterPresentationReadiness(character) {
  const presentation = getCharacterPresentation(character);
  const mode = presentation.mode;
  const expressions = character?.expressions ?? [];
  const expressionCount = expressions.length;
  const mappedExpressionCount = expressions.filter((expression) =>
    isExpressionMappedForPresentationMode(expression, mode)
  ).length;
  const fallbackHealth = getCharacterAssetHealth(
    presentation.fallbackSpriteAssetId || character?.defaultSpriteId,
    ["sprite", "cg", "ui"]
  );
  const primaryAssetId =
    mode === "live2d"
      ? presentation.live2d.modelAssetId
      : mode === "model3d"
        ? presentation.model3d.modelAssetId
        : presentation.fallbackSpriteAssetId || character?.defaultSpriteId;
  const expectedPrimaryTypes = mode === "live2d" ? ["live2d"] : mode === "model3d" ? ["model3d"] : ["sprite", "cg", "ui"];
  const primaryHealth = getCharacterAssetHealth(primaryAssetId, expectedPrimaryTypes);
  const issues = [];

  if (!fallbackHealth.ok) {
    issues.push({
      tone: "warn-text",
      title: "兜底立绘还不稳",
      detail: "即使后续接入 Live2D/3D，兜底立绘也能保证截图、存档、低配回退和未安装渲染器时不空屏。",
    });
  }

  if (mode === "live2d") {
    if (!primaryHealth.ok) {
      issues.push({
        tone: "danger-text",
        title: "Live2D 模型入口不可用",
        detail: primaryHealth.detail,
      });
    } else if (!String(primaryHealth.asset?.path ?? "").toLowerCase().endsWith(".model3.json")) {
      issues.push({
        tone: "warn-text",
        title: "建议绑定 .model3.json 入口",
        detail: "Live2D 最稳的入口是 .model3.json，单独 moc3 或 motion 文件后续可能无法自动找到贴图和动作。",
      });
    }
  }

  if (mode === "model3d") {
    if (!primaryHealth.ok) {
      issues.push({
        tone: "danger-text",
        title: "3D 模型文件不可用",
        detail: primaryHealth.detail,
      });
    } else if (!/\.(glb|gltf|vrm)$/i.test(primaryHealth.asset?.path ?? "")) {
      issues.push({
        tone: "warn-text",
        title: "建议优先使用 glb / gltf / vrm",
        detail: "fbx 和 obj 可以先记录，但后续原生 Runtime 更可能优先支持 glb、gltf、vrm。",
      });
    }
  }

  if (expressionCount === 0) {
    issues.push({
      tone: "warn-text",
      title: "还没有表情条目",
      detail: "建议至少保留一个默认表情，后续 Live2D/3D 动作映射会更清晰。",
    });
  } else if (mode !== "sprite" && mappedExpressionCount < expressionCount) {
    issues.push({
      tone: "warn-text",
      title: "表情映射还没覆盖完",
      detail: `当前 ${mappedExpressionCount}/${expressionCount} 个表情有 ${getCharacterPresentationModeLabel(character)} 映射。`,
    });
  }

  const fallbackScore = fallbackHealth.ok ? 22 : fallbackHealth.asset ? 10 : 0;
  const primaryScore = primaryHealth.ok ? 40 : primaryHealth.asset ? 18 : mode === "sprite" ? 18 : 0;
  const expressionScore =
    expressionCount === 0
      ? 6
      : Math.round((mappedExpressionCount / Math.max(1, expressionCount)) * 26);
  const safetyScore = fallbackHealth.ok && primaryHealth.ok ? 12 : fallbackHealth.ok || primaryHealth.ok ? 6 : 0;
  const score = Math.max(0, Math.min(100, fallbackScore + primaryScore + expressionScore + safetyScore));

  return {
    score,
    tone: getCharacterPresentationReadinessTone(score),
    mode,
    fallbackHealth,
    primaryHealth,
    expressionCount,
    mappedExpressionCount,
    issues,
  };
}

function parseCharacterLayerAssetIds(value) {
  return String(value ?? "")
    .split(/[\n,，、;；]+/)
    .map((item) => item.trim())
    .filter(Boolean)
    .slice(0, 12);
}

function isMajorCharacterStats(stats) {
  return (stats.totalLines ?? 0) >= 12 || (stats.scenesCount ?? 0) >= 3;
}

function matchesCharacterFilterMode(stats, filterMode) {
  const safeFilter = getSafeCharacterFilterMode(filterMode);

  if (safeFilter === "missing_voice") {
    return (stats.missingVoiceCount ?? 0) > 0;
  }

  if (safeFilter === "voiced") {
    return (stats.totalLines ?? 0) > 0 && (stats.missingVoiceCount ?? 0) === 0;
  }

  if (safeFilter === "major") {
    return isMajorCharacterStats(stats);
  }

  if (safeFilter === "silent") {
    return (stats.totalLines ?? 0) === 0;
  }

  return true;
}

function buildCharacterSearchText(character, stats) {
  return normalizeDashboardSearchQuery(
    [
      character.displayName,
      character.bio,
      character.id,
      getPositionLabel(character.defaultPosition),
      getCharacterPresentationModeLabel(character),
      (character.expressions ?? []).map((expression) => expression.name).join(" "),
      (stats.topExpressions ?? []).map(([name]) => name).join(" "),
      (stats.missingVoiceCount ?? 0) > 0 ? "待配音" : "语音已齐",
      isMajorCharacterStats(stats) ? "台词较多" : "",
      (stats.totalLines ?? 0) === 0 ? "暂无台词" : "",
    ]
      .filter(Boolean)
      .join(" ")
  );
}

function countCharactersForFilterMode(filterMode) {
  return state.data.characters.filter((character) =>
    matchesCharacterFilterMode(buildCharacterDialogueStats(character.id), filterMode)
  ).length;
}

function buildCharacterRosterOverview() {
  const filterMode = getSafeCharacterFilterMode(state.characterFilterMode);
  const terms = getDashboardSearchTerms(state.characterSearchQuery);
  const characters = state.data.characters
    .map((character) => {
      const stats = buildCharacterDialogueStats(character.id);
      return {
        character,
        stats,
        searchText: buildCharacterSearchText(character, stats),
      };
    })
    .filter((entry) => {
      if (!matchesCharacterFilterMode(entry.stats, filterMode)) {
        return false;
      }

      if (!terms.length) {
        return true;
      }

      return terms.every((term) => entry.searchText.includes(term));
    })
    .sort((left, right) => {
      const missingVoiceDiff = (right.stats.missingVoiceCount ?? 0) - (left.stats.missingVoiceCount ?? 0);
      if (missingVoiceDiff !== 0) {
        return missingVoiceDiff;
      }

      const totalLineDiff = (right.stats.totalLines ?? 0) - (left.stats.totalLines ?? 0);
      if (totalLineDiff !== 0) {
        return totalLineDiff;
      }

      return left.character.displayName.localeCompare(right.character.displayName, "zh-Hans-CN");
    });

  return {
    characters,
    totalCount: state.data.characters.length,
    visibleCount: characters.length,
    hiddenSelectedCharacter:
      Boolean(state.selectedCharacterId) &&
      state.data.charactersById.has(state.selectedCharacterId) &&
      !characters.some((entry) => entry.character.id === state.selectedCharacterId),
  };
}

function renderCharacterFilterBar() {
  const modes = ["all", "missing_voice", "voiced", "major", "silent"];

  return modes
    .map((mode) => {
      const count = mode === "all" ? state.data.characters.length : countCharactersForFilterMode(mode);
      return `
        <button
          type="button"
          class="asset-tag-chip ${getSafeCharacterFilterMode(state.characterFilterMode) === mode ? "is-active" : ""}"
          data-action="set-character-filter"
          data-character-filter="${mode}"
        >
          <span>${escapeHtml(getCharacterFilterLabel(mode))}</span>
          <strong>${count}</strong>
        </button>
      `;
    })
    .join("");
}

function renderCharacterListSummary(overview) {
  const activeLabels = [];

  if ((state.characterSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.characterSearchQuery.trim()}`);
  }

  if (getSafeCharacterFilterMode(state.characterFilterMode) !== "all") {
    activeLabels.push(`视角：${getCharacterFilterLabel(state.characterFilterMode)}`);
  }

  return `
    <div class="story-filter-summary-main">
      <strong>命中 ${overview.visibleCount}/${overview.totalCount} 位角色</strong>
      <span class="panel-note">角色多起来以后，这里会比手动翻列表省很多时间</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有角色筛选，正在显示全部角色。</span>'
      }
      ${
        overview.hiddenSelectedCharacter
          ? '<span class="issue-tag warn-text">当前正在查看的角色被筛选隐藏了，右侧详情不会丢。</span>'
          : ""
      }
    </div>
  `;
}

function renderCharactersScreen() {
  const character = state.data.charactersById.get(state.selectedCharacterId) ?? state.data.characters[0];
  const rosterOverview = buildCharacterRosterOverview();
  const selectedStats = character ? buildCharacterDialogueStats(character.id) : null;
  const starterKitPanel = renderStarterKitPanel("characters");
  const isAdvancedMode = isAdvancedEditorMode();

  if (refs.characterSearchInput && refs.characterSearchInput.value !== state.characterSearchQuery) {
    refs.characterSearchInput.value = state.characterSearchQuery;
  }

  if (refs.characterFilterBar) {
    refs.characterFilterBar.innerHTML = isAdvancedMode ? renderCharacterFilterBar() : "";
  }

  if (refs.characterListSummary) {
    refs.characterListSummary.innerHTML = isAdvancedMode
      ? renderCharacterListSummary(rosterOverview)
      : renderBeginnerCharacterSummary(rosterOverview, character, selectedStats);
  }

  if (refs.characterFilterClearButton) {
    refs.characterFilterClearButton.disabled = !hasActiveCharacterFilter();
  }

  refs.characterMeta.textContent = character
    ? `${character.displayName} · ${getCharacterPresentationModeLabel(character)} · ${character.expressions.length} 个表情 · ${selectedStats.totalLines} 句台词 · 语音覆盖 ${selectedStats.voiceCoverage}%`
    : "还没有角色";

  refs.characterList.innerHTML =
    rosterOverview.characters.length > 0
      ? rosterOverview.characters
          .map((entry) => renderCharacterCard(entry.character, entry.character.id === character?.id, entry.stats))
          .join("")
      : renderEmpty("这个角色筛选下暂时没有命中的角色。可换一个关键词，或点击上面的“清空角色筛选”。");
  refs.characterDetails.innerHTML = character
    ? `${starterKitPanel}${!isAdvancedMode ? renderBeginnerCharacterGuide(character, selectedStats) : ""}${renderCharacterOverview(character, selectedStats)}`
    : `${starterKitPanel}${!isAdvancedMode ? renderBeginnerCharacterGuide(character, selectedStats) : ""}${renderEmpty("还没有角色数据。")}`;

  refs.expressionGrid.innerHTML = character
    ? character.expressions
        .map((expression) => {
          const asset = state.data.assetsById.get(expression.spriteAssetId);
          const layerCount = (expression.layerAssetIds ?? []).length;
          const live2dBinding = [expression.live2dExpression, expression.live2dMotion].filter(Boolean).join(" / ");
          const model3dBinding = [expression.model3dExpression, expression.model3dAnimation].filter(Boolean).join(" / ");
          return `
            <article class="asset-card">
              <div class="asset-thumb" data-asset-type="sprite"></div>
              <span class="asset-tag">表情</span>
              <strong>${escapeHtml(expression.name)}</strong>
              <div class="asset-meta">${escapeHtml(asset?.name ?? expression.spriteAssetId)}</div>
              <div class="scene-card-tags">
                ${layerCount > 0 ? `<span class="issue-tag good-text">差分图层 ${layerCount}</span>` : `<span class="issue-tag">普通立绘</span>`}
                ${live2dBinding ? `<span class="issue-tag good-text">Live2D ${escapeHtml(live2dBinding)}</span>` : ""}
                ${model3dBinding ? `<span class="issue-tag good-text">3D ${escapeHtml(model3dBinding)}</span>` : ""}
              </div>
            </article>
          `;
        })
        .join("")
    : renderEmpty("还没有表情数据。");
}

function renderScriptScreen() {
  const allEntries = analyzeScriptEntries(buildScriptEntries());
  const filteredEntries = getFilteredScriptEntries(allEntries);
  const isAdvancedMode = isAdvancedEditorMode();
  const visibleEntries = isAdvancedMode ? filteredEntries : filteredEntries.slice(0, 8);

  if (refs.scriptSearchInput && refs.scriptSearchInput.value !== state.scriptSearchQuery) {
    refs.scriptSearchInput.value = state.scriptSearchQuery;
  }

  if (refs.scriptChapterSelect) {
    refs.scriptChapterSelect.innerHTML = renderScriptChapterOptions(state.scriptChapterFilter);
    refs.scriptChapterSelect.value = getSafeScriptChapterFilter(state.scriptChapterFilter);
  }

  if (refs.scriptCharacterSelect) {
    refs.scriptCharacterSelect.innerHTML = renderScriptCharacterOptions(state.scriptCharacterFilter);
    refs.scriptCharacterSelect.value = getSafeScriptCharacterFilter(state.scriptCharacterFilter);
  }

  if (refs.scriptTypeSelect) {
    refs.scriptTypeSelect.value = getSafeScriptTypeFilter(state.scriptTypeFilter);
  }

  if (refs.scriptVoiceSelect) {
    refs.scriptVoiceSelect.value = getSafeScriptVoiceFilter(state.scriptVoiceFilter);
  }

  if (refs.scriptIssueSelect) {
    refs.scriptIssueSelect.value = getSafeScriptIssueFilter(state.scriptIssueFilter);
  }

  if (refs.scriptResultMeta) {
    refs.scriptResultMeta.textContent = isAdvancedMode
      ? getScriptResultMeta(filteredEntries, allEntries.length)
      : filteredEntries.length > visibleEntries.length
        ? `新手模式先显示 ${visibleEntries.length}/${filteredEntries.length} 条，深度筛台本时再切高级模式`
        : `新手模式正在显示 ${visibleEntries.length} 条常用台本内容`;
  }

  if (refs.scriptFilterSummary) {
    refs.scriptFilterSummary.innerHTML = isAdvancedMode
      ? renderScriptFilterSummary(filteredEntries, allEntries)
      : renderBeginnerScriptGuide(filteredEntries, allEntries);
  }

  if (refs.scriptResultList) {
    refs.scriptResultList.innerHTML =
      visibleEntries.length > 0
        ? visibleEntries.map((entry) => renderScriptEntryCard(entry)).join("")
        : renderEmpty("这个筛选下还没有内容。可以换个角色、章节或搜索词试试看。");
  }

  if (refs.scriptSummary) {
    refs.scriptSummary.innerHTML = isAdvancedMode
      ? renderScriptSummary(filteredEntries, allEntries)
      : renderBeginnerScriptSummary(filteredEntries, allEntries);
  }
}

function buildScriptEntries() {
  const entries = [];

  state.data.chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      const sceneEntries = [];

      (scene.blocks ?? []).forEach((block, blockIndex) => {
        if (block.type === "dialogue") {
          const speakerName =
            state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId ?? "角色";
          const voiceAsset = block.voiceAssetId
            ? state.data.assetsById.get(block.voiceAssetId)
            : null;

          sceneEntries.push({
            entryId: `${scene.id}-${block.id}`,
            type: "dialogue",
            chapterId: chapter.chapterId,
            chapterName: chapter.name,
            sceneId: scene.id,
            sceneName: scene.name,
            blockId: block.id,
            blockIndex,
            characterId: block.speakerId ?? "",
            speakerName,
            title: `${speakerName}：${truncateText(block.text || "这句台词还没填正文。", 36)}`,
            text: block.text || "这句台词还没填正文。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张`,
            expressionName: getExpressionName(block.speakerId, block.expressionId),
            voiceStatus: block.voiceAssetId ? "voiced" : "missing",
            voiceAssetId: block.voiceAssetId ?? "",
            voiceName: voiceAsset?.name ?? "",
            voiceFileExists: Boolean(voiceAsset?.fileExists),
            voiceAssetPath: voiceAsset?.path ?? "",
            sourceText: String(block.text ?? "").trim(),
            contentLength: String(block.text ?? "").trim().length,
            searchText: [
              chapter.name,
              scene.name,
              speakerName,
              block.text,
              getExpressionName(block.speakerId, block.expressionId),
              voiceAsset?.name,
            ]
              .filter(Boolean)
              .join(" "),
          });
          return;
        }

        if (block.type === "narration") {
          sceneEntries.push({
            entryId: `${scene.id}-${block.id}`,
            type: "narration",
            chapterId: chapter.chapterId,
            chapterName: chapter.name,
            sceneId: scene.id,
            sceneName: scene.name,
            blockId: block.id,
            blockIndex,
            characterId: "",
            speakerName: "旁白",
            title: `旁白：${truncateText(block.text || "这句旁白还没填正文。", 36)}`,
            text: block.text || "这句旁白还没填正文。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张`,
            expressionName: "",
            voiceStatus: "not_required",
            voiceName: "",
            sourceText: String(block.text ?? "").trim(),
            contentLength: String(block.text ?? "").trim().length,
            searchText: [chapter.name, scene.name, "旁白", block.text].filter(Boolean).join(" "),
          });
          return;
        }

        if (block.type === "choice") {
          const choiceText = (block.options ?? [])
            .map((option) => option.text)
            .filter(Boolean)
            .join(" / ");

          sceneEntries.push({
            entryId: `${scene.id}-${block.id}`,
            type: "choice",
            chapterId: chapter.chapterId,
            chapterName: chapter.name,
            sceneId: scene.id,
            sceneName: scene.name,
            blockId: block.id,
            blockIndex,
            characterId: "",
            speakerName: "选项",
            title: `选项：${truncateText(choiceText || "这个选项还没写文案。", 36)}`,
            text: choiceText || "这个选项还没写文案。",
            meta: `${chapter.name} · ${scene.name} · 第 ${blockIndex + 1} 张 · ${(block.options ?? []).length} 个选项`,
            expressionName: "",
            voiceStatus: "not_required",
            voiceName: "",
            sourceText: choiceText.trim(),
            contentLength: choiceText.trim().length,
            searchText: [chapter.name, scene.name, "选项", choiceText].filter(Boolean).join(" "),
          });
        }
      });

      sceneEntries.forEach((entry, index) => {
        const previousEntry = sceneEntries[index - 1] ?? null;
        const nextEntry = sceneEntries[index + 1] ?? null;

        entries.push({
          ...entry,
          previousContext: previousEntry ? createScriptEntryContextSummary(previousEntry) : null,
          nextContext: nextEntry ? createScriptEntryContextSummary(nextEntry) : null,
        });
      });
    });
  });

  return entries;
}

function createScriptEntryContextSummary(entry) {
  return {
    label:
      entry.type === "dialogue"
        ? entry.speakerName
        : entry.type === "narration"
          ? "旁白"
          : "选项",
    text: truncateText(entry.text, 42),
    sceneId: entry.sceneId,
    blockId: entry.blockId,
  };
}

function entryToVoicePlaceholderItem(entry) {
  if (!entry?.sceneId || !entry?.blockId) {
    return null;
  }

  return {
    sceneId: entry.sceneId,
    blockId: entry.blockId,
  };
}

function analyzeScriptEntries(entries) {
  const duplicateCounts = new Map();

  entries.forEach((entry) => {
    const duplicateKey = getScriptDuplicateKey(entry);
    if (!duplicateKey) {
      return;
    }
    duplicateCounts.set(duplicateKey, (duplicateCounts.get(duplicateKey) ?? 0) + 1);
  });

  return entries.map((entry) => {
    const issues = [];
    const duplicateKey = getScriptDuplicateKey(entry);

    if (!entry.sourceText) {
      issues.push("placeholder");
    }

    if (entry.sourceText && entry.contentLength > getScriptLengthLimit(entry.type)) {
      issues.push("too_long");
    }

    if (entry.type === "dialogue" && entry.voiceStatus === "missing") {
      issues.push("missing_voice");
    }

    if (duplicateKey && (duplicateCounts.get(duplicateKey) ?? 0) > 1) {
      issues.push("duplicate");
    }

    return {
      ...entry,
      issues,
    };
  });
}

function getScriptDuplicateKey(entry) {
  const normalizedText = normalizeScriptSearchQuery(entry.sourceText);
  if (!normalizedText || normalizedText.length < 4) {
    return "";
  }

  const ownerKey =
    entry.type === "dialogue" ? entry.characterId || entry.speakerName : entry.type;
  return `${entry.type}|${ownerKey}|${normalizedText}`;
}

function getScriptLengthLimit(type) {
  if (type === "choice") {
    return 52;
  }

  if (type === "narration") {
    return 46;
  }

  return 38;
}

function getFilteredScriptEntries(allEntries) {
  const chapterFilter = getSafeScriptChapterFilter(state.scriptChapterFilter);
  const characterFilter = getSafeScriptCharacterFilter(state.scriptCharacterFilter);
  const typeFilter = getSafeScriptTypeFilter(state.scriptTypeFilter);
  const voiceFilter = getSafeScriptVoiceFilter(state.scriptVoiceFilter);
  const issueFilter = getSafeScriptIssueFilter(state.scriptIssueFilter);
  const terms = getScriptSearchTerms(state.scriptSearchQuery);

  return allEntries.filter((entry) => {
    if (chapterFilter !== "all" && entry.chapterId !== chapterFilter) {
      return false;
    }

    if (characterFilter !== "all" && entry.characterId !== characterFilter) {
      return false;
    }

    if (typeFilter !== "all" && entry.type !== typeFilter) {
      return false;
    }

    if (voiceFilter === "missing" && entry.voiceStatus !== "missing") {
      return false;
    }

    if (voiceFilter === "voiced" && entry.voiceStatus !== "voiced") {
      return false;
    }

    if (voiceFilter === "not_required" && entry.voiceStatus !== "not_required") {
      return false;
    }

    if (issueFilter === "any" && (entry.issues?.length ?? 0) === 0) {
      return false;
    }

    if (issueFilter !== "all" && issueFilter !== "any" && !(entry.issues ?? []).includes(issueFilter)) {
      return false;
    }

    if (!terms.length) {
      return true;
    }

    const haystack = normalizeScriptSearchQuery(
      [entry.title, entry.text, entry.meta, entry.speakerName, entry.searchText].join(" ")
    );
    return terms.every((term) => haystack.includes(term));
  });
}

function renderScriptChapterOptions(selectedChapterId) {
  const safeSelected = getSafeScriptChapterFilter(selectedChapterId);
  return [
    `<option value="all">全部章节</option>`,
    ...state.data.chapters.map(
      (chapter) =>
        `<option value="${chapter.chapterId}" ${chapter.chapterId === safeSelected ? "selected" : ""}>${escapeHtml(chapter.name)}</option>`
    ),
  ].join("");
}

function renderScriptCharacterOptions(selectedCharacterId) {
  const safeSelected = getSafeScriptCharacterFilter(selectedCharacterId);
  return [
    `<option value="all">全部角色</option>`,
    ...state.data.characters.map(
      (character) =>
        `<option value="${character.id}" ${character.id === safeSelected ? "selected" : ""}>${escapeHtml(character.displayName)}</option>`
    ),
  ].join("");
}

function renderScriptEntryCard(entry) {
  const tagTone =
    entry.type === "dialogue" ? "good-text" : entry.type === "choice" ? "warn-text" : "";
  const voiceTag =
    entry.voiceStatus === "missing"
      ? '<span class="issue-tag warn-text">待绑语音</span>'
      : entry.voiceStatus === "voiced"
        ? '<span class="issue-tag good-text">已绑语音</span>'
        : '<span class="issue-tag">不需要语音</span>';
  const characterButton =
    entry.characterId && entry.type === "dialogue"
      ? `
          <button
            type="button"
            class="toolbar-button"
            data-action="open-dashboard-character"
            data-character-id="${entry.characterId}"
          >
            看角色资料
          </button>
        `
      : "";
  const createVoiceButton =
    entry.type === "dialogue" && entry.voiceStatus === "missing"
      ? `
          <button
            type="button"
            class="toolbar-button"
            data-action="create-voice-placeholder"
            data-scene-id="${entry.sceneId}"
            data-block-id="${entry.blockId}"
          >
            生成语音条目
          </button>
        `
      : "";
  const issueBadges = renderScriptIssueBadges(entry.issues ?? []);

  return `
    <article class="script-entry-card">
      <div class="script-entry-top">
        <div class="script-entry-badges">
          <span class="issue-tag ${tagTone}">${escapeHtml(getScriptTypeLabel(entry.type))}</span>
          ${voiceTag}
          ${issueBadges}
        </div>
        <span class="script-entry-meta">${escapeHtml(entry.meta)}</span>
      </div>
      <strong>${escapeHtml(entry.title)}</strong>
      <p>${escapeHtml(entry.text)}</p>
      ${renderScriptContextPreview(entry)}
      <div class="script-entry-footer">
        <div class="script-entry-notes">
          <span>${escapeHtml(entry.sceneName)}</span>
          <span>${escapeHtml(entry.expressionName || entry.voiceName || "可直接继续修改")}</span>
        </div>
        <div class="script-entry-actions">
          <button
            type="button"
            class="toolbar-button"
            data-action="copy-script-entry"
            data-scene-id="${entry.sceneId}"
            data-block-id="${entry.blockId}"
          >
            复制资料
          </button>
          <button
            type="button"
            class="toolbar-button"
            data-action="preview-story-location"
            data-scene-id="${entry.sceneId}"
            data-block-id="${entry.blockId}"
          >
            试玩这句
          </button>
          <button
            type="button"
            class="toolbar-button toolbar-button-primary"
            data-action="open-character-line"
            data-scene-id="${entry.sceneId}"
            data-block-id="${entry.blockId}"
          >
            打开卡片
          </button>
          ${createVoiceButton}
          ${characterButton}
        </div>
      </div>
    </article>
  `;
}

function renderScriptContextPreview(entry) {
  if (!entry.previousContext && !entry.nextContext) {
    return "";
  }

  return `
    <div class="script-context-preview">
      ${
        entry.previousContext
          ? `
              <div class="script-context-line">
                <span class="issue-tag">上一句</span>
                <strong>${escapeHtml(entry.previousContext.label)}</strong>
                <span>${escapeHtml(entry.previousContext.text)}</span>
              </div>
            `
          : ""
      }
      ${
        entry.nextContext
          ? `
              <div class="script-context-line">
                <span class="issue-tag good-text">下一句</span>
                <strong>${escapeHtml(entry.nextContext.label)}</strong>
                <span>${escapeHtml(entry.nextContext.text)}</span>
              </div>
            `
          : ""
      }
    </div>
  `;
}

function renderScriptFilterSummary(filteredEntries, allEntries) {
  const queryText = state.scriptSearchQuery.trim();
  const pieces = [];

  if (queryText) {
    pieces.push(`关键词：${queryText}`);
  }

  if (state.scriptChapterFilter !== "all") {
    pieces.push(`章节：${getScriptChapterFilterLabel(state.scriptChapterFilter)}`);
  }

  if (state.scriptCharacterFilter !== "all") {
    pieces.push(`角色：${getScriptCharacterFilterLabel(state.scriptCharacterFilter)}`);
  }

  if (state.scriptTypeFilter !== "all") {
    pieces.push(`类型：${getScriptTypeLabel(state.scriptTypeFilter)}`);
  }

  if (state.scriptVoiceFilter !== "all") {
    pieces.push(`语音：${getScriptVoiceFilterLabel(state.scriptVoiceFilter)}`);
  }

  if (state.scriptIssueFilter !== "all") {
    pieces.push(`体检：${getScriptIssueFilterLabel(state.scriptIssueFilter)}`);
  }

  return `
    <article class="detail-card">
      <strong>当前筛选</strong>
      <p>${pieces.length > 0 ? escapeHtml(pieces.join(" / ")) : "当前正在看全项目的完整台本。"}</p>
    </article>
    <article class="detail-card">
      <strong>命中情况</strong>
      <p>共筛出 ${filteredEntries.length} 条，完整项目一共有 ${allEntries.length} 条正文内容。</p>
    </article>
  `;
}

function renderBeginnerScriptGuide(filteredEntries, allEntries) {
  const missingVoiceCount = filteredEntries.filter((entry) => entry.voiceStatus === "missing").length;
  const issueCount = filteredEntries.filter((entry) => (entry.issues ?? []).length > 0).length;
  const chapterCount = new Set(filteredEntries.map((entry) => entry.chapterId)).size;

  return `
    <article class="detail-card beginner-script-card">
      <strong>台本页是高级工具</strong>
      <p>这里更适合集中处理配音统筹、文本体检和角色口吻统一。新手模式下仅显示最核心的信息。</p>
      <div class="detail-actions">
        ${renderQuickActionButton({ label: "切到高级模式", action: "set-editor-mode", dataset: { "editor-mode": "advanced" } }, true)}
        ${renderQuickActionButton({ label: "回剧情页继续写", action: "switch-screen", screen: "story" })}
      </div>
      <div class="story-filter-chip-row">
        <span class="issue-tag good-text">当前命中 ${filteredEntries.length} 条</span>
        <span class="issue-tag">涉及 ${chapterCount} 个章节</span>
        <span class="issue-tag">${missingVoiceCount} 条待绑语音</span>
        <span class="issue-tag">${issueCount} 条待确认内容</span>
      </div>
      <div class="detail-meta">
        全项目总共有 ${allEntries.length} 条正文内容。需要处理配音排班、CSV 导出或角色口吻分析时，可切换到高级模式。
      </div>
    </article>
  `;
}

function renderScriptSummary(filteredEntries, allEntries) {
  const dialogueCount = filteredEntries.filter((entry) => entry.type === "dialogue").length;
  const narrationCount = filteredEntries.filter((entry) => entry.type === "narration").length;
  const choiceCount = filteredEntries.filter((entry) => entry.type === "choice").length;
  const missingVoiceCount = filteredEntries.filter((entry) => entry.voiceStatus === "missing").length;
  const issueCounts = countScriptIssues(filteredEntries);
  const totalChars = filteredEntries.reduce((sum, entry) => sum + String(entry.text ?? "").trim().length, 0);
  const averageLength = filteredEntries.length > 0 ? Math.round(totalChars / filteredEntries.length) : 0;
  const topSpeaker = getTopScriptSpeaker(filteredEntries);
  const totalDialogueInProject = allEntries.filter((entry) => entry.type === "dialogue").length;
  const missingVoiceInProject = allEntries.filter((entry) => entry.voiceStatus === "missing").length;

  return `
    <div class="summary-grid">
      ${renderStatCard("当前命中", filteredEntries.length)}
      ${renderStatCard("待绑语音", missingVoiceCount)}
      ${renderStatCard("台词数", dialogueCount)}
      ${renderStatCard("有问题条目", issueCounts.any)}
    </div>
    ${
      missingVoiceCount > 0
        ? `
          <article class="detail-card">
            <strong>这一轮可以直接开工补语音</strong>
            <p>如需先建立配音工作流，可直接为当前筛选里的待绑语音台词批量生成占位条目，再跳去语音素材页继续上传真实文件。</p>
            <div class="detail-actions">
              <button type="button" class="toolbar-button toolbar-button-primary" data-action="create-script-voice-placeholders">
                为当前筛选批量生成语音条目
              </button>
            </div>
          </article>
        `
        : ""
    }
    ${renderDetailRows([
      ["旁白数量", narrationCount],
      ["选项数量", choiceCount],
      ["平均字数", `${averageLength} 字`],
      ["最常出现角色", topSpeaker],
      ["待补正文", `${issueCounts.placeholder} 条`],
      ["偏长内容", `${issueCounts.too_long} 条`],
      ["疑似重复", `${issueCounts.duplicate} 条`],
      ["全项目对话", `${totalDialogueInProject} 句`],
      ["全项目待配音", `${missingVoiceInProject} 句`],
    ])}
    ${renderProjectVoiceOverviewPanel(allEntries)}
    ${renderScriptRecordingGroupSection(filteredEntries)}
    ${renderScriptVoiceBatchSection(filteredEntries)}
    ${renderScriptActionQueueSection(filteredEntries)}
    ${renderScriptChapterRhythmSection(filteredEntries)}
    ${renderScriptVoiceprintSection(filteredEntries)}
  `;
}

function renderBeginnerScriptSummary(filteredEntries, allEntries) {
  const dialogueCount = filteredEntries.filter((entry) => entry.type === "dialogue").length;
  const narrationCount = filteredEntries.filter((entry) => entry.type === "narration").length;
  const choiceCount = filteredEntries.filter((entry) => entry.type === "choice").length;
  const missingVoiceCount = filteredEntries.filter((entry) => entry.voiceStatus === "missing").length;
  const issueCounts = countScriptIssues(filteredEntries);
  const topSpeaker = getTopScriptSpeaker(filteredEntries);

  return `
    <div class="summary-grid">
      ${renderStatCard("当前命中", filteredEntries.length)}
      ${renderStatCard("待绑语音", missingVoiceCount)}
      ${renderStatCard("台词数", dialogueCount)}
      ${renderStatCard("问题条目", issueCounts.any)}
    </div>
    ${renderDetailRows([
      ["旁白数量", narrationCount],
      ["选项数量", choiceCount],
      ["最常出现角色", topSpeaker],
      ["全项目正文", `${allEntries.length} 条`],
      ["使用方式", "可先用这里查句子和补语音，深度分析等切到高级模式后再看"],
    ])}
    <article class="detail-card beginner-script-card">
      <strong>新手模式下优先查看这些信息</strong>
      <p>如需快速查找句子、定位待绑语音或导出基础台本，这一页已经足够。更细的批次分组、章节节奏和角色口吻画像会在高级模式中完整展开。</p>
      <div class="detail-actions">
        ${
          missingVoiceCount > 0
            ? renderQuickActionButton({ label: "只看待绑语音", action: "focus-script-missing-voice" }, true)
            : renderQuickActionButton({ label: "回剧情页继续写", action: "switch-screen", screen: "story" }, true)
        }
        ${
          missingVoiceCount > 0
            ? renderQuickActionButton(
                { label: "批量生成语音条目", action: "create-script-voice-placeholders" }
              )
            : ""
        }
        ${renderQuickActionButton({ label: "打开高级模式", action: "set-editor-mode", dataset: { "editor-mode": "advanced" } })}
      </div>
    </article>
    ${renderScriptRecordingGroupSection(filteredEntries, { compact: true })}
  `;
}

function getScriptVoiceWorkflowState(entry) {
  if (entry?.type !== "dialogue") {
    return "not_required";
  }
  if (!entry.voiceAssetId) {
    return "missing_binding";
  }
  if (entry.voiceFileExists) {
    return "ready";
  }
  return "placeholder";
}

function getScriptVoiceWorkflowLabel(entry) {
  const workflow = getScriptVoiceWorkflowState(entry);
  if (workflow === "missing_binding") {
    return "还没建语音条目";
  }
  if (workflow === "placeholder") {
    return "已建占位，待上传真实文件";
  }
  if (workflow === "ready") {
    return "语音文件已就绪";
  }
  return "不需要语音";
}

function buildSuggestedVoiceBaseName(entry) {
  if (entry.voiceName) {
    return entry.voiceName;
  }
  const speaker = String(entry.speakerName || "角色").trim();
  const chapter = String(entry.chapterName || "章节").trim();
  const scene = String(entry.sceneName || "场景").trim();
  return `${speaker}_${chapter}_${scene}_${String((entry.blockIndex ?? 0) + 1).padStart(3, "0")}`;
}

function buildSuggestedVoiceFileName(entry) {
  const existingPathName = entry.voiceAssetPath ? entry.voiceAssetPath.split("/").pop() ?? "" : "";
  if (existingPathName) {
    return existingPathName;
  }
  return `${sanitizeFileName(buildSuggestedVoiceBaseName(entry)) || "voice_line"}.wav`;
}

function buildScriptRecordingGroups(entries) {
  const groups = new Map();

  entries
    .filter((entry) => entry.type === "dialogue" && entry.characterId)
    .forEach((entry) => {
      const key = `${entry.characterId}:${entry.chapterId}`;
      const workflow = getScriptVoiceWorkflowState(entry);
      const group =
        groups.get(key) ??
        {
          key,
          characterId: entry.characterId,
          speakerName: entry.speakerName,
          chapterId: entry.chapterId,
          chapterName: entry.chapterName,
          lineCount: 0,
          totalChars: 0,
          sceneIds: new Set(),
          missingBindingCount: 0,
          placeholderCount: 0,
          readyCount: 0,
          firstEntry: entry,
        };

      group.lineCount += 1;
      group.totalChars += entry.contentLength ?? String(entry.text ?? "").trim().length;
      group.sceneIds.add(entry.sceneId);
      if (workflow === "missing_binding") {
        group.missingBindingCount += 1;
      } else if (workflow === "placeholder") {
        group.placeholderCount += 1;
      } else if (workflow === "ready") {
        group.readyCount += 1;
      }

      if ((entry.blockIndex ?? 9999) < (group.firstEntry?.blockIndex ?? 9999)) {
        group.firstEntry = entry;
      }

      groups.set(key, group);
    });

  return Array.from(groups.values())
    .map((group) => {
      const averageLength = group.lineCount > 0 ? Math.round(group.totalChars / group.lineCount) : 0;
      const pendingCount = group.missingBindingCount + group.placeholderCount;
      const readyCoverage = group.lineCount > 0 ? Math.round((group.readyCount / group.lineCount) * 100) : 100;
      const recordingMinutes = Math.max(1, Math.round(group.totalChars / 55));
      return {
        ...group,
        sceneCount: group.sceneIds.size,
        averageLength,
        pendingCount,
        readyCoverage,
        recordingMinutes,
        priorityScore:
          pendingCount * 28 +
          group.placeholderCount * 8 +
          group.missingBindingCount * 12 +
          group.sceneIds.size * 6 +
          group.totalChars / 20,
      };
    })
    .sort((left, right) => {
      if (right.priorityScore !== left.priorityScore) {
        return right.priorityScore - left.priorityScore;
      }
      if (right.pendingCount !== left.pendingCount) {
        return right.pendingCount - left.pendingCount;
      }
      return left.chapterName.localeCompare(right.chapterName, "zh-CN");
    });
}

function buildProjectVoiceOverview(entries) {
  const dialogueEntries = entries.filter((entry) => entry.type === "dialogue");
  const pendingEntries = getVoiceSheetEntries(entries);
  const missingBindingCount = pendingEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "missing_binding"
  ).length;
  const placeholderCount = pendingEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "placeholder"
  ).length;
  const readyCount = dialogueEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "ready"
  ).length;
  const totalChars = dialogueEntries.reduce(
    (sum, entry) => sum + String(entry.text ?? "").trim().length,
    0
  );
  const recordingMinutes = dialogueEntries.length > 0 ? Math.max(1, Math.round(totalChars / 55)) : 0;
  const readyCoverage =
    dialogueEntries.length > 0 ? Math.round((readyCount / dialogueEntries.length) * 100) : 100;
  const topCharacters = buildScriptRecordingGroups(entries)
    .filter((group) => group.pendingCount > 0)
    .slice(0, 3);
  const topChapters = buildScriptChapterRhythms(entries)
    .map((chapter) => ({
      ...chapter,
      pendingCount: chapter.missingBindingCount + chapter.placeholderVoiceCount,
      priorityScore:
        (chapter.missingBindingCount + chapter.placeholderVoiceCount) * 28 +
        chapter.issueCount * 6 +
        chapter.totalEntries,
    }))
    .filter((chapter) => chapter.pendingCount > 0)
    .sort((left, right) => {
      if (right.priorityScore !== left.priorityScore) {
        return right.priorityScore - left.priorityScore;
      }
      if (right.pendingCount !== left.pendingCount) {
        return right.pendingCount - left.pendingCount;
      }
      return left.chapterName.localeCompare(right.chapterName, "zh-CN");
    })
    .slice(0, 3);

  let summary = "项目里暂时还没有角色台词。";
  if (dialogueEntries.length > 0 && pendingEntries.length === 0) {
    summary = "全项目角色台词都已经有真实语音文件了，下一步更适合做最终复查和正式导出。";
  } else if (missingBindingCount > 0) {
    summary = `现在最该先补的是 ${missingBindingCount} 句还没建语音条目的台词，先把占位条目补起来最划算。`;
  } else if (placeholderCount > 0) {
    summary = `现在主要卡在 ${placeholderCount} 句“占位待上传”，更适合直接整理录音文件并批量匹配回占位条目。`;
  } else if (dialogueEntries.length > 0) {
    summary = "语音条目已经基本立住了，下一步更适合做分章节或分角色的录音交付整理。";
  }

  if (topChapters[0]?.chapterName && pendingEntries.length > 0) {
    summary += ` 当前最值得先推的是《${topChapters[0].chapterName}》。`;
  }

  return {
    dialogueCount: dialogueEntries.length,
    pendingCount: pendingEntries.length,
    missingBindingCount,
    placeholderCount,
    readyCount,
    readyCoverage,
    recordingMinutes,
    topCharacters,
    topChapters,
    summary,
  };
}

