function buildScriptChapterRhythmSummary(rhythm) {
  const mainTone =
    rhythm.choiceRatio >= 0.12 || rhythm.choiceCount >= 2
      ? "分支感明显"
      : rhythm.narrationRatio >= 0.36
        ? "铺陈和气氛偏重"
        : rhythm.dialogueRatio >= 0.72
          ? "对话推进很强"
          : "推进和铺陈比较均衡";
  const paceLabel =
    rhythm.averageLength >= 22
      ? "字句偏长"
      : rhythm.averageLength <= 10
        ? "短句推进快"
        : "句长适中";
  const cleanLabel =
    rhythm.issueCount > 0
      ? `还有 ${rhythm.issueCount} 条待处理`
      : rhythm.missingVoiceCount > 0
        ? `还有 ${rhythm.missingVoiceCount} 句待配音`
        : "当前状态比较干净";
  return `${mainTone} / ${paceLabel} / ${cleanLabel}`;
}

function renderScriptVoiceprintSection(filteredEntries) {
  const voiceprints = buildScriptVoiceprints(filteredEntries);

  if (voiceprints.length === 0) {
    return `
      <article class="detail-card voiceprint-panel">
        <strong>角色口吻画像</strong>
        <p>当前筛选里还没有可分析的角色台词。先筛某个章节或角色，再回来这里看口吻差异。</p>
      </article>
    `;
  }

  const spotlightCharacterId = getSafeScriptCharacterFilter(state.scriptCharacterFilter);
  if (spotlightCharacterId !== "all") {
    const spotlight =
      voiceprints.find((voiceprint) => voiceprint.characterId === spotlightCharacterId) ?? voiceprints[0];
    return renderScriptVoiceprintSpotlight(spotlight);
  }

  const topVoiceprints = voiceprints.slice(0, 3);
  return `
    <section class="voiceprint-panel">
      <div class="panel-heading">
        <h2>角色口吻画像</h2>
        <span class="badge badge-soft">先筛角色会更细</span>
      </div>
      <div class="voiceprint-stack">
        ${topVoiceprints.map((voiceprint) => renderScriptVoiceprintCard(voiceprint)).join("")}
      </div>
    </section>
  `;
}

function buildScriptVoiceprints(entries) {
  const groups = new Map();

  entries
    .filter((entry) => entry.type === "dialogue" && entry.characterId)
    .forEach((entry) => {
      const group =
        groups.get(entry.characterId) ??
        {
          characterId: entry.characterId,
          speakerName: entry.speakerName,
          lineCount: 0,
          totalLength: 0,
          missingVoiceCount: 0,
          issueCount: 0,
          questionCount: 0,
          exclaimCount: 0,
          pauseCount: 0,
          longCount: 0,
          expressionCounts: new Map(),
          openingCounts: new Map(),
        };

      const sourceText = String(entry.sourceText ?? "").trim();
      group.lineCount += 1;
      group.totalLength += entry.contentLength ?? sourceText.length;
      group.missingVoiceCount += entry.voiceStatus === "missing" ? 1 : 0;
      group.issueCount += (entry.issues?.length ?? 0) > 0 ? 1 : 0;
      group.questionCount += /[?？]/.test(sourceText) ? 1 : 0;
      group.exclaimCount += /[!！]/.test(sourceText) ? 1 : 0;
      group.pauseCount += /(…|\.{3,}|，|、)/.test(sourceText) ? 1 : 0;
      group.longCount += (entry.contentLength ?? sourceText.length) >= 24 ? 1 : 0;

      const expressionName = String(entry.expressionName ?? "").trim();
      if (expressionName) {
        group.expressionCounts.set(expressionName, (group.expressionCounts.get(expressionName) ?? 0) + 1);
      }

      const openingText = extractScriptOpening(sourceText);
      if (openingText) {
        group.openingCounts.set(openingText, (group.openingCounts.get(openingText) ?? 0) + 1);
      }

      groups.set(entry.characterId, group);
    });

  return Array.from(groups.values())
    .map((group) => {
      const lineCount = group.lineCount || 1;
      const averageLength = Math.round(group.totalLength / lineCount);
      const questionRatio = group.questionCount / lineCount;
      const exclaimRatio = group.exclaimCount / lineCount;
      const pauseRatio = group.pauseCount / lineCount;
      const longRatio = group.longCount / lineCount;
      const voiceCoverage = Math.round(((group.lineCount - group.missingVoiceCount) / lineCount) * 100);
      const topExpressions = getTopNamedCounts(group.expressionCounts);
      const topOpenings = getTopNamedCounts(group.openingCounts, { minCount: 2 });
      const summary = buildScriptVoiceprintSummary({
        averageLength,
        questionRatio,
        exclaimRatio,
        pauseRatio,
        longRatio,
        topOpenings,
      });

      return {
        characterId: group.characterId,
        speakerName: group.speakerName,
        lineCount: group.lineCount,
        averageLength,
        missingVoiceCount: group.missingVoiceCount,
        voiceCoverage,
        issueCount: group.issueCount,
        questionRatio,
        exclaimRatio,
        pauseRatio,
        longRatio,
        topExpressions,
        topOpenings,
        summary,
      };
    })
    .sort((left, right) => {
      if (right.lineCount !== left.lineCount) {
        return right.lineCount - left.lineCount;
      }
      if (right.issueCount !== left.issueCount) {
        return right.issueCount - left.issueCount;
      }
      return left.speakerName.localeCompare(right.speakerName, "zh-CN");
    });
}

