function buildScriptTxtContent(filteredEntries, totalEntryCount) {
  const lines = [];
  const scopeText = getScriptFilterSummaryText();
  const groupedByChapter = new Map();

  filteredEntries.forEach((entry) => {
    const chapterBucket = groupedByChapter.get(entry.chapterName) ?? new Map();
    const sceneBucket = chapterBucket.get(entry.sceneName) ?? [];
    sceneBucket.push(entry);
    chapterBucket.set(entry.sceneName, sceneBucket);
    groupedByChapter.set(entry.chapterName, chapterBucket);
  });

  lines.push(`${state.data.project.title} · Tony Na Engine 台本导出`);
  lines.push(`导出时间：${formatDate(new Date().toISOString())}`);
  lines.push(`当前筛选：${scopeText}`);
  lines.push(`导出条数：${filteredEntries.length} / 全项目 ${totalEntryCount}`);
  lines.push("");

  groupedByChapter.forEach((sceneMap, chapterName) => {
    lines.push(`【章节】${chapterName}`);
    sceneMap.forEach((entries, sceneName) => {
      lines.push(`  [场景] ${sceneName}`);
      entries.forEach((entry) => {
        const issueText =
          (entry.issues ?? []).length > 0
            ? ` [问题：${(entry.issues ?? []).map((issue) => getScriptIssueFilterLabel(issue)).join(" / ")}]`
            : "";
        const previousText = entry.previousContext
          ? ` [上一句：${entry.previousContext.label}：${entry.previousContext.text}]`
          : "";
        const nextText = entry.nextContext
          ? ` [下一句：${entry.nextContext.label}：${entry.nextContext.text}]`
          : "";
        if (entry.type === "dialogue") {
          lines.push(
            `  - ${entry.speakerName}：${entry.text} ${
              entry.voiceStatus === "missing"
                ? "（待绑语音）"
                : entry.voiceStatus === "voiced"
                  ? `（语音：${entry.voiceName || "已绑定"}）`
                  : ""
            }${issueText}${previousText}${nextText}`
          );
        } else if (entry.type === "narration") {
          lines.push(`  - [旁白] ${entry.text}${issueText}${previousText}${nextText}`);
        } else {
          lines.push(`  - [选项] ${entry.text}${issueText}${previousText}${nextText}`);
        }
      });
      lines.push("");
    });
  });

  return `\uFEFF${lines.join("\n")}`;
}

function buildScriptCsvContent(filteredEntries, totalEntryCount) {
  const scopeText = getScriptFilterSummaryText();
  const rows = [
    ["项目名", state.data.project.title],
    ["导出时间", formatDate(new Date().toISOString())],
    ["当前筛选", scopeText],
    ["导出条数", `${filteredEntries.length} / 全项目 ${totalEntryCount}`],
    [],
    ["章节", "场景", "卡片序号", "内容类型", "角色", "表情", "上一句", "正文", "下一句", "语音状态", "语音名", "问题标签"],
    ...filteredEntries.map((entry) => [
      entry.chapterName,
      entry.sceneName,
      entry.blockIndex + 1,
      getScriptTypeLabel(entry.type),
      entry.speakerName,
      entry.expressionName,
      entry.previousContext ? `${entry.previousContext.label}：${entry.previousContext.text}` : "",
      entry.text,
      entry.nextContext ? `${entry.nextContext.label}：${entry.nextContext.text}` : "",
      getScriptVoiceStatusText(entry.voiceStatus),
      entry.voiceName,
      (entry.issues ?? []).map((issue) => getScriptIssueFilterLabel(issue)).join(" / "),
    ]),
  ];

  return `\uFEFF${rows.map((row) => row.map(formatCsvCell).join(",")).join("\n")}`;
}

function getVoiceSheetEntries(sourceEntries, filters = {}) {
  const safeCharacterId = filters.characterId ? getSafeScriptCharacterFilter(filters.characterId) : "all";
  const safeChapterId = filters.chapterId ? getSafeScriptChapterFilter(filters.chapterId) : "all";

  return sourceEntries.filter((entry) => {
    if (entry.type !== "dialogue") {
      return false;
    }
    if (safeCharacterId !== "all" && entry.characterId !== safeCharacterId) {
      return false;
    }
    if (safeChapterId !== "all" && entry.chapterId !== safeChapterId) {
      return false;
    }
    return getScriptVoiceWorkflowState(entry) !== "ready";
  });
}

function buildScriptVoiceSheetContent(filteredEntries, totalEntryCount, filters = {}) {
  const scopeText =
    filters.characterId || filters.chapterId
      ? [
          filters.characterId ? `角色=${getScriptCharacterFilterLabel(filters.characterId)}` : "",
          filters.chapterId ? `章节=${getScriptChapterFilterLabel(filters.chapterId)}` : "",
        ]
          .filter(Boolean)
          .join(" / ")
      : getScriptFilterSummaryText();

  const rows = [
    ["项目名", state.data.project.title],
    ["导出时间", formatDate(new Date().toISOString())],
    ["当前范围", scopeText || "全项目待录语音"],
    ["导出条数", `${filteredEntries.length} / 全项目待录 ${totalEntryCount}`],
    [],
    [
      "角色",
      "章节",
      "场景",
      "卡片序号",
      "当前状态",
      "当前语音条目",
      "当前语音路径",
      "目标语音条目名",
      "目标录音文件名",
      "表情",
      "正文",
      "上一句",
      "下一句",
    ],
    ...filteredEntries.map((entry) => [
      entry.speakerName,
      entry.chapterName,
      entry.sceneName,
      entry.blockIndex + 1,
      getScriptVoiceWorkflowLabel(entry),
      entry.voiceName,
      entry.voiceAssetPath,
      buildSuggestedVoiceBaseName(entry),
      buildSuggestedVoiceFileName(entry),
      entry.expressionName,
      entry.text,
      entry.previousContext ? `${entry.previousContext.label}：${entry.previousContext.text}` : "",
      entry.nextContext ? `${entry.nextContext.label}：${entry.nextContext.text}` : "",
    ]),
  ];

  return `\uFEFF${rows.map((row) => row.map(formatCsvCell).join(",")).join("\n")}`;
}

function getScriptFilterSummaryText() {
  const pieces = [];
  const queryText = state.scriptSearchQuery.trim();

  if (queryText) {
    pieces.push(`关键词=${queryText}`);
  }

  if (state.scriptChapterFilter !== "all") {
    pieces.push(`章节=${getScriptChapterFilterLabel(state.scriptChapterFilter)}`);
  }

  if (state.scriptCharacterFilter !== "all") {
    pieces.push(`角色=${getScriptCharacterFilterLabel(state.scriptCharacterFilter)}`);
  }

  if (state.scriptTypeFilter !== "all") {
    pieces.push(`类型=${getScriptTypeLabel(state.scriptTypeFilter)}`);
  }

  if (state.scriptVoiceFilter !== "all") {
    pieces.push(`语音=${getScriptVoiceFilterLabel(state.scriptVoiceFilter)}`);
  }

  if (state.scriptIssueFilter !== "all") {
    pieces.push(`体检=${getScriptIssueFilterLabel(state.scriptIssueFilter)}`);
  }

  return pieces.length > 0 ? pieces.join(" / ") : "全项目全部内容";
}

function getScriptVoiceStatusText(status) {
  if (status === "missing") {
    return "待绑语音";
  }

  if (status === "voiced") {
    return "已绑语音";
  }

  return "不需要语音";
}

function getSafeScriptIssueFilter(value) {
  return Object.prototype.hasOwnProperty.call(SCRIPT_ISSUE_FILTER_LABELS, value) ? value : "all";
}

function getScriptIssueFilterLabel(value) {
  return SCRIPT_ISSUE_FILTER_LABELS[getSafeScriptIssueFilter(value)] ?? SCRIPT_ISSUE_FILTER_LABELS.all;
}

function buildScriptExportFileName(format) {
  const extension = format === "csv" ? "csv" : "txt";
  const date = new Date();
  const dateStamp = [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("");
  const title = sanitizeFileName(state.data.project.title || "tony-na-engine");
  const scope = sanitizeFileName(getScriptFilterSummaryText()).slice(0, 28) || "full-script";
  return `${title}_script_${scope}_${dateStamp}.${extension}`;
}

function buildScriptVoiceSheetFileName(filters = {}) {
  const date = new Date();
  const dateStamp = [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("");
  const title = sanitizeFileName(state.data.project.title || "tony-na-engine");
  const scopeText =
    filters.characterId || filters.chapterId
      ? [
          filters.characterId ? getScriptCharacterFilterLabel(filters.characterId) : "",
          filters.chapterId ? getScriptChapterFilterLabel(filters.chapterId) : "",
        ]
          .filter(Boolean)
          .join("_")
      : getScriptFilterSummaryText();
  const scope = sanitizeFileName(scopeText).slice(0, 28) || "voice_sheet";
  return `${title}_voice_sheet_${scope}_${dateStamp}.csv`;
}

function buildCharacterVoiceBriefFileName(character) {
  const date = new Date();
  const dateStamp = [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("");
  const title = sanitizeFileName(state.data.project.title || "tony-na-engine");
  const characterName = sanitizeFileName(character?.displayName || character?.id || "character");
  return `${title}_voice_delivery_${characterName}_${dateStamp}.txt`;
}

function buildChapterVoiceBriefFileName(chapter) {
  const date = new Date();
  const dateStamp = [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("");
  const title = sanitizeFileName(state.data.project.title || "tony-na-engine");
  const chapterName = sanitizeFileName(chapter?.name || chapter?.chapterId || "chapter");
  return `${title}_voice_delivery_${chapterName}_${dateStamp}.txt`;
}

function buildProjectVoiceBriefFileName() {
  const date = new Date();
  const dateStamp = [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("");
  const title = sanitizeFileName(state.data.project.title || "tony-na-engine");
  return `${title}_voice_delivery_project_${dateStamp}.txt`;
}

function buildCharacterVoiceBriefContent(character, stats) {
  const pendingLines = stats.lines.filter((line) => !line.voiceFileExists);
  const lines = [
    `${state.data.project.title} · ${character.displayName} 配音交付说明`,
    `导出时间：${formatDate(new Date().toISOString())}`,
    `角色：${character.displayName}`,
    `待录总数：${pendingLines.length} 句`,
    `已就绪：${stats.readyVoiceCount} 句`,
    `已建占位待上传：${stats.placeholderVoiceCount} 句`,
    `还没建语音条目：${stats.missingVoiceCount} 句`,
    `真实文件覆盖率：${stats.readyVoiceCoverage}%`,
    `预计录音时长：约 ${stats.estimatedRecordingMinutes} 分钟`,
    "",
    "交付方式：",
    "1. 先按下面的“目标录音文件名”录制并命名。",
    "2. 如果这句已经有语音占位条目，优先往对应条目上传真实文件。",
    "3. 录完后回 Tony Na Engine 的语音素材页批量匹配，就能自动回绑大部分语音。",
    "",
    "待录台词清单：",
  ];

  pendingLines.forEach((line) => {
    lines.push(
      `- ${line.chapterName} / ${line.sceneName} / 第 ${line.blockIndex + 1} 张`,
      `  状态：${line.voiceAssetId ? "已建占位，待上传真实文件" : "还没建语音条目"}`,
      `  目标语音条目名：${buildSuggestedVoiceBaseName(line)}`,
      `  目标录音文件名：${buildSuggestedVoiceFileName(line)}`,
      `  表情：${line.expressionName || "暂不明显"}`,
      `  台词：${line.text || "这句台词还没填正文。"}`,
      ""
    );
  });

  if (pendingLines.length === 0) {
    lines.push("这个角色目前所有台词都已经有真实语音文件了。");
  }

  return `\uFEFF${lines.join("\n")}`;
}

function buildProjectVoiceBriefContent(allEntries) {
  const overview = buildProjectVoiceOverview(allEntries);
  const lines = [
    `${state.data.project.title} · 整项目配音交付说明`,
    `导出时间：${formatDate(new Date().toISOString())}`,
    `项目对话总数：${overview.dialogueCount} 句`,
    `待录总数：${overview.pendingCount} 句`,
    `缺语音条目：${overview.missingBindingCount} 句`,
    `已建占位待上传：${overview.placeholderCount} 句`,
    `真实文件已就绪：${overview.readyCount} 句`,
    `真实语音覆盖率：${overview.readyCoverage}%`,
    `预计录音时长：约 ${overview.recordingMinutes} 分钟`,
    "",
    "当前优先推进项：",
    overview.summary,
    "",
    "交付方式：",
    "1. 先看下面的“优先章节”和“优先角色批次”，从最卡进度的部分开始补。",
    "2. 章节或角色范围需要更细台词清单时，回 Tony Na Engine 继续导出对应章节 / 角色的命名清单和交付说明。",
    "3. 录完后优先用语音素材页的“批量匹配语音文件”回绑真实文件。",
    "",
  ];

  if (overview.topChapters.length > 0) {
    lines.push("优先章节：");
    overview.topChapters.forEach((chapter) => {
      lines.push(
        `- ${chapter.chapterName}：待录 ${chapter.pendingCount} 句（缺条目 ${chapter.missingBindingCount} / 占位待上传 ${chapter.placeholderVoiceCount} / 已就绪 ${chapter.readyVoiceCount} / 真实覆盖 ${chapter.readyVoiceCoverage}% / 约 ${chapter.recordingMinutes} 分钟）`
      );
    });
    lines.push("");
  }

  if (overview.topCharacters.length > 0) {
    lines.push("优先角色批次：");
    overview.topCharacters.forEach((group) => {
      lines.push(
        `- ${group.speakerName} / ${group.chapterName}：待录 ${group.pendingCount} 句（缺条目 ${group.missingBindingCount} / 占位待上传 ${group.placeholderCount} / 已就绪 ${group.readyCount} / 涉及 ${group.sceneCount} 场 / 约 ${group.recordingMinutes} 分钟）`
      );
    });
    lines.push("");
  }

  const pendingEntries = getVoiceSheetEntries(allEntries);
  if (pendingEntries.length > 0) {
    lines.push("最前面的待录台词样例：");
    pendingEntries.slice(0, 12).forEach((entry) => {
      lines.push(
        `- ${entry.chapterName} / ${entry.sceneName} / ${entry.speakerName} / 第 ${entry.blockIndex + 1} 张`,
        `  状态：${getScriptVoiceWorkflowLabel(entry)}`,
        `  目标语音条目名：${buildSuggestedVoiceBaseName(entry)}`,
        `  目标录音文件名：${buildSuggestedVoiceFileName(entry)}`,
        `  台词：${entry.text || "这句台词还没填正文。"}`,
        ""
      );
    });
  } else {
    lines.push("目前全项目已经没有待录台词了。");
  }

  return `\uFEFF${lines.join("\n")}`;
}

function buildChapterVoiceBriefContent(chapter, dialogueEntries, pendingEntries) {
  const missingBindingCount = pendingEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "missing_binding"
  ).length;
  const placeholderCount = pendingEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "placeholder"
  ).length;
  const readyCount = dialogueEntries.filter(
    (entry) => getScriptVoiceWorkflowState(entry) === "ready"
  ).length;
  const readyCoverage =
    dialogueEntries.length > 0 ? Math.round((readyCount / dialogueEntries.length) * 100) : 100;
  const totalChars = dialogueEntries.reduce(
    (sum, entry) => sum + String(entry.text ?? "").trim().length,
    0
  );
  const recordingMinutes = Math.max(1, Math.round(totalChars / 55));
  const groupedByScene = new Map();

  pendingEntries.forEach((entry) => {
    const bucket = groupedByScene.get(entry.sceneName) ?? [];
    bucket.push(entry);
    groupedByScene.set(entry.sceneName, bucket);
  });

  const lines = [
    `${state.data.project.title} · ${chapter.name} 配音交付说明`,
    `导出时间：${formatDate(new Date().toISOString())}`,
    `章节：${chapter.name}`,
    `本章对话数：${dialogueEntries.length} 句`,
    `待录总数：${pendingEntries.length} 句`,
    `缺语音条目：${missingBindingCount} 句`,
    `已建占位待上传：${placeholderCount} 句`,
    `真实文件已就绪：${readyCount} 句`,
    `真实文件覆盖率：${readyCoverage}%`,
    `预计录音时长：约 ${recordingMinutes} 分钟`,
    "",
    "交付方式：",
    "1. 先按下面每句给出的“目标录音文件名”录制和命名。",
    "2. 已有语音占位的句子，录完后优先直接匹配回对应条目。",
    "3. 如果这章还缺语音条目，可以先在台本页一键生成占位，再批量匹配真实文件。",
    "",
  ];

  if (pendingEntries.length === 0) {
    lines.push("这章目前所有台词都已经有真实语音文件了。");
    return `\uFEFF${lines.join("\n")}`;
  }

  lines.push("按场景拆分的待录台词：");
  groupedByScene.forEach((sceneEntries, sceneName) => {
    lines.push(`【场景】${sceneName}`);
    sceneEntries.forEach((entry) => {
      lines.push(
        `- ${entry.speakerName} / 第 ${entry.blockIndex + 1} 张`,
        `  状态：${getScriptVoiceWorkflowLabel(entry)}`,
        `  目标语音条目名：${buildSuggestedVoiceBaseName(entry)}`,
        `  目标录音文件名：${buildSuggestedVoiceFileName(entry)}`,
        `  表情：${entry.expressionName || "暂不明显"}`,
        `  台词：${entry.text || "这句台词还没填正文。"}`,
        ""
      );
    });
  });

  return `\uFEFF${lines.join("\n")}`;
}

function sanitizeFileName(value) {
  return String(value ?? "")
    .trim()
    .replace(/[\\/:*?"<>|]/g, "_")
    .replace(/\s+/g, "_")
    .replace(/_+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function formatCsvCell(value) {
  const text = String(value ?? "");
  return `"${text.replaceAll('"', '""')}"`;
}

function downloadTextFile(fileName, content, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = fileName;
  document.body.append(anchor);
  anchor.click();
  anchor.remove();
  setTimeout(() => {
    URL.revokeObjectURL(url);
  }, 0);
}

function getScriptResultMeta(filteredEntries, totalEntries) {
  return `${filteredEntries.length} 条结果 · 项目正文总计 ${totalEntries} 条`;
}

function getTopScriptSpeaker(entries) {
  const counts = new Map();
  entries
    .filter((entry) => entry.type === "dialogue" && entry.speakerName)
    .forEach((entry) => {
      counts.set(entry.speakerName, (counts.get(entry.speakerName) ?? 0) + 1);
    });

  const topEntry = Array.from(counts.entries()).sort((left, right) => right[1] - left[1])[0];
  return topEntry ? `${topEntry[0]} × ${topEntry[1]}` : "当前筛选里没有角色台词";
}

function normalizeScriptSearchQuery(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function getScriptSearchTerms(value) {
  const query = normalizeScriptSearchQuery(value);
  return query ? query.split(" ").filter(Boolean) : [];
}

function resetScriptFilters() {
  state.scriptSearchQuery = "";
  state.scriptChapterFilter = "all";
  state.scriptCharacterFilter = "all";
  state.scriptTypeFilter = "all";
  state.scriptVoiceFilter = "all";
  state.scriptIssueFilter = "all";
}

function getSafeScriptChapterFilter(chapterId) {
  if (chapterId === "all") {
    return "all";
  }

  return state.data.chaptersById.has(chapterId) ? chapterId : "all";
}

function getSafeScriptCharacterFilter(characterId) {
  if (characterId === "all") {
    return "all";
  }

  return state.data.charactersById.has(characterId) ? characterId : "all";
}

function getSafeScriptTypeFilter(type) {
  return Object.prototype.hasOwnProperty.call(SCRIPT_TYPE_LABELS, type) ? type : "all";
}

function getSafeScriptVoiceFilter(value) {
  return Object.prototype.hasOwnProperty.call(SCRIPT_VOICE_FILTER_LABELS, value) ? value : "all";
}

function getScriptTypeLabel(type) {
  return type === "all" ? "全部内容" : SCRIPT_TYPE_LABELS[getSafeScriptTypeFilter(type)] ?? "全部内容";
}

function getScriptVoiceFilterLabel(value) {
  return SCRIPT_VOICE_FILTER_LABELS[getSafeScriptVoiceFilter(value)] ?? SCRIPT_VOICE_FILTER_LABELS.all;
}

function getScriptChapterFilterLabel(chapterId) {
  return chapterId === "all"
    ? "全部章节"
    : state.data.chaptersById.get(chapterId)?.name ?? "全部章节";
}

function getScriptCharacterFilterLabel(characterId) {
  return characterId === "all"
    ? "全部角色"
    : state.data.charactersById.get(characterId)?.displayName ?? "全部角色";
}

function buildCharacterDialogueStats(characterId) {
  const character = state.data.charactersById.get(characterId);
  const lines = [];
  const sceneIds = new Set();
  const expressionCounts = new Map();
  let showCount = 0;
  let hideCount = 0;

  state.data.chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      (scene.blocks ?? []).forEach((block, blockIndex) => {
        if (block.type === "dialogue" && block.speakerId === characterId) {
          sceneIds.add(scene.id);
          const expressionName = getExpressionName(characterId, block.expressionId);
          const voiceAsset = block.voiceAssetId ? state.data.assetsById.get(block.voiceAssetId) : null;
          expressionCounts.set(expressionName, (expressionCounts.get(expressionName) ?? 0) + 1);
          lines.push({
            sceneId: scene.id,
            sceneName: scene.name,
            chapterId: chapter.chapterId,
            chapterName: chapter.name,
            blockId: block.id,
            blockIndex,
            text: block.text ?? "",
            voiceAssetId: block.voiceAssetId ?? "",
            voiceName: voiceAsset?.name ?? (block.voiceAssetId || ""),
            voiceAssetPath: voiceAsset?.path ?? "",
            voiceFileExists: Boolean(voiceAsset?.fileExists),
            expressionName,
          });
        }

        if (block.type === "character_show" && block.characterId === characterId) {
          showCount += 1;
        }

        if (block.type === "character_hide" && block.characterId === characterId) {
          hideCount += 1;
        }
      });
    });
  });

  const voicedLines = lines.filter((line) => line.voiceAssetId);
  const missingVoiceLines = lines.filter((line) => !line.voiceAssetId);
  const placeholderVoiceLines = lines.filter((line) => line.voiceAssetId && !line.voiceFileExists);
  const readyVoiceLines = lines.filter((line) => line.voiceAssetId && line.voiceFileExists);
  const totalChars = lines.reduce((sum, line) => sum + String(line.text ?? "").trim().length, 0);
  const voiceCoverage =
    lines.length > 0 ? Math.round((voicedLines.length / lines.length) * 100) : 0;
  const readyVoiceCoverage =
    lines.length > 0 ? Math.round((readyVoiceLines.length / lines.length) * 100) : 0;
  const topExpressions = Array.from(expressionCounts.entries())
    .sort((left, right) => right[1] - left[1])
    .slice(0, 3);

  return {
    character,
    lines,
    voicedLines,
    missingVoiceLines,
    placeholderVoiceLines,
    readyVoiceLines,
    totalLines: lines.length,
    voicedLineCount: voicedLines.length,
    missingVoiceCount: missingVoiceLines.length,
    placeholderVoiceCount: placeholderVoiceLines.length,
    readyVoiceCount: readyVoiceLines.length,
    scenesCount: sceneIds.size,
    totalChars,
    averageLineLength: lines.length > 0 ? Math.round(totalChars / lines.length) : 0,
    voiceCoverage,
    readyVoiceCoverage,
    estimatedRecordingMinutes: Math.max(1, Math.round(totalChars / 55)),
    showCount,
    hideCount,
    topExpressions,
  };
}

function buildCharacterScenePresenceOverview(characterId, stats) {
  const routeOverview = buildSceneRouteOverview();
  const routeSceneMap = new Map((routeOverview.nodes ?? []).map((scene) => [scene.id, scene]));
  const groupedScenes = new Map();

  stats.lines.forEach((line) => {
    const routeScene = routeSceneMap.get(line.sceneId);
    const sourceScene = state.data.scenesById.get(line.sceneId);

    if (!groupedScenes.has(line.sceneId)) {
      groupedScenes.set(line.sceneId, {
        id: line.sceneId,
        name: line.sceneName,
        chapterName: line.chapterName,
        chapterIndex: routeScene?.chapterIndex ?? 999,
        sceneIndex: routeScene?.sceneIndex ?? line.blockIndex,
        status: routeScene?.status ?? getSafeSceneStatus(sourceScene?.status),
        priority: routeScene?.priority ?? getSafeScenePriority(sourceScene?.priority),
        notes: routeScene?.notes ?? String(sourceScene?.notes ?? "").trim(),
        completionScore: routeScene?.completionScore ?? 0,
        missingVoiceCount: routeScene?.missingVoiceCount ?? 0,
        hasEffects: routeScene?.hasEffects ?? false,
        hasBackground: routeScene?.hasBackground ?? false,
        hasMusic: routeScene?.hasMusic ?? false,
        hasStoryContent: routeScene?.hasStoryContent ?? Boolean((sourceScene?.blocks ?? []).length),
        brokenRouteCount: routeScene?.brokenRouteCount ?? 0,
        errorCount: routeScene?.errorCount ?? 0,
        warningCount: routeScene?.warningCount ?? 0,
        lineCount: 0,
        voicedLineCount: 0,
        characterMissingVoiceCount: 0,
        totalChars: 0,
        firstBlockId: line.blockId,
        firstBlockIndex: line.blockIndex,
        sampleText: "",
        expressionCounts: new Map(),
      });
    }

    const sceneEntry = groupedScenes.get(line.sceneId);
    sceneEntry.lineCount += 1;
    sceneEntry.totalChars += String(line.text ?? "").trim().length;
    if (line.voiceAssetId) {
      sceneEntry.voicedLineCount += 1;
    } else {
      sceneEntry.characterMissingVoiceCount += 1;
    }

    if (!sceneEntry.sampleText && String(line.text ?? "").trim()) {
      sceneEntry.sampleText = String(line.text ?? "").trim();
    }

    sceneEntry.expressionCounts.set(
      line.expressionName,
      (sceneEntry.expressionCounts.get(line.expressionName) ?? 0) + 1
    );

    if (line.blockIndex < sceneEntry.firstBlockIndex) {
      sceneEntry.firstBlockIndex = line.blockIndex;
      sceneEntry.firstBlockId = line.blockId;
    }
  });

  const scenes = Array.from(groupedScenes.values())
    .map((scene) => {
      const topExpression = Array.from(scene.expressionCounts.entries()).sort((left, right) => right[1] - left[1])[0]?.[0] ?? "暂不明显";
      const safeStatus = getSafeSceneStatus(scene.status);
      const safePriority = getSafeScenePriority(scene.priority);
      const readyForPreview = safeStatus === "ready" || (scene.completionScore ?? 0) >= 80;
      const urgencyScore =
        scene.characterMissingVoiceCount * 40 +
        (safePriority === "rush" ? 24 : safePriority === "focus" ? 16 : 0) +
        (!readyForPreview ? 12 : 0) +
        (!scene.hasEffects && scene.lineCount > 0 ? 10 : 0) +
        (scene.errorCount > 0 || scene.brokenRouteCount > 0 ? 12 : 0) +
        Math.max(0, 100 - (scene.completionScore ?? 0)) / 10 +
        scene.lineCount;

      return {
        ...scene,
        averageLineLength: scene.lineCount > 0 ? Math.round(scene.totalChars / scene.lineCount) : 0,
        topExpression,
        readyForPreview,
        urgencyScore,
        planningSummary: buildDashboardScenePlanningSummary(scene),
        nextStep: buildDashboardScenePlanningNextStep(scene),
      };
    })
    .sort((left, right) => {
      if (left.chapterIndex !== right.chapterIndex) {
        return left.chapterIndex - right.chapterIndex;
      }
      return left.sceneIndex - right.sceneIndex;
    });

  const priorityScenes = [...scenes]
    .sort((left, right) => {
      if (right.urgencyScore !== left.urgencyScore) {
        return right.urgencyScore - left.urgencyScore;
      }
      if (right.characterMissingVoiceCount !== left.characterMissingVoiceCount) {
        return right.characterMissingVoiceCount - left.characterMissingVoiceCount;
      }
      return left.chapterIndex - right.chapterIndex || left.sceneIndex - right.sceneIndex;
    })
    .slice(0, 4);

  return {
    scenes,
    priorityScenes,
    readySceneCount: scenes.filter((scene) => scene.readyForPreview).length,
    missingVoiceSceneCount: scenes.filter((scene) => scene.characterMissingVoiceCount > 0).length,
    flatSceneCount: scenes.filter((scene) => scene.lineCount > 0 && !scene.hasEffects).length,
    focusSceneCount: scenes.filter((scene) => ["rush", "focus"].includes(getSafeScenePriority(scene.priority))).length,
  };
}

function buildCharacterRelationshipOverview(characterId) {
  const routeOverview = buildSceneRouteOverview();
  const routeSceneMap = new Map((routeOverview.nodes ?? []).map((scene) => [scene.id, scene]));
  const relations = new Map();

  state.data.chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      const dialogueBlocks = (scene.blocks ?? [])
        .map((block, blockIndex) => ({
          ...block,
          blockIndex,
        }))
        .filter((block) => block.type === "dialogue" && block.speakerId);

      const selfBlocks = dialogueBlocks.filter((block) => block.speakerId === characterId);

      if (selfBlocks.length === 0) {
        return;
      }

      const routeScene = routeSceneMap.get(scene.id);
      const safeStatus = routeScene?.status ?? getSafeSceneStatus(scene.status);
      const safePriority = routeScene?.priority ?? getSafeScenePriority(scene.priority);
      const readyForPreview = safeStatus === "ready" || (routeScene?.completionScore ?? 0) >= 80;
      const sceneCompletionScore = routeScene?.completionScore ?? 0;
      const sceneHasEffects = routeScene?.hasEffects ?? false;
      const partnerIds = Array.from(
        new Set(dialogueBlocks.map((block) => block.speakerId).filter((speakerId) => speakerId && speakerId !== characterId))
      );

      if (partnerIds.length === 0) {
        return;
      }

      const sceneExchanges = new Map();
      for (let index = 0; index < dialogueBlocks.length - 1; index += 1) {
        const left = dialogueBlocks[index];
        const right = dialogueBlocks[index + 1];

        if (!left?.speakerId || !right?.speakerId || left.speakerId === right.speakerId) {
          continue;
        }

        if (left.speakerId !== characterId && right.speakerId !== characterId) {
          continue;
        }

        const partnerId = left.speakerId === characterId ? right.speakerId : left.speakerId;
        const exchangeEntry = sceneExchanges.get(partnerId) ?? { count: 0, sample: "" };
        exchangeEntry.count += 1;
        if (!exchangeEntry.sample) {
          const leftName = state.data.charactersById.get(left.speakerId)?.displayName ?? left.speakerId;
          const rightName = state.data.charactersById.get(right.speakerId)?.displayName ?? right.speakerId;
          exchangeEntry.sample = `${leftName}：${truncateText(left.text || "……", 18)} / ${rightName}：${truncateText(
            right.text || "……",
            18
          )}`;
        }
        sceneExchanges.set(partnerId, exchangeEntry);
      }

      partnerIds.forEach((partnerId) => {
        const partnerCharacter = state.data.charactersById.get(partnerId);
        if (!partnerCharacter) {
          return;
        }

        const partnerBlocks = dialogueBlocks.filter((block) => block.speakerId === partnerId);
        const exchange = sceneExchanges.get(partnerId) ?? { count: 0, sample: "" };
        const sampleText =
          exchange.sample ||
          `${state.data.charactersById.get(characterId)?.displayName ?? characterId}：${truncateText(
            selfBlocks[0]?.text || partnerBlocks[0]?.text || "……",
            30
          )}`;
        const duoMissingVoiceCount =
          selfBlocks.filter((block) => !block.voiceAssetId).length +
          partnerBlocks.filter((block) => !block.voiceAssetId).length;
        const sceneScore =
          exchange.count * 26 +
          (selfBlocks.length + partnerBlocks.length) * 6 +
          (safePriority === "rush" ? 18 : safePriority === "focus" ? 12 : 0) +
          duoMissingVoiceCount * 8 +
          (!sceneHasEffects ? 6 : 0);

        if (!relations.has(partnerId)) {
          relations.set(partnerId, {
            characterId: partnerId,
            displayName: partnerCharacter.displayName,
            sharedSceneCount: 0,
            sharedLineCount: 0,
            selfLineCount: 0,
            partnerLineCount: 0,
            exchangeCount: 0,
            readySceneCount: 0,
            focusSceneCount: 0,
            duoMissingVoiceCount: 0,
            flatSharedSceneCount: 0,
            bestSceneScore: -1,
            bestScene: null,
          });
        }

        const relation = relations.get(partnerId);
        relation.sharedSceneCount += 1;
        relation.sharedLineCount += selfBlocks.length + partnerBlocks.length;
        relation.selfLineCount += selfBlocks.length;
        relation.partnerLineCount += partnerBlocks.length;
        relation.exchangeCount += exchange.count;
        relation.duoMissingVoiceCount += duoMissingVoiceCount;
        if (readyForPreview) {
          relation.readySceneCount += 1;
        }
        if (["rush", "focus"].includes(getSafeScenePriority(safePriority))) {
          relation.focusSceneCount += 1;
        }
        if (!sceneHasEffects) {
          relation.flatSharedSceneCount += 1;
        }

        if (sceneScore > relation.bestSceneScore) {
          relation.bestSceneScore = sceneScore;
          relation.bestScene = {
            id: scene.id,
            name: scene.name,
            chapterName: chapter.name,
            status: safeStatus,
            priority: safePriority,
            completionScore: sceneCompletionScore,
            readyForPreview,
            exchangeCount: exchange.count,
            selfLineCount: selfBlocks.length,
            partnerLineCount: partnerBlocks.length,
            duoMissingVoiceCount,
            sampleText,
            planningSummary: buildDashboardScenePlanningSummary({
              status: safeStatus,
              priority: safePriority,
              notes: scene.notes ?? "",
            }),
            nextStep: buildDashboardScenePlanningNextStep({
              status: safeStatus,
              priority: safePriority,
              completionScore: sceneCompletionScore,
              missingVoiceCount: duoMissingVoiceCount,
              hasEffects: sceneHasEffects,
              hasBackground: routeScene?.hasBackground ?? true,
              hasMusic: routeScene?.hasMusic ?? true,
              hasStoryContent: Boolean(dialogueBlocks.length),
              brokenRouteCount: routeScene?.brokenRouteCount ?? 0,
              errorCount: routeScene?.errorCount ?? 0,
              warningCount: routeScene?.warningCount ?? 0,
            }),
          };
        }
      });
    });
  });

  const partners = Array.from(relations.values())
    .map((relation) => {
      const chemistryScore =
        relation.exchangeCount * 24 +
        relation.sharedSceneCount * 12 +
        relation.focusSceneCount * 12 +
        relation.duoMissingVoiceCount * 5 +
        relation.sharedLineCount;
      let suggestion = "这组对手戏已经有基础，可以继续细化表情、语气和节奏。";

      if (relation.duoMissingVoiceCount > 0) {
        suggestion = `这组对手戏还有 ${relation.duoMissingVoiceCount} 句没绑语音，先补语音最划算。`;
      } else if (relation.exchangeCount === 0) {
        suggestion = "这两人已经常同场，但真正来回接话还不多，可以考虑补一段更直接的互动。";
      } else if (relation.flatSharedSceneCount > 0) {
        suggestion = "这组关系已经有来回接话了，下一步最适合补镜头、震动或滤镜，把火花做出来。";
      } else if (relation.focusSceneCount > 0) {
        suggestion = "这组对手戏已经落在重点场景里，适合优先把那几场推到可试玩。";
      }

      return {
        ...relation,
        chemistryScore,
        suggestion,
      };
    })
    .sort((left, right) => {
      if (right.chemistryScore !== left.chemistryScore) {
        return right.chemistryScore - left.chemistryScore;
      }
      if (right.sharedSceneCount !== left.sharedSceneCount) {
        return right.sharedSceneCount - left.sharedSceneCount;
      }
      return right.exchangeCount - left.exchangeCount;
    });

  return {
    partners,
    topPartners: partners.slice(0, 4),
    totalPartnersCount: partners.length,
    highChemistryCount: partners.filter((partner) => partner.exchangeCount >= 2).length,
    readyPartnerCount: partners.filter((partner) => partner.readySceneCount > 0).length,
    pendingDuoCount: partners.filter((partner) => partner.duoMissingVoiceCount > 0).length,
  };
}

function renderCharacterScenePresenceBadges(scene) {
  const badges = [
    `<span class="issue-tag">角色台词 ${scene.lineCount} 句</span>`,
    `<span class="issue-tag ${getSceneStatusToneClass(scene.status)}">状态：${escapeHtml(
      getSceneStatusLabel(scene.status)
    )}</span>`,
    `<span class="issue-tag ${getScenePriorityToneClass(scene.priority)}">优先级：${escapeHtml(
      getScenePriorityLabel(scene.priority)
    )}</span>`,
    `<span class="issue-tag">完成度 ${scene.completionScore}%</span>`,
  ];

  if (scene.characterMissingVoiceCount > 0) {
    badges.push(`<span class="issue-tag warn-text">本角色待配音 ${scene.characterMissingVoiceCount} 句</span>`);
  }

  if (!scene.hasEffects && scene.lineCount > 0) {
    badges.push('<span class="issue-tag">演出偏素</span>');
  }

  return badges.join("");
}

function renderCharacterSceneCard(scene, { highlight = false } = {}) {
  return `
    <article class="character-line-card character-scene-card ${highlight ? "is-highlight" : ""}">
      <div class="character-line-head">
        <strong>${escapeHtml(scene.name)}</strong>
        <span>${escapeHtml(scene.chapterName)} · 第 ${scene.firstBlockIndex + 1} 张台词起</span>
      </div>
      <div class="character-scene-tags">
        ${renderCharacterScenePresenceBadges(scene)}
      </div>
      <p>${escapeHtml(truncateText(scene.sampleText || "这场里已经有这个角色的台词了。", 78))}</p>
      <div class="character-scene-note">${escapeHtml(scene.planningSummary)}</div>
      <div class="character-line-meta">
        <span>常用表情：${escapeHtml(scene.topExpression)} · 平均句长 ${scene.averageLineLength} 字</span>
        <div class="script-entry-actions">
          <button
            type="button"
            class="toolbar-button"
            data-action="preview-scene-from-map"
            data-scene-id="${scene.id}"
          >
            ${scene.readyForPreview ? "直接试玩" : "试玩这段"}
          </button>
          <button
            type="button"
            class="toolbar-button toolbar-button-primary"
            data-action="open-scene-from-map"
            data-scene-id="${scene.id}"
          >
            继续写这里
          </button>
        </div>
      </div>
      <div class="helper-text">${escapeHtml(scene.nextStep)}</div>
    </article>
  `;
}

