function matchesPreviewSceneFilterMode(sceneNode, filterMode) {
  const safeFilter = getSafePreviewSceneFilterMode(filterMode);

  if (safeFilter === "focus") {
    return ["rush", "focus"].includes(getSafeScenePriority(sceneNode.priority));
  }

  if (safeFilter === "ready") {
    return getSafeSceneStatus(sceneNode.status) === "ready" || (sceneNode.completionScore ?? 0) >= 80;
  }

  if (safeFilter === "issues") {
    return (
      (sceneNode.brokenRouteCount ?? 0) > 0 ||
      (sceneNode.errorCount ?? 0) > 0 ||
      (sceneNode.warningCount ?? 0) > 0 ||
      sceneNode.isOrphan ||
      buildRouteSceneProductionNotes(sceneNode).some((note) => note !== "可以继续抛光")
    );
  }

  return true;
}

function buildPreviewScenePickerOverview(routeOverview) {
  const filterMode = getSafePreviewSceneFilterMode(state.previewSceneFilterMode);
  const terms = getDashboardSearchTerms(state.previewSceneSearchQuery);
  const chapters = (routeOverview.chapters ?? [])
    .map((chapter) => {
      const chapterSearchText = normalizeDashboardSearchQuery(chapter.name);
      const chapterMatchesQuery = terms.length > 0 && terms.every((term) => chapterSearchText.includes(term));
      const scenes = (chapter.scenes ?? []).filter((sceneNode) => {
        if (!matchesPreviewSceneFilterMode(sceneNode, filterMode)) {
          return false;
        }

        if (!terms.length) {
          return true;
        }

        if (chapterMatchesQuery) {
          return true;
        }

        return terms.every((term) => buildStorySceneTreeSearchText(sceneNode).includes(term));
      });

      return {
        ...chapter,
        filteredScenes: scenes,
      };
    })
    .filter((chapter) => chapter.filteredScenes.length > 0);

  const visibleSceneIds = new Set(
    chapters.flatMap((chapter) => chapter.filteredScenes.map((sceneNode) => sceneNode.id))
  );

  return {
    chapters,
    totalSceneCount: routeOverview.nodes?.length ?? 0,
    visibleSceneCount: visibleSceneIds.size,
    totalChapterCount: routeOverview.chapters?.length ?? 0,
    visibleChapterCount: chapters.length,
    hiddenSelectedScene:
      Boolean(state.previewStartSceneId ?? state.previewSceneId) &&
      (routeOverview.nodes?.some((node) => node.id === (state.previewStartSceneId ?? state.previewSceneId)) ?? false) &&
      !visibleSceneIds.has(state.previewStartSceneId ?? state.previewSceneId),
  };
}

function countPreviewScenesForFilterMode(routeOverview, filterMode) {
  return (routeOverview.nodes ?? []).filter((sceneNode) =>
    matchesPreviewSceneFilterMode(sceneNode, filterMode)
  ).length;
}

function renderPreviewSceneFilterBar(routeOverview) {
  const modes = ["all", "focus", "ready", "issues"];

  return modes
    .map((mode) => {
      const count =
        mode === "all"
          ? routeOverview.nodes?.length ?? 0
          : countPreviewScenesForFilterMode(routeOverview, mode);

      return `
        <button
          type="button"
          class="asset-tag-chip ${getSafePreviewSceneFilterMode(state.previewSceneFilterMode) === mode ? "is-active" : ""}"
          data-action="set-preview-scene-filter"
          data-preview-scene-filter="${mode}"
        >
          <span>${escapeHtml(getPreviewSceneFilterLabel(mode))}</span>
          <strong>${count}</strong>
        </button>
      `;
    })
    .join("");
}

function renderPreviewSceneSummary(overview) {
  const activeLabels = [];

  if ((state.previewSceneSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.previewSceneSearchQuery.trim()}`);
  }

  if (getSafePreviewSceneFilterMode(state.previewSceneFilterMode) !== "all") {
    activeLabels.push(`视角：${getPreviewSceneFilterLabel(state.previewSceneFilterMode)}`);
  }

  return `
    <div class="story-filter-summary-main">
      <strong>命中 ${overview.visibleSceneCount}/${overview.totalSceneCount} 个试玩起点 · ${overview.visibleChapterCount}/${overview.totalChapterCount} 个章节</strong>
      <span class="panel-note">选起点时不用再一章章慢慢翻了</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有试玩场景筛选，正在显示全部起点。</span>'
      }
      ${
        overview.hiddenSelectedScene
          ? '<span class="issue-tag warn-text">当前试玩起点被筛选隐藏了，试玩进度不会丢。</span>'
          : ""
      }
    </div>
  `;
}

function renderBeginnerPreviewSceneSummary(overview) {
  return `
    <div class="story-filter-summary-main">
      <strong>这里有 ${overview.visibleSceneCount} 个可试玩起点</strong>
      <span class="panel-note">新手模式先直接点左边场景开跑，不用先管复杂筛选</span>
    </div>
    <div class="story-filter-chip-row">
      <span class="issue-tag good-text">先找你刚写的那一场</span>
      <span class="issue-tag">如果看起来太多，直接用上面的搜索框搜场景名就行</span>
      ${
        overview.hiddenSelectedScene
          ? '<span class="issue-tag warn-text">当前试玩起点还保留着，上面的搜索或旧筛选不会把进度弄丢。</span>'
          : ""
      }
    </div>
  `;
}

function renderBeginnerPreviewGuide(session, snapshot) {
  const routeSummary = buildPreviewRouteSummary(session);
  const firstErrorAction = state.validation.errors[0] ? getValidationIssueAction(state.validation.errors[0]) : null;
  const missingVoiceWarning = state.validation.warnings.find(
    (issue) => issue.message === "这句台词还没有绑定语音。"
  );
  const firstVoiceAction = missingVoiceWarning ? getValidationIssueAction(missingVoiceWarning) : null;

  let title = "先把这段剧情顺着跑完";
  let description = "新手模式下，这里先只看最重要的事：能不能顺着往下读、哪里先修、什么时候可以导出。";
  let actions = [
    { label: "下一句", action: "preview-next" },
    { label: "回剧情页继续写", action: "switch-screen", screen: "story" },
  ];

  if (state.validation.errors.length > 0) {
    title = "先把结构错误修掉再继续试玩";
    description = `当前还有 ${state.validation.errors.length} 项结构错误。先修这一批，后面的试玩和导出会稳很多。`;
    actions = [
      firstErrorAction ? { ...firstErrorAction, label: "打开第一条错误" } : { label: "去剧情页修", action: "switch-screen", screen: "story" },
      { label: "继续留在试玩页", action: "switch-screen", screen: "preview" },
    ];
  } else if (!snapshot || (session?.timeline?.length ?? 0) <= 1) {
    title = "先把这一段真正点着跑起来";
    description = "别急着研究调试工具，先点“下一句”一路往下走，看看这场能不能顺着讲完。";
    actions = [
      { label: "下一句", action: "preview-next" },
      { label: "重新开始", action: "preview-reset" },
    ];
  } else if (firstVoiceAction) {
    title = "剧情已经能跑了，顺手补最前面的待绑语音";
    description = "现在这版已经能继续试玩，下一步最值钱的是先把最前面那句待绑语音补上。";
    actions = [
      { ...firstVoiceAction, label: "打开第一句待配音" },
      { label: "继续试玩这版", action: "preview-next" },
    ];
  } else if (state.lastExportResult?.missingAssets > 0) {
    title = "导出前先把缺失素材补齐";
    description = `最近一次导出还有 ${state.lastExportResult.missingAssets} 个素材没找到。先补这批，试玩包会完整很多。`;
    actions = [
      { label: "去素材页补缺口", action: "focus-asset-gap", dataset: { "asset-filter-mode": "urgent_missing" } },
      { label: "继续试玩这版", action: "switch-screen", screen: "preview" },
    ];
  } else if ((session?.timeline?.length ?? 0) > 1) {
    title = "这版已经能继续试玩了";
    description = "试玩手感稳定后即可开始导出试玩包；如需继续微调节奏，可再往下跑几句。";
    actions = [
      { label: "导出试玩包", action: "export-build", dataset: { "export-target": "web" } },
      { label: "继续试玩这版", action: "preview-next" },
    ];
  }

  return `
    <article class="detail-card beginner-guide-panel">
      <div class="panel-heading">
        <div>
          <h3>新手收尾顺序</h3>
          <span class="panel-note">先能跑、再修错、再补语音和素材，最后再导出</span>
        </div>
        <span class="badge badge-soft">试玩收尾</span>
      </div>
      <article class="beginner-guide-card beginner-guide-focus-card">
        <strong>${escapeHtml(title)}</strong>
        <p>${escapeHtml(description)}</p>
        <div class="detail-actions">
          ${actions.map((action, index) => renderQuickActionButton(action, index === 0)).join("")}
        </div>
      </article>
      <div class="route-summary-strip beginner-guide-metrics">
        ${renderRouteMetricCard("已走步数", session ? `${session.position + 1} / ${session.timeline.length}` : "0 / 0", "这次试玩已经往前走了多少步")}
        ${renderRouteMetricCard("走过场景", routeSummary.visitedSceneCount, "这轮已经实际走到过多少场景")}
        ${renderRouteMetricCard("结构错误", `${state.validation.errors.length} 项`, "先清零会更稳")}
        ${renderRouteMetricCard("待绑语音", `${state.validation.warnings.filter((issue) => issue.message === "这句台词还没有绑定语音。").length} 句`, "不急着一次补完")}
      </div>
    </article>
  `;
}

function renderPreviewScreen() {
  const isBlankProject = isCurrentProjectBlank();
  const isAdvancedMode = isAdvancedEditorMode();
  const session = ensurePreviewSession();
  const snapshot = getCurrentPreviewSnapshot();
  syncPreviewDebugDraft(snapshot);
  const resolution = getProjectResolution();
  const typingPresentation = preparePreviewTypewriter(snapshot);
  const routeOverview = buildSceneRouteOverview();
  const previewSceneOverview = buildPreviewScenePickerOverview(routeOverview);

  if (snapshot && !typingPresentation.active) {
    markPreviewSnapshotAsRead(snapshot);
  }

  if (refs.previewSceneSearchInput && refs.previewSceneSearchInput.value !== state.previewSceneSearchQuery) {
    refs.previewSceneSearchInput.value = state.previewSceneSearchQuery;
  }

  if (!isAdvancedMode && getSafePreviewSceneFilterMode(state.previewSceneFilterMode) !== "all") {
    state.previewSceneFilterMode = "all";
  }

  if (refs.previewSceneFilterBar) {
    refs.previewSceneFilterBar.innerHTML = isAdvancedMode ? renderPreviewSceneFilterBar(routeOverview) : "";
  }

  if (refs.previewSceneSummary) {
    refs.previewSceneSummary.innerHTML = isAdvancedMode
      ? renderPreviewSceneSummary(previewSceneOverview)
      : renderBeginnerPreviewSceneSummary(previewSceneOverview);
  }

  if (refs.previewSceneClearButton) {
    refs.previewSceneClearButton.disabled =
      !state.previewSceneSearchQuery &&
      (isAdvancedMode ? getSafePreviewSceneFilterMode(state.previewSceneFilterMode) === "all" : true);
  }

  refs.previewSceneList.innerHTML = renderSceneTree(
    snapshot?.sceneId ?? state.previewStartSceneId,
    "select-preview-scene",
    {
      routeOverview,
      filteredChapters: previewSceneOverview.chapters,
      showFilteredCounts: true,
      emptyMessage: "这个试玩筛选下暂时没有命中的场景。可换一个关键词，或点击上面的“清空试玩筛选”。",
    }
  );
  refs.previewMeta.textContent = isBlankProject
    ? `${resolution.width} × ${resolution.height} · 当前还是空白项目，先创建第一章以后就能试玩`
    : snapshot
    ? `${resolution.width} × ${resolution.height} · ${
        state.data.scenesById.get(session.startSceneId)?.name ?? session.startSceneId
      } 起点 · 当前 ${snapshot.sceneName} · 第 ${session.position + 1} 步`
    : `${resolution.width} × ${resolution.height} · 还没有可试玩场景`;
  refs.previewStage.style.cssText = getStageContainerStyle(true);
  refs.previewStage.innerHTML = isBlankProject
    ? renderBlankProjectStarterPanel("story")
    : snapshot
    ? renderStage(snapshot.visualState, true, {
        choiceOptions: typingPresentation.active ? [] : snapshot.choiceOptions,
        hint: getPreviewHint(snapshot),
        isComplete: snapshot.completed,
        dialogueTextOverride: typingPresentation.text,
        isTyping: typingPresentation.active,
        dialogTheme: state.previewPlayback.dialogTheme,
        dialogHidden: state.previewDialogHidden,
      })
    : renderEmpty("没有场景可预览。");
  refs.previewLog.innerHTML = session ? renderPreviewTimeline(session) : "";
  refs.validationSummary.innerHTML = renderPreviewSidebar(session);
  updatePreviewControls(session);
  renderPreviewPlaybackControls(snapshot);
  syncPreviewMusic(snapshot);
  syncPreviewVoice(snapshot);
  syncPreviewOneShotAudio(snapshot);
  schedulePreviewAutoAdvance(snapshot);
}

function ensurePreviewSession() {
  if (
    !state.previewSession ||
    state.previewSession.startSceneId !== (state.previewStartSceneId ?? state.previewSceneId)
  ) {
    resetPreviewSession(state.previewStartSceneId ?? state.previewSceneId ?? state.selectedSceneId);
  }

  return state.previewSession;
}

function resetPreviewSession(sceneId = null) {
  stopPreviewTypewriter();
  const safeSceneId = getSafeSceneId(sceneId ?? state.selectedSceneId);
  stopPreviewAutoAdvance();
  stopPreviewMusicPlayback();
  stopPreviewOneShotAudios();
  stopPreviewVoicePlayback();
  state.previewStartSceneId = safeSceneId;
  state.previewSceneId = safeSceneId;
  state.previewDialogHidden = false;
  state.previewSession = createPreviewSession(safeSceneId);
  state.previewBlockIndex = 0;
  state.previewLastSfxStepKey = null;
  persistPreviewAutoResume();
}

function createPreviewSession(startSceneId) {
  const safeStartSceneId = getSafeSceneId(startSceneId ?? state.selectedSceneId);
  const initialVisualState = createInitialPreviewVisualState();
  const initialVariables = createInitialVariableState();
  const firstSnapshot = buildPreviewSnapshot(
    safeStartSceneId,
    0,
    initialVisualState,
    initialVariables
  );

  return {
    startSceneId: safeStartSceneId,
    timeline: [firstSnapshot],
    position: 0,
  };
}

function movePreviewBackward() {
  const session = ensurePreviewSession();

  if (!session || session.position <= 0) {
    return;
  }

  stopPreviewAutoAdvance();
  session.position -= 1;
  state.previewSceneId = getCurrentPreviewSnapshot()?.sceneId ?? state.previewStartSceneId;
  persistPreviewAutoResume();
}

function movePreviewForward() {
  const session = ensurePreviewSession();
  const current = getCurrentPreviewSnapshot();

  if (!session || !current) {
    return;
  }

  if (session.position < session.timeline.length - 1) {
    stopPreviewAutoAdvance();
    session.position += 1;
    state.previewSceneId = getCurrentPreviewSnapshot()?.sceneId ?? state.previewStartSceneId;
    return;
  }

  if (current.choiceOptions.length > 0 || current.completed) {
    return;
  }

  const nextSnapshot = createNextPreviewSnapshot(current);
  stopPreviewAutoAdvance();
  session.timeline.push(nextSnapshot);
  session.position = session.timeline.length - 1;
  state.previewSceneId = nextSnapshot.sceneId ?? state.previewStartSceneId;
  persistPreviewAutoResume();
}

function choosePreviewOption(optionId) {
  const session = ensurePreviewSession();
  const current = getCurrentPreviewSnapshot();

  if (!session || !current || current.choiceOptions.length === 0) {
    return;
  }

  const option = current.choiceOptions.find((item) => item.id === optionId);

  if (!option) {
    return;
  }

  const nextVariables = clonePreviewVariables(current.variables);
  applyChoiceEffectsToPreviewVariables(nextVariables, option.effects ?? []);
  current.selectedOptionId = option.id;
  const nextSnapshot = buildPreviewSnapshot(
    option.gotoSceneId,
    0,
    current.visualState,
    nextVariables
  );

  stopPreviewAutoAdvance();
  session.timeline = session.timeline.slice(0, session.position + 1);
  session.timeline.push(nextSnapshot);
  session.position = session.timeline.length - 1;
  state.previewSceneId = nextSnapshot.sceneId ?? state.previewStartSceneId;
  persistPreviewAutoResume();
}

function updatePreviewDebugDraftValue(variableId, rawValue) {
  const variable = state.data.variablesById.get(variableId);

  if (!variable) {
    return;
  }

  const snapshot = getCurrentPreviewSnapshot();
  if (!snapshot) {
    return;
  }

  if (!state.previewDebugDraft) {
    state.previewDebugDraft = clonePreviewVariables(snapshot.variables);
  }

  let nextValue = rawValue;
  if (variable.type === "number") {
    if (rawValue === "" || rawValue === null || rawValue === undefined) {
      nextValue = getPreviewDebugDraftValue(variableId, snapshot);
    } else {
      nextValue = clampPreviewVariableNumber(variableId, getSafeNumber(rawValue, getPreviewDebugDraftValue(variableId, snapshot)));
    }
  } else if (variable.type === "boolean") {
    nextValue = rawValue === true || rawValue === "true";
  } else {
    nextValue = String(rawValue ?? "");
  }

  state.previewDebugDraft = {
    ...state.previewDebugDraft,
    [variableId]: normalizeVariableValue(variableId, nextValue),
  };
  state.previewDebugSnapshotKey = getPreviewSnapshotKey(snapshot);
}

function updatePreviewDebugDraftValueFromField(target) {
  const variableId = target.dataset.previewDebugVariable ?? "";
  updatePreviewDebugDraftValue(variableId, target.value);
}

function buildPreviewSnapshotWithDebugVariables(snapshot, variables) {
  const nextSnapshot = {
    ...snapshot,
    visualState: clonePreviewVisualState(snapshot.visualState),
    variables: clonePreviewVariables(variables),
    choiceOptions: JSON.parse(JSON.stringify(snapshot.choiceOptions ?? [])),
  };

  if (nextSnapshot.blockType === "condition" && nextSnapshot.block) {
    const targetSceneId = resolveConditionTargetSceneId(nextSnapshot.block, nextSnapshot.variables);
    nextSnapshot.transitionTargetSceneId = targetSceneId;
    nextSnapshot.visualState.speakerName = "系统判断";
    nextSnapshot.visualState.dialogueText = `判断完成，下一步会去：${
      state.data.scenesById.get(targetSceneId)?.name ?? targetSceneId
    }`;
  }

  return nextSnapshot;
}

function resetPreviewDebugDraftToCurrent() {
  const snapshot = getCurrentPreviewSnapshot();

  if (!snapshot) {
    return;
  }

  state.previewDebugDraft = clonePreviewVariables(snapshot.variables);
  state.previewDebugSnapshotKey = getPreviewSnapshotKey(snapshot);
  renderPreviewScreen();
  setSaveStatus("分支调试值已恢复成当前试玩状态");
  showToast("调试变量已恢复");
}

function resetPreviewDebugDraftToDefaults() {
  const snapshot = getCurrentPreviewSnapshot();

  if (!snapshot) {
    return;
  }

  state.previewDebugDraft = createInitialVariableState();
  state.previewDebugSnapshotKey = getPreviewSnapshotKey(snapshot);
  renderPreviewScreen();
  setSaveStatus("分支调试值已重置成项目默认值");
  showToast("调试变量：已恢复默认");
}

function applyPreviewDebugDraft() {
  const session = ensurePreviewSession();
  const snapshot = getCurrentPreviewSnapshot();

  if (!session || !snapshot) {
    return;
  }

  if (!state.data.variables.length) {
    setSaveStatus("这个项目还没有变量可调");
    return;
  }

  if (snapshot.completed) {
    setSaveStatus("这条路线已经结束了，先回上一句再试变量");
    showToast("路线结束后不能直接改这一步", "error");
    return;
  }

  const changedCount = countPreviewDebugDraftChanges(snapshot);
  if (changedCount === 0) {
    setSaveStatus("调试值和当前试玩一致，不需要再写入");
    showToast("当前没有新的调试改动");
    return;
  }

  const nextVariables = state.data.variables.reduce((result, variable) => {
    result[variable.id] = getPreviewDebugDraftValue(variable.id, snapshot);
    return result;
  }, {});
  const nextSnapshot = buildPreviewSnapshotWithDebugVariables(snapshot, nextVariables);

  stopPreviewAutoAdvance();
  session.timeline = session.timeline.slice(0, session.position + 1);
  session.timeline[session.position] = nextSnapshot;
  state.previewSceneId = nextSnapshot.sceneId ?? state.previewStartSceneId;
  state.previewDebugDraft = clonePreviewVariables(nextSnapshot.variables);
  state.previewDebugSnapshotKey = getPreviewSnapshotKey(nextSnapshot);
  persistPreviewAutoResume();
  renderPreviewScreen();

  const targetName =
    nextSnapshot.blockType === "condition"
      ? state.data.scenesById.get(nextSnapshot.transitionTargetSceneId)?.name ?? nextSnapshot.transitionTargetSceneId
      : "";
  const statusMessage =
    nextSnapshot.blockType === "condition" && targetName
      ? `已把 ${changedCount} 项调试变量写入当前试玩，下一句会去：${targetName}`
      : `已把 ${changedCount} 项调试变量写入当前试玩`;
  setSaveStatus(statusMessage);
  showToast(`分支调试：已写入 ${changedCount} 项`);
}

function getCurrentPreviewSnapshot() {
  const session = state.previewSession;
  return session?.timeline?.[session.position] ?? null;
}

function getPreviewSnapshotKey(snapshot) {
  if (!snapshot) {
    return "";
  }

  return `${snapshot.sceneId ?? "none"}:${snapshot.blockId ?? "complete"}:${snapshot.blockIndex}:${
    state.previewSession?.position ?? 0
  }`;
}

function shouldUsePreviewTypewriter(snapshot) {
  if (!snapshot || snapshot.completed) {
    return false;
  }

  if (state.previewPlayback.textSpeed === "instant") {
    return false;
  }

  if (snapshot.blockType !== "dialogue" && snapshot.blockType !== "narration") {
    return false;
  }

  return (snapshot.visualState?.dialogueText ?? "").trim().length > 0;
}

function isPreviewTypewriterActive() {
  return Boolean(state.previewTyping?.active);
}

function stopPreviewTypewriter() {
  if (state.previewTyping?.timer) {
    window.clearTimeout(state.previewTyping.timer);
  }

  state.previewTyping = {
    timer: null,
    snapshotKey: null,
    fullText: "",
    visibleText: "",
    active: false,
  };
}

function completePreviewTypewriter() {
  if (!state.previewTyping?.active) {
    return false;
  }

  if (state.previewTyping.timer) {
    window.clearTimeout(state.previewTyping.timer);
  }

  state.previewTyping.timer = null;
  state.previewTyping.visibleText = state.previewTyping.fullText;
  state.previewTyping.active = false;
  markPreviewSnapshotAsRead(getCurrentPreviewSnapshot());
  return true;
}

function preparePreviewTypewriter(snapshot) {
  if (!snapshot || !shouldUsePreviewTypewriter(snapshot)) {
    stopPreviewTypewriter();
    markPreviewSnapshotAsRead(snapshot);
    return {
      text: snapshot?.visualState?.dialogueText ?? "",
      active: false,
    };
  }

  if (state.previewPlayback.skipRead && isPreviewSnapshotRead(snapshot)) {
    stopPreviewTypewriter();
    markPreviewSnapshotAsRead(snapshot);
    return {
      text: snapshot.visualState?.dialogueText ?? "",
      active: false,
    };
  }

  const snapshotKey = getPreviewSnapshotKey(snapshot);
  const fullText = snapshot.visualState?.dialogueText ?? "";

  if (state.previewTyping.snapshotKey !== snapshotKey || state.previewTyping.fullText !== fullText) {
    stopPreviewTypewriter();
    state.previewTyping.snapshotKey = snapshotKey;
    state.previewTyping.fullText = fullText;
    state.previewTyping.visibleText = fullText.slice(0, getNextTypewriterIndex(fullText, 0));
    state.previewTyping.active = state.previewTyping.visibleText.length < fullText.length;

    if (state.previewTyping.active) {
      schedulePreviewTypewriterTick(snapshotKey);
    }
  }

  return {
    text: state.previewTyping.active ? state.previewTyping.visibleText : fullText,
    active: state.previewTyping.active,
  };
}

function schedulePreviewTypewriterTick(expectedKey) {
  if (state.previewTyping.timer) {
    window.clearTimeout(state.previewTyping.timer);
  }

  state.previewTyping.timer = window.setTimeout(() => {
    if (state.previewTyping.snapshotKey !== expectedKey || !state.previewTyping.active) {
      return;
    }

    const nextIndex = getNextTypewriterIndex(
      state.previewTyping.fullText,
      state.previewTyping.visibleText.length
    );
    state.previewTyping.visibleText = state.previewTyping.fullText.slice(0, nextIndex);

    const dialogNode = refs.previewStage?.querySelector(".dialog-text");
    if (dialogNode) {
      dialogNode.textContent = state.previewTyping.visibleText;
      dialogNode.classList.toggle("is-typing", nextIndex < state.previewTyping.fullText.length);
    }

    if (nextIndex >= state.previewTyping.fullText.length) {
      state.previewTyping.timer = null;
      state.previewTyping.active = false;
      renderPreviewScreen();
      return;
    }

    schedulePreviewTypewriterTick(expectedKey);
  }, getTypewriterStepDelay(state.previewPlayback.textSpeed));
}

function getNextTypewriterIndex(text, currentIndex) {
  if (currentIndex >= text.length) {
    return text.length;
  }

  let nextIndex = currentIndex + 1;
  const currentChar = text[currentIndex] ?? "";

  if (/[A-Za-z0-9]/.test(currentChar)) {
    while (nextIndex < text.length && nextIndex < currentIndex + 3 && /[A-Za-z0-9]/.test(text[nextIndex])) {
      nextIndex += 1;
    }
  }

  while (nextIndex < text.length && /\s/.test(text[nextIndex])) {
    nextIndex += 1;
  }

  return nextIndex;
}

function getSafeTextSpeed(speed) {
  return Object.hasOwn(TEXT_SPEED_LABELS, speed) ? speed : "normal";
}

function getTextSpeedLabel(speed) {
  return TEXT_SPEED_LABELS[getSafeTextSpeed(speed)];
}

function getSafeDialogTheme(theme) {
  return Object.hasOwn(DIALOG_THEME_LABELS, theme) ? theme : "project";
}

function getDialogThemeLabel(theme) {
  return DIALOG_THEME_LABELS[getSafeDialogTheme(theme)];
}

function getBrowserStorage() {
  try {
    return window.localStorage;
  } catch (error) {
    return null;
  }
}

function loadStoredEditorUiThemeMode() {
  const storage = getBrowserStorage();

  if (!storage) {
    return PREVIEW_PLAYBACK_DEFAULTS.uiThemeMode;
  }

  try {
    return getSafeUiThemeMode(storage.getItem(EDITOR_UI_THEME_STORAGE_KEY));
  } catch (error) {
    return PREVIEW_PLAYBACK_DEFAULTS.uiThemeMode;
  }
}

function persistStoredEditorUiThemeMode(mode) {
  const storage = getBrowserStorage();

  if (!storage) {
    return;
  }

  try {
    storage.setItem(EDITOR_UI_THEME_STORAGE_KEY, getSafeUiThemeMode(mode));
  } catch (error) {
    // Ignore storage write failures so theme switching still works in-memory.
  }
}

function getProjectStorageScope(project = state.data?.project) {
  const rawKey = String(project?.projectId ?? project?.title ?? "tony-na-project")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fa5_-]+/g, "-")
    .replace(/-+/g, "-")
    .slice(0, 72);

  return rawKey || "project";
}

function getPreviewPlaybackStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-preview:${getProjectStorageScope(project)}`;
}

function sanitizePreviewPlaybackSettings(source = {}) {
  return {
    textSpeed: getSafeTextSpeed(source.textSpeed ?? PREVIEW_PLAYBACK_DEFAULTS.textSpeed),
    dialogTheme: getSafeDialogTheme(source.dialogTheme ?? PREVIEW_PLAYBACK_DEFAULTS.dialogTheme),
    uiThemeMode: getSafeUiThemeMode(source.uiThemeMode ?? PREVIEW_PLAYBACK_DEFAULTS.uiThemeMode),
    autoPlay: Boolean(source.autoPlay ?? PREVIEW_PLAYBACK_DEFAULTS.autoPlay),
    skipRead: Boolean(source.skipRead ?? PREVIEW_PLAYBACK_DEFAULTS.skipRead),
    voiceEnabled: source.voiceEnabled !== false,
    bgmVolume: getSafeVolumePercent(source.bgmVolume, PREVIEW_PLAYBACK_DEFAULTS.bgmVolume),
    sfxVolume: getSafeVolumePercent(source.sfxVolume, PREVIEW_PLAYBACK_DEFAULTS.sfxVolume),
    voiceVolume: getSafeVolumePercent(source.voiceVolume, PREVIEW_PLAYBACK_DEFAULTS.voiceVolume),
  };
}

function loadStoredPreviewPlaybackSettings(project = state.data?.project) {
  const storage = getBrowserStorage();
  const globalUiThemeMode = loadStoredEditorUiThemeMode();

  if (!storage) {
    return { ...PREVIEW_PLAYBACK_DEFAULTS, uiThemeMode: globalUiThemeMode };
  }

  try {
    const raw = storage.getItem(getPreviewPlaybackStorageKey(project));

    if (!raw) {
      return { ...PREVIEW_PLAYBACK_DEFAULTS, uiThemeMode: globalUiThemeMode };
    }

    return sanitizePreviewPlaybackSettings(JSON.parse(raw));
  } catch (error) {
    return { ...PREVIEW_PLAYBACK_DEFAULTS, uiThemeMode: globalUiThemeMode };
  }
}

function persistPreviewPlaybackSettings() {
  const storage = getBrowserStorage();
  persistStoredEditorUiThemeMode(state.previewPlayback?.uiThemeMode);

  if (!storage || !state.data?.project) {
    return;
  }

  try {
    storage.setItem(
      getPreviewPlaybackStorageKey(state.data.project),
      JSON.stringify(sanitizePreviewPlaybackSettings(state.previewPlayback))
    );
  } catch (error) {
    // Ignore storage write failures so preview controls keep working in stricter environments.
  }
}

function renderGlobalUiThemeSwitch() {
  const activeMode = getSafeUiThemeMode(state.previewPlayback?.uiThemeMode);
  refs.globalUiThemeButtons?.forEach((button) => {
    const isActive = button.dataset.uiThemeMode === activeMode;
    button.classList.toggle("is-active", isActive);
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
  });
}

function syncEditorUiThemeControls() {
  if (refs.previewUiThemeSelect) {
    refs.previewUiThemeSelect.value = getSafeUiThemeMode(state.previewPlayback.uiThemeMode);
  }

  if (refs.previewMenuUiThemeSelect) {
    refs.previewMenuUiThemeSelect.value = getSafeUiThemeMode(state.previewPlayback.uiThemeMode);
  }

  renderGlobalUiThemeSwitch();
}

function getPreviewAutoResumeStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-autoresume:${getProjectStorageScope(project)}`;
}

function getPreviewReadHistoryStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-read:${getProjectStorageScope(project)}`;
}

function getPreviewSaveSlotStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-saves:${getProjectStorageScope(project)}`;
}

function getPreviewQuickSaveStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-quicksave:${getProjectStorageScope(project)}`;
}

function createEmptyPreviewSaveSlots() {
  return Array.from({ length: getProjectFormalSaveSlotCount() }, () => null);
}

function deepClonePreviewData(value) {
  try {
    return JSON.parse(JSON.stringify(value ?? null));
  } catch (error) {
    return null;
  }
}

function sanitizeStoredPreviewSnapshot(source) {
  if (!source || typeof source !== "object") {
    return null;
  }

  const sceneId = typeof source.sceneId === "string" ? source.sceneId : null;
  const scene = sceneId ? state.data?.scenesById.get(sceneId) : null;
  const choiceOptions = Array.isArray(source.choiceOptions)
    ? source.choiceOptions
        .map((option) => deepClonePreviewData(option))
        .filter(Boolean)
    : [];

  return {
    sceneId,
    sceneName: String(source.sceneName ?? scene?.name ?? sceneId ?? "试玩记录"),
    blockIndex: Number.isFinite(Number(source.blockIndex)) ? Number(source.blockIndex) : -1,
    blockId: source.blockId == null ? null : String(source.blockId),
    blockType: source.completed ? "complete" : String(source.blockType ?? "dialogue"),
    block: source.block && typeof source.block === "object" ? deepClonePreviewData(source.block) : null,
    visualState: clonePreviewVisualState(source.visualState),
    variables: clonePreviewVariables(source.variables),
    choiceOptions,
    transitionTargetSceneId:
      source.transitionTargetSceneId == null ? null : String(source.transitionTargetSceneId),
    selectedOptionId: source.selectedOptionId == null ? null : String(source.selectedOptionId),
    resolvedBranchId: source.resolvedBranchId == null ? null : String(source.resolvedBranchId),
    completed: Boolean(source.completed),
  };
}

function sanitizeStoredPreviewSession(source) {
  if (!source || typeof source !== "object") {
    return null;
  }

  const fallbackSceneId = getSafeSceneId(
    source.startSceneId ?? state.data?.project?.entrySceneId ?? state.selectedSceneId
  );
  const timeline = Array.isArray(source.timeline)
    ? source.timeline
        .map((snapshot) => sanitizeStoredPreviewSnapshot(snapshot))
        .filter(Boolean)
    : [];

  if (timeline.length === 0) {
    return null;
  }

  return {
    startSceneId: getSafeSceneId(source.startSceneId ?? timeline[0]?.sceneId ?? fallbackSceneId),
    timeline,
    position: clamp(Number(source.position) || 0, 0, timeline.length - 1),
  };
}

function sanitizeStoredPreviewSaveSlot(source) {
  if (!source || typeof source !== "object") {
    return null;
  }

  const session = sanitizeStoredPreviewSession(source.session);

  if (!session) {
    return null;
  }

  return {
    savedAt: source.savedAt ? String(source.savedAt) : new Date().toISOString(),
    session,
    thumbnailDataUrl: typeof source.thumbnailDataUrl === "string" ? source.thumbnailDataUrl : "",
  };
}

function loadStoredPreviewAutoResume(project = state.data?.project) {
  const storage = getBrowserStorage();

  if (!storage) {
    return null;
  }

  try {
    const raw = storage.getItem(getPreviewAutoResumeStorageKey(project));

    if (!raw) {
      return null;
    }

    return sanitizeStoredPreviewSaveSlot(JSON.parse(raw));
  } catch (error) {
    return null;
  }
}

function loadStoredPreviewSaveSlots(project = state.data?.project) {
  const storage = getBrowserStorage();
  const slotCount = getProjectFormalSaveSlotCount(project);

  if (!storage) {
    return Array.from({ length: slotCount }, () => null);
  }

  try {
    const raw = storage.getItem(getPreviewSaveSlotStorageKey(project));

    if (!raw) {
      return Array.from({ length: slotCount }, () => null);
    }

    const parsed = JSON.parse(raw);
    const sourceSlots = Array.isArray(parsed) ? parsed : Array.isArray(parsed?.slots) ? parsed.slots : [];

    return Array.from({ length: slotCount }, (_, index) =>
      sanitizeStoredPreviewSaveSlot(sourceSlots[index])
    );
  } catch (error) {
    return Array.from({ length: slotCount }, () => null);
  }
}

function loadStoredPreviewQuickSave(project = state.data?.project) {
  const storage = getBrowserStorage();

  if (!storage) {
    return null;
  }

  try {
    const raw = storage.getItem(getPreviewQuickSaveStorageKey(project));

    if (!raw) {
      return null;
    }

    return sanitizeStoredPreviewSaveSlot(JSON.parse(raw));
  } catch (error) {
    return null;
  }
}

function persistPreviewAutoResume() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    return;
  }

  const session = sanitizeStoredPreviewSession(state.previewSession);

  if (!session) {
    return;
  }

  state.previewAutoResume = {
    savedAt: new Date().toISOString(),
    session: deepClonePreviewData(session),
    thumbnailDataUrl: buildPreviewThumbnailDataUrl(getCurrentPreviewSnapshot()),
  };

  try {
    storage.setItem(
      getPreviewAutoResumeStorageKey(state.data.project),
      JSON.stringify(state.previewAutoResume)
    );
  } catch (error) {
    // Ignore storage write failures so auto resume remains optional.
  }
}

function persistPreviewSaveSlots() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    return;
  }

  try {
    const payload = state.previewSaveSlots.map((slot) =>
      slot
        ? {
            savedAt: slot.savedAt,
            session: deepClonePreviewData(slot.session),
            thumbnailDataUrl: slot.thumbnailDataUrl ?? "",
          }
        : null
    );

    storage.setItem(getPreviewSaveSlotStorageKey(state.data.project), JSON.stringify(payload));
  } catch (error) {
    // Ignore storage write failures so save slots remain optional.
  }
}

function persistPreviewQuickSave() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    return;
  }

  try {
    storage.setItem(
      getPreviewQuickSaveStorageKey(state.data.project),
      JSON.stringify(
        state.previewQuickSave
          ? {
              savedAt: state.previewQuickSave.savedAt,
              session: deepClonePreviewData(state.previewQuickSave.session),
              thumbnailDataUrl: state.previewQuickSave.thumbnailDataUrl ?? "",
            }
          : null
      )
    );
  } catch (error) {
    // Ignore storage write failures so quick save remains optional.
  }
}

function clearStoredPreviewAutoResume() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    state.previewAutoResume = null;
    return;
  }

  state.previewAutoResume = null;

  try {
    storage.removeItem(getPreviewAutoResumeStorageKey(state.data.project));
  } catch (error) {
    // Ignore storage cleanup failures.
  }
}

function clearStoredPreviewQuickSave() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    state.previewQuickSave = null;
    return;
  }

  state.previewQuickSave = null;

  try {
    storage.removeItem(getPreviewQuickSaveStorageKey(state.data.project));
  } catch (error) {
    // Ignore storage cleanup failures.
  }
}

function loadStoredPreviewReadHistory(project = state.data?.project) {
  const storage = getBrowserStorage();

  if (!storage) {
    return new Set();
  }

  try {
    const raw = storage.getItem(getPreviewReadHistoryStorageKey(project));

    if (!raw) {
      return new Set();
    }

    const parsed = JSON.parse(raw);
    const values = Array.isArray(parsed) ? parsed : [];
    return new Set(values.filter((value) => typeof value === "string" && value.trim()));
  } catch (error) {
    return new Set();
  }
}

function persistPreviewReadHistory() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    return;
  }

  try {
    storage.setItem(
      getPreviewReadHistoryStorageKey(state.data.project),
      JSON.stringify(Array.from(state.previewReadHistory))
    );
  } catch (error) {
    // Ignore storage write failures so read history remains optional.
  }
}

function getRecentWorkspaceStorageKey(project = state.data?.project) {
  return `tony-na-engine:editor-recent-work:${getProjectStorageScope(project)}`;
}

function getSafeRecentWorkspaceType(type) {
  return Object.prototype.hasOwnProperty.call(RECENT_WORKSPACE_TYPE_LABELS, type) ? type : "scene";
}

function sanitizeRecentWorkspaceText(value, maxLength = 140) {
  const text = String(value ?? "").trim();
  return text ? text.slice(0, maxLength) : "";
}

function getRecentWorkspaceItemKey(entry) {
  if (!entry) {
    return "";
  }

  if (entry.type === "script") {
    return `script:${entry.sceneId ?? ""}:${entry.blockId ?? ""}`;
  }

  if (entry.type === "asset") {
    return `asset:${entry.assetId ?? ""}`;
  }

  if (entry.type === "character") {
    return `character:${entry.characterId ?? ""}`;
  }

  return `scene:${entry.sceneId ?? ""}`;
}

function sanitizeRecentWorkspaceEntry(source = {}) {
  if (!source || typeof source !== "object") {
    return null;
  }

  const type = getSafeRecentWorkspaceType(source.type);
  const updatedAt = new Date(source.updatedAt ?? Date.now());
  const base = {
    type,
    updatedAt: Number.isNaN(updatedAt.getTime()) ? new Date().toISOString() : updatedAt.toISOString(),
    title: sanitizeRecentWorkspaceText(source.title, 160),
    subtitle: sanitizeRecentWorkspaceText(source.subtitle, 180),
    summary: sanitizeRecentWorkspaceText(source.summary, 240),
  };

  if (type === "script") {
    const sceneId = String(source.sceneId ?? "").trim();
    const blockId = String(source.blockId ?? "").trim();
    return sceneId && blockId ? { ...base, sceneId, blockId } : null;
  }

  if (type === "asset") {
    const assetId = String(source.assetId ?? "").trim();
    return assetId ? { ...base, assetId } : null;
  }

  if (type === "character") {
    const characterId = String(source.characterId ?? "").trim();
    return characterId ? { ...base, characterId } : null;
  }

  const sceneId = String(source.sceneId ?? "").trim();
  return sceneId ? { ...base, sceneId } : null;
}

function loadStoredRecentWorkspaceItems(project = state.data?.project) {
  const storage = getBrowserStorage();

  if (!storage) {
    return [];
  }

  try {
    const raw = storage.getItem(getRecentWorkspaceStorageKey(project));

    if (!raw) {
      return [];
    }

    const parsed = JSON.parse(raw);
    const entries = Array.isArray(parsed) ? parsed : Array.isArray(parsed?.items) ? parsed.items : [];
    return entries
      .map((entry) => sanitizeRecentWorkspaceEntry(entry))
      .filter(Boolean)
      .slice(0, RECENT_WORKSPACE_LIMIT);
  } catch (error) {
    return [];
  }
}

function persistRecentWorkspaceItems() {
  const storage = getBrowserStorage();

  if (!storage || !state.data?.project) {
    return;
  }

  try {
    storage.setItem(
      getRecentWorkspaceStorageKey(state.data.project),
      JSON.stringify(state.recentWorkspaceItems.slice(0, RECENT_WORKSPACE_LIMIT))
    );
  } catch (error) {
    // Ignore storage write failures so the editor keeps working in stricter environments.
  }
}

function recordRecentWorkspaceItem(source = {}) {
  const entry = sanitizeRecentWorkspaceEntry({
    ...source,
    updatedAt: new Date().toISOString(),
  });

  if (!entry) {
    return;
  }

  const nextKey = getRecentWorkspaceItemKey(entry);
  state.recentWorkspaceItems = [
    entry,
    ...state.recentWorkspaceItems.filter((item) => getRecentWorkspaceItemKey(item) !== nextKey),
  ].slice(0, RECENT_WORKSPACE_LIMIT);
  persistRecentWorkspaceItems();
}

function rememberRecentScene(sceneId) {
  const scene = state.data?.scenesById.get(getSafeSceneId(sceneId));

  if (!scene) {
    return;
  }

  recordRecentWorkspaceItem({
    type: "scene",
    sceneId: scene.id,
    title: scene.name,
    subtitle: `${scene.chapterName} · ${getSceneStatusLabel(scene.status)} / ${getScenePriorityLabel(scene.priority)}`,
    summary: scene.notes || "这个场景会一直记在首页，方便你回头继续写。",
  });
}

function rememberRecentScript(sceneId, blockId) {
  const scene = state.data?.scenesById.get(getSafeSceneId(sceneId));
  const block = scene?.blocks?.find((item) => item.id === blockId);

  if (!scene || !block) {
    return;
  }

  const summary = getBlockSummary(block, scene);
  recordRecentWorkspaceItem({
    type: "script",
    sceneId: scene.id,
    blockId: block.id,
    title: truncateText(summary.title, 72),
    subtitle: `${scene.chapterName} · ${scene.name}`,
    summary: summary.meta,
  });
}

function rememberRecentAsset(assetId) {
  const asset = state.data?.assetsById.get(assetId);

  if (!asset) {
    return;
  }

  const usageCount = state.data?.assetUsage?.get(asset.id)?.length ?? 0;
  recordRecentWorkspaceItem({
    type: "asset",
    assetId: asset.id,
    title: asset.name,
    subtitle: `${getAssetTypeLabel(asset.type)} · ${asset.fileExists ? "已导入" : "待导入"}`,
    summary: usageCount > 0 ? `当前被 ${usageCount} 处内容引用。` : "暂时还没有被剧情正式用到。",
  });
}

function rememberRecentCharacter(characterId) {
  const character = state.data?.charactersById.get(characterId);

  if (!character) {
    return;
  }

  const stats = buildCharacterDialogueStats(character.id);
  recordRecentWorkspaceItem({
    type: "character",
    characterId: character.id,
    title: character.displayName,
    subtitle: character.bio || "角色资料页",
    summary:
      stats.totalLines > 0
        ? `台词 ${stats.totalLines} 句 · 待配音 ${stats.missingVoiceCount} 句 · 出场 ${stats.scenesCount} 场`
        : "这个角色暂时还没有正文台词。",
  });
}

function clearRecentWorkspaceItems() {
  state.recentWorkspaceItems = [];
  const storage = getBrowserStorage();

  if (storage && state.data?.project) {
    try {
      storage.removeItem(getRecentWorkspaceStorageKey(state.data.project));
    } catch (error) {
      // Ignore storage cleanup failures.
    }
  }

  if (state.currentScreen === "dashboard") {
    renderDashboard();
  }

  setSaveStatus("最近工作区已清空");
  showToast("最近工作区已清空");
}

function getSafeVolumePercent(value, fallback = 100) {
  const numeric = Number(value);

  if (!Number.isFinite(numeric)) {
    return fallback;
  }

  return Math.min(100, Math.max(0, Math.round(numeric)));
}

function getVolumeRatio(value, fallback = 100) {
  return getSafeVolumePercent(value, fallback) / 100;
}

function formatVolumePercent(value, fallback = 100) {
  return `${getSafeVolumePercent(value, fallback)}%`;
}

function getTypewriterStepDelay(speed) {
  return {
    slow: 42,
    normal: 28,
    fast: 18,
    instant: 0,
  }[getSafeTextSpeed(speed)];
}

function getPreviewSnapshotStepKey(snapshot) {
  if (!snapshot) {
    return "";
  }

  return `${snapshot.sceneId ?? "none"}:${snapshot.blockId ?? "complete"}:${snapshot.blockIndex}`;
}

function getPreviewReadStepKey(snapshot) {
  if (!snapshot) {
    return "";
  }

  return `${snapshot.sceneId ?? "none"}:${snapshot.blockId ?? "complete"}:${snapshot.blockIndex}`;
}

function isPreviewSnapshotRead(snapshot) {
  const stepKey = getPreviewReadStepKey(snapshot);
  return Boolean(stepKey) && state.previewReadHistory.has(stepKey);
}

function markPreviewSnapshotAsRead(snapshot) {
  const stepKey = getPreviewReadStepKey(snapshot);

  if (!stepKey || state.previewReadHistory.has(stepKey)) {
    return false;
  }

  state.previewReadHistory.add(stepKey);
  persistPreviewReadHistory();
  return true;
}

function getPreviewVoiceAssetId(snapshot) {
  if (!snapshot || snapshot.blockType !== "dialogue") {
    return "";
  }

  return snapshot.block?.voiceAssetId ?? "";
}

function getPreviewAutoAdvanceDelay(snapshot) {
  if (!snapshot) {
    return 0;
  }

  if (snapshot.blockType === "dialogue" || snapshot.blockType === "narration") {
    const text = snapshot.visualState?.dialogueText ?? "";
    const multiplier = {
      slow: 92,
      normal: 72,
      fast: 58,
      instant: 42,
    }[getSafeTextSpeed(state.previewPlayback.textSpeed)];
    return Math.min(6800, Math.max(1100, 520 + text.length * multiplier));
  }

  if (snapshot.blockType === "jump" || snapshot.blockType === "condition") {
    return 520;
  }

  return 820;
}

function stopPreviewAutoAdvance() {
  if (previewAutoAdvanceTimer) {
    window.clearTimeout(previewAutoAdvanceTimer);
    previewAutoAdvanceTimer = null;
  }

  previewAutoAdvanceKey = null;
}

function stopPreviewMusicPlayback() {
  if (previewMusicAudio) {
    previewMusicAudio.pause();
    previewMusicAudio.src = "";
    previewMusicAudio = null;
  }

  previewCurrentMusicAssetId = null;
}

function stopPreviewOneShotAudios() {
  previewActiveSfxAudios.forEach((audio) => {
    audio.pause();
    audio.src = "";
  });
  previewActiveSfxAudios.clear();
}

function stopPreviewVoicePlayback({ resetStepKey = true } = {}) {
  previewVoiceAudio.pause();
  previewVoiceAudio.currentTime = 0;
  previewVoiceAudio.src = "";
  previewVoiceAudio.load?.();

  if (resetStepKey) {
    state.previewVoiceStepKey = null;
  }
}

function updatePreviewAudioVolumes() {
  if (previewMusicAudio) {
    previewMusicAudio.volume = getVolumeRatio(state.previewPlayback.bgmVolume, 72);
  }

  previewActiveSfxAudios.forEach((audio) => {
    audio.volume = getVolumeRatio(state.previewPlayback.sfxVolume, 85);
  });

  if (previewVoiceAudio.currentSrc || previewVoiceAudio.src) {
    previewVoiceAudio.volume = getVolumeRatio(state.previewPlayback.voiceVolume, 92);
  }
}

function updatePreviewVolumeControl(controlId, rawValue, announce = false) {
  let label = "";

  if (controlId === "previewBgmVolumeRange" || controlId === "previewMenuBgmVolumeRange") {
    state.previewPlayback.bgmVolume = getSafeVolumePercent(rawValue, 72);
    updatePreviewAudioVolumes();
    label = `试玩 BGM 音量已调到：${formatVolumePercent(state.previewPlayback.bgmVolume, 72)}`;
  } else if (controlId === "previewSfxVolumeRange" || controlId === "previewMenuSfxVolumeRange") {
    state.previewPlayback.sfxVolume = getSafeVolumePercent(rawValue, 85);
    updatePreviewAudioVolumes();
    label = `试玩音效音量已调到：${formatVolumePercent(state.previewPlayback.sfxVolume, 85)}`;
  } else if (controlId === "previewVoiceVolumeRange" || controlId === "previewMenuVoiceVolumeRange") {
    state.previewPlayback.voiceVolume = getSafeVolumePercent(rawValue, 92);
    updatePreviewAudioVolumes();
    label = `试玩语音音量已调到：${formatVolumePercent(state.previewPlayback.voiceVolume, 92)}`;
  } else {
    return false;
  }

  persistPreviewPlaybackSettings();
  renderPreviewPlaybackControls(getCurrentPreviewSnapshot());

  if (announce) {
    setSaveStatus(label);
  }

  return true;
}

function syncPreviewMusic(snapshot) {
  const nextMusicAssetId = snapshot?.visualState?.musicAssetId ?? null;

  if (!nextMusicAssetId) {
    stopPreviewMusicPlayback();
    return;
  }

  if (previewCurrentMusicAssetId === nextMusicAssetId && previewMusicAudio) {
    previewMusicAudio.volume = getVolumeRatio(state.previewPlayback.bgmVolume, 72);
    return;
  }

  stopPreviewMusicPlayback();
  const asset = state.data.assetsById.get(nextMusicAssetId);
  const previewUrl = getAssetPublicUrl(asset);

  previewCurrentMusicAssetId = nextMusicAssetId;

  if (!previewUrl) {
    return;
  }

  const audio = new Audio(encodeURI(previewUrl));
  audio.loop = true;
  audio.volume = getVolumeRatio(state.previewPlayback.bgmVolume, 72);
  audio.play().catch(() => {});
  previewMusicAudio = audio;
}

function playPreviewOneShotAudio(previewUrl) {
  const audio = new Audio(encodeURI(previewUrl));
  audio.volume = getVolumeRatio(state.previewPlayback.sfxVolume, 85);
  previewActiveSfxAudios.add(audio);
  const cleanup = () => {
    previewActiveSfxAudios.delete(audio);
  };
  audio.addEventListener("ended", cleanup, { once: true });
  audio.addEventListener("error", cleanup, { once: true });
  audio.play().catch(cleanup);
}

function syncPreviewOneShotAudio(snapshot) {
  if (!snapshot) {
    return;
  }

  const snapshotKey = getPreviewSnapshotKey(snapshot);

  if (state.previewLastSfxStepKey === snapshotKey) {
    return;
  }

  state.previewLastSfxStepKey = snapshotKey;

  if (snapshot.blockType !== "sfx_play") {
    return;
  }

  const asset = state.data.assetsById.get(snapshot.block?.assetId);
  const previewUrl = getAssetPublicUrl(asset);

  if (!previewUrl) {
    return;
  }

  playPreviewOneShotAudio(previewUrl);
}

function handlePreviewVoiceEnded() {
  const snapshot = getCurrentPreviewSnapshot();
  const snapshotKey = getPreviewSnapshotStepKey(snapshot);

  if (snapshotKey && snapshotKey === state.previewVoiceStepKey) {
    schedulePreviewAutoAdvance(snapshot, { preferVoiceEnding: true });
  }
}

function handlePreviewVoiceError() {
  const snapshot = getCurrentPreviewSnapshot();
  schedulePreviewAutoAdvance(snapshot);
}

function syncPreviewVoice(snapshot) {
  const voiceAssetId = getPreviewVoiceAssetId(snapshot);
  const snapshotKey = getPreviewSnapshotStepKey(snapshot);

  if (!state.previewPlayback.voiceEnabled || !voiceAssetId) {
    stopPreviewVoicePlayback();
    return;
  }

  if (state.previewVoiceStepKey === snapshotKey && (previewVoiceAudio.currentSrc || previewVoiceAudio.src)) {
    return;
  }

  const asset = state.data.assetsById.get(voiceAssetId);
  const previewUrl = getAssetPublicUrl(asset);

  stopPreviewVoicePlayback({ resetStepKey: false });
  state.previewVoiceStepKey = snapshotKey;

  if (!previewUrl) {
    return;
  }

  previewVoiceAudio.src = encodeURI(previewUrl);
  previewVoiceAudio.currentTime = 0;
  previewVoiceAudio.volume = getVolumeRatio(state.previewPlayback.voiceVolume, 92);
  previewVoiceAudio.play().catch(() => {
    schedulePreviewAutoAdvance(snapshot);
  });
}

function schedulePreviewAutoAdvance(snapshot, options = {}) {
  stopPreviewAutoAdvance();

  const skipActive = state.previewPlayback.skipRead;
  const autoPlayActive = state.previewPlayback.autoPlay;

  if (
    (!autoPlayActive && !skipActive) ||
    !snapshot ||
    snapshot.completed ||
    snapshot.choiceOptions.length > 0
  ) {
    return;
  }

  if (skipActive && !isPreviewSnapshotRead(snapshot)) {
    state.previewPlayback.skipRead = false;
    persistPreviewPlaybackSettings();
    renderPreviewPlaybackControls(snapshot);
    setSaveStatus("遇到未读内容，已停止跳过");
    showToast("跳过已读已在新内容前停下");
    return;
  }

  if (isPreviewTypewriterActive()) {
    return;
  }

  const snapshotKey = getPreviewSnapshotStepKey(snapshot);
  const voiceAssetId = getPreviewVoiceAssetId(snapshot);
  const hasVoicePlaying =
    !skipActive &&
    options.preferVoiceEnding !== true &&
    Boolean(voiceAssetId) &&
    state.previewPlayback.voiceEnabled &&
    state.previewVoiceStepKey === snapshotKey &&
    Boolean(previewVoiceAudio.currentSrc || previewVoiceAudio.src) &&
    !previewVoiceAudio.paused;

  if (hasVoicePlaying) {
    previewAutoAdvanceKey = snapshotKey;
    return;
  }

  previewAutoAdvanceKey = snapshotKey;
  previewAutoAdvanceTimer = window.setTimeout(() => {
    if ((!state.previewPlayback.autoPlay && !state.previewPlayback.skipRead) || previewAutoAdvanceKey !== snapshotKey) {
      return;
    }

    const current = getCurrentPreviewSnapshot();
    if (!current || getPreviewSnapshotStepKey(current) !== snapshotKey) {
      return;
    }

    movePreviewForward();
    renderPreviewScreen();
  }, skipActive ? 70 : options.preferVoiceEnding ? 180 : getPreviewAutoAdvanceDelay(snapshot));
}

function togglePreviewAutoPlay() {
  state.previewPlayback.autoPlay = !state.previewPlayback.autoPlay;

  if (state.previewPlayback.autoPlay) {
    state.previewPlayback.skipRead = false;
  }

  persistPreviewPlaybackSettings();
  stopPreviewAutoAdvance();
  renderPreviewScreen();
  setSaveStatus(state.previewPlayback.autoPlay ? "试玩自动播放已开启" : "试玩自动播放已关闭");
  showToast(state.previewPlayback.autoPlay ? "自动播放：开" : "自动播放：关");
}

function togglePreviewSkipRead() {
  state.previewPlayback.skipRead = !state.previewPlayback.skipRead;

  if (state.previewPlayback.skipRead) {
    state.previewPlayback.autoPlay = false;
  }

  persistPreviewPlaybackSettings();
  stopPreviewAutoAdvance();
  renderPreviewScreen();
  setSaveStatus(state.previewPlayback.skipRead ? "试玩跳过已读已开启" : "试玩跳过已读已关闭");
  showToast(state.previewPlayback.skipRead ? "跳过已读：开" : "跳过已读：关");
}

function togglePreviewVoiceEnabled() {
  state.previewPlayback.voiceEnabled = !state.previewPlayback.voiceEnabled;
  persistPreviewPlaybackSettings();

  if (!state.previewPlayback.voiceEnabled) {
    stopPreviewVoicePlayback();
  }

  renderPreviewScreen();
  setSaveStatus(state.previewPlayback.voiceEnabled ? "试玩语音已开启" : "试玩语音已关闭");
  showToast(state.previewPlayback.voiceEnabled ? "语音：开" : "语音：关");
}

async function replayCurrentPreviewVoice() {
  const snapshot = getCurrentPreviewSnapshot();
  const voiceAssetId = getPreviewVoiceAssetId(snapshot);

  if (!voiceAssetId) {
    setSaveStatus("当前这句台词没有绑定语音", true);
    showToast("当前这句还没有语音", "error");
    return;
  }

  if (!state.previewPlayback.voiceEnabled) {
    state.previewPlayback.voiceEnabled = true;
    persistPreviewPlaybackSettings();
  }

  stopPreviewAutoAdvance();
  state.previewVoiceStepKey = null;
  syncPreviewVoice(snapshot);
  renderPreviewPlaybackControls(snapshot);
  setSaveStatus("已重新播放当前语音");
  showToast("正在重播当前语音");
}

function renderPreviewPlaybackControls(snapshot) {
  if (refs.previewTextSpeedSelect) {
    refs.previewTextSpeedSelect.value = getSafeTextSpeed(state.previewPlayback.textSpeed);
  }

  if (refs.previewDialogThemeSelect) {
    refs.previewDialogThemeSelect.value = getSafeDialogTheme(state.previewPlayback.dialogTheme);
  }

  syncEditorUiThemeControls();

  if (refs.previewBgmVolumeRange) {
    refs.previewBgmVolumeRange.value = String(getSafeVolumePercent(state.previewPlayback.bgmVolume, 72));
  }

  if (refs.previewBgmVolumeValue) {
    refs.previewBgmVolumeValue.textContent = formatVolumePercent(state.previewPlayback.bgmVolume, 72);
  }

  if (refs.previewSfxVolumeRange) {
    refs.previewSfxVolumeRange.value = String(getSafeVolumePercent(state.previewPlayback.sfxVolume, 85));
  }

  if (refs.previewSfxVolumeValue) {
    refs.previewSfxVolumeValue.textContent = formatVolumePercent(state.previewPlayback.sfxVolume, 85);
  }

  if (refs.previewVoiceVolumeRange) {
    refs.previewVoiceVolumeRange.value = String(getSafeVolumePercent(state.previewPlayback.voiceVolume, 92));
  }

  if (refs.previewVoiceVolumeValue) {
    refs.previewVoiceVolumeValue.textContent = formatVolumePercent(state.previewPlayback.voiceVolume, 92);
  }

  if (refs.previewAutoPlayButton) {
    refs.previewAutoPlayButton.textContent = `自动播放：${state.previewPlayback.autoPlay ? "开" : "关"}`;
  }

  if (refs.previewVoiceToggleButton) {
    refs.previewVoiceToggleButton.textContent = `语音：${state.previewPlayback.voiceEnabled ? "开" : "关"}`;
  }

  if (refs.previewSkipReadButton) {
    refs.previewSkipReadButton.textContent = `跳过已读：${state.previewPlayback.skipRead ? "开" : "关"}`;
  }

  if (refs.previewDialogToggleButton) {
    refs.previewDialogToggleButton.textContent = state.previewDialogHidden ? "显示对话框" : "隐藏对话框";
  }

  if (refs.previewReplayVoiceButton) {
    refs.previewReplayVoiceButton.disabled = !getPreviewVoiceAssetId(snapshot);
  }

  if (refs.previewSystemMenuButton) {
    refs.previewSystemMenuButton.disabled = !state.data;
  }

  applyEditorUiTheme(state.previewPlayback.uiThemeMode);

  renderPreviewAutoResumePanel();
  renderPreviewSaveSlots();
  renderPreviewSystemMenu();
  renderPreviewReturnConfirmDialog();
  renderPreviewSaveConfirmDialog();
  renderPreviewSaveDialog();
}

function createInitialPreviewVisualState() {
  return {
    backgroundAssetId: null,
    backgroundName: "未设置背景",
    scene3dPreview: null,
    scene3dPreview: null,
    musicName: "未播放",
    particleEffect: null,
    screenShake: null,
    screenFlash: null,
    screenFade: null,
    cameraZoom: null,
    cameraPan: null,
    screenFilter: null,
    depthBlur: null,
    activeCharacterId: null,
    characterTransitionEvent: null,
    characterEmphasisEvent: null,
    visibleCharacters: [],
    speakerName: "预览面板",
    dialogueText: "点“下一句”以后，这里会按真实分支逻辑推进。",
  };
}

function clonePreviewVisualState(visualState) {
  return {
    ...createInitialPreviewVisualState(),
    ...(visualState ?? {}),
    particleEffect: visualState?.particleEffect
      ? normalizeParticleEffectConfig(visualState.particleEffect)
      : null,
    scene3dPreview: visualState?.scene3dPreview ? getSafeScene3dPreviewConfig(visualState.scene3dPreview) : null,
    screenShake: visualState?.screenShake
      ? {
          intensity: getSafeShakeIntensity(visualState.screenShake.intensity),
          duration: getSafeEffectDuration(visualState.screenShake.duration),
        }
      : null,
    screenFlash: visualState?.screenFlash
      ? {
          color: getSafeFlashColor(visualState.screenFlash.color),
          intensity: getSafeFlashIntensity(visualState.screenFlash.intensity),
          duration: getSafeEffectDuration(visualState.screenFlash.duration),
        }
      : null,
    screenFade: visualState?.screenFade
      ? {
          color: getSafeFadeColor(visualState.screenFade.color),
          duration: getSafeEffectDuration(visualState.screenFade.duration),
        }
      : null,
    cameraZoom: visualState?.cameraZoom
      ? {
          action: getSafeCameraZoomAction(visualState.cameraZoom.action),
          strength: getSafeCameraZoomStrength(visualState.cameraZoom.strength),
          focus: getSafeCameraZoomFocus(visualState.cameraZoom.focus),
        }
      : null,
    cameraPan: visualState?.cameraPan
      ? {
          target: getSafeCameraPanTarget(visualState.cameraPan.target),
          strength: getSafeCameraPanStrength(visualState.cameraPan.strength),
        }
      : null,
    screenFilter: visualState?.screenFilter
      ? {
          preset: getSafeScreenFilterPreset(visualState.screenFilter.preset),
          strength: getSafeScreenFilterStrength(visualState.screenFilter.strength),
        }
      : null,
    depthBlur: visualState?.depthBlur
      ? {
          focus: getSafeDepthBlurFocus(visualState.depthBlur.focus),
          strength: getSafeDepthBlurStrength(visualState.depthBlur.strength),
        }
      : null,
    activeCharacterId: visualState?.activeCharacterId ?? null,
    characterTransitionEvent: visualState?.characterTransitionEvent
      ? JSON.parse(JSON.stringify(visualState.characterTransitionEvent))
      : null,
    characterEmphasisEvent: visualState?.characterEmphasisEvent
      ? JSON.parse(JSON.stringify(visualState.characterEmphasisEvent))
      : null,
    visibleCharacters: (visualState?.visibleCharacters ?? []).map((characterState) => ({
      ...characterState,
    })),
  };
}

function clearTransientStageEffects(visualState) {
  if (!visualState) {
    return;
  }

  visualState.screenShake = null;
  visualState.screenFlash = null;
  visualState.activeCharacterId = null;
  visualState.characterTransitionEvent = null;
  visualState.characterEmphasisEvent = null;
}

function createInitialVariableState() {
  return state.data.variables.reduce((result, variable) => {
    result[variable.id] = getVariableDefaultValue(variable.id);
    return result;
  }, {});
}

function clonePreviewVariables(variables) {
  return JSON.parse(JSON.stringify(variables ?? {}));
}

function buildPreviewSnapshot(sceneId, blockIndex, previousVisualState, previousVariables) {
  const scene = state.data.scenesById.get(sceneId);
  const baseVisualState = clonePreviewVisualState(previousVisualState);
  const baseVariables = clonePreviewVariables(previousVariables);

  if (!scene) {
    return createPreviewTerminalSnapshot(
      {
        sceneId,
        sceneName: sceneId || "未知场景",
      },
      baseVisualState,
      baseVariables,
      "目标场景不存在，试玩在这里停下来了。"
    );
  }

  const block = scene.blocks?.[blockIndex];

  if (!block) {
    return createPreviewTerminalSnapshot(
      {
        sceneId: scene.id,
        sceneName: scene.name,
      },
      baseVisualState,
      baseVariables,
      "这个场景还没有卡片，试玩在这里停下来了。"
    );
  }

  const nextVisualState = clonePreviewVisualState(baseVisualState);
  clearTransientStageEffects(nextVisualState);
  const nextVariables = clonePreviewVariables(baseVariables);
  const transitionTargetSceneId = applyBlockToPreviewState(block, nextVisualState, nextVariables);
  const conditionResult =
    block.type === "condition" ? resolveConditionBranchResult(block, nextVariables) : null;

  return {
    sceneId: scene.id,
    sceneName: scene.name,
    blockIndex,
    blockId: block.id,
    blockType: block.type,
    block,
    visualState: nextVisualState,
    variables: nextVariables,
    choiceOptions: block.type === "choice" ? (block.options ?? []).map((option) => ({ ...option })) : [],
    transitionTargetSceneId,
    selectedOptionId: null,
    resolvedBranchId: conditionResult?.branchKey ?? null,
    completed: false,
  };
}

function createPreviewTerminalSnapshot(scene, visualState, variables, message) {
  const nextVisualState = clonePreviewVisualState(visualState);
  clearTransientStageEffects(nextVisualState);
  nextVisualState.speakerName = "试玩结束";
  nextVisualState.dialogueText = message;

  return {
    sceneId: scene.sceneId ?? null,
    sceneName: scene.sceneName ?? "试玩结束",
    blockIndex: -1,
    blockId: null,
    blockType: "complete",
    block: null,
    visualState: nextVisualState,
    variables: clonePreviewVariables(variables),
    choiceOptions: [],
    transitionTargetSceneId: null,
    selectedOptionId: null,
    resolvedBranchId: null,
    completed: true,
  };
}

function createNextPreviewSnapshot(currentSnapshot) {
  if (currentSnapshot.transitionTargetSceneId) {
    return buildPreviewSnapshot(
      currentSnapshot.transitionTargetSceneId,
      0,
      currentSnapshot.visualState,
      currentSnapshot.variables
    );
  }

  const scene = state.data.scenesById.get(currentSnapshot.sceneId);
  const nextBlockIndex = currentSnapshot.blockIndex + 1;

  if (scene?.blocks?.[nextBlockIndex]) {
    return buildPreviewSnapshot(
      currentSnapshot.sceneId,
      nextBlockIndex,
      currentSnapshot.visualState,
      currentSnapshot.variables
    );
  }

  return createPreviewTerminalSnapshot(
    currentSnapshot,
    currentSnapshot.visualState,
    currentSnapshot.variables,
    "这段试玩已经走完了。点“重新开始”可以再走一遍。"
  );
}

function createPreviewRegressionSession(startSceneId) {
  const safeStartSceneId = getSafeSceneId(startSceneId ?? state.selectedSceneId);
  const initialVisualState = createInitialPreviewVisualState();
  const initialVariables = createInitialVariableState();
  const firstSnapshot = buildPreviewSnapshot(
    safeStartSceneId,
    0,
    initialVisualState,
    initialVariables
  );

  return {
    startSceneId: safeStartSceneId,
    timeline: [firstSnapshot],
    position: 0,
  };
}

function getCurrentPreviewRegressionSnapshot(session) {
  return session?.timeline?.[session.position] ?? null;
}

function movePreviewRegressionForward(session) {
  const current = getCurrentPreviewRegressionSnapshot(session);

  if (!session || !current || current.choiceOptions.length > 0 || current.completed) {
    return current;
  }

  const nextSnapshot = createNextPreviewSnapshot(current);
  session.timeline.push(nextSnapshot);
  session.position = session.timeline.length - 1;
  return nextSnapshot;
}

function choosePreviewRegressionOption(session, optionId) {
  const current = getCurrentPreviewRegressionSnapshot(session);

  if (!session || !current || current.choiceOptions.length === 0) {
    return current;
  }

  const option = current.choiceOptions.find((item) => item.id === optionId);

  if (!option) {
    return current;
  }

  const nextVariables = clonePreviewVariables(current.variables);
  applyChoiceEffectsToPreviewVariables(nextVariables, option.effects ?? []);
  current.selectedOptionId = option.id;
  const nextSnapshot = buildPreviewSnapshot(
    option.gotoSceneId,
    0,
    current.visualState,
    nextVariables
  );

  session.timeline.push(nextSnapshot);
  session.position = session.timeline.length - 1;
  return nextSnapshot;
}

function applyBlockToPreviewState(block, visualState, variables) {
  switch (block.type) {
    case "background": {
      const asset = state.data.assetsById.get(block.assetId);
      visualState.backgroundAssetId = block.assetId;
      visualState.backgroundName = asset?.name ?? block.assetId;
      visualState.scene3dPreview =
        asset?.type === "scene3d" ? getSafeScene3dPreviewConfig(block.scene3dPreview) : null;
      visualState.speakerName = "画面";
      visualState.dialogueText =
        asset?.type === "scene3d"
          ? `进入 3D 场景：${asset?.name ?? block.assetId} / yaw ${visualState.scene3dPreview.yaw} / pitch ${visualState.scene3dPreview.pitch} / zoom ${visualState.scene3dPreview.zoom}`
          : `背景切换到：${asset?.name ?? block.assetId}`;
      return null;
    }
    case "music_play": {
      const asset = state.data.assetsById.get(block.assetId);
      visualState.musicName = asset?.name ?? block.assetId;
      visualState.speakerName = "音乐";
      visualState.dialogueText = `开始播放：${asset?.name ?? block.assetId}`;
      return null;
    }
    case "music_stop":
      visualState.musicName = "未播放";
      visualState.speakerName = "音乐";
      visualState.dialogueText = "背景音乐停止了。";
      return null;
    case "particle_effect": {
      const action = getSafeParticleAction(block.action);
      if (action === "stop") {
        visualState.particleEffect = null;
        visualState.speakerName = "粒子特效";
        visualState.dialogueText = "当前场景里的粒子特效已经关闭。";
        return null;
      }
      visualState.particleEffect = normalizeParticleEffectConfig(block);
      visualState.speakerName = "粒子特效";
      visualState.dialogueText = `${getParticlePresetLabel(block.preset)}开始出现，${getParticleEmissionModeLabel(
        visualState.particleEffect.emissionMode
      )} / ${getParticleEmitterShapeLabel(visualState.particleEffect.emitterShape)} / ${visualState.particleEffect.density} 颗。`;
      return null;
    }
    case "screen_shake":
      visualState.screenShake = {
        intensity: getSafeShakeIntensity(block.intensity),
        duration: getSafeEffectDuration(block.duration),
      };
      visualState.speakerName = "屏幕演出";
      visualState.dialogueText = `画面会${getShakeIntensityLabel(block.intensity)}地震动一下，持续 ${getEffectDurationLabel(
        block.duration
      )}。`;
      return null;
    case "screen_flash":
      visualState.screenFlash = {
        color: getSafeFlashColor(block.color),
        intensity: getSafeFlashIntensity(block.intensity),
        duration: getSafeEffectDuration(block.duration),
      };
      visualState.speakerName = "屏幕演出";
      visualState.dialogueText = `画面会出现一次${getFlashColorLabel(block.color)}，强度 ${getFlashIntensityLabel(
        block.intensity
      )}。`;
      return null;
    case "screen_fade": {
      const fadeAction = getSafeFadeAction(block.action);
      visualState.screenFade =
        fadeAction === "fade_out"
          ? {
              color: getSafeFadeColor(block.color),
              duration: getSafeEffectDuration(block.duration),
            }
          : null;
      visualState.speakerName = "画面过场";
      visualState.dialogueText =
        fadeAction === "fade_out"
          ? `画面会慢慢淡到${getFadeColorLabel(block.color)}，持续 ${getEffectDurationLabel(block.duration)}。`
          : `画面会从${getFadeColorLabel(block.color)}慢慢亮起，持续 ${getEffectDurationLabel(block.duration)}。`;
      return null;
    }
    case "camera_zoom": {
      const zoomAction = getSafeCameraZoomAction(block.action);
      visualState.cameraZoom =
        zoomAction === "reset"
          ? null
          : {
              action: zoomAction,
              strength: getSafeCameraZoomStrength(block.strength),
              focus: getSafeCameraZoomFocus(block.focus),
            };
      visualState.speakerName = "镜头演出";
      visualState.dialogueText =
        zoomAction === "reset"
          ? "镜头会恢复到正常大小。"
          : `镜头会${getCameraZoomActionLabel(block.action)}，强度 ${getCameraZoomStrengthLabel(
              block.strength
            )}，重点看${getCameraZoomFocusLabel(block.focus)}。`;
      return null;
    }
    case "camera_pan": {
      const target = getSafeCameraPanTarget(block.target);
      visualState.cameraPan =
        target === "center"
          ? null
          : {
              target,
              strength: getSafeCameraPanStrength(block.strength),
            };
      visualState.speakerName = "镜头演出";
      visualState.dialogueText =
        target === "center"
          ? "镜头会慢慢回到中间。"
          : `镜头会${getCameraPanTargetLabel(block.target)}，幅度 ${getCameraPanStrengthLabel(block.strength)}。`;
      return null;
    }
    case "screen_filter": {
      const filterAction = getSafeScreenFilterAction(block.action);
      visualState.screenFilter =
        filterAction === "clear"
          ? null
          : {
              preset: getSafeScreenFilterPreset(block.preset),
              strength: getSafeScreenFilterStrength(block.strength),
            };
      visualState.speakerName = "画面滤镜";
      visualState.dialogueText =
        filterAction === "clear"
          ? "当前画面的回忆滤镜会在这里关闭。"
          : `画面会套上${getScreenFilterPresetLabel(block.preset)}，强度 ${getScreenFilterStrengthLabel(
              block.strength
            )}。`;
      return null;
    }
    case "depth_blur": {
      const blurAction = getSafeDepthBlurAction(block.action);
      visualState.depthBlur =
        blurAction === "clear"
          ? null
          : {
              focus: getSafeDepthBlurFocus(block.focus),
              strength: getSafeDepthBlurStrength(block.strength),
            };
      visualState.speakerName = "镜头景深";
      visualState.dialogueText =
        blurAction === "clear"
          ? "当前画面的景深模糊会在这里关闭。"
          : `画面会加上景深模糊，重点突出${getDepthBlurFocusLabel(block.focus)}，强度 ${getDepthBlurStrengthLabel(
              block.strength
            )}。`;
      return null;
    }
    case "character_show":
      upsertPreviewCharacter(visualState, {
        characterId: block.characterId,
        position: block.position ?? getDefaultCharacterPosition(block.characterId),
        expressionId: block.expressionId,
        expressionName: getExpressionName(block.characterId, block.expressionId),
      });
      if (getSafeTransition(block.transition) === "fade") {
        visualState.characterTransitionEvent = {
          mode: "show",
          characterId: block.characterId,
        };
      }
      visualState.speakerName = "角色演出";
      visualState.dialogueText = `${
        state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId
      } 出现在画面里。`;
      return null;
    case "character_hide": {
      const previousState =
        getPreviewCharacterState(visualState, block.characterId) ??
        createFallbackPreviewCharacterState(block.characterId);
      removePreviewCharacter(visualState, block.characterId);
      if (getSafeTransition(block.transition) === "fade") {
        visualState.characterTransitionEvent = {
          mode: "hide",
          characterState: previousState,
        };
      }
      visualState.speakerName = "角色演出";
      visualState.dialogueText = `${
        state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId
      } 离开了画面。`;
      return null;
    }
    case "dialogue": {
      const characterName =
        state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId;
      visualState.activeCharacterId = block.speakerId;
      visualState.characterEmphasisEvent = {
        mode: "dialogue",
        characterId: block.speakerId,
      };
      visualState.speakerName = characterName;
      visualState.dialogueText = block.text;
      upsertPreviewCharacter(visualState, {
        characterId: block.speakerId,
        position:
          getPreviewCharacterState(visualState, block.speakerId)?.position ??
          getDefaultCharacterPosition(block.speakerId),
        expressionId: block.expressionId,
        expressionName: getExpressionName(block.speakerId, block.expressionId),
      });
      return null;
    }
    case "narration":
      visualState.speakerName = "旁白";
      visualState.dialogueText = block.text;
      return null;
    case "choice":
      visualState.speakerName = "选择分支";
      visualState.dialogueText = "请选择一个选项继续试玩。";
      return null;
    case "variable_set": {
      const value = setPreviewVariableValue(variables, block.variableId, block.value);
      visualState.speakerName = "系统变量";
      visualState.dialogueText = `${
        state.data.variablesById.get(block.variableId)?.name ?? block.variableId
      } 设为 ${formatVariableValue(block.variableId, value)}`;
      return null;
    }
    case "variable_add": {
      const value = addPreviewVariableValue(variables, block.variableId, block.value);
      visualState.speakerName = "系统变量";
      visualState.dialogueText = `${
        state.data.variablesById.get(block.variableId)?.name ?? block.variableId
      } 现在是 ${formatVariableValue(block.variableId, value)}`;
      return null;
    }
    case "condition": {
      const branchResult = resolveConditionBranchResult(block, variables);
      visualState.speakerName = "系统判断";
      visualState.dialogueText = `判断完成，下一步会去：${
        state.data.scenesById.get(branchResult.targetSceneId)?.name ?? branchResult.targetSceneId
      }`;
      return branchResult.targetSceneId;
    }
    case "jump":
      visualState.speakerName = "场景跳转";
      visualState.dialogueText = `下一步会跳到：${
        state.data.scenesById.get(block.targetSceneId)?.name ?? block.targetSceneId
      }`;
      return getSafeSceneId(block.targetSceneId, block.targetSceneId);
    default:
      visualState.speakerName = BLOCK_LABELS[block.type] ?? block.type;
      visualState.dialogueText = "这张卡片会参与试玩流程。";
      return null;
  }
}

function getPreviewCharacterState(visualState, characterId) {
  return (visualState.visibleCharacters ?? []).find(
    (characterState) => characterState.characterId === characterId
  );
}

function upsertPreviewCharacter(visualState, characterState) {
  const visibleMap = new Map(
    (visualState.visibleCharacters ?? []).map((item) => [item.characterId, { ...item }])
  );
  visibleMap.set(characterState.characterId, { ...characterState });
  visualState.visibleCharacters = Array.from(visibleMap.values()).sort(
    (left, right) => getPositionOrder(left.position) - getPositionOrder(right.position)
  );
}

function removePreviewCharacter(visualState, characterId) {
  visualState.visibleCharacters = (visualState.visibleCharacters ?? []).filter(
    (characterState) => characterState.characterId !== characterId
  );
}

function createFallbackPreviewCharacterState(characterId) {
  const safeExpressionId = getSafeExpressionId(characterId, "");
  return {
    characterId,
    position: getDefaultCharacterPosition(characterId),
    expressionId: safeExpressionId,
    expressionName: getExpressionName(characterId, safeExpressionId),
  };
}

function getPreviewVariableValue(variables, variableId) {
  if (Object.hasOwn(variables, variableId)) {
    return normalizeVariableValue(variableId, variables[variableId]);
  }

  return getVariableDefaultValue(variableId);
}

function clampPreviewVariableNumber(variableId, value) {
  const [minValue, maxValue] = getVariableNumberBounds(variableId);
  let nextValue = value;

  if (minValue !== null) {
    nextValue = Math.max(nextValue, minValue);
  }

  if (maxValue !== null) {
    nextValue = Math.min(nextValue, maxValue);
  }

  return nextValue;
}

function setPreviewVariableValue(variables, variableId, value) {
  const nextValue = normalizeVariableValue(variableId, value);
  variables[variableId] =
    typeof nextValue === "number" ? clampPreviewVariableNumber(variableId, nextValue) : nextValue;
  return variables[variableId];
}

function addPreviewVariableValue(variables, variableId, delta) {
  const currentValue = getSafeNumber(getPreviewVariableValue(variables, variableId), 0);
  return setPreviewVariableValue(variables, variableId, currentValue + getSafeNumber(delta, 0));
}

function applyChoiceEffectsToPreviewVariables(variables, effects) {
  (effects ?? []).forEach((effect) => {
    if (effect.type === "variable_add") {
      addPreviewVariableValue(variables, effect.variableId, effect.value);
      return;
    }

    if (effect.type === "variable_set") {
      setPreviewVariableValue(variables, effect.variableId, effect.value);
    }
  });
}

function getConditionBranchKey(branch, index) {
  const explicitId = String(branch?.id ?? "").trim();
  return explicitId || `branch-${index + 1}`;
}

function resolveConditionBranchResult(block, variables) {
  const matchedBranchIndex = (block.branches ?? []).findIndex((branch) =>
    (branch.when ?? []).every((rule) => evaluateConditionRule(rule, variables))
  );

  if (matchedBranchIndex >= 0) {
    const matchedBranch = block.branches?.[matchedBranchIndex] ?? null;
    return {
      branchKey: getConditionBranchKey(matchedBranch, matchedBranchIndex),
      targetSceneId: getSafeSceneId(matchedBranch?.gotoSceneId, matchedBranch?.gotoSceneId),
      branch: matchedBranch,
      matched: true,
    };
  }

  return {
    branchKey: "else",
    targetSceneId: getSafeSceneId(block.elseGotoSceneId, block.elseGotoSceneId),
    branch: null,
    matched: false,
  };
}

function resolveConditionTargetSceneId(block, variables) {
  return resolveConditionBranchResult(block, variables).targetSceneId;
}

function evaluateConditionRule(rule, variables) {
  const left = getPreviewVariableValue(variables, rule.variableId);
  const right = normalizeVariableValue(rule.variableId, rule.value);

  switch (rule.operator) {
    case ">":
      return left > right;
    case ">=":
      return left >= right;
    case "<":
      return left < right;
    case "<=":
      return left <= right;
    case "!=":
      return left !== right;
    case "==":
    default:
      return left === right;
  }
}

function getPreviewHint(snapshot) {
  if (!snapshot) {
    return "";
  }

  if (isPreviewTypewriterActive()) {
    return "可以点画面、按空格/回车，先把整句文字直接显示出来。";
  }

  if (state.previewDialogHidden) {
    return "对话框现在是隐藏状态，点画面、按 H 或右键可以恢复。";
  }

  if (state.previewPlayback.autoPlay && snapshot.choiceOptions.length === 0 && !snapshot.completed) {
    return "自动播放已开启，这一段会自己继续往下走。";
  }

  if (state.previewPlayback.skipRead && snapshot.choiceOptions.length === 0 && !snapshot.completed) {
    return "跳过已读已开启，已经看过的内容会快速略过，遇到新句子会停下。";
  }

  if (snapshot.choiceOptions.length > 0) {
    return "需要先点一个选项，试玩才会继续。";
  }

  if (snapshot.completed) {
    return "这条试玩路线已经结束了。";
  }

  if (snapshot.blockType === "condition") {
    return "下一句会按当前变量结果跳到对应场景。";
  }

  if (snapshot.blockType === "jump") {
    return "下一句会进入目标场景。";
  }

  return "可以直接点画面，按空格/回车/右方向继续，左方向回上一句，R 重新开始，S 开关跳过已读，H 隐藏对话框。";
}

function updatePreviewControls(session) {
  const snapshot = getCurrentPreviewSnapshot();
  const canUseRecordedNext =
    Boolean(session) && session.position < Math.max((session?.timeline?.length ?? 1) - 1, 0);
  const typingActive = isPreviewTypewriterActive();

  if (refs.previewPrevButton) {
    refs.previewPrevButton.disabled = !session || session.position <= 0;
  }

  if (refs.previewNextButton) {
    refs.previewNextButton.textContent = typingActive ? "显示整句" : "下一句";
    refs.previewNextButton.disabled =
      !snapshot ||
      (!typingActive && !canUseRecordedNext && (snapshot.choiceOptions.length > 0 || snapshot.completed));
  }

  if (refs.previewResetButton) {
    refs.previewResetButton.disabled = !session;
  }
}

function renderSceneTree(selectedSceneId, actionName, options = {}) {
  const routeOverview = options.routeOverview ?? buildSceneRouteOverview();
  const chapters =
    options.filteredChapters ??
    (options.useStoryFilters
      ? options.sceneTreeOverview?.chapters ?? buildStorySceneTreeOverview(routeOverview).chapters
      : routeOverview.chapters);
  const showFilteredCounts = options.showFilteredCounts ?? options.useStoryFilters;
  const emptyMessage =
    options.emptyMessage ??
    (options.useStoryFilters
      ? "这个项目树筛选下暂时没有命中的场景。可换一个关键词，或点击上面的“清空项目树筛选”。"
      : "当前还没有可显示的场景。");

  if (!chapters.length) {
    return renderEmpty(emptyMessage);
  }

  return chapters
    .map((chapter) => {
      const chapterScenes = options.useStoryFilters ? chapter.filteredScenes ?? [] : chapter.scenes ?? [];
      const sceneCards = chapterScenes
        .map((scene) => {
          return `
            <article
              class="scene-card ${scene.id === selectedSceneId ? "is-selected" : ""}"
              data-action="${actionName}"
              data-scene-id="${scene.id}"
            >
              <strong>${escapeHtml(scene.name)}</strong>
              <div class="scene-meta">${scene.blockCount ?? scene.blocks?.length ?? 0} 张卡片</div>
              <div class="scene-card-tags">${renderScenePlanningBadges(scene)}</div>
              ${renderScenePlanningQuickButtons(scene)}
              ${
                scene.notes
                  ? `<div class="scene-note-preview">${escapeHtml(truncateText(scene.notes, 46))}</div>`
                  : ""
              }
            </article>
          `;
        })
        .join("");

      return `
        <div class="chapter-divider">
          ${escapeHtml(chapter.name)}
          ${
            showFilteredCounts
              ? ` · 命中 ${chapterScenes.length}/${chapter.scenes?.length ?? chapterScenes.length}`
              : ""
          }
        </div>
        ${sceneCards}
      `;
    })
    .join("");
}

function renderAssetTypeList(assetPool = state.data.assetList, duplicateOverview = buildAssetDuplicateOverview()) {
  const counts = countAssetsByType(assetPool);
  const asset3dRiskAssetIds = getNativeRuntime3dRiskAssetIdSet();
  const mediaBudgetAssetIds = buildAssetMediaBudgetReport(state.data).assetIds;
  return Object.keys(ASSET_TYPE_LABELS)
    .map((type) => {
      const count = counts.get(type) ?? 0;
      const missingCount = assetPool.filter((asset) => asset.type === type && isAssetMissingFile(asset)).length;
      const urgentMissingCount = assetPool.filter((asset) => asset.type === type && isAssetUrgentMissing(asset)).length;
      const duplicateCount = duplicateOverview.perTypeMap.get(type)?.duplicateCount ?? 0;
      const asset3dRiskCount = assetPool.filter(
        (asset) => asset.type === type && asset3dRiskAssetIds.has(asset.id)
      ).length;
      const mediaBudgetCount = assetPool.filter(
        (asset) => asset.type === type && mediaBudgetAssetIds.has(asset.id)
      ).length;
      return `
        <article
          class="scene-card ${type === state.selectedAssetType ? "is-selected" : ""}"
          data-action="select-asset-type"
          data-asset-type="${type}"
        >
          <strong>${ASSET_TYPE_LABELS[type]}</strong>
          <div class="scene-meta">${count} 个文件 · ${
            asset3dRiskCount > 0
              ? `3D 风险 ${asset3dRiskCount}`
              : mediaBudgetCount > 0
                ? `体积预算 ${mediaBudgetCount}`
                : missingCount > 0
                  ? `待导入 ${missingCount}`
                  : duplicateCount > 0
                    ? `疑似重复 ${duplicateCount}`
                    : "已补齐"
          }</div>
          ${
            missingCount > 0 || urgentMissingCount > 0 || duplicateCount > 0 || asset3dRiskCount > 0 || mediaBudgetCount > 0
              ? `
                  <div class="scene-card-tags">
                    ${
                      asset3dRiskCount > 0
                        ? `<span class="issue-tag warn-text">3D 发布风险 ${asset3dRiskCount}</span>`
                        : ""
                    }
                    ${
                      mediaBudgetCount > 0
                        ? `<span class="issue-tag warn-text">素材预算 ${mediaBudgetCount}</span>`
                        : ""
                    }
                    ${
                      missingCount > 0 || urgentMissingCount > 0
                        ? `<span class="issue-tag ${urgentMissingCount > 0 ? "warn-text" : ""}">
                            ${urgentMissingCount > 0 ? `已引用缺口 ${urgentMissingCount}` : `待导入 ${missingCount}`}
                          </span>`
                        : ""
                    }
                    ${
                      duplicateCount > 0
                        ? `<span class="issue-tag ${missingCount === 0 && urgentMissingCount === 0 ? "danger-text" : ""}">疑似重复 ${duplicateCount}</span>`
                        : ""
                    }
                  </div>
                `
              : ""
          }
        </article>
      `;
    })
    .join("");
}

function renderAssetGapBoard(duplicateOverview = buildAssetDuplicateOverview()) {
  const overview = buildAssetGapOverview(state.data, duplicateOverview);
  const currentTypeSummary = overview.perTypeMap.get(state.selectedAssetType) ?? null;
  const native3dRiskCount = countNativeRuntime3dRiskAssetsByType();
  const currentTypeNative3dRiskCount = countNativeRuntime3dRiskAssetsByType(state.selectedAssetType);
  const mediaBudgetReport = buildAssetMediaBudgetReport(state.data);
  const currentTypeMediaBudgetCount = mediaBudgetReport.items.filter((item) => item.type === state.selectedAssetType).length;
  const hasActiveFilters =
    state.assetFilterMode !== "all" ||
    Boolean(state.assetSearchQuery.trim()) ||
    Boolean(state.assetTagFilter) ||
    state.assetFavoriteOnly;

  return `
    <section class="asset-gap-board-shell">
      <div class="asset-gap-board-head">
        <div class="asset-gap-board-copy">
          <strong>素材缺口和整理看板</strong>
          <span>先补已经被项目引用却还没导入真实文件的素材，再顺手清理疑似重复资源，项目会稳很多。</span>
        </div>
        ${
          hasActiveFilters
            ? `
                <button class="toolbar-button" data-action="clear-asset-search">
                  恢复全部视角
                </button>
              `
            : ""
        }
      </div>
      <div class="asset-gap-stat-grid">
        ${renderAssetGapStatCard(
          "已就绪",
          overview.readyCount,
          overview.readyCount > 0 ? "这些素材已经有真实文件，可以直接预览和导出。" : "当前还没有已就绪素材。",
          "good"
        )}
        ${renderAssetGapStatCard(
          "待导入",
          overview.missingCount,
          overview.missingCount > 0 ? "点一下只看还没导入真实文件的素材。" : "目前所有素材都已经有真实文件。",
          "warn",
          overview.missingCount > 0
            ? { action: "focus-asset-gap", filterMode: "missing_file" }
            : null
        )}
        ${renderAssetGapStatCard(
          "已引用缺口",
          overview.urgentMissingCount,
          overview.urgentMissingCount > 0
            ? "这些素材已经被剧情或角色引用，可优先补上。"
            : "当前没有“已引用但缺文件”的高优先级缺口。",
          overview.urgentMissingCount > 0 ? "urgent" : "good",
          overview.urgentMissingCount > 0
            ? { action: "focus-asset-gap", filterMode: "urgent_missing" }
            : null
        )}
        ${renderAssetGapStatCard(
          "暂未使用",
          overview.unusedCount,
          overview.unusedCount > 0 ? "点一下就能回到闲置素材清理视角。" : "目前没有闲置素材。",
          "soft",
          overview.unusedCount > 0
            ? { action: "focus-unused-assets" }
            : null
        )}
        ${renderAssetGapStatCard(
          "疑似重复",
          overview.duplicateCount,
          overview.duplicateCount > 0 ? "点一下只看需要整理的疑似重复素材。" : "目前没有明显的重复素材信号。",
          overview.duplicateCount > 0 ? "urgent" : "good",
          overview.duplicateCount > 0
            ? { action: "focus-asset-gap", filterMode: "duplicate" }
            : null
        )}
        ${renderAssetGapStatCard(
          "3D 风险",
          native3dRiskCount,
          native3dRiskCount > 0
            ? "最近一次原生 Runtime 体检标记了这些 3D 素材，点一下直接集中处理。"
            : "最近一次原生 Runtime 3D 体检没有留下风险素材。",
          native3dRiskCount > 0 ? "urgent" : "good",
          native3dRiskCount > 0
            ? { action: "focus-asset-gap", filterMode: "asset3d_risk" }
            : null
        )}
        ${renderAssetGapStatCard(
          "素材预算",
          mediaBudgetReport.count,
          mediaBudgetReport.count > 0
            ? `有 ${mediaBudgetReport.count} 个素材建议压缩，合计 ${mediaBudgetReport.totalLabel}。`
            : "当前没有明显超预算的大图、大音频或大视频。",
          mediaBudgetReport.blockerCount > 0 ? "urgent" : mediaBudgetReport.count > 0 ? "warn" : "good",
          mediaBudgetReport.count > 0
            ? { action: "focus-asset-gap", filterMode: "media_budget" }
            : null
        )}
      </div>
      <div class="asset-gap-focus-grid">
        <article class="detail-card asset-gap-focus-card">
          <strong>当前分类：${escapeHtml(getAssetTypeLabel(state.selectedAssetType))}</strong>
          <div class="detail-meta">${escapeHtml(getAssetTypeGapSummaryText(state.selectedAssetType, null, state.data, duplicateOverview))}</div>
          <div class="scene-card-tags">
            ${
              currentTypeSummary
                ? `
                    <span class="issue-tag ${currentTypeSummary.missingCount > 0 ? "" : "good-text"}">
                      ${
                        currentTypeSummary.missingCount > 0
                          ? `待导入 ${currentTypeSummary.missingCount}`
                          : currentTypeSummary.duplicateCount > 0
                            ? "缺口已补齐，适合回头整理"
                            : "这一类已补齐"
                      }
                    </span>
                    ${
                      currentTypeSummary.urgentMissingCount > 0
                        ? `<span class="issue-tag warn-text">已引用缺口 ${currentTypeSummary.urgentMissingCount}</span>`
                        : ""
                    }
                    ${
                      currentTypeSummary.unusedCount > 0
                        ? `<span class="issue-tag">暂未使用 ${currentTypeSummary.unusedCount}</span>`
                        : ""
                    }
                    ${
                      currentTypeSummary.duplicateCount > 0
                        ? `<span class="issue-tag danger-text">疑似重复 ${currentTypeSummary.duplicateCount}</span>`
                        : ""
                    }
                    ${
                      currentTypeNative3dRiskCount > 0
                        ? `<span class="issue-tag warn-text">3D 发布风险 ${currentTypeNative3dRiskCount}</span>`
                        : ""
                    }
                    ${
                      currentTypeMediaBudgetCount > 0
                        ? `<span class="issue-tag warn-text">素材预算 ${currentTypeMediaBudgetCount}</span>`
                        : ""
                    }
                  `
                : `<span class="issue-tag">这一类暂时没有素材</span>`
            }
          </div>
          <div class="detail-actions">
            <button
              class="toolbar-button ${state.assetFilterMode === "missing_file" ? "toolbar-button-primary" : ""}"
              data-action="focus-asset-gap"
              data-asset-filter-mode="missing_file"
              data-asset-type="${escapeHtml(state.selectedAssetType)}"
              ${currentTypeSummary?.missingCount > 0 ? "" : "disabled"}
            >
              只看这类待导入
            </button>
            <button
              class="toolbar-button ${state.assetFilterMode === "urgent_missing" ? "toolbar-button-primary" : ""}"
              data-action="focus-asset-gap"
              data-asset-filter-mode="urgent_missing"
              data-asset-type="${escapeHtml(state.selectedAssetType)}"
              ${currentTypeSummary?.urgentMissingCount > 0 ? "" : "disabled"}
            >
              先补这类已引用缺口
            </button>
            <button
              class="toolbar-button ${state.assetFilterMode === "duplicate" ? "toolbar-button-primary" : ""}"
              data-action="focus-asset-gap"
              data-asset-filter-mode="duplicate"
              data-asset-type="${escapeHtml(state.selectedAssetType)}"
              ${currentTypeSummary?.duplicateCount > 0 ? "" : "disabled"}
            >
              只看这类疑似重复
            </button>
            <button
              class="toolbar-button ${state.assetFilterMode === "asset3d_risk" ? "toolbar-button-primary" : ""}"
              data-action="focus-asset-gap"
              data-asset-filter-mode="asset3d_risk"
              data-asset-type="${escapeHtml(state.selectedAssetType)}"
              ${currentTypeNative3dRiskCount > 0 ? "" : "disabled"}
            >
              只看这类 3D 风险
            </button>
            <button
              class="toolbar-button ${state.assetFilterMode === "media_budget" ? "toolbar-button-primary" : ""}"
              data-action="focus-asset-gap"
              data-asset-filter-mode="media_budget"
              data-asset-type="${escapeHtml(state.selectedAssetType)}"
              ${currentTypeMediaBudgetCount > 0 ? "" : "disabled"}
            >
              只看这类体积风险
            </button>
          </div>
        </article>
        <article class="detail-card asset-gap-focus-card">
          <strong>现在最值得先补或整理的分类</strong>
          ${
            overview.priorityTypes.length > 0
              ? `
                  <div class="asset-gap-priority-list">
                    ${overview.priorityTypes
                      .map(
                        (typeSummary) => `
                          <button
                            class="asset-gap-priority-item ${typeSummary.type === state.selectedAssetType ? "is-active" : ""}"
                            data-action="focus-asset-gap"
                            data-asset-filter-mode="${
                              typeSummary.urgentMissingCount > 0
                                ? "urgent_missing"
                                : typeSummary.missingCount > 0
                                  ? "missing_file"
                                  : "duplicate"
                            }"
                            data-asset-type="${escapeHtml(typeSummary.type)}"
                          >
                            <strong>${escapeHtml(typeSummary.label)}</strong>
                            <div class="detail-meta">
                              待导入 ${typeSummary.missingCount} 个 · 已引用缺口 ${typeSummary.urgentMissingCount} 个 · 疑似重复 ${typeSummary.duplicateCount} 个
                            </div>
                          </button>
                        `
                      )
                      .join("")}
                  </div>
                `
              : `<div class="helper-text">当前各类素材都已经补得比较齐了，可以回头整理标签和闲置素材。</div>`
          }
        </article>
        <article class="detail-card asset-gap-focus-card">
          <strong>重复整理优先清单</strong>
          ${
            duplicateOverview.priorityClusters.length > 0
              ? `
                  <div class="asset-gap-priority-list">
                    ${duplicateOverview.priorityClusters
                      .map(
                        (cluster) => `
                          <article class="asset-gap-priority-item">
                            <strong>${escapeHtml(cluster.preferredAsset.name)}</strong>
                            <div class="detail-meta">
                              ${escapeHtml(getAssetTypeLabel(cluster.preferredAsset.type))} · 这一组共 ${cluster.assetIds.length} 项 · ${
                                cluster.usedAssetsCount > 0 ? `已使用 ${cluster.usedAssetsCount} 项` : "暂时还没有被正文使用"
                              }
                            </div>
                            <div class="scene-card-tags">
                              <span class="issue-tag good-text">主版本</span>
                              ${cluster.reasonLabels
                                .map((label) => `<span class="issue-tag ${label.toneClass}">${escapeHtml(label.text)}</span>`)
                                .join("")}
                            </div>
                            <div class="helper-text">${escapeHtml(cluster.preferredNotes.join(" · "))}</div>
                            <div class="script-entry-actions">
                              <button
                                type="button"
                                class="toolbar-button toolbar-button-primary"
                                data-action="open-asset-from-issue"
                                data-asset-id="${cluster.preferredAsset.id}"
                              >
                                打开主版本项
                              </button>
                            </div>
                          </article>
                        `
                      )
                      .join("")}
                  </div>
                `
              : `<div class="helper-text">当前还没有明显的重复素材信号。后面导入变多以后，这里会自动列出值得优先整理的重复组。</div>`
          }
        </article>
      </div>
    </section>
  `;
}

function renderAssetGapStatCard(label, count, note, tone = "soft", action = null) {
  const tagName = action ? "button" : "article";
  const attrs = action
    ? `type="button" class="asset-gap-stat-card is-${tone}" data-action="${action.action}"${
        action.filterMode ? ` data-asset-filter-mode="${escapeHtml(action.filterMode)}"` : ""
      }${action.assetType ? ` data-asset-type="${escapeHtml(action.assetType)}"` : ""}`
    : `class="asset-gap-stat-card is-${tone}"`;

  return `
    <${tagName} ${attrs}>
      <span class="asset-gap-stat-label">${escapeHtml(label)}</span>
      <strong>${count}</strong>
      <span class="asset-gap-stat-note">${escapeHtml(note)}</span>
    </${tagName}>
  `;
}

function renderBlockCard(block, scene, index, isSelected, canDragBlocks = false) {
  const summary = getBlockSummary(block, scene);
  return `
    <article
      class="block-card ${isSelected ? "is-selected" : ""}"
      data-action="select-block"
      data-block-id="${block.id}"
      draggable="${canDragBlocks ? "true" : "false"}"
    >
      <span class="block-tag">${BLOCK_LABELS[block.type] ?? block.type}</span>
      <strong>${escapeHtml(summary.title)}</strong>
      <div class="block-meta">第 ${index + 1} 张 · ${escapeHtml(summary.meta)}</div>
      ${canDragBlocks ? '<div class="block-card-drag-hint">拖住这张卡片，就能改顺序</div>' : ""}
      ${renderStoryBlockIssueBadges(block)}
    </article>
  `;
}

function renderAssetCard(asset, isSelected, duplicateInfo = null) {
  const usageCount = getAssetUsageCount(asset.id);
  const usageText = usageCount > 0 ? `已使用 ${usageCount} 处` : "暂时未使用";
  const fileText = asset.fileExists ? "文件已就绪" : "还没导入真实文件";
  const native3dRisk = getNativeRuntime3dRiskForAsset(asset.id);
  const mediaBudgetRisk = getAssetMediaBudgetRisk(asset);
  return `
    <article
      class="asset-card ${isSelected ? "is-selected" : ""}"
      data-action="select-asset"
      data-asset-id="${asset.id}"
    >
      <div class="asset-card-topline">
        <div class="asset-card-check">
          <input
            type="checkbox"
            data-action="toggle-asset-bulk"
            data-asset-id="${asset.id}"
            ${isAssetChecked(asset.id) ? "checked" : ""}
            aria-label="勾选素材 ${escapeHtml(asset.name)}"
          />
          <span>加入多选</span>
        </div>
        <span class="asset-tag">${getAssetTypeLabel(asset.type)}</span>
      </div>
      ${renderAssetThumb(asset)}
      <strong>${escapeHtml(asset.name)}</strong>
      <div class="asset-meta">
        ${escapeHtml(asset.path)} · ${usageText} · ${fileText}
      </div>
      <div class="scene-card-tags">
        ${
          asset.fileExists
            ? `<span class="issue-tag good-text">可直接预览</span>`
            : `<span class="issue-tag ${usageCount > 0 ? "warn-text" : ""}">${
                usageCount > 0 ? "已引用但缺文件" : "待导入"
              }</span>`
        }
        ${usageCount === 0 ? `<span class="issue-tag">暂未使用</span>` : ""}
        ${
          native3dRisk
            ? `<span class="issue-tag warn-text">3D 风险：${escapeHtml(
                truncateText(native3dRisk.summary ?? native3dRisk.statusLabel ?? "需要复核", 30)
              )}</span>`
            : ""
        }
        ${
          mediaBudgetRisk
            ? `<span class="issue-tag warn-text">体积：${escapeHtml(mediaBudgetRisk.fileSizeLabel)}</span>`
            : ""
        }
        ${
          duplicateInfo
            ? duplicateInfo.isPreferred
              ? `<span class="issue-tag good-text">这一组优先留它</span>`
              : `<span class="issue-tag ${duplicateInfo.tone === "danger" ? "danger-text" : "warn-text"}">疑似重复 ${duplicateInfo.relatedCount}</span>`
            : ""
        }
      </div>
      ${(asset.tags ?? []).length ? `<div class="asset-card-tags">${renderInlineAssetTags(asset.tags.slice(0, 3))}</div>` : ""}
      <div class="asset-card-actions">
        <button
          class="asset-favorite-button ${asset.favorite ? "is-active" : ""}"
          data-action="toggle-asset-favorite"
          data-asset-id="${asset.id}"
        >
          ${asset.favorite ? "★ 已收藏" : "☆ 收藏"}
        </button>
        ${
          isAudioAssetType(asset.type)
            ? `
              <button
                class="asset-preview-button"
                data-action="toggle-asset-audio"
                data-asset-id="${asset.id}"
                ${asset.fileExists ? "" : "disabled"}
              >
                ${state.activeAssetAudioId === asset.id ? "停止试听" : "试听一下"}
              </button>
            `
            : ""
        }
      </div>
    </article>
  `;
}

function renderCharacterCard(character, isSelected, stats = null) {
  const safeStats = stats ?? buildCharacterDialogueStats(character.id);
  return `
    <article
      class="character-card ${isSelected ? "is-selected" : ""}"
      data-action="select-character"
      data-character-id="${character.id}"
    >
      <strong>${escapeHtml(character.displayName)}</strong>
      <div class="scene-meta">
        ${escapeHtml(getCharacterPresentationModeLabel(character))} · ${escapeHtml(getPositionLabel(character.defaultPosition))} · ${character.expressions.length} 个表情 · ${safeStats.totalLines} 句台词
      </div>
      <div class="character-card-metrics">
        <span class="issue-tag ${safeStats.missingVoiceCount > 0 ? "warn-text" : "good-text"}">
          ${safeStats.missingVoiceCount > 0 ? `待配音 ${safeStats.missingVoiceCount}` : "语音已齐"}
        </span>
        <span class="issue-tag">覆盖率 ${safeStats.voiceCoverage}%</span>
      </div>
    </article>
  `;
}

function renderAssetDetails(asset, duplicateOverview = buildAssetDuplicateOverview()) {
  const usages = state.data.assetUsage.get(asset.id) ?? [];
  const duplicateInfo = duplicateOverview.infoByAssetId.get(asset.id) ?? null;
  const assetTypeLabel = getAssetTypeLabel(asset.type);
  const usagePreview = usages.slice(0, 4).join(" / ");
  return `
    ${renderAssetPreviewCard(asset)}
    <article class="detail-card">
      <strong>素材信息编辑</strong>
      <div class="detail-stack">
        <div class="detail-row">
          <label for="assetMetaNameInput">素材名称</label>
          <input id="assetMetaNameInput" type="text" value="${escapeHtml(asset.name)}" />
        </div>
        <div class="detail-row">
          <label for="assetMetaTagsInput">素材标签</label>
          <input
            id="assetMetaTagsInput"
            type="text"
            value="${escapeHtml((asset.tags ?? []).join(", "))}"
            placeholder="用逗号分开，比如：校园, 黄昏, 教室"
          />
        </div>
      </div>
      <p class="helper-text">标签支持中文逗号、英文逗号、顿号或空行分开。点保存后，搜索和标签筛选都会立刻生效。</p>
      <div class="detail-actions">
        <button
          class="asset-favorite-button ${asset.favorite ? "is-active" : ""}"
          data-action="toggle-asset-favorite"
          data-asset-id="${asset.id}"
        >
          ${asset.favorite ? "★ 取消收藏" : "☆ 收藏这个素材"}
        </button>
        <button class="toolbar-button toolbar-button-primary" data-action="save-asset-meta">
          保存素材信息
        </button>
      </div>
      ${renderInlineAssetTags(asset.tags ?? [])}
    </article>
    ${renderDetailRows([
      ["素材名称", asset.name],
      ["素材类型", getAssetTypeLabel(asset.type)],
      ["文件路径", asset.path],
      ["文件状态", asset.fileExists ? "已导入，可直接预览" : "还没找到真实文件"],
      ["文件大小", asset.fileExists ? formatFileSize(asset.fileSizeBytes) : "暂时未知"],
      ["标签", asset.tags?.join(" / ") || "未填写"],
      ["使用状态", usages.length > 0 ? `已使用 ${usages.length} 处` : "暂时未使用"],
      ["重复检查", duplicateInfo ? duplicateInfo.summary : "当前没有明显重复信号"],
    ])}
    ${renderNativeRuntime3dAssetRiskDetail(asset)}
    ${renderAssetMediaBudgetDetail(asset)}
    <article class="detail-card asset-danger-card">
      <strong>删除这个${escapeHtml(assetTypeLabel)}</strong>
      <div class="scene-card-tags">
        ${
          usages.length > 0
            ? `<span class="issue-tag warn-text">正在被 ${usages.length} 处引用，暂时不能删除</span>`
            : `<span class="issue-tag danger-text">当前没有引用，可以删除</span>`
        }
      </div>
      <p class="helper-text">
        ${
          usages.length > 0
            ? `先把剧情、角色或其他位置里对这个${assetTypeLabel}的引用解除，再回来删除。${usagePreview ? `当前最前面的引用有：${escapeHtml(usagePreview)}` : ""}`
            : `这里删掉的是当前这个${assetTypeLabel}条目。这个动作不能撤回；如仅需更换文件，优先使用上面的“替换当前文件”。`
        }
      </p>
      <div class="detail-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-danger"
          data-action="delete-asset"
          ${usages.length > 0 ? "disabled" : ""}
        >
          删掉这个${escapeHtml(assetTypeLabel)}
        </button>
      </div>
    </article>
    ${renderAssetDuplicateRecommendationCard(asset, duplicateInfo)}
    <article class="detail-card">
      <strong>疑似重复素材</strong>
      ${renderAssetDuplicateList(asset, duplicateOverview)}
    </article>
    <article class="detail-card">
      <strong>被这些位置使用</strong>
      ${renderAssetUsageList(usages)}
    </article>
  `;
}

function renderAssetMediaBudgetDetail(asset) {
  const risk = getAssetMediaBudgetRisk(asset);
  if (!risk) {
    return "";
  }

  return `
    <article class="detail-card asset-gap-focus-card">
      <strong>素材性能预算</strong>
      <div class="scene-card-tags">
        <span class="issue-tag ${risk.severity === "blocker" ? "danger-text" : "warn-text"}">${escapeHtml(risk.severityLabel)}</span>
        <span class="issue-tag">${escapeHtml(risk.typeLabel)}</span>
        <span class="issue-tag">当前 ${escapeHtml(risk.fileSizeLabel)}</span>
      </div>
      <p class="helper-text">${escapeHtml(risk.suggestion)}</p>
      ${renderDetailRows([
        ["建议预算", risk.warnLabel],
        ["明显超预算线", risk.blockerLabel],
        ["当前体积", risk.fileSizeLabel],
      ])}
      <div class="detail-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-primary"
          data-action="focus-asset-gap"
          data-asset-filter-mode="media_budget"
        >
          只看体积风险素材
        </button>
      </div>
    </article>
  `;
}

function renderNativeRuntime3dAssetRiskDetail(asset) {
  const risk = getNativeRuntime3dRiskForAsset(asset.id);
  if (!risk) {
    return "";
  }

  const exportResult = state.lastExportResult;
  const usagePreview = Array.isArray(risk.usagePreview) ? risk.usagePreview.filter(Boolean) : [];
  const issueBreakdown = Array.isArray(risk.issueBreakdown) ? risk.issueBreakdown.filter(Boolean) : [];
  return `
    <article class="detail-card asset-gap-focus-card">
      <strong>3D 发布体检定位</strong>
      <div class="scene-card-tags">
        <span class="issue-tag warn-text">${escapeHtml(risk.statusLabel ?? "需要复核")}</span>
        <span class="issue-tag">${escapeHtml(risk.typeLabel ?? getAssetTypeLabel(asset.type))}</span>
        ${
          Number.isFinite(Number(risk.usageCount))
            ? `<span class="issue-tag">引用 ${Number(risk.usageCount)} 处</span>`
            : ""
        }
      </div>
      <p class="helper-text">${escapeHtml(
        risk.summary ?? "最近一次原生 Runtime 3D 体检标记了这个素材，建议发布前处理。"
      )}</p>
      ${
        issueBreakdown.length
          ? `<div class="story-filter-chip-row">
              ${issueBreakdown
                .map((item) => `<span class="issue-tag warn-text">${escapeHtml(`${item.label ?? "风险"} ${item.count ?? 0}`)}</span>`)
                .join("")}
            </div>`
          : ""
      }
      ${renderDetailRows([
        ["建议动作", risk.recommendedAction ?? "复核 3D 资产导入状态。"],
        ["导出路径", risk.exportUrl || "未记录"],
        ["引用位置", usagePreview.length ? usagePreview.join(" / ") : "最近报告没有记录引用位置"],
      ])}
      <div class="detail-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-primary"
          data-action="focus-asset-gap"
          data-asset-filter-mode="asset3d_risk"
        >
          只看 3D 风险素材
        </button>
        ${
          exportResult?.asset3dSummaryPublicUrl
            ? `<a class="toolbar-button" href="${escapeHtml(exportResult.asset3dSummaryPublicUrl)}" target="_blank" rel="noreferrer">打开 3D 摘要</a>`
            : ""
        }
        ${
          exportResult?.asset3dReportPublicUrl
            ? `<a class="toolbar-button" href="${escapeHtml(exportResult.asset3dReportPublicUrl)}" target="_blank" rel="noreferrer">打开机器清单</a>`
            : ""
        }
      </div>
    </article>
  `;
}

function renderAssetDuplicateRecommendationCard(asset, duplicateInfo) {
  if (!duplicateInfo) {
    return "";
  }

  if (duplicateInfo.isPreferred) {
    return `
      <article class="detail-card">
        <strong>整理结论</strong>
        <div class="scene-card-tags">
          <span class="issue-tag good-text">这组里优先保留这一项</span>
        </div>
        <p class="helper-text">${escapeHtml(duplicateInfo.preferredNotes.join(" · "))}</p>
      </article>
    `;
  }

  return `
    <article class="detail-card">
      <strong>整理结论</strong>
      <div class="scene-card-tags">
        <span class="issue-tag warn-text">优先保留：${escapeHtml(duplicateInfo.preferredAsset?.name ?? "")}</span>
      </div>
      <p class="helper-text">${escapeHtml(duplicateInfo.preferredNotes.join(" · "))}</p>
      <div class="detail-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-primary"
          data-action="open-asset-from-issue"
          data-asset-id="${duplicateInfo.preferredAssetId}"
        >
          打开主版本项
        </button>
      </div>
    </article>
  `;
}

function renderAssetDuplicateList(asset, duplicateOverview = buildAssetDuplicateOverview()) {
  const info = duplicateOverview.infoByAssetId.get(asset.id);

  if (!info || info.relatedIds.length === 0) {
    return `<div class="detail-meta">当前还没有发现和这个素材高度相似的条目。</div>`;
  }

  return `
    <div class="asset-duplicate-shell">
      <div class="scene-card-tags">
        ${getAssetDuplicateReasonLabels(info).map((label) => `<span class="issue-tag ${label.toneClass}">${escapeHtml(label.text)}</span>`).join("")}
      </div>
      <div class="helper-text">${escapeHtml(info.reasonNote)}</div>
      <div class="asset-duplicate-list">
        ${info.relatedIds
          .map((assetId) => state.data.assetsById.get(assetId))
          .filter(Boolean)
          .map((relatedAsset) => {
            const relatedUsage = getAssetUsageCount(relatedAsset.id);
            const reasonLabels = getAssetDuplicateReasonLabels(info, relatedAsset.id);
            return `
              <article class="asset-duplicate-item">
                <div class="asset-duplicate-copy">
                  <strong>${escapeHtml(relatedAsset.name)}</strong>
                  <div class="detail-meta">${escapeHtml(relatedAsset.path)} · ${escapeHtml(getAssetTypeLabel(relatedAsset.type))} · ${
                    relatedUsage > 0 ? `已使用 ${relatedUsage} 处` : "暂时未使用"
                  }</div>
                  <div class="scene-card-tags">
                    ${relatedAsset.id === info.preferredAssetId ? `<span class="issue-tag good-text">主版本</span>` : ""}
                    ${reasonLabels.map((label) => `<span class="issue-tag ${label.toneClass}">${escapeHtml(label.text)}</span>`).join("")}
                    ${
                      relatedAsset.fileExists
                        ? `<span class="issue-tag good-text">文件已就绪</span>`
                        : `<span class="issue-tag ${relatedUsage > 0 ? "warn-text" : ""}">${
                            relatedUsage > 0 ? "已引用但缺文件" : "待导入"
                          }</span>`
                    }
                  </div>
                </div>
                <div class="script-entry-actions">
                  <button type="button" class="toolbar-button toolbar-button-primary" data-action="open-asset-from-issue" data-asset-id="${relatedAsset.id}">
                    打开这个素材
                  </button>
                </div>
              </article>
            `;
          })
          .join("")}
      </div>
    </div>
  `;
}

function renderAssetUsageList(usages) {
  if (!usages.length) {
    return `<div class="detail-meta">当前还没有找到使用记录。</div>`;
  }

  return `
    <div class="asset-usage-list">
      ${usages
        .map((usage) => {
          const actionButton =
            usage.kind === "story"
              ? `
                  <button
                    type="button"
                    class="toolbar-button toolbar-button-primary"
                    data-action="open-character-line"
                    data-scene-id="${escapeHtml(usage.sceneId ?? "")}"
                    data-block-id="${escapeHtml(usage.blockId ?? "")}"
                  >
                    打开这处使用
                  </button>
                `
              : usage.kind === "character"
                ? `
                    <button
                      type="button"
                      class="toolbar-button"
                      data-action="open-dashboard-character"
                      data-character-id="${escapeHtml(usage.characterId ?? "")}"
                    >
                      看角色资料
                    </button>
                  `
                : "";

          return `
            <article class="asset-usage-item">
              <div class="asset-usage-copy">
                <strong>${escapeHtml(usage.label ?? "使用位置")}</strong>
                ${
                  usage.meta
                    ? `<div class="detail-meta">${escapeHtml(usage.meta)}</div>`
                    : ""
                }
              </div>
              <div class="script-entry-actions">
                ${actionButton}
              </div>
            </article>
          `;
        })
        .join("")}
    </div>
  `;
}

function renderInlineAssetTags(tags) {
  if (!tags.length) {
    return `<div class="helper-text">这个素材还没有标签。可补上“校园 / 黄昏 / 教室 / 日常”等标签，后续筛选会更方便。</div>`;
  }

  return `
    <div class="asset-tag-chip-row">
      ${tags.map((tag) => renderAssetTagChip(tag)).join("")}
    </div>
  `;
}

function renderAssetTagFilterBar(assets) {
  const tagCounts = getAssetTagCounts(assets);

  if (!tagCounts.length) {
    return `<div class="helper-text">当前这一类素材还没有标签。可在右侧补充标签，后续搜索会更方便。</div>`;
  }

  const activeLabel = state.assetTagFilter
    ? `<span class="helper-text">当前标签：${escapeHtml(state.assetTagFilter)}</span>`
    : `<span class="helper-text">点标签可以快速筛选当前分类。</span>`;

  return `
    <div class="asset-tag-filter-head">
      ${activeLabel}
      ${
        state.assetTagFilter
          ? `<button class="toolbar-button" data-action="clear-asset-search">清空全部筛选</button>`
          : ""
      }
    </div>
    <div class="asset-tag-chip-row">
      ${tagCounts.map(({ tag, count }) => renderAssetTagChip(tag, count)).join("")}
    </div>
  `;
}

function renderAssetPresetTagBar(selectedAsset, currentCheckedIds) {
  const presetTags = getAssetPresetTags(state.selectedAssetType);

  if (!presetTags.length) {
    return "";
  }

  const helperText =
    currentCheckedIds.length > 0
      ? `当前会优先给勾选的 ${currentCheckedIds.length} 个素材快速加标签。`
      : selectedAsset
        ? `现在点一下会把标签加到当前素材：${selectedAsset.name}`
        : "先选中一个素材，或者先勾选几项，再点下面的标签。";

  return `
    <div class="asset-tag-filter-head">
      <span class="asset-selection-note">${escapeHtml(helperText)}</span>
    </div>
    <div class="asset-tag-chip-row">
      ${presetTags.map((tag) => renderAssetPresetTagChip(tag)).join("")}
    </div>
  `;
}

function renderAssetTagChip(tag, count = null) {
  return `
    <button
      class="asset-tag-chip ${state.assetTagFilter === tag ? "is-active" : ""}"
      data-action="select-asset-tag"
      data-asset-tag="${escapeHtml(tag)}"
    >
      <span>${escapeHtml(tag)}</span>
      ${count === null ? "" : `<strong>${count}</strong>`}
    </button>
  `;
}

function renderAssetPresetTagChip(tag) {
  return `
    <button
      class="asset-tag-chip asset-preset-tag-chip"
      data-action="apply-asset-preset-tag"
      data-preset-tag="${escapeHtml(tag)}"
    >
      ${escapeHtml(tag)}
    </button>
  `;
}

function getAssetTagCounts(assets) {
  const counts = new Map();
  assets.forEach((asset) => {
    (asset.tags ?? []).forEach((tag) => {
      const cleanTag = String(tag ?? "").trim();
      if (!cleanTag) {
        return;
      }
      counts.set(cleanTag, (counts.get(cleanTag) ?? 0) + 1);
    });
  });

  return Array.from(counts.entries())
    .sort((left, right) => left[0].localeCompare(right[0], "zh-Hans-CN"))
    .map(([tag, count]) => ({ tag, count }));
}

function getAssetFilterSummary() {
  const parts = [getAssetFilterModeLabel(state.assetFilterMode)];
  if (state.assetFavoriteOnly) {
    parts.push("仅看收藏");
  }
  if (state.assetSearchQuery.trim()) {
    parts.push(`搜索：${state.assetSearchQuery.trim()}`);
  }
  if (state.assetTagFilter) {
    parts.push(`标签：${state.assetTagFilter}`);
  }
  if (state.assetSortMode !== "default") {
    parts.push(`排序：${getAssetSortLabel(state.assetSortMode)}`);
  }
  return parts.join(" · ");
}

function getAssetEmptyMessage(fallback = "这个分类里暂时没有素材。") {
  if (state.assetFavoriteOnly && state.assetSearchQuery.trim() && state.assetTagFilter) {
    return `收藏素材里没有同时匹配“${state.assetSearchQuery.trim()}”和标签“${state.assetTagFilter}”的内容。`;
  }
  if (state.assetFavoriteOnly && state.assetSearchQuery.trim()) {
    return `收藏素材里没有匹配“${state.assetSearchQuery.trim()}”的内容。`;
  }
  if (state.assetFavoriteOnly && state.assetTagFilter) {
    return `收藏素材里没有标签为“${state.assetTagFilter}”的内容。`;
  }
  if (state.assetFavoriteOnly) {
    return "当前还没有收藏素材。可先点击卡片上的星标收藏常用素材。";
  }
  if (state.assetSearchQuery.trim() && state.assetTagFilter) {
    return `没有找到同时匹配“${state.assetSearchQuery.trim()}”和标签“${state.assetTagFilter}”的素材。`;
  }
  if (state.assetSearchQuery.trim()) {
    return `没有找到匹配“${state.assetSearchQuery.trim()}”的素材。`;
  }
  if (state.assetTagFilter) {
    return `当前分类里没有标签为“${state.assetTagFilter}”的素材。`;
  }
  if (state.assetFilterMode === "unused") {
    return "这个分类里目前没有未使用素材。";
  }
  if (state.assetFilterMode === "missing_file") {
    return "这个分类里目前没有待导入素材。";
  }
  if (state.assetFilterMode === "urgent_missing") {
    return "这个分类里目前没有“已引用但缺文件”的素材。";
  }
  if (state.assetFilterMode === "duplicate") {
    return "这个分类里目前没有疑似重复素材。";
  }
  if (state.assetFilterMode === "asset3d_risk") {
    return "最近一次原生 Runtime 3D 体检里没有需要定位的风险素材。";
  }
  if (state.assetFilterMode === "media_budget") {
    return "当前分类里没有明显超出发布预算的大素材。";
  }
  return fallback;
}

function parseAssetTagsInput(value) {
  return Array.from(
    new Set(
      String(value ?? "")
        .split(/[\n,，、;；]+/)
        .map((tag) => tag.trim())
        .filter(Boolean)
    )
  ).slice(0, 20);
}

function clearAssetSearchFilters() {
  state.assetFilterMode = "all";
  state.assetSearchQuery = "";
  state.assetTagFilter = "";
  state.assetFavoriteOnly = false;
  if (refs.assetSearchInput) {
    refs.assetSearchInput.value = "";
  }
  renderAssetsScreen();
  setSaveStatus("已清空素材筛选条件");
}

function toggleFavoriteAssetsFilter() {
  state.assetFavoriteOnly = !state.assetFavoriteOnly;
  renderAssetsScreen();
  setSaveStatus(state.assetFavoriteOnly ? "现在只显示收藏素材" : "已恢复显示全部收藏状态");
}

async function saveSelectedAssetMetadata() {
  const asset = getSelectedAsset();
  if (!asset) {
    setSaveStatus("先选中一个素材");
    return;
  }

  const nameInput = document.getElementById("assetMetaNameInput");
  const tagsInput = document.getElementById("assetMetaTagsInput");
  const name = String(nameInput?.value ?? "").trim();
  const tags = parseAssetTagsInput(tagsInput?.value ?? "");

  if (!name) {
    window.alert("素材名称不能为空。");
    setSaveStatus("素材名称不能为空", true);
    return;
  }

  try {
    setSaveStatus(`正在保存素材信息：${asset.name}`);
    await postJson(API_UPDATE_ASSET_META, {
      assetId: asset.id,
      name,
      tags,
    });

    if (state.assetTagFilter && !tags.includes(state.assetTagFilter)) {
      state.assetTagFilter = "";
    }

    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: asset.id,
    });
    setSaveStatus(`素材信息已保存：${name}`);
    showToast(`素材信息已保存：${name}`);
  } catch (error) {
    setSaveStatus("保存素材信息失败", true);
    showToast("保存素材信息失败", "error");
    window.alert(`保存素材信息没有成功：${error.message}`);
  }
}

async function toggleAssetFavorite(assetId) {
  const asset = state.data?.assetsById.get(assetId);
  if (!asset) {
    return;
  }

  try {
    const nextFavorite = !asset.favorite;
    setSaveStatus(`${nextFavorite ? "正在收藏" : "正在取消收藏"}：${asset.name}`);
    await postJson(API_UPDATE_ASSET_META, {
      assetId: asset.id,
      favorite: nextFavorite,
    });
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: asset.id,
    });
    setSaveStatus(`${nextFavorite ? "已收藏" : "已取消收藏"}：${asset.name}`);
    showToast(`${nextFavorite ? "已收藏" : "已取消收藏"}：${asset.name}`);
  } catch (error) {
    setSaveStatus("切换收藏失败", true);
    showToast("切换收藏失败", "error");
    window.alert(`切换收藏状态没有成功：${error.message}`);
  }
}

async function saveCharacterPresentation(characterId) {
  const character = state.data?.charactersById.get(characterId);
  if (!character) {
    setSaveStatus("先选中一个角色", true);
    return;
  }

  const presentation = {
    mode: getSafeCharacterPresentationMode(document.getElementById("characterPresentationModeSelect")?.value),
    fallbackSpriteAssetId: document.getElementById("characterPresentationFallbackSpriteSelect")?.value || "",
    live2d: {
      modelAssetId: document.getElementById("characterPresentationLive2dAssetSelect")?.value || "",
      idleMotion: String(document.getElementById("characterPresentationLive2dIdleInput")?.value ?? "").trim(),
      blink: Boolean(document.getElementById("characterPresentationLive2dBlinkInput")?.checked),
      breath: Boolean(document.getElementById("characterPresentationLive2dBreathInput")?.checked),
      lipSync: Boolean(document.getElementById("characterPresentationLive2dLipSyncInput")?.checked),
      cursorTracking: Boolean(document.getElementById("characterPresentationLive2dCursorInput")?.checked),
    },
    model3d: {
      modelAssetId: document.getElementById("characterPresentationModel3dAssetSelect")?.value || "",
      idleAnimation: String(document.getElementById("characterPresentationModel3dIdleInput")?.value ?? "").trim(),
    },
  };
  const expressionBindings = Array.from(document.querySelectorAll(".character-expression-binding-card")).map((card) => ({
    expressionId: card.dataset.expressionId || "",
    layerAssetIds: parseCharacterLayerAssetIds(card.querySelector(".characterExpressionLayerAssetsInput")?.value),
    live2dExpression: String(card.querySelector(".characterExpressionLive2dExpressionInput")?.value ?? "").trim(),
    live2dMotion: String(card.querySelector(".characterExpressionLive2dMotionInput")?.value ?? "").trim(),
    model3dExpression: String(card.querySelector(".characterExpressionModel3dExpressionInput")?.value ?? "").trim(),
    model3dAnimation: String(card.querySelector(".characterExpressionModel3dAnimationInput")?.value ?? "").trim(),
  }));

  try {
    setSaveStatus(`正在保存角色表现：${character.displayName}`);
    await postJson(API_UPDATE_CHARACTER_PRESENTATION, {
      characterId: character.id,
      presentation,
      expressionBindings,
    });
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedCharacterId: character.id,
    });
    setSaveStatus(`角色表现已保存：${character.displayName}`);
    showToast(`角色表现已保存：${character.displayName}`);
  } catch (error) {
    setSaveStatus("保存角色表现失败", true);
    showToast("保存角色表现失败", "error");
    window.alert(`保存角色表现没有成功：${error.message}`);
  }
}

async function applyBulkAssetTags(mode) {
  const checkedAssets = getCurrentCheckedAssetsOfSelectedType();
  const assets = checkedAssets.length > 0 ? checkedAssets : getCurrentFilteredAssetsOfSelectedType();
  if (!assets.length) {
    setSaveStatus("当前筛选结果里没有可批量处理的素材", true);
    return;
  }

  const tags = parseAssetTagsInput(refs.assetBulkTagsInput?.value ?? "");
  if (!tags.length) {
    window.alert("先输入至少一个标签，再批量处理。");
    setSaveStatus("先输入至少一个标签", true);
    return;
  }

  const actionLabel = mode === "remove" ? "移除" : "添加";
  const targetLabel =
    checkedAssets.length > 0 ? `当前勾选的 ${checkedAssets.length} 个素材` : `当前筛选结果里的 ${assets.length} 个素材`;
  const confirmed = window.confirm(
    `确定要给${targetLabel}批量${actionLabel}标签吗？\n\n标签：${tags.join(" / ")}`
  );
  if (!confirmed) {
    return;
  }

  try {
    setSaveStatus(`正在批量${actionLabel}标签...`);
    const result = await postJson(API_BULK_UPDATE_ASSET_TAGS, {
      assetIds: assets.map((asset) => asset.id),
      mode,
      tags,
    });

    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: state.selectedAssetType,
      selectedAssetId: getSelectedAsset()?.id ?? state.selectedAssetId,
    });
    if (refs.assetBulkTagsInput) {
      refs.assetBulkTagsInput.value = "";
    }
    setSaveStatus(`已批量${actionLabel}标签：${result.updatedCount} 个素材`);
    showToast(`已批量${actionLabel}标签：${result.updatedCount} 个素材`);
  } catch (error) {
    setSaveStatus("批量改标签失败", true);
    showToast("批量改标签失败", "error");
    window.alert(`批量改标签没有成功：${error.message}`);
  }
}

async function applyPresetTag(tag) {
  const cleanTag = String(tag ?? "").trim();
  if (!cleanTag) {
    return;
  }

  const checkedAssets = getCurrentCheckedAssetsOfSelectedType();
  const selectedAsset = getSelectedAsset();
  const targetAssets = checkedAssets.length > 0 ? checkedAssets : selectedAsset ? [selectedAsset] : [];

  if (!targetAssets.length) {
    setSaveStatus("先选中或勾选至少一个素材", true);
    showToast("先选中一个素材，再点预设标签", "error");
    return;
  }

  try {
    const targetLabel =
      checkedAssets.length > 0 ? `勾选的 ${checkedAssets.length} 个素材` : `当前素材：${selectedAsset?.name ?? ""}`;
    setSaveStatus(`正在添加预设标签：${cleanTag}`);
    await postJson(API_BULK_UPDATE_ASSET_TAGS, {
      assetIds: targetAssets.map((asset) => asset.id),
      mode: "add",
      tags: [cleanTag],
    });
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: state.selectedAssetType,
      selectedAssetId: selectedAsset?.id ?? targetAssets[0]?.id ?? state.selectedAssetId,
    });
    setSaveStatus(`已给${targetLabel}加上标签：${cleanTag}`);
    showToast(`已加预设标签：${cleanTag}`);
  } catch (error) {
    setSaveStatus("添加预设标签失败", true);
    showToast("添加预设标签失败", "error");
    window.alert(`添加预设标签没有成功：${error.message}`);
  }
}

function renderAssetThumb(asset) {
  const statusLabel = asset.fileExists ? "已导入" : "待导入";
  const statusClass = asset.fileExists ? "is-ready" : "is-missing";
  const previewUrl = getAssetPublicUrl(asset);

  if (asset.fileExists && previewUrl && isImageAssetType(asset.type)) {
    return `
      <div class="asset-thumb asset-thumb-visual" data-asset-type="${asset.type}">
        <img
          class="asset-thumb-image"
          src="${escapeHtml(previewUrl)}"
          alt="${escapeHtml(asset.name)}"
          loading="lazy"
        />
        <span class="asset-thumb-status ${statusClass}">${statusLabel}</span>
      </div>
    `;
  }

  const helperText = isAudioAssetType(asset.type)
    ? "点下面按钮就能试听"
    : isVideoAssetType(asset.type)
      ? "可在右侧详情里播放"
      : asset.fileExists
        ? "右侧可以看大图预览"
        : "先把真实文件导进来";

  return `
    <div class="asset-thumb" data-asset-type="${asset.type}">
      <span class="asset-thumb-status ${statusClass}">${statusLabel}</span>
      <div class="asset-thumb-label">${escapeHtml(getAssetTypeLabel(asset.type))}</div>
      <div class="asset-thumb-note">${escapeHtml(helperText)}</div>
    </div>
  `;
}

function renderAssetPreviewCard(asset) {
  const previewUrl = getAssetPublicUrl(asset);
  const audioButtonLabel = state.activeAssetAudioId === asset.id ? "停止试听" : "试听一下";

  if (!asset.fileExists || !previewUrl) {
    return `
      <article class="detail-card">
        <strong>素材预览</strong>
        <div class="asset-preview-panel asset-preview-empty">
          <div class="empty-note">这个素材条目已经建好了，但真实文件还没导入，所以现在还不能预览。</div>
        </div>
      </article>
    `;
  }

  if (isImageAssetType(asset.type)) {
    return `
      <article class="detail-card">
        <strong>素材预览</strong>
        <div class="asset-preview-panel">
          <img class="asset-preview-image" src="${escapeHtml(previewUrl)}" alt="${escapeHtml(asset.name)}" />
        </div>
      </article>
    `;
  }

  if (isAudioAssetType(asset.type)) {
    return `
      <article class="detail-card">
        <strong>素材预览</strong>
        <div class="asset-preview-panel">
          <audio class="asset-preview-audio" controls preload="none" src="${escapeHtml(previewUrl)}"></audio>
          <div class="detail-actions">
            <button class="toolbar-button" data-action="toggle-asset-audio" data-asset-id="${asset.id}">
              ${audioButtonLabel}
            </button>
          </div>
        </div>
      </article>
    `;
  }

  if (isVideoAssetType(asset.type)) {
    return `
      <article class="detail-card">
        <strong>素材预览</strong>
        <div class="asset-preview-panel">
          <video class="asset-preview-video" controls preload="metadata" playsinline src="${escapeHtml(previewUrl)}"></video>
        </div>
      </article>
    `;
  }

  return `
    <article class="detail-card">
      <strong>素材预览</strong>
      <div class="asset-preview-panel asset-preview-empty">
        <div class="empty-note">这个素材类型暂时还没有专门的预览方式，但文件已经就绪了。</div>
      </div>
    </article>
  `;
}

function renderMiniStage(scene, blockIndex) {
  return `
    <div class="mini-stage" style="${getStageContainerStyle()}">
      ${renderStage(computeVisualState(scene, blockIndex), false)}
    </div>
  `;
}

function renderStage(visualState, large, options = {}) {
  const backdrop = `${getBackdropStyle(visualState.backgroundAssetId, visualState.scene3dPreview)}; ${getDepthBlurBackdropStyle(visualState.depthBlur)}`;
  const dialogPresentation = buildDialogBoxPresentation(options.dialogTheme, state.data?.project, state.data?.assetsById);
  const particleMarkup = renderParticleEffectLayer(
    visualState.particleEffect,
    large,
    visualState.depthBlur,
    visualState
  );
  const filterMarkup = renderStageFilterLayer(visualState.screenFilter);
  const flashMarkup = renderScreenFlashLayer(visualState.screenFlash);
  const fadeMarkup = renderStageFadeLayer(visualState.screenFade);
  const shakePresentation = getScreenShakePresentation(visualState.screenShake);
  const worldPresentation = getStageWorldPresentation(
    visualState.cameraZoom,
    visualState.cameraPan,
    visualState.screenFilter
  );
  const castMarkup = renderStageCastMarkup(
    visualState.visibleCharacters,
    visualState.depthBlur,
    visualState.characterTransitionEvent,
    visualState.activeCharacterId,
    visualState.characterEmphasisEvent
  );
  const dialogueText = options.dialogueTextOverride ?? visualState.dialogueText;
  const choiceMarkup =
    large && (options.choiceOptions?.length ?? 0) > 0
      ? `
        <div class="preview-choice-list">
          ${options.choiceOptions
            .map(
              (option) => `
                <button class="preview-choice-button" data-action="preview-choice" data-option-id="${option.id}">
                  <strong>${escapeHtml(option.text)}</strong>
                  <span>进入 ${escapeHtml(
                    state.data.scenesById.get(option.gotoSceneId)?.name ?? option.gotoSceneId
                  )}</span>
                </button>
              `
            )
            .join("")}
        </div>
      `
      : "";
  const hintMarkup = options.hint
    ? `<div class="preview-hint ${options.isComplete ? "preview-hint-complete" : ""}">${escapeHtml(
        options.hint
      )}</div>`
    : "";
  const dialogHiddenHintMarkup =
    large && options.dialogHidden
      ? `<div class="dialog-hidden-hint">对话框已隐藏，点画面、按 H 或右键恢复。</div>`
      : "";
  const stageEffectTokens = [
    visualState.screenShake
      ? `<span class="stage-token">震动：${escapeHtml(getShakeIntensityLabel(visualState.screenShake.intensity))}</span>`
      : "",
    visualState.screenFlash
      ? `<span class="stage-token">闪屏：${escapeHtml(getFlashColorLabel(visualState.screenFlash.color))}</span>`
      : "",
    visualState.screenFade
      ? `<span class="stage-token">黑场：${escapeHtml(getFadeColorLabel(visualState.screenFade.color))}</span>`
      : "",
    visualState.cameraZoom
      ? `<span class="stage-token">镜头：${escapeHtml(getCameraZoomActionLabel(visualState.cameraZoom.action))}</span>`
      : "",
    visualState.cameraPan
      ? `<span class="stage-token">平移：${escapeHtml(getCameraPanTargetLabel(visualState.cameraPan.target))}</span>`
      : "",
    visualState.screenFilter
      ? `<span class="stage-token">滤镜：${escapeHtml(getScreenFilterPresetLabel(visualState.screenFilter.preset))}</span>`
      : "",
    visualState.depthBlur
      ? `<span class="stage-token">景深：${escapeHtml(getDepthBlurFocusLabel(visualState.depthBlur.focus))}</span>`
      : "",
  ]
    .filter(Boolean)
    .join("");

  return `
    <div class="stage-scene ${shakePresentation.className}" ${shakePresentation.style ? `style="${shakePresentation.style}"` : ""}>
      <div class="stage-world" ${worldPresentation.style ? `style="${worldPresentation.style}"` : ""}>
        <div class="stage-backdrop" style="${backdrop}"></div>
        ${particleMarkup}
        <div class="stage-cast stage-cast-world">${castMarkup}</div>
      </div>
      ${filterMarkup}
      ${fadeMarkup}
      <div class="stage-overlay ${large ? "stage-overlay-large" : ""}" data-dialog-anchor="${dialogPresentation.anchor}">
        <div class="stage-topline">
          <span class="stage-token">背景：${escapeHtml(visualState.backgroundName)}</span>
          <span class="stage-token">音乐：${escapeHtml(visualState.musicName)}</span>
          ${
            visualState.particleEffect
              ? `<span class="stage-token">特效：${escapeHtml(
                  describeParticleEffect(visualState.particleEffect)
                )}</span>`
              : ""
          }
          ${stageEffectTokens}
        </div>
        ${dialogHiddenHintMarkup}
        <div
          class="dialog-box ${options.dialogHidden ? "is-hidden" : ""}"
          data-dialog-theme="${dialogPresentation.theme}"
          style="${dialogPresentation.style}"
        >
          <div class="dialog-box-art ${dialogPresentation.assetUrl ? "has-image" : ""}"></div>
          <div class="dialog-speaker">${escapeHtml(visualState.speakerName)}</div>
          <div class="dialog-text ${options.isTyping ? "is-typing" : ""}">${escapeHtml(dialogueText)}</div>
          ${choiceMarkup}
          ${hintMarkup}
        </div>
      </div>
      ${flashMarkup}
    </div>
  `;
}

function renderStageCastMarkup(
  visibleCharacters,
  depthBlur,
  characterTransitionEvent,
  activeCharacterId,
  characterEmphasisEvent
) {
  const cards = [...(visibleCharacters ?? [])];

  if (characterTransitionEvent?.mode === "hide" && characterTransitionEvent.characterState) {
    cards.push({
      ...characterTransitionEvent.characterState,
      __ghostMode: "hide",
    });
  }

  if (cards.length === 0) {
    return `<div class="empty-note">当前画面还没有角色站在画面里。</div>`;
  }

  return cards
    .sort((left, right) => getPositionOrder(left.position) - getPositionOrder(right.position))
    .map((characterState) =>
      renderStageSpriteCard(
        characterState,
        depthBlur,
        characterTransitionEvent,
        activeCharacterId,
        characterEmphasisEvent
      )
    )
    .join("");
}

function renderStageSpriteCard(
  characterState,
  depthBlur,
  characterTransitionEvent,
  activeCharacterId,
  characterEmphasisEvent
) {
  const character = state.data.charactersById.get(characterState.characterId);
  const classes = ["sprite-card"];
  const isGhostHide = characterState.__ghostMode === "hide";
  const presentationLabel = character ? getCharacterPresentationModeLabel(character) : "普通立绘";
  const expression = (character?.expressions ?? []).find((item) => item.id === characterState.expressionId);
  const expressionBindingStatus = getCharacterExpressionBindingStatus(expression);

  if (shouldBlurStageCharacter(characterState.position, depthBlur)) {
    classes.push("is-depth-muted");
    classes.push(`depth-strength-${getSafeDepthBlurStrength(depthBlur?.strength)}`);
  } else if (depthBlur) {
    classes.push("is-depth-focus");
  }

  if (characterTransitionEvent?.mode === "show" && characterTransitionEvent.characterId === characterState.characterId) {
    classes.push("is-entering");
  }

  if (isGhostHide) {
    classes.push("is-leaving");
  }

  classes.push("is-breathing");

  if (activeCharacterId === characterState.characterId) {
    classes.push("is-speaking");
  }

  if (characterEmphasisEvent?.characterId === characterState.characterId) {
    classes.push("is-emphasis");
  }

  return `
    <div class="${classes.join(" ")}" data-position="${characterState.position}" data-presentation="${escapeHtml(getCharacterPresentation(character).mode)}">
      <div class="sprite-card-inner">
        <div class="sprite-name">${escapeHtml(character?.displayName ?? characterState.characterId)}</div>
        <div class="sprite-expression">${escapeHtml(characterState.expressionName)}</div>
        <div class="sprite-presentation">${escapeHtml(presentationLabel)} · ${escapeHtml(expressionBindingStatus.label)}</div>
      </div>
    </div>
  `;
}

function shouldBlurStageCharacter(position, depthBlur) {
  if (!depthBlur) {
    return false;
  }

  const focus = getSafeDepthBlurFocus(depthBlur.focus);
  return focus !== "full" && position !== focus;
}

function renderParticleEffectLayer(particleEffect, large = false, depthBlur = null, stageContext = null) {
  if (!particleEffect) {
    return "";
  }

  const config = normalizeParticleEffectConfig(particleEffect);
  const combos = buildParticleComboVariants(config);

  return `
    <div
      class="stage-particle-layer"
      data-particle-preset="${config.preset}"
      data-particle-intensity="${config.intensity}"
      data-particle-speed="${config.speed}"
      data-particle-wind="${config.wind}"
      data-particle-area="${config.area}"
      data-particle-combo="${config.comboPreset}"
      data-particle-emission="${config.emissionMode}"
      data-particle-emitter-shape="${config.emitterShape}"
      data-particle-follow="${config.follow}"
      data-particle-blend="${config.blend}"
      data-particle-layers="${config.layerCount}"
      data-has-custom-image="${config.assetId ? "true" : "false"}"
      style="${getDepthBlurParticleStyle(depthBlur)}"
      aria-hidden="true"
    >
      ${combos
        .map((comboConfig) => {
          const layers = buildParticleLayerVariants(comboConfig);
          return layers
            .map((layerConfig) => {
              const particleCount = getParticleItemCount(layerConfig, large);
              return Array.from({ length: particleCount }, (_, index) =>
                renderParticleItem(
                  layerConfig,
                  comboConfig.__comboIndex * 10000 + layerConfig.__layerIndex * 1000 + index,
                  stageContext
                )
              ).join("");
            })
            .join("");
        })
        .join("")}
    </div>
  `;
}

function renderParticleItem(particleEffect, index, stageContext = null) {
  const config = normalizeParticleEffectConfig(particleEffect);
  const motion = getParticleMotionProfile(config.preset);
  const areaLayout = getParticleAreaLayout(config.area, 100);
  const anchor = getParticleEmitterAnchor(config, stageContext);
  const emitterShape = getSafeParticleEmitterShape(config.emitterShape);
  const curves = getParticleCurveProfile(config);
  const colorCurve = getParticleColorCurveProfile(config);
  const speedMultiplier = getParticleSpeedMultiplier(config.speed);
  const duration = (config.lifeMin + (config.lifeMax - config.lifeMin) * getParticleRandom(index, 2)) * speedMultiplier;
  const baseSize = config.sizeMin + (config.sizeMax - config.sizeMin) * getParticleRandom(index, 3);
  const depthShift = (getParticleRandom(index, 4) - 0.5) * 2 * (config.spreadZ / 100) + anchor.z / 100;
  const depthScale = 1 + depthShift * 0.42;
  const profileAspect = motion.aspect;
  const width =
    profileAspect === "rain"
      ? Math.max(1.5, baseSize * 0.28)
      : profileAspect === "petal"
        ? baseSize * 1.08
        : profileAspect === "confetti"
          ? baseSize * 0.76
          : baseSize;
  const height =
    profileAspect === "rain"
      ? Math.max(18, baseSize * 8.6)
      : profileAspect === "petal"
        ? Math.max(6, baseSize * 0.82)
        : profileAspect === "confetti"
          ? Math.max(6, baseSize * 1.34)
          : width;
  const seedX = getParticleRandom(index, 5);
  const seedY = getParticleRandom(index, 6);
  const seedAngle = getParticleRandom(index, 13) * Math.PI * 2;
  const seedRadius = Math.sqrt(getParticleRandom(index, 14));
  let left = anchor.x;
  let startY = anchor.y;

  if (emitterShape === "point") {
    left += (seedX - 0.5) * Math.max(4, config.spreadX * 0.12);
    startY += (seedY - 0.5) * Math.max(4, config.spreadY * 0.12);
  } else if (emitterShape === "line") {
    left += (seedX - 0.5) * config.spreadX;
    startY += (seedY - 0.5) * Math.max(4, config.spreadY * 0.12);
  } else if (emitterShape === "box") {
    left += (seedX - 0.5) * config.spreadX;
    startY += (seedY - 0.5) * config.spreadY;
  } else if (emitterShape === "circle") {
    left += Math.cos(seedAngle) * (config.spreadX * 0.5) * seedRadius;
    startY += Math.sin(seedAngle) * (config.spreadY * 0.5) * seedRadius;
  }

  left = clamp(left, areaLayout.start, areaLayout.start + areaLayout.width);
  startY = clamp(startY, -24, 124);

  const travelY = motion.endBase - motion.startBase;
  const fieldX = clamp(config.fieldX, 0, 100);
  const fieldY = clamp(config.fieldY, -20, 120);
  const fieldDeltaX = fieldX - left;
  const fieldDeltaY = fieldY - startY;
  const endY =
    startY +
    travelY +
    config.gravityY * 0.18 +
    config.attractionY * 0.34 +
    fieldDeltaY * curves.force.y * 0.22 +
    (getParticleRandom(index, 15) - 0.5) * config.spreadY * 0.35;
  const windBias = getParticleWindBias(config.wind, config.preset);
  const driftX =
    windBias +
    config.gravityX * 0.88 +
    config.attractionX * 0.58 +
    fieldDeltaX * curves.force.x * 0.24 +
    (getParticleRandom(index, 7) - 0.5) * config.turbulence * 1.9 +
    (getParticleRandom(index, 16) - 0.5) * config.vortex * (0.42 + curves.force.orbit) +
    fieldDeltaY * curves.force.orbit * 0.18 +
    depthShift * config.spreadZ * 0.35;
  const opacityStart =
    config.opacityMin + (config.opacityMax - config.opacityMin) * getParticleRandom(index, 8);
  const opacityMid = clamp(opacityStart * curves.opacity.mid, 0, 1);
  const opacityEnd = clamp(
    opacityStart * curves.opacity.end * (config.preset === "bubbles" ? 1.16 : config.preset === "embers" ? 0.92 : 1),
    0,
    1
  );
  const rotationStart =
    config.rotationMin + (config.rotationMax - config.rotationMin) * getParticleRandom(index, 9);
  const rotationEnd =
    rotationStart +
    config.spin * (0.45 + getParticleRandom(index, 10) * 0.75) +
    config.vortex * (0.4 + getParticleRandom(index, 17) * 0.35);
  const midY = startY + (endY - startY) * (0.5 + getParticleRandom(index, 19) * 0.12);
  const rotationMid = rotationStart + (rotationEnd - rotationStart) * (0.48 + getParticleRandom(index, 20) * 0.14);
  const blur = Math.max(
    0,
    Math.abs(depthShift) * (config.spreadZ / 100) * 4.2 +
      (config.preset === "dust" ? 1.1 : 0) +
      (config.preset === "bubbles" ? 0.8 : 0)
  );
  const scaleBase = 0.68 + depthShift * 0.28 + config.gravityZ * 0.002 + anchor.z * 0.002;
  const scaleStart = clamp(scaleBase * curves.size.start, 0.22, 2.8);
  const scaleMid = clamp(scaleBase * curves.size.mid, 0.18, 3.2);
  const scaleEnd = clamp(
    scaleBase * curves.size.end + config.gravityZ * 0.004 + (motion.endBase < motion.startBase ? 0.16 : 0.05),
    0.16,
    3.4
  );
  const particleColor = mixParticleColors(config.color, config.colorAccent, getParticleRandom(index, 11));
  const particleAccent = mixParticleColors(
    config.colorAccent,
    config.colorEnd,
    getParticleRandom(index, 12) * 0.32
  );
  const particleEnd = mixParticleColors(config.colorEnd, config.colorAccent, getParticleRandom(index, 21) * 0.24);
  const filterStart = `blur(calc(var(--particle-blur, 0px) + var(--particle-blur-extra, 0px))) hue-rotate(${colorCurve.hue.start}deg) saturate(${colorCurve.saturation.start.toFixed(
    3
  )}) brightness(${colorCurve.brightness.start.toFixed(3)})`;
  const filterMid = `blur(calc(var(--particle-blur, 0px) + var(--particle-blur-extra, 0px))) hue-rotate(${colorCurve.hue.mid}deg) saturate(${colorCurve.saturation.mid.toFixed(
    3
  )}) brightness(${colorCurve.brightness.mid.toFixed(3)})`;
  const filterEnd = `blur(calc(var(--particle-blur, 0px) + var(--particle-blur-extra, 0px))) hue-rotate(${colorCurve.hue.end}deg) saturate(${colorCurve.saturation.end.toFixed(
    3
  )}) brightness(${colorCurve.brightness.end.toFixed(3)})`;
  const imageStyle = getParticleImageStyle(config.assetId);
  const emissionDelay =
    config.emissionMode === "burst"
      ? -(getParticleRandom(index, 18) * Math.min(0.9, Math.max(0.18, duration * 0.18)))
      : -((index * 0.35) % Math.max(duration * 0.72, 1.2));

  return `
    <span
      class="stage-particle-item ${imageStyle ? "has-custom-image" : ""}"
      style="
        --particle-left:${left.toFixed(2)}%;
        --particle-start-y:${startY.toFixed(2)}%;
        --particle-mid-y:${midY.toFixed(2)}%;
        --particle-end-y:${endY.toFixed(2)}%;
        --particle-duration:${duration.toFixed(2)}s;
        --particle-delay:${emissionDelay.toFixed(2)}s;
        --particle-width:${width.toFixed(2)}px;
        --particle-height:${height.toFixed(2)}px;
        --particle-drift-x:${driftX.toFixed(2)}px;
        --particle-opacity-start:${opacityStart.toFixed(3)};
        --particle-opacity-mid:${opacityMid.toFixed(3)};
        --particle-opacity-end:${opacityEnd.toFixed(3)};
        --particle-scale-start:${scaleStart.toFixed(3)};
        --particle-scale-mid:${scaleMid.toFixed(3)};
        --particle-scale-end:${scaleEnd.toFixed(3)};
        --particle-rotate-start:${rotationStart.toFixed(2)}deg;
        --particle-rotate-mid:${rotationMid.toFixed(2)}deg;
        --particle-rotate-end:${rotationEnd.toFixed(2)}deg;
        --particle-blur:${blur.toFixed(2)}px;
        --particle-color:${particleColor};
        --particle-color-accent:${particleAccent};
        --particle-color-end:${particleEnd};
        --particle-filter-start:${filterStart};
        --particle-filter-mid:${filterMid};
        --particle-filter-end:${filterEnd};
        --particle-blend:${getParticleBlendCssValue(config.blend)};
        ${imageStyle}
      "
    ></span>
  `;
}

function getParticleItemCount(particleEffect, large = false) {
  const config = normalizeParticleEffectConfig(particleEffect);
  const intensityMultiplier = {
    light: 0.72,
    medium: 1,
    heavy: 1.28,
  }[config.intensity];
  const areaMultiplier = config.area === "full" ? 1 : 0.64;
  const presetMultiplier = getParticlePresetDensityMultiplier(config.preset);
  const count = Math.round(config.density * intensityMultiplier * areaMultiplier * presetMultiplier);
  return clamp(large ? count + 8 : Math.max(count - 4, 6), 6, large ? 220 : 180);
}

function renderScreenFlashLayer(screenFlash) {
  if (!screenFlash) {
    return "";
  }

  return `
    <div
      class="stage-flash-layer is-active"
      style="
        --flash-rgb:${getFlashColorRgb(screenFlash.color)};
        --flash-opacity:${getFlashOpacity(screenFlash.intensity)};
        --flash-duration:${getEffectDurationSeconds(screenFlash.duration)}s;
      "
      aria-hidden="true"
    ></div>
  `;
}

function renderStageFilterLayer(screenFilter) {
  if (!screenFilter) {
    return "";
  }

  const wash = getScreenFilterWash(screenFilter);
  return `
    <div
      class="stage-filter-layer"
      style="
        --filter-wash:${wash.background};
        --filter-opacity:${wash.opacity};
      "
      aria-hidden="true"
    ></div>
  `;
}

function renderStageFadeLayer(screenFade) {
  if (!screenFade) {
    return "";
  }

  return `
    <div
      class="stage-fade-layer"
      style="--fade-rgb:${getFadeColorRgb(screenFade.color)};"
      aria-hidden="true"
    ></div>
  `;
}

function getStageWorldPresentation(cameraZoom, cameraPan, screenFilter) {
  const styles = [];
  const filterCss = getScreenFilterCss(screenFilter);
  const scale = cameraZoom ? getCameraZoomScale(cameraZoom.action, cameraZoom.strength) : 1;
  const panOffset = cameraPan ? getCameraPanOffset(cameraPan.target, cameraPan.strength) : 0;

  styles.push(`transform:translate3d(${panOffset.toFixed(2)}%, 0, 0) scale(${scale.toFixed(3)})`);
  styles.push(`transform-origin:${getCameraZoomOrigin(cameraZoom?.focus ?? "center")}`);

  if (filterCss) {
    styles.push(`filter:${filterCss}`);
  }

  return {
    style: styles.join(";"),
  };
}

function getDepthBlurBackdropStyle(depthBlur) {
  if (!depthBlur) {
    return "";
  }

  return `filter:blur(${getDepthBlurBackdropPx(depthBlur.strength)}px) brightness(0.96); transform:scale(1.05);`;
}

function getDepthBlurParticleStyle(depthBlur) {
  if (!depthBlur) {
    return "";
  }

  return `filter:blur(${getDepthBlurParticlePx(depthBlur.strength)}px); opacity:${getDepthBlurSpriteOpacity(
    depthBlur.strength
  )};`;
}

function getScreenShakePresentation(screenShake) {
  if (!screenShake) {
    return {
      className: "",
      style: "",
    };
  }

  return {
    className: "is-shaking",
    style: `--shake-distance:${getShakeDistance(screenShake.intensity)}px; --shake-duration:${getEffectDurationSeconds(
      screenShake.duration
    )}s;`,
  };
}

function getPreviewChoiceDecision(snapshot) {
  if (!snapshot || snapshot.blockType !== "choice") {
    return null;
  }

  const selectedOptionId = String(snapshot.selectedOptionId ?? "").trim();
  const selectedOption =
    (snapshot.block?.options ?? []).find((option) => option.id === selectedOptionId) ??
    (snapshot.choiceOptions ?? []).find((option) => option.id === selectedOptionId) ??
    null;

  if (!selectedOption) {
    return {
      title: "等待选择",
      meta: `还有 ${(snapshot.choiceOptions ?? snapshot.block?.options ?? []).length} 个选项可选`,
      pending: true,
    };
  }

  const effectsCount = selectedOption.effects?.length ?? 0;
  const targetSceneName =
    state.data.scenesById.get(selectedOption.gotoSceneId)?.name ?? selectedOption.gotoSceneId ?? "未设置目标";

  return {
    title: `已选：${selectedOption.text?.trim() || "未命名选项"}`,
    meta: `去 ${targetSceneName}${effectsCount > 0 ? ` · ${effectsCount} 条效果` : ""}`,
    pending: false,
  };
}

function getPreviewConditionDecision(snapshot) {
  if (!snapshot || snapshot.blockType !== "condition" || !snapshot.block) {
    return null;
  }

  const branchKey = String(snapshot.resolvedBranchId ?? "").trim();

  if (!branchKey) {
    return null;
  }

  if (branchKey === "else") {
    const targetSceneName =
      state.data.scenesById.get(snapshot.block.elseGotoSceneId)?.name ??
      snapshot.block.elseGotoSceneId ??
      "未设置目标";

    return {
      title: "命中：否则",
      meta: `去 ${targetSceneName}`,
      pending: false,
    };
  }

  const branchIndex = (snapshot.block.branches ?? []).findIndex(
    (branch, index) => getConditionBranchKey(branch, index) === branchKey
  );
  const branch = branchIndex >= 0 ? snapshot.block.branches?.[branchIndex] ?? null : null;

  if (!branch) {
    return {
      title: "命中：条件分支",
      meta: "这条分支结果已经被记录，但原分支定义暂时找不到。",
      pending: false,
    };
  }

  const targetSceneName = state.data.scenesById.get(branch.gotoSceneId)?.name ?? branch.gotoSceneId ?? "未设置目标";
  const rules = (branch.when ?? []).map((rule) => formatPreviewConditionRule(rule)).filter(Boolean);

  return {
    title: `命中：${rules.join(" 且 ") || `条件分支 ${branchIndex + 1}`}`,
    meta: `去 ${targetSceneName}`,
    pending: false,
  };
}

function getPreviewRouteDecisionSummary(snapshot) {
  if (!snapshot || snapshot.completed) {
    return null;
  }

  if (snapshot.blockType === "choice") {
    return getPreviewChoiceDecision(snapshot);
  }

  if (snapshot.blockType === "condition") {
    return getPreviewConditionDecision(snapshot);
  }

  return null;
}

function buildPreviewRouteSummary(session) {
  const timeline = session?.timeline ?? [];
  const sceneIds = new Set();
  const items = [];
  let choiceCount = 0;
  let conditionCount = 0;
  let pendingChoiceCount = 0;

  timeline.forEach((snapshot, index) => {
    if (snapshot?.sceneId) {
      sceneIds.add(snapshot.sceneId);
    }

    const decision = getPreviewRouteDecisionSummary(snapshot);

    if (!decision) {
      return;
    }

    if (snapshot.blockType === "choice") {
      if (decision.pending) {
        pendingChoiceCount += 1;
      } else {
        choiceCount += 1;
      }
    } else if (snapshot.blockType === "condition") {
      conditionCount += 1;
    }

    items.push({
      index,
      sceneId: snapshot.sceneId,
      blockId: snapshot.blockId,
      blockType: snapshot.blockType,
      sceneName: snapshot.sceneName,
      title: decision.title,
      meta: decision.meta,
      pending: decision.pending,
      isCurrent: index === session.position,
    });
  });

  return {
    visitedSceneCount: sceneIds.size,
    choiceCount,
    conditionCount,
    pendingChoiceCount,
    items,
  };
}

function renderPreviewTimeline(session) {
  return session.timeline
    .map((snapshot, index) => {
      const summary = snapshot.completed
        ? { title: snapshot.visualState.dialogueText, meta: "试玩结束" }
        : getBlockSummary(snapshot.block, state.data.scenesById.get(snapshot.sceneId));
      const hasVoice = Boolean(getPreviewVoiceAssetId(snapshot));
      const routeDecision = getPreviewRouteDecisionSummary(snapshot);

      return `
        <article class="list-card history-log-card ${index === session.position ? "is-selected" : ""}">
          <button
            class="history-log-main"
            type="button"
            data-action="jump-preview-history"
            data-preview-index="${index}"
          >
            <strong>${index + 1}. ${escapeHtml(
              snapshot.completed ? "试玩结束" : BLOCK_LABELS[snapshot.blockType] ?? snapshot.blockType
            )}</strong>
            <p>${escapeHtml(summary.title)}</p>
            <div class="detail-meta">${escapeHtml(snapshot.sceneName)}</div>
            ${
              routeDecision
                ? `<div class="history-log-decision ${routeDecision.pending ? "warn-text" : "good-text"}">${escapeHtml(
                    `${routeDecision.title} · ${routeDecision.meta}`
                  )}</div>`
                : ""
            }
          </button>
          <div class="history-log-actions">
            <button
              class="toolbar-button"
              type="button"
              data-action="replay-preview-history-voice"
              data-preview-index="${index}"
              ${hasVoice ? "" : "disabled"}
            >
              重播语音
            </button>
          </div>
        </article>
      `;
    })
    .join("");
}

function syncPreviewDebugDraft(snapshot) {
  const snapshotKey = getPreviewSnapshotKey(snapshot);

  if (!snapshot) {
    state.previewDebugDraft = null;
    state.previewDebugSnapshotKey = "";
    return;
  }

  if (!state.previewDebugDraft || state.previewDebugSnapshotKey !== snapshotKey) {
    state.previewDebugDraft = clonePreviewVariables(snapshot.variables);
    state.previewDebugSnapshotKey = snapshotKey;
    return;
  }

  state.previewDebugDraft = state.data.variables.reduce((result, variable) => {
    const currentValue =
      Object.prototype.hasOwnProperty.call(state.previewDebugDraft ?? {}, variable.id)
        ? state.previewDebugDraft[variable.id]
        : Object.hasOwn(snapshot.variables ?? {}, variable.id)
          ? snapshot.variables?.[variable.id]
          : getVariableDefaultValue(variable.id);
    result[variable.id] = normalizeVariableValue(variable.id, currentValue);
    return result;
  }, {});
}

function getPreviewDebugDraftValue(variableId, snapshot) {
  const draftValue =
    state.previewDebugDraft && Object.prototype.hasOwnProperty.call(state.previewDebugDraft, variableId)
      ? state.previewDebugDraft[variableId]
      : Object.hasOwn(snapshot?.variables ?? {}, variableId)
        ? snapshot?.variables?.[variableId]
        : getVariableDefaultValue(variableId);
  return normalizeVariableValue(variableId, draftValue);
}

function arePreviewVariableValuesEqual(variableId, leftValue, rightValue) {
  return normalizeVariableValue(variableId, leftValue) === normalizeVariableValue(variableId, rightValue);
}

function countPreviewDebugDraftChanges(snapshot) {
  if (!snapshot) {
    return 0;
  }

  return state.data.variables.filter((variable) => {
    const currentValue = Object.hasOwn(snapshot.variables ?? {}, variable.id)
      ? snapshot.variables?.[variable.id]
      : getVariableDefaultValue(variable.id);
    const draftValue = getPreviewDebugDraftValue(variable.id, snapshot);
    return !arePreviewVariableValuesEqual(variable.id, draftValue, currentValue);
  }).length;
}

function getPreviewDebugConditionTarget(snapshot, variables) {
  if (!snapshot || snapshot.blockType !== "condition" || !snapshot.block) {
    return null;
  }

  const targetSceneId = resolveConditionTargetSceneId(snapshot.block, variables);
  return state.data.scenesById.get(targetSceneId)?.name ?? targetSceneId;
}

function getPreviewDebugHint(snapshot) {
  if (!snapshot) {
    return "先开始一段试玩，这里才会出现可调的变量。";
  }

  if (snapshot.completed) {
    return "这条路线已经结束了。想继续试别的变量组合，可以先点“上一句”或“重新开始”。";
  }

  if (snapshot.blockType === "condition") {
    const targetName = getPreviewDebugConditionTarget(snapshot, state.previewDebugDraft ?? snapshot.variables);
    return targetName
      ? `如果现在继续，条件判断会按这里的值跳去：${targetName}`
      : "如果现在继续，条件判断会按这里写入的变量结果决定去向。";
  }

  if (snapshot.choiceOptions.length > 0) {
    return "这一步是选项。这里改的是“选项结算前”的变量，选项效果会在这个基础上继续叠加。";
  }

  if (snapshot.blockType === "variable_set" || snapshot.blockType === "variable_add") {
    return "当前这一步本身就在改变量。这里手动写入后，会以你写入的值继续往后试玩。";
  }

  return "这里不会改项目文件，只会改当前这条试玩路线后续用到的变量。";
}

function renderPreviewDebugEditor(variable, draftValue) {
  const inputId = `previewDebug-${variable.id}`;

  if (variable.type === "number") {
    const [minValue, maxValue] = getVariableNumberBounds(variable);
    const minAttr = minValue !== null ? ` min="${minValue}"` : "";
    const maxAttr = maxValue !== null ? ` max="${maxValue}"` : "";
    return `
      <input
        id="${inputId}"
        type="number"
        data-preview-debug-variable="${escapeHtml(variable.id)}"
        value="${escapeHtml(String(draftValue))}"
        step="1"${minAttr}${maxAttr}
      />
    `;
  }

  if (variable.type === "boolean") {
    return `
      <select id="${inputId}" data-preview-debug-variable="${escapeHtml(variable.id)}">
        <option value="true" ${draftValue === true ? "selected" : ""}>是</option>
        <option value="false" ${draftValue === false ? "selected" : ""}>否</option>
      </select>
    `;
  }

  return `
    <input
      id="${inputId}"
      type="text"
      data-preview-debug-variable="${escapeHtml(variable.id)}"
      value="${escapeHtml(String(draftValue ?? ""))}"
      placeholder="这里可以直接写路线名或状态词"
    />
  `;
}

function renderPreviewDebugPanel(snapshot) {
  if (!snapshot) {
    return `
      <article class="detail-card preview-debug-card">
        <strong>分支调试台</strong>
        <p class="helper-text">先开始一段试玩，这里就能直接改变量、试条件分支。</p>
      </article>
    `;
  }

  if (state.data.variables.length === 0) {
    return `
      <article class="detail-card preview-debug-card">
        <strong>分支调试台</strong>
        <p class="helper-text">这个项目目前还没有变量，所以这里暂时不用调。</p>
      </article>
    `;
  }

  const changedCount = countPreviewDebugDraftChanges(snapshot);
  const draftSummary =
    changedCount > 0
      ? `当前已改动 ${changedCount} 项，点击“写入当前试玩”后，后续分支会按这些值继续。`
      : "这里显示的是当前真正生效的变量，可直接修改并写入当前试玩。";

  return `
    <article class="detail-card preview-debug-card">
      <strong>分支调试台</strong>
      <p class="helper-text">这里不会改剧情文件，只影响当前试玩路线，特别适合试条件分支、好感度和路线锁。</p>
      <div class="preview-debug-summary">
        <span class="issue-tag ${changedCount > 0 ? "warn-text" : "good-text"}">
          ${changedCount > 0 ? `待写入 ${changedCount} 项` : "已和当前试玩同步"}
        </span>
        <span>${escapeHtml(draftSummary)}</span>
      </div>
      <div class="detail-stack preview-debug-list">
        ${state.data.variables
          .map((variable) => {
            const currentValue = Object.hasOwn(snapshot.variables ?? {}, variable.id)
              ? snapshot.variables?.[variable.id]
              : getVariableDefaultValue(variable.id);
            const draftValue = getPreviewDebugDraftValue(variable.id, snapshot);
            const changed = !arePreviewVariableValuesEqual(variable.id, draftValue, currentValue);
            const [minValue, maxValue] = getVariableNumberBounds(variable);
            const minMaxText =
              variable.type === "number" && (minValue !== null || maxValue !== null)
                ? ` · 范围 ${minValue !== null ? minValue : "-∞"} ~ ${maxValue !== null ? maxValue : "+∞"}`
                : "";

            return `
              <div class="preview-debug-row ${changed ? "is-edited" : ""}">
                <div class="preview-debug-copy">
                  <label for="previewDebug-${escapeHtml(variable.id)}">${escapeHtml(variable.name)}</label>
                  <div class="preview-debug-meta">
                    ${escapeHtml(getVariableTypeLabel(variable.type))} · 当前：${escapeHtml(
                      formatVariableValue(variable.id, currentValue)
                    )}${escapeHtml(minMaxText)}
                  </div>
                </div>
                <div class="preview-debug-control">
                  ${renderPreviewDebugEditor(variable, draftValue)}
                </div>
              </div>
            `;
          })
          .join("")}
      </div>
      <div class="preview-debug-note">${escapeHtml(getPreviewDebugHint(snapshot))}</div>
      <div class="detail-actions preview-debug-actions">
        <button
          class="toolbar-button toolbar-button-primary"
          type="button"
          data-action="apply-preview-debug-draft"
          ${changedCount > 0 && !snapshot.completed ? "" : "disabled"}
        >
          写入当前试玩
        </button>
        <button
          class="toolbar-button"
          type="button"
          data-action="reset-preview-debug-draft"
          ${changedCount > 0 ? "" : "disabled"}
        >
          恢复当前步变量
        </button>
        <button class="toolbar-button" type="button" data-action="reset-preview-debug-defaults">
          全部重置默认
        </button>
      </div>
    </article>
  `;
}

function renderPreviewRouteSummaryPanel(session) {
  if (!session) {
    return `
      <article class="detail-card preview-route-card">
        <strong>路线摘要</strong>
        <p class="helper-text">开始一段试玩后，这里会记录已选选项和命中过的条件。</p>
      </article>
    `;
  }

  const routeSummary = buildPreviewRouteSummary(session);
  const recentItems = routeSummary.items.slice(-6).reverse();

  return `
    <article class="detail-card preview-route-card">
      <div class="preview-route-head">
        <div>
          <strong>路线摘要</strong>
          <p class="helper-text">这里会把这次试玩里真正生效过的选项和条件结果按顺序记下来，回头查路线会轻松很多。</p>
        </div>
        ${
          routeSummary.pendingChoiceCount > 0
            ? `<span class="issue-tag warn-text">当前还有 ${routeSummary.pendingChoiceCount} 个分支口在等你选择</span>`
            : ""
        }
      </div>
      <div class="preview-route-metrics">
        <div class="preview-route-metric">
          <span>走过场景</span>
          <strong>${routeSummary.visitedSceneCount}</strong>
        </div>
        <div class="preview-route-metric">
          <span>已选选项</span>
          <strong>${routeSummary.choiceCount}</strong>
        </div>
        <div class="preview-route-metric">
          <span>命中条件</span>
          <strong>${routeSummary.conditionCount}</strong>
        </div>
      </div>
      ${
        recentItems.length === 0
          ? '<div class="preview-route-note">这轮试玩暂时还没有经过选项或条件判断。继续往后走，路线记录会自动出现。</div>'
          : `
            <div class="detail-stack preview-route-list">
              ${recentItems
                .map(
                  (item) => `
                    <article class="preview-route-item ${item.isCurrent ? "is-current" : ""}">
                      <div class="preview-route-step">
                        <span>第 ${item.index + 1} 步</span>
                        <strong>${escapeHtml(item.blockType === "choice" ? "选项结果" : "条件结果")}</strong>
                      </div>
                      <div class="preview-route-copy">
                        <strong>${escapeHtml(item.title)}</strong>
                        <p>${escapeHtml(`${item.sceneName} · ${item.meta}`)}</p>
                      </div>
                      <div class="detail-actions">
                        <button
                          type="button"
                          class="toolbar-button toolbar-button-primary"
                          data-action="jump-preview-history"
                          data-preview-index="${item.index}"
                        >
                          跳回这一步
                        </button>
                        <button
                          type="button"
                          class="toolbar-button"
                          data-action="open-character-line"
                          data-scene-id="${item.sceneId}"
                          data-block-id="${item.blockId}"
                        >
                          打开卡片
                        </button>
                      </div>
                    </article>
                  `
                )
                .join("")}
            </div>
          `
      }
    </article>
  `;
}

function formatPreviewConditionRule(rule) {
  const variableName = state.data.variablesById.get(rule?.variableId)?.name ?? rule?.variableId ?? "变量";
  const operator = rule?.operator ?? "==";
  return `${variableName} ${operator} ${formatVariableValue(rule?.variableId, rule?.value)}`;
}

function buildPreviewBranchCoverage(session) {
  const timeline = session?.timeline ?? [];
  const visitedPointKeys = new Set();
  const coveredOutcomeKeys = new Set();

  timeline.forEach((snapshot) => {
    if (!snapshot || snapshot.completed || !snapshot.blockId) {
      return;
    }

    if (snapshot.blockType === "choice") {
      const pointKey = `choice:${snapshot.sceneId}:${snapshot.blockId}`;
      visitedPointKeys.add(pointKey);
      const selectedOptionId = String(snapshot.selectedOptionId ?? "").trim();

      if (selectedOptionId) {
        coveredOutcomeKeys.add(`${pointKey}:${selectedOptionId}`);
      }
      return;
    }

    if (snapshot.blockType === "condition") {
      const pointKey = `condition:${snapshot.sceneId}:${snapshot.blockId}`;
      visitedPointKeys.add(pointKey);
      const resolvedBranchId = String(snapshot.resolvedBranchId ?? "").trim();

      if (resolvedBranchId) {
        coveredOutcomeKeys.add(`${pointKey}:${resolvedBranchId}`);
      }
    }
  });

  const points = [];

  state.data.chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      (scene.blocks ?? []).forEach((block, blockIndex) => {
        if (block.type === "choice") {
          const pointKey = `choice:${scene.id}:${block.id}`;
          const outcomes = (block.options ?? []).map((option, index) => {
            const optionKey = String(option?.id ?? "").trim() || `option-${index + 1}`;
            const outcomeKey = `${pointKey}:${optionKey}`;
            const effectsCount = option.effects?.length ?? 0;
            const targetSceneName =
              state.data.scenesById.get(option.gotoSceneId)?.name ?? option.gotoSceneId ?? "未设置目标";

            return {
              key: outcomeKey,
              label: option.text?.trim() || `选项 ${index + 1}`,
              meta: `${targetSceneName}${effectsCount > 0 ? ` · ${effectsCount} 条效果` : ""}`,
              covered: coveredOutcomeKeys.has(outcomeKey),
            };
          });

          points.push({
            key: pointKey,
            sceneId: scene.id,
            blockId: block.id,
            blockType: block.type,
            title: `${scene.name} / 选项分支`,
            meta: `${scene.chapterName ?? chapter.name} · 第 ${blockIndex + 1} 张卡片`,
            visited: visitedPointKeys.has(pointKey),
            outcomes,
          });
          return;
        }

        if (block.type === "condition") {
          const pointKey = `condition:${scene.id}:${block.id}`;
          const branchOutcomes = (block.branches ?? []).map((branch, index) => {
            const branchKey = getConditionBranchKey(branch, index);
            const outcomeKey = `${pointKey}:${branchKey}`;
            const targetSceneName =
              state.data.scenesById.get(branch.gotoSceneId)?.name ?? branch.gotoSceneId ?? "未设置目标";
            const rules = (branch.when ?? []).map((rule) => formatPreviewConditionRule(rule)).filter(Boolean);

            return {
              key: outcomeKey,
              label: rules.join(" 且 ") || `条件分支 ${index + 1}`,
              meta: `命中后去：${targetSceneName}`,
              covered: coveredOutcomeKeys.has(outcomeKey),
            };
          });

          const elseOutcomeKey = `${pointKey}:else`;
          const elseTargetSceneName =
            state.data.scenesById.get(block.elseGotoSceneId)?.name ?? block.elseGotoSceneId ?? "未设置目标";

          points.push({
            key: pointKey,
            sceneId: scene.id,
            blockId: block.id,
            blockType: block.type,
            title: `${scene.name} / 条件判断`,
            meta: `${scene.chapterName ?? chapter.name} · 第 ${blockIndex + 1} 张卡片`,
            visited: visitedPointKeys.has(pointKey),
            outcomes: [
              ...branchOutcomes,
              {
                key: elseOutcomeKey,
                label: "否则",
                meta: `都不满足时去：${elseTargetSceneName}`,
                covered: coveredOutcomeKeys.has(elseOutcomeKey),
              },
            ],
          });
        }
      });
    });
  });

  const currentSnapshot = getCurrentPreviewSnapshot();
  const pointsWithCoverage = points.map((point) => {
    const coveredCount = point.outcomes.filter((outcome) => outcome.covered).length;
    return {
      ...point,
      coveredCount,
      remainingCount: Math.max(point.outcomes.length - coveredCount, 0),
      isCurrent:
        currentSnapshot?.sceneId === point.sceneId &&
        currentSnapshot?.blockId === point.blockId &&
        (currentSnapshot?.blockType === "choice" || currentSnapshot?.blockType === "condition"),
    };
  });

  const unvisitedPoints = pointsWithCoverage.filter((point) => !point.visited);
  const partialPoints = pointsWithCoverage.filter((point) => point.remainingCount > 0 && point.visited);
  const fullyCoveredPoints = pointsWithCoverage.filter((point) => point.remainingCount === 0);
  const totalOutcomeCount = pointsWithCoverage.reduce((total, point) => total + point.outcomes.length, 0);
  const coveredOutcomeCount = pointsWithCoverage.reduce((total, point) => total + point.coveredCount, 0);

  return {
    totalPoints: pointsWithCoverage.length,
    visitedPointCount: pointsWithCoverage.length - unvisitedPoints.length,
    fullyCoveredPointCount: fullyCoveredPoints.length,
    totalOutcomeCount,
    coveredOutcomeCount,
    remainingOutcomeCount: Math.max(totalOutcomeCount - coveredOutcomeCount, 0),
    unvisitedPoints,
    partialPoints,
    points: pointsWithCoverage,
    currentPendingChoice:
      currentSnapshot?.blockType === "choice" && currentSnapshot?.choiceOptions?.length > 0 ? currentSnapshot : null,
  };
}

function renderPreviewCoveragePoint(point, tone = "pending") {
  const badgeClass = tone === "pending" ? "warn-text" : point.remainingCount > 1 ? "warn-text" : "good-text";
  const badgeText =
    tone === "pending"
      ? "还没走到"
      : point.remainingCount > 0
        ? `还差 ${point.remainingCount} 条`
        : "这处已测完";

  return `
    <article class="preview-coverage-item ${point.isCurrent ? "is-current" : ""}">
      <div class="preview-coverage-item-head">
        <div class="preview-coverage-copy">
          <strong>${escapeHtml(point.title)}</strong>
          <p>${escapeHtml(point.meta)}</p>
        </div>
        <span class="issue-tag ${badgeClass}">${escapeHtml(badgeText)}</span>
      </div>
      <div class="preview-coverage-progress">
        <span>已试 ${point.coveredCount}/${point.outcomes.length} 条</span>
        <span>${point.blockType === "choice" ? "选项结果" : "判断结果"}</span>
      </div>
      <div class="preview-coverage-branch-list">
        ${point.outcomes
          .map(
            (outcome) => `
              <span
                class="preview-coverage-branch ${outcome.covered ? "is-covered" : "is-missing"}"
                title="${escapeHtml(`${outcome.label} · ${outcome.meta}`)}"
              >
                ${escapeHtml(truncateText(outcome.label, 22))}
              </span>
            `
          )
          .join("")}
      </div>
      <div class="detail-actions">
        <button
          type="button"
          class="toolbar-button toolbar-button-primary"
          data-action="preview-story-location"
          data-scene-id="${point.sceneId}"
          data-block-id="${point.blockId}"
        >
          试玩这里
        </button>
        <button
          type="button"
          class="toolbar-button"
          data-action="open-character-line"
          data-scene-id="${point.sceneId}"
          data-block-id="${point.blockId}"
        >
          打开卡片
        </button>
      </div>
    </article>
  `;
}

function renderPreviewBranchCoveragePanel(session) {
  const coverage = buildPreviewBranchCoverage(session);

  if (coverage.totalPoints === 0) {
    return `
      <article class="detail-card preview-coverage-card">
        <strong>分支覆盖</strong>
        <p class="helper-text">这个项目目前还没有选项或条件判断，所以这里暂时不用查覆盖率。</p>
      </article>
    `;
  }

  const unvisitedMarkup = coverage.unvisitedPoints
    .slice(0, 3)
    .map((point) => renderPreviewCoveragePoint(point, "pending"))
    .join("");
  const partialMarkup = coverage.partialPoints
    .slice(0, 3)
    .map((point) => renderPreviewCoveragePoint(point, "partial"))
    .join("");
  const remainingUnvisitedCount = Math.max(coverage.unvisitedPoints.length - 3, 0);
  const remainingPartialCount = Math.max(coverage.partialPoints.length - 3, 0);

  return `
    <article class="detail-card preview-coverage-card">
      <div class="preview-coverage-head">
        <div>
          <strong>分支覆盖</strong>
          <p class="helper-text">这里会看这次试玩已经踩过哪些分支口、还有哪些路线结果没测到。</p>
        </div>
        <div class="route-badge-row">
          <span class="issue-tag ${coverage.remainingOutcomeCount > 0 ? "warn-text" : "good-text"}">
            ${coverage.remainingOutcomeCount > 0 ? `还差 ${coverage.remainingOutcomeCount} 条路线` : "这轮试玩已测完"}
          </span>
        </div>
      </div>
      <div class="preview-coverage-metrics">
        <div class="preview-coverage-metric">
          <span>已遇到分支口</span>
          <strong>${coverage.visitedPointCount} / ${coverage.totalPoints}</strong>
        </div>
        <div class="preview-coverage-metric">
          <span>已试路线结果</span>
          <strong>${coverage.coveredOutcomeCount} / ${coverage.totalOutcomeCount}</strong>
        </div>
        <div class="preview-coverage-metric">
          <span>整处测完</span>
          <strong>${coverage.fullyCoveredPointCount} / ${coverage.totalPoints}</strong>
        </div>
      </div>
      ${
        coverage.currentPendingChoice
          ? `
            <div class="preview-coverage-note">
              当前正停在一个选项口。你一旦选完，下面的覆盖结果会立刻更新。
            </div>
          `
          : coverage.remainingOutcomeCount === 0
            ? `
              <div class="preview-coverage-note is-complete">
                这次试玩已经把所有分支结果都测到了，可以放心去试别的起点了。
              </div>
            `
            : ""
      }
      <div class="preview-coverage-section">
        <div class="preview-coverage-section-head">
          <strong>还没走到的分支口</strong>
          <span>${coverage.unvisitedPoints.length} 处</span>
        </div>
        ${
          unvisitedMarkup ||
          '<div class="preview-coverage-note is-complete">所有分支口这轮都已经走到过了。</div>'
        }
        ${
          remainingUnvisitedCount > 0
            ? `<div class="preview-coverage-note">后面还有 ${remainingUnvisitedCount} 处分支口没展示出来，等你继续试玩时会自动补上。</div>`
            : ""
        }
      </div>
      <div class="preview-coverage-section">
        <div class="preview-coverage-section-head">
          <strong>已经走到但还没试全</strong>
          <span>${coverage.partialPoints.length} 处</span>
        </div>
        ${
          partialMarkup ||
          '<div class="preview-coverage-note is-complete">目前这轮已经没有“走到但没试全”的分支口了。</div>'
        }
        ${
          remainingPartialCount > 0
            ? `<div class="preview-coverage-note">后面还有 ${remainingPartialCount} 处未试全的分支口，可以继续往下翻起点树慢慢补。</div>`
            : ""
        }
      </div>
    </article>
  `;
}

function renderPreviewSidebar(session) {
  const snapshot = getCurrentPreviewSnapshot();
  const resolution = getProjectResolution();
  const isAdvancedMode = isAdvancedEditorMode();
  const variableRows = state.data.variables
    .map(
      (variable) => `
        <div class="detail-row">
          <label>${escapeHtml(variable.name)}</label>
          <div class="value">${escapeHtml(
            formatVariableValue(
              variable.id,
              Object.hasOwn(snapshot?.variables ?? {}, variable.id)
                ? snapshot?.variables?.[variable.id]
                : getVariableDefaultValue(variable.id)
            )
          )}</div>
        </div>
      `
    )
    .join("");

  return `
    ${!isAdvancedMode ? renderBeginnerPreviewGuide(session, snapshot) : ""}
    ${renderDetailRows([
      ["试玩起点", state.data.scenesById.get(session?.startSceneId)?.name ?? session?.startSceneId ?? "未设置"],
      ["项目分辨率", `${resolution.width} × ${resolution.height}`],
      ["当前场景", snapshot?.sceneName ?? "未开始"],
      [
        "当前卡片",
        snapshot?.completed
          ? "试玩结束"
          : snapshot
            ? `${BLOCK_LABELS[snapshot.blockType] ?? snapshot.blockType} · 第 ${snapshot.blockIndex + 1} 张`
            : "未开始",
      ],
      ["已走步数", session ? `${session.position + 1} / ${session.timeline.length}` : "0 / 0"],
    ])}
    ${isAdvancedMode ? renderPreviewDebugPanel(snapshot) : ""}
    ${isAdvancedMode ? renderPreviewBranchCoveragePanel(session) : ""}
    ${isAdvancedMode ? renderPreviewRouteSummaryPanel(session) : ""}
    ${
      isAdvancedMode
        ? `
            <article class="detail-card">
              <strong>当前变量状态</strong>
              <p class="helper-text">这里显示已经真正写进当前试玩路线里的值。上面的调试台只有在你点“写入当前试玩”后才会生效。</p>
              <div class="detail-stack">
                ${variableRows || renderEmpty("这个项目还没有变量。")}
              </div>
            </article>
          `
        : ""
    }
    <article class="detail-card">
      <strong>分辨率切换</strong>
      <p>制作 Full HD 版本时，这里可直接切到 1920 × 1080。</p>
      <div class="detail-actions">
        ${renderResolutionButtons()}
      </div>
    </article>
    ${renderProjectRuntimeSettingsPanel()}
    ${renderProjectValidationSummary()}
  `;
}

function buildPreviewIssueItems() {
  const items = [];

  state.validation.errors.forEach((issue) => {
    items.push({
      kind: "errors",
      toneClass: "danger-text",
      label: "错误",
      title: issue.message,
      meta: issue.location,
      action: getValidationIssueAction(issue),
      searchText: normalizeDashboardSearchQuery(`${issue.message} ${issue.location}`),
    });
  });

  state.validation.warnings.forEach((issue) => {
    items.push({
      kind: "warnings",
      toneClass: "warn-text",
      label: "提醒",
      title: issue.message,
      meta: issue.location,
      action: getValidationIssueAction(issue),
      searchText: normalizeDashboardSearchQuery(`${issue.message} ${issue.location}`),
    });
  });

  const exportResult = state.lastExportResult;
  if (exportResult?.missingAssets > 0) {
    items.push({
      kind: "export_missing",
      toneClass: "warn-text",
      label: "导出缺失",
      title: `最近一次导出里有 ${exportResult.missingAssets} 个素材没找到`,
      meta: exportResult.missingAssetNames?.length
        ? exportResult.missingAssetNames.slice(0, 8).join(" / ")
        : "可以先去素材页确认文件有没有导入成功。",
      action: {
        label: "去素材页定位",
        action: "switch-screen",
        screen: "assets",
      },
      searchText: normalizeDashboardSearchQuery(
        [
          "导出缺失",
          exportResult.buildPath,
          ...(exportResult.missingAssetNames ?? []),
        ].join(" ")
      ),
    });
  }

  const mediaBudgetReport = buildAssetMediaBudgetReport();
  if (mediaBudgetReport.count > 0) {
    items.push({
      kind: "media_budget",
      toneClass: mediaBudgetReport.blockerCount > 0 ? "danger-text" : "warn-text",
      label: "素材预算",
      title: `有 ${mediaBudgetReport.count} 个素材体积建议发布前处理`,
      meta: mediaBudgetReport.items
        .slice(0, 6)
        .map((item) => `${item.name} · ${item.fileSizeLabel}`)
        .join(" / "),
      action: {
        label: "去素材页压缩清单",
        action: "focus-asset-gap",
        dataset: { "asset-filter-mode": "media_budget" },
      },
      searchText: normalizeDashboardSearchQuery(
        [
          "素材预算 大素材 体积 压缩 图片 音频 视频",
          ...mediaBudgetReport.items.map((item) => `${item.name} ${item.typeLabel} ${item.fileSizeLabel}`),
        ].join(" ")
      ),
    });
  }

  const unusedAssets = getUnusedAssets();
  if (unusedAssets.length > 0) {
    items.push({
      kind: "unused_assets",
      toneClass: "",
      label: "闲置素材",
      title: `当前有 ${unusedAssets.length} 个素材还没有进剧情`,
      meta: unusedAssets
        .slice(0, 6)
        .map((asset) => `${asset.name} · ${getAssetTypeLabel(asset.type)}`)
        .join(" / "),
      action: {
        label: "去素材页定位",
        action: "focus-unused-assets",
      },
      searchText: normalizeDashboardSearchQuery(
        [
          "未使用素材 闲置素材",
          ...unusedAssets.map((asset) => `${asset.name} ${asset.type}`),
        ].join(" ")
      ),
    });
  }

  return items;
}

function getFilteredPreviewIssueItems(items) {
  const filterMode = getSafePreviewIssueFilterMode(state.previewIssueFilterMode);
  const terms = getDashboardSearchTerms(state.previewIssueSearchQuery);

  return items.filter((item) => {
    if (filterMode !== "all" && item.kind !== filterMode) {
      return false;
    }

    if (!terms.length) {
      return true;
    }

    return terms.every((term) => item.searchText.includes(term));
  });
}

function countPreviewIssueItemsByKind(items, kind) {
  if (kind === "all") {
    return items.length;
  }

  return items.filter((item) => item.kind === kind).length;
}

function renderPreviewIssueFilterBar(items) {
  const modes = ["all", "errors", "warnings", "export_missing", "media_budget", "unused_assets"];

  return modes
    .map((mode) => `
      <button
        type="button"
        class="asset-tag-chip ${getSafePreviewIssueFilterMode(state.previewIssueFilterMode) === mode ? "is-active" : ""}"
        data-action="set-preview-issue-filter"
        data-preview-issue-filter="${mode}"
      >
        <span>${escapeHtml(getPreviewIssueFilterLabel(mode))}</span>
        <strong>${countPreviewIssueItemsByKind(items, mode)}</strong>
      </button>
    `)
    .join("");
}

function renderPreviewIssueSummary(filteredItems, totalItems) {
  const activeLabels = [];

  if ((state.previewIssueSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.previewIssueSearchQuery.trim()}`);
  }

  if (getSafePreviewIssueFilterMode(state.previewIssueFilterMode) !== "all") {
    activeLabels.push(`视角：${getPreviewIssueFilterLabel(state.previewIssueFilterMode)}`);
  }

  return `
    <div class="story-filter-summary-main">
      <strong>命中 ${filteredItems.length}/${totalItems.length} 条检查项目</strong>
      <span class="panel-note">现在可以直接搜问题位置、素材名或错误关键词</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有额外筛选，正在显示全部检查项目。</span>'
      }
    </div>
  `;
}

function getFilteredInspectionIssueItems(items) {
  const filterMode = getSafePreviewIssueFilterMode(state.inspectionIssueFilterMode);
  const terms = getDashboardSearchTerms(state.inspectionIssueSearchQuery);

  return items.filter((item) => {
    if (filterMode !== "all" && item.kind !== filterMode) {
      return false;
    }

    if (!terms.length) {
      return true;
    }

    return terms.every((term) => item.searchText.includes(term));
  });
}

function renderInspectionIssueFilterBar(items) {
  const modes = ["all", "errors", "warnings", "export_missing", "media_budget", "unused_assets"];

  return modes
    .map((mode) => `
      <button
        type="button"
        class="asset-tag-chip ${getSafePreviewIssueFilterMode(state.inspectionIssueFilterMode) === mode ? "is-active" : ""}"
        data-action="set-inspection-filter"
        data-inspection-issue-filter="${mode}"
      >
        <span>${escapeHtml(getPreviewIssueFilterLabel(mode))}</span>
        <strong>${countPreviewIssueItemsByKind(items, mode)}</strong>
      </button>
    `)
    .join("");
}

function renderInspectionIssueSummary(filteredItems, totalItems) {
  const activeLabels = [];

  if ((state.inspectionIssueSearchQuery ?? "").trim()) {
    activeLabels.push(`关键词：${state.inspectionIssueSearchQuery.trim()}`);
  }

  if (getSafePreviewIssueFilterMode(state.inspectionIssueFilterMode) !== "all") {
    activeLabels.push(`视角：${getPreviewIssueFilterLabel(state.inspectionIssueFilterMode)}`);
  }

  return `
    <div class="story-filter-summary-main">
      <strong>命中 ${filteredItems.length}/${totalItems.length} 条巡检项目</strong>
      <span class="panel-note">可以直接搜场景名、素材名、错误关键词或导出缺失</span>
    </div>
    <div class="story-filter-chip-row">
      ${
        activeLabels.length > 0
          ? activeLabels.map((label) => `<span class="issue-tag good-text">${escapeHtml(label)}</span>`).join("")
          : '<span class="issue-tag">当前没有额外筛选，正在显示全部巡检项目。</span>'
      }
    </div>
  `;
}

function buildPreviewSprintTasks() {
  const tasks = [];
  const exportResult = state.lastExportResult;
  const native3dDigest = exportResult?.target === "native_runtime" ? exportResult.asset3dReportDigest ?? null : null;
  const mediaBudgetReport = buildAssetMediaBudgetReport();
  const unusedAssets = getUnusedAssets();
  const missingVoiceWarnings = state.validation.warnings.filter(
    (issue) => issue.message === "这句台词还没有绑定语音。"
  );
  const nonVoiceWarnings = state.validation.warnings.filter(
    (issue) => issue.message !== "这句台词还没有绑定语音。"
  );

  if (state.validation.errors.length > 0) {
    const firstErrorAction = getValidationIssueAction(state.validation.errors[0]);
    tasks.push({
      tone: "danger",
      title: "先清结构错误",
      description: "这些问题最容易让剧情断掉、跳错场景，或者让试玩包跑不完整。先修这一批最稳。",
      metrics: [
        ["结构错误", `${state.validation.errors.length} 项`],
        ["首个位置", truncateText(state.validation.errors[0]?.location ?? "待定位", 24)],
      ],
      tags: ["优先级最高", "先修完再导出更稳"],
      actions: [
        {
          label: "只看结构错误",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "errors" },
        },
        firstErrorAction ? { ...firstErrorAction, label: "打开第一条" } : { label: "去剧情页修", action: "switch-screen", screen: "story" },
      ],
    });
  }

  if ((exportResult?.missingAssets ?? 0) > 0) {
    tasks.push({
      tone: "warn",
      title: "补齐导出缺失素材",
      description: "这些素材在编辑器里已有条目，但最近一次导出时未找到真实文件。补齐后，试玩包会更完整。",
      metrics: [
        ["缺失素材", `${exportResult.missingAssets} 个`],
        ["最近导出", truncateText(exportResult.buildPath ?? "刚刚导出", 24)],
      ],
      tags: ["会直接影响试玩包", "优先补已被引用的文件"],
      actions: [
        {
          label: "只看导出缺失",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "export_missing" },
        },
        {
          label: "去素材页补缺口",
          action: "focus-asset-gap",
          dataset: { "asset-filter-mode": "urgent_missing" },
        },
      ],
    });
  }

  if (native3dDigest?.topIssues?.length > 0) {
    const firstIssue = native3dDigest.topIssues[0] ?? {};
    const focusFirstIssueAction = firstIssue.assetId
      ? { label: "定位首个风险素材", action: "open-asset-from-issue", assetId: firstIssue.assetId }
      : null;
    tasks.push({
      tone: native3dDigest.status === "unavailable" ? "danger" : "warn",
      title: "处理 3D 发布体检风险",
      description:
        native3dDigest.summaryLine ??
        "原生 Runtime 的 3D 资产体检发现了需要发布前确认的问题，优先处理可以减少目标机渲染和打包风险。",
      metrics: (native3dDigest.metrics ?? [])
        .filter((metric) => ["问题", "性能预算", "估算三角面", "Draw Call"].includes(metric.label))
        .slice(0, 4)
        .map((metric) => [metric.label, metric.value]),
      tags: [
        "原生 Runtime",
        truncateText(`${firstIssue.typeLabel ?? "3D 资产"}：${firstIssue.summary ?? firstIssue.statusLabel ?? "需要复核"}`, 36),
      ],
      actions: [
        focusFirstIssueAction,
        {
          label: "只看 3D 风险素材",
          action: "focus-asset-gap",
          dataset: { "asset-filter-mode": "asset3d_risk" },
        },
        exportResult?.asset3dSummaryPublicUrl
          ? { label: "打开 3D 摘要", href: exportResult.asset3dSummaryPublicUrl }
          : { label: "生成 3D 摘要", action: "export-build", dataset: { "export-target": "native_runtime" } },
      ].filter(Boolean),
    });
  }

  if (mediaBudgetReport.count > 0) {
    const largest = mediaBudgetReport.largest;
    tasks.push({
      tone: mediaBudgetReport.blockerCount > 0 ? "warn" : "soft",
      title: "压一轮大素材预算",
      description:
        mediaBudgetReport.blockerCount > 0
          ? "有素材已经明显超出建议预算，正式发包前最好先压缩，避免包体、加载峰值和低配设备体验一起变重。"
          : "这些素材不会立刻卡死导出，但发布前压一轮能明显改善包体和加载体验。",
      metrics: [
        ["预算风险", `${mediaBudgetReport.count} 个`],
        ["明显超线", `${mediaBudgetReport.blockerCount} 个`],
        ["合计体积", mediaBudgetReport.totalLabel],
        ["最大素材", truncateText(largest ? `${largest.name} · ${largest.fileSizeLabel}` : "未记录", 24)],
      ],
      tags: [
        "包体优化",
        largest ? truncateText(`${largest.typeLabel}：${largest.suggestion}`, 42) : "建议发布前压缩",
      ],
      actions: [
        {
          label: "只看体积风险素材",
          action: "focus-asset-gap",
          dataset: { "asset-filter-mode": "media_budget" },
        },
        largest
          ? {
              label: "打开最大素材",
              action: "open-asset-from-issue",
              assetId: largest.assetId,
            }
          : { label: "去素材页", action: "switch-screen", screen: "assets" },
      ],
    });
  }

  if (missingVoiceWarnings.length > 0) {
    const firstVoiceAction = getValidationIssueAction(missingVoiceWarnings[0]);
    tasks.push({
      tone: "warn",
      title: "把待绑语音集中补一轮",
      description: "这些台词已经写好了，但还没绑语音。先集中筛出来，后面配音和测试都会轻松很多。",
      metrics: [
        ["待绑语音", `${missingVoiceWarnings.length} 句`],
        ["优先场景", truncateText(missingVoiceWarnings[0]?.location ?? "台词卡片", 24)],
      ],
      tags: ["先集中补更省事", "台本页已经支持导出配音表"],
      actions: [
        { label: "只看待绑语音", action: "focus-script-missing-voice" },
        firstVoiceAction ? { ...firstVoiceAction, label: "打开第一句" } : { label: "去台本页", action: "switch-screen", screen: "script" },
      ],
    });
  }

  if (unusedAssets.length > 0) {
    tasks.push({
      tone: "soft",
      title: "顺手清一下闲置素材",
      description: "这些素材暂时没进剧情。整理掉重复或无用条目，后面导出和查素材都会更轻。",
      metrics: [
        ["闲置素材", `${unusedAssets.length} 个`],
        ["示例", truncateText(unusedAssets[0]?.name ?? "素材", 24)],
      ],
      tags: ["不会卡导出", "但会让工程更干净"],
      actions: [
        { label: "去素材页定位", action: "focus-unused-assets" },
        {
          label: "只看闲置素材",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "unused_assets" },
        },
      ],
    });
  }

  if (nonVoiceWarnings.length > 0) {
    const firstWarningAction = getValidationIssueAction(nonVoiceWarnings[0]);
    tasks.push({
      tone: "good",
    title: "处理补充提醒",
      description: "这些不是硬错误，但处理后试玩手感和导出稳定度通常会更好。",
      metrics: [
        ["补充提醒", `${nonVoiceWarnings.length} 项`],
        ["首个位置", truncateText(nonVoiceWarnings[0]?.location ?? "待定位", 24)],
      ],
      tags: ["不急但很值", "适合导出前收尾"],
      actions: [
        {
          label: "只看补充提醒",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "warnings" },
        },
        firstWarningAction ? { ...firstWarningAction, label: "打开第一条" } : { label: "继续检查", action: "switch-screen", screen: "preview" },
      ],
    });
  }

  return tasks.slice(0, 5);
}

function renderPreviewSprintCard(task) {
  return `
    <article class="preview-sprint-card is-${task.tone}">
      <div class="preview-sprint-head">
        <strong>${escapeHtml(task.title)}</strong>
        <span class="issue-tag ${getDashboardTaskToneClass(task.tone)}">${escapeHtml(
          task.tone === "danger" ? "先修" : task.tone === "warn" ? "优先做" : task.tone === "good" ? "值得做" : "顺手清"
        )}</span>
      </div>
      <p>${escapeHtml(task.description)}</p>
      <div class="preview-sprint-metrics">
        ${task.metrics
          .map(
            ([label, value]) => `
              <article class="preview-sprint-metric">
                <span>${escapeHtml(label)}</span>
                <strong>${escapeHtml(value)}</strong>
              </article>
            `
          )
          .join("")}
      </div>
      ${
        task.tags?.length
          ? `<div class="story-filter-chip-row">
              ${task.tags.map((tag) => `<span class="issue-tag">${escapeHtml(tag)}</span>`).join("")}
            </div>`
          : ""
      }
      <div class="preview-sprint-actions">
        ${task.actions.map((action, index) => renderQuickActionButton(action, index === 0)).join("")}
      </div>
    </article>
  `;
}

function renderPreviewSprintPanel() {
  const tasks = buildPreviewSprintTasks();

  return `
    <article class="detail-card preview-sprint-panel">
      <div class="panel-heading">
        <h2>导出冲刺助手</h2>
        <span class="badge badge-soft">优先处理最影响导出的事项</span>
      </div>
      <p class="helper-text">这里会先排出当前优先处理的问题，并提供可直接跳转的按钮，减少来回翻页的次数。</p>
      ${
        tasks.length > 0
          ? `<div class="preview-sprint-grid">${tasks.map((task) => renderPreviewSprintCard(task)).join("")}</div>`
          : renderEmpty("当前最影响导出的几类问题已经不明显了。可直接继续试玩，或再导出一版确认效果。")
      }
    </article>
  `;
}

function buildReleaseChecklistItems() {
  const project = state.data?.project ?? {};
  const resolution = getProjectResolution(project);
  const releaseVersion = getProjectReleaseVersion(project);
  const hasStoredReleaseVersion = Boolean(String(project.releaseVersion ?? "").trim());
  const urgentMissingAssets = state.data.assetList.filter((asset) => isAssetUrgentMissing(asset)).length;
  const mediaBudgetReport = buildAssetMediaBudgetReport();
  const missingVoiceWarnings = state.validation.warnings.filter(
    (issue) => issue.message === "这句台词还没有绑定语音。"
  ).length;
  const exportResult = state.lastExportResult;
  const nativeRcStatus = exportResult?.target === "native_runtime" ? exportResult.releaseCandidateReportStatus : "";
  const nativeRcSummary = exportResult?.releaseCandidateReportSummary ?? {};
  const nativeRcReadiness = exportResult?.releaseCandidateReadinessEstimate ?? {};
  const nativeRcHasReport = exportResult?.target === "native_runtime" && Boolean(nativeRcStatus);
  const native3dStatus = exportResult?.target === "native_runtime" ? exportResult.asset3dReportStatus : "";
  const native3dSummary = exportResult?.asset3dReportSummary ?? {};
  const native3dDigest = exportResult?.target === "native_runtime" ? exportResult.asset3dReportDigest ?? null : null;
  const native3dHasReport = exportResult?.target === "native_runtime" && Boolean(native3dStatus);

  const items = [
    {
      severity: hasStoredReleaseVersion ? "good" : "warn",
      title: "发布版本",
      toneClass: hasStoredReleaseVersion ? "good-text" : "warn-text",
      status: hasStoredReleaseVersion ? "已写入项目" : "待保存",
      description: hasStoredReleaseVersion
        ? `当前项目文件里的发布版本是 ${releaseVersion}。`
        : `当前导出会临时使用 ${releaseVersion}，但项目文件里还没正式写入。`,
      action: !hasStoredReleaseVersion ? { label: "保存这个版本", action: "save-release-version" } : null,
    },
    {
      severity: resolution.width === 1920 && resolution.height === 1080 ? "good" : "warn",
      title: "项目分辨率",
      toneClass: resolution.width === 1920 && resolution.height === 1080 ? "good-text" : "warn-text",
      status: resolution.width === 1920 && resolution.height === 1080 ? "适合正式桌面版" : "待切到 1920×1080",
      description:
        resolution.width === 1920 && resolution.height === 1080
          ? "当前已经是 Full HD 桌面分辨率。"
          : `现在是 ${resolution.width} × ${resolution.height}；如需做正式桌面版，可先切到 1920 × 1080。`,
      action:
        resolution.width === 1920 && resolution.height === 1080
          ? null
          : {
              label: "切到 1920×1080",
              action: "set-resolution",
              dataset: { width: "1920", height: "1080" },
            },
    },
    {
      severity: state.validation.errors.length === 0 ? "good" : "blocker",
      title: "结构错误",
      toneClass: state.validation.errors.length === 0 ? "good-text" : "danger-text",
      status: state.validation.errors.length === 0 ? "可以继续导出" : `还有 ${state.validation.errors.length} 项`,
      description:
        state.validation.errors.length === 0
          ? "当前没有会直接打断剧情结构的错误。"
          : "这些错误最容易让桌面包出现断链、跳错场景或无法继续推进。",
      action:
        state.validation.errors.length > 0
          ? {
              label: "只看结构错误",
              action: "set-preview-issue-filter",
              dataset: { "preview-issue-filter": "errors" },
            }
          : null,
    },
    {
      severity: urgentMissingAssets === 0 ? "good" : "blocker",
      title: "引用缺口素材",
      toneClass: urgentMissingAssets === 0 ? "good-text" : "warn-text",
      status: urgentMissingAssets === 0 ? "已齐" : `还差 ${urgentMissingAssets} 个`,
      description:
        urgentMissingAssets === 0
          ? "当前没有“已经被剧情引用但缺真实文件”的素材。"
          : "这些素材已经被剧情卡片引用，但导出时会直接缺图、缺音或缺视频。",
      action:
        urgentMissingAssets > 0
          ? {
              label: "去补缺口素材",
              action: "focus-asset-gap",
              dataset: { "asset-filter-mode": "urgent_missing" },
            }
          : null,
    },
    {
      severity: mediaBudgetReport.blockerCount > 0 ? "blocker" : mediaBudgetReport.count > 0 ? "warn" : "good",
      title: "素材性能预算",
      toneClass: mediaBudgetReport.blockerCount > 0 ? "danger-text" : mediaBudgetReport.count > 0 ? "warn-text" : "good-text",
      status:
        mediaBudgetReport.count === 0
          ? "体积健康"
          : mediaBudgetReport.blockerCount > 0
            ? `明显超预算 ${mediaBudgetReport.blockerCount} 个`
            : `建议压缩 ${mediaBudgetReport.count} 个`,
      description:
        mediaBudgetReport.count === 0
          ? "当前没有明显超出建议预算的大图、大音频或大视频。"
          : `建议发布前处理 ${mediaBudgetReport.count} 个大素材，合计 ${mediaBudgetReport.totalLabel}；最大项是 ${
              mediaBudgetReport.largest?.name ?? "未记录"
            }。`,
      action:
        mediaBudgetReport.count > 0
          ? {
              label: "只看体积风险素材",
              action: "focus-asset-gap",
              dataset: { "asset-filter-mode": "media_budget" },
            }
          : null,
    },
    {
      severity: missingVoiceWarnings === 0 ? "good" : "warn",
      title: "语音覆盖",
      toneClass: missingVoiceWarnings === 0 ? "good-text" : "warn-text",
      status: missingVoiceWarnings === 0 ? "当前没有待绑语音提醒" : `还差 ${missingVoiceWarnings} 句`,
      description:
        missingVoiceWarnings === 0
          ? "至少当前检查里没有新的待绑语音提醒。"
          : "如果这是正式发布前版本，可把这些台词集中补完语音，或确认本身就是无语音设计。",
      action: missingVoiceWarnings > 0 ? { label: "只看待绑语音", action: "focus-script-missing-voice" } : null,
    },
    {
      severity: nativeRcHasReport
        ? nativeRcStatus === "preview_ready"
          ? "good"
          : nativeRcStatus === "blocked" || nativeRcStatus === "unavailable"
            ? "blocker"
            : "warn"
        : "warn",
      title: "原生 Runtime RC",
      toneClass: nativeRcHasReport ? getNativeRuntimeRcToneClass(nativeRcStatus) : "warn-text",
      status: nativeRcHasReport ? getNativeRuntimeRcStatusLabel(nativeRcStatus) : "还没导过原生 Runtime 包",
      description: nativeRcHasReport
        ? `阻塞 ${nativeRcSummary.blockers ?? 0} / 提醒 ${nativeRcSummary.warnings ?? 0} / 桌面 Preview 估算 ${formatNativeRuntimeReadinessPercent(
            nativeRcReadiness.desktopPreviewPercent
          )}。`
        : "导出一次原生 Runtime 包后，编辑器会自动生成发布候选总报告，直接告诉你这包能不能进入三系统打包。",
      action: nativeRcHasReport
        ? {
            label: "打开 RC 报告",
            href: exportResult.releaseCandidateReportPublicUrl,
          }
        : {
            label: "生成原生 RC 检查包",
            action: "export-build",
            dataset: { "export-target": "native_runtime" },
        },
    },
    {
      severity: native3dHasReport
        ? native3dStatus === "ready" || native3dStatus === "no_3d_assets"
          ? "good"
          : native3dStatus === "unavailable"
            ? "blocker"
            : "warn"
        : "warn",
      title: "3D 资产清单",
      toneClass: native3dHasReport ? getNativeRuntime3dAssetToneClass(native3dStatus) : "warn-text",
      status: native3dHasReport ? getNativeRuntime3dAssetStatusLabel(native3dStatus) : "还没生成",
      description: native3dHasReport
        ? native3dDigest?.summaryLine ??
          `3D 模型 ${native3dSummary.model3dCount ?? 0} / 3D 场景 ${native3dSummary.scene3dCount ?? 0} / 问题 ${
            native3dSummary.issueCount ?? 0
          } / 未使用 ${native3dSummary.unusedCount ?? 0}。`
        : "导出原生 Runtime 包后，会自动生成 3D 模型与 3D 场景的结构、依赖和引用位置清单。",
      action: native3dHasReport
        ? native3dDigest?.topIssues?.[0]?.assetId
          ? {
              label: "定位首个风险素材",
              action: "open-asset-from-issue",
              assetId: native3dDigest.topIssues[0].assetId,
            }
          : {
              label: native3dDigest?.topIssues?.length ? "打开 3D 摘要" : "打开 3D 清单",
              href: native3dDigest?.topIssues?.length && exportResult.asset3dSummaryPublicUrl ? exportResult.asset3dSummaryPublicUrl : exportResult.asset3dReportPublicUrl,
            }
        : {
            label: "生成 3D 清单",
            action: "export-build",
            dataset: { "export-target": "native_runtime" },
          },
    },
    {
      severity:
        ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target) && exportResult.runtimeMode === "nwjs"
          ? "good"
          : ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target)
            ? "warn"
            : "warn",
      title: "原生桌面壳",
      toneClass:
        ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target) && exportResult.runtimeMode === "nwjs"
          ? "good-text"
          : ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target)
            ? "warn-text"
            : "",
      status:
        ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target) && exportResult.runtimeMode === "nwjs"
          ? "已走真桌面壳"
          : ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target)
            ? "当前是兜底模式"
            : "还没导过桌面包",
      description:
        ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target) && exportResult.runtimeMode === "nwjs"
          ? `最近一次桌面包已经走到 ${exportResult.packageModeLabel ?? "桌面壳模式"}。`
          : ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target)
            ? `最近一次桌面包没有拿到完整 NW.js 运行壳。${exportResult.runtimeWarning ? `原因：${exportResult.runtimeWarning}` : ""}`
            : "可至少导一次原生桌面包，确认桌面壳、图标和启动画面都已齐全。",
      action: {
        label: "去预览导出页",
        action: "switch-screen",
        screen: "preview",
      },
    },
  ];

  return items;
}

function buildReleaseChecklistSummary(items = buildReleaseChecklistItems()) {
  const blockerCount = items.filter((item) => item.severity === "blocker").length;
  const warnCount = items.filter((item) => item.severity === "warn").length;
  const readyCount = items.filter((item) => item.severity === "good").length;

  if (blockerCount > 0) {
    return {
      toneClass: "danger-text",
      badge: "先补阻塞项",
      title: `当前还有 ${blockerCount} 个发布阻塞项`,
      description: "这几个问题最容易直接影响正式交付，处理完成后再打正式包会更稳。",
      metrics: [
        ["阻塞项", `${blockerCount} 个`],
        ["提醒项", `${warnCount} 个`],
        ["已就绪", `${readyCount} 项`],
      ],
    };
  }

  if (warnCount > 0) {
    return {
      toneClass: "warn-text",
      badge: "基本可发",
      title: `当前没有硬阻塞，但还有 ${warnCount} 个待确认项`,
      description: "现在已经能继续导出，只是还有几项内容适合在正式交付前再确认一遍。",
      metrics: [
        ["阻塞项", "0 个"],
        ["提醒项", `${warnCount} 个`],
        ["已就绪", `${readyCount} 项`],
      ],
    };
  }

  return {
    toneClass: "good-text",
    badge: "可以交付",
    title: "当前这轮发布检查已经全部通过",
    description: "版本、分辨率、结构、素材缺口和桌面包状态目前都没有明显问题，可以继续打正式包。",
    metrics: [
      ["阻塞项", "0 个"],
      ["提醒项", "0 个"],
      ["已就绪", `${readyCount} 项`],
    ],
  };
}

function renderReleaseChecklistCard(item) {
  return `
    <article class="issue-card">
      <span class="issue-tag ${item.toneClass}">${escapeHtml(item.status)}</span>
      <strong>${escapeHtml(item.title)}</strong>
      <div class="issue-meta">${escapeHtml(item.description)}</div>
      ${item.action ? `<div class="issue-card-footer">${renderQuickActionButton(item.action, true)}</div>` : ""}
    </article>
  `;
}

function getNativeRuntimeRcStatusLabel(status) {
  switch (status) {
    case "preview_ready":
      return "Preview RC 可进入三系统打包";
    case "preview_ready_with_warnings":
      return "Preview RC 可打包，但有提醒";
    case "preview_ready_with_optional_failures":
      return "Preview 主链可打包，但有非核心失败";
    case "blocked":
      return "存在阻塞项，先修复再打包";
    case "unavailable":
      return "RC 报告暂不可用";
    default:
      return status ? String(status) : "尚未生成";
  }
}

function getNativeRuntimeRcToneClass(status) {
  if (status === "preview_ready") return "good-text";
  if (status === "blocked" || status === "unavailable") return "danger-text";
  if (status === "preview_ready_with_warnings" || status === "preview_ready_with_optional_failures") return "warn-text";
  return "";
}

function getNativeRuntime3dAssetStatusLabel(status) {
  switch (status) {
    case "ready":
      return "3D 资产清单通过";
    case "no_3d_assets":
      return "当前没有 3D 资产";
    case "needs_attention":
      return "3D 资产需要处理";
    case "unavailable":
      return "3D 清单暂不可用";
    default:
      return status ? String(status) : "尚未生成";
  }
}

function getNativeRuntime3dAssetToneClass(status) {
  if (status === "ready" || status === "no_3d_assets") return "good-text";
  if (status === "unavailable") return "danger-text";
  if (status === "needs_attention") return "warn-text";
  return "";
}

function formatNativeRuntime3dNumber(value) {
  const numberValue = Number(value);
  if (!Number.isFinite(numberValue)) return "0";
  return Math.max(0, Math.round(numberValue)).toLocaleString("zh-CN");
}

function formatNativeRuntime3dRiskLine(digest = {}) {
  const risks = digest.riskCounts ?? {};
  const parts = Object.entries(risks)
    .filter(([, value]) => Number(value) > 0)
    .map(([label, value]) => `${label} ${value}`);
  return parts.length ? parts.join(" / ") : "暂无明显风险";
}

function formatNativeRuntimeReadinessPercent(value) {
  const numberValue = Number(value);
  if (!Number.isFinite(numberValue)) return "未估算";
  return `${Math.max(0, Math.min(100, Math.round(numberValue)))}%`;
}

function renderReleaseSettingsPanel() {
  const project = state.data?.project ?? {};
  const releaseVersion = getProjectReleaseVersion(project);
  const hasStoredReleaseVersion = Boolean(String(project.releaseVersion ?? "").trim());
  const currentBaseVersion = getReleaseVersionBase(releaseVersion);

  return `
    <article class="detail-card">
      <strong>发布版本</strong>
      <p class="helper-text">这里会写进项目文件、导出发布清单和桌面包说明里。保持统一的版本号习惯会更便于后续发布，例如 1.0.0-preview、1.0.0-beta、1.0.0。</p>
      <div class="asset-search-row story-tree-filter-row">
        <label class="asset-search-field">
          <span class="sr-only">发布版本</span>
          <input
            id="projectReleaseVersionInput"
            type="text"
            value="${escapeHtml(releaseVersion)}"
            placeholder="例如 1.0.0-preview"
          />
        </label>
        <button class="toolbar-button toolbar-button-primary" data-action="save-release-version">
          保存版本
        </button>
      </div>
      <div class="detail-actions">
        <button class="toolbar-button" data-action="apply-release-version-preset" data-release-preset="preview">
          预设：${escapeHtml(`${currentBaseVersion}-preview`)}
        </button>
        <button class="toolbar-button" data-action="apply-release-version-preset" data-release-preset="beta">
          预设：${escapeHtml(`${currentBaseVersion}-beta`)}
        </button>
        <button class="toolbar-button" data-action="apply-release-version-preset" data-release-preset="rc">
          预设：${escapeHtml(`${currentBaseVersion}-rc1`)}
        </button>
        <button class="toolbar-button" data-action="apply-release-version-preset" data-release-preset="release">
          预设：${escapeHtml(currentBaseVersion)}
        </button>
      </div>
      <div class="detail-meta">
        ${
          hasStoredReleaseVersion
            ? `当前项目文件已保存发布版本：${escapeHtml(releaseVersion)}`
            : `当前还没有正式写入项目文件，导出时会先临时使用默认版本：${escapeHtml(releaseVersion)}`
        }
      </div>
    </article>
  `;
}

function renderReleaseChecklistPanel() {
  const items = buildReleaseChecklistItems();
  const summary = buildReleaseChecklistSummary(items);
  return `
    <article class="detail-card preview-sprint-panel">
      <div class="panel-heading">
        <h2>发布检查清单</h2>
        <span class="badge badge-soft">导出前最后看一眼</span>
      </div>
      <p class="helper-text">这里会把最容易影响正式交付的检查项集中列出来，每一项都尽量给你一个马上可点的动作。</p>
      <div class="detail-actions">
        <button class="toolbar-button toolbar-button-primary" data-action="export-release-control-report">
          导出发布总控报告
        </button>
        <button class="toolbar-button" data-action="export-release-control-json">
          导出 JSON 数据
        </button>
        <button class="toolbar-button" data-action="export-inspection-report">
          导出巡检报告
        </button>
      </div>
      <article class="preview-sprint-card is-soft">
        <div class="preview-sprint-head">
          <strong>${escapeHtml(summary.title)}</strong>
          <span class="issue-tag ${summary.toneClass}">${escapeHtml(summary.badge)}</span>
        </div>
        <p>${escapeHtml(summary.description)}</p>
        <div class="preview-sprint-metrics">
          ${summary.metrics
            .map(
              ([label, value]) => `
                <article class="preview-sprint-metric">
                  <span>${escapeHtml(label)}</span>
                  <strong>${escapeHtml(value)}</strong>
                </article>
              `
            )
            .join("")}
        </div>
      </article>
      <div class="preview-sprint-grid">${items.map((item) => renderReleaseChecklistCard(item)).join("")}</div>
    </article>
  `;
}

function buildPreviewRegressionSeeds(routeOverview) {
  const seeds = [];
  const seenSceneIds = new Set();

  function appendSeed(sceneId, sourceLabel, reason, score = 0) {
    const safeSceneId = getSafeSceneId(sceneId);
    const scene = state.data?.scenesById.get(safeSceneId);

    if (!scene || seenSceneIds.has(scene.id)) {
      return;
    }

    seenSceneIds.add(scene.id);
    seeds.push({
      sceneId: scene.id,
      sceneName: scene.name,
      chapterName: scene.chapterName ?? "未分章",
      sourceLabel,
      reason,
      score,
    });
  }

  appendSeed(
    state.data?.project?.entrySceneId,
    "项目入口",
    "从游戏真正开始的位置先跑一遍，是最基础也最关键的一条烟测路线。",
    100
  );

  routeOverview.chapters.forEach((chapter) => {
    const firstScene = chapter.scenes?.[0];
    if (!firstScene) {
      return;
    }
    appendSeed(
      firstScene.id,
      `章节起点 · ${chapter.name}`,
      "把每一章的第一场先跑通，最容易提前发现章节切换和起手坏链。",
      90
    );
  });

  routeOverview.nodes
    .filter((node) => node.branchTargetCount > 1)
    .sort((left, right) => {
      if (right.branchTargetCount !== left.branchTargetCount) {
        return right.branchTargetCount - left.branchTargetCount;
      }
      return (right.errorCount ?? 0) - (left.errorCount ?? 0);
    })
    .slice(0, PREVIEW_REGRESSION_BRANCHING_SEED_LIMIT)
    .forEach((node) => {
      appendSeed(
        node.id,
        "分支场景",
        `这里有 ${node.branchTargetCount} 条去向，先按默认选项烟测一遍，最容易提前发现跳转断裂。`,
        80
      );
    });

  routeOverview.nodes
    .filter((node) => (node.errorCount ?? 0) > 0 || node.brokenRouteCount > 0 || node.isOrphan)
    .sort((left, right) => {
      const leftScore = (left.errorCount ?? 0) * 10 + left.brokenRouteCount * 6 + (left.isOrphan ? 4 : 0);
      const rightScore =
        (right.errorCount ?? 0) * 10 + right.brokenRouteCount * 6 + (right.isOrphan ? 4 : 0);
      return rightScore - leftScore;
    })
    .forEach((node) => {
      appendSeed(
        node.id,
        "问题高发场景",
        "这段本身已经带问题信号，适合在正式导出前顺手做一次重点回归。",
        70
      );
    });

  if (!seeds.length && state.data?.scenes?.[0]?.id) {
    appendSeed(
      state.data.scenes[0].id,
      "默认起点",
      "项目里暂时没有更明显的关键节点，就先从第一场开始回归。",
      60
    );
  }

  return seeds
    .sort((left, right) => {
      if (right.score !== left.score) {
        return right.score - left.score;
      }
      return left.sceneName.localeCompare(right.sceneName, "zh-CN");
    })
    .slice(0, PREVIEW_REGRESSION_MAX_CASES);
}

function getPreviewRegressionTerminalMeta(snapshot, previousSnapshot, steps) {
  const message = String(snapshot?.visualState?.dialogueText ?? "").trim();

  if (message.includes("目标场景不存在")) {
    return {
      status: "fail",
      title: "跳转到了不存在的场景",
      detail: "这条路线在推进过程中撞到了一个不存在的目标场景，正式发布前必须先把跳转补对。",
      anchorSnapshot: previousSnapshot ?? snapshot,
    };
  }

  if (message.includes("这个场景还没有卡片")) {
    return {
      status: "fail",
      title: "进入了空场景",
      detail: "这条路线会把玩家带进一个没有任何卡片的场景，试玩会直接卡住。",
      anchorSnapshot: snapshot?.blockId ? snapshot : previousSnapshot ?? snapshot,
    };
  }

  if (steps <= 1) {
    return {
      status: "warn",
      title: "这条路线结束得太快",
      detail: "烟测虽然没有直接撞错，但这条路线几乎一开场就结束了，可确认是否缺少正文、跳转或分支承接。",
      anchorSnapshot: previousSnapshot ?? snapshot,
    };
  }

  return {
    status: "pass",
    title: "这条关键路线已经走通",
    detail: "本次烟测能顺利走到结尾，没有撞到坏链或死循环。",
    anchorSnapshot: previousSnapshot ?? snapshot,
  };
}

function buildPreviewRegressionCaseActions(caseResult) {
  const actions = [];

  if (caseResult.anchorBlockId) {
    actions.push({
      label: "试玩问题位置",
      action: "preview-story-location",
      sceneId: caseResult.anchorSceneId,
      blockId: caseResult.anchorBlockId,
    });
    actions.push({
      label: "打开对应卡片",
      action: "open-character-line",
      sceneId: caseResult.anchorSceneId,
      blockId: caseResult.anchorBlockId,
    });
    return actions;
  }

  if (caseResult.seedSceneId) {
    actions.push({
      label: "试玩这段",
      action: "preview-scene-from-map",
      sceneId: caseResult.seedSceneId,
    });
  }

  if (caseResult.anchorSceneId) {
    actions.push({
      label: "打开场景",
      action: "open-scene-from-map",
      sceneId: caseResult.anchorSceneId,
    });
  }

  return actions;
}

function runPreviewRegressionCase(seed) {
  const session = createPreviewRegressionSession(seed.sceneId);
  const visitedStepCounts = new Map();
  const visitedSceneIds = new Set();
  const selectedOptionTexts = [];
  let previousSnapshot = null;
  let steps = 0;
  let choiceCount = 0;

  while (steps < PREVIEW_REGRESSION_MAX_STEPS) {
    const snapshot = getCurrentPreviewRegressionSnapshot(session);

    if (!snapshot) {
      break;
    }

    if (snapshot.sceneId) {
      visitedSceneIds.add(snapshot.sceneId);
    }

    const stateKey = [
      snapshot.sceneId ?? "none",
      snapshot.blockId ?? "complete",
      snapshot.blockIndex,
      snapshot.selectedOptionId ?? "",
      snapshot.resolvedBranchId ?? "",
    ].join(":");
    const nextRepeatCount = (visitedStepCounts.get(stateKey) ?? 0) + 1;
    visitedStepCounts.set(stateKey, nextRepeatCount);

    if (nextRepeatCount > PREVIEW_REGRESSION_MAX_REPEAT) {
      const anchorSnapshot = previousSnapshot ?? snapshot;
      const result = {
        id: `${seed.sceneId}:loop`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: "fail",
        statusLabel: "疑似死循环",
        reason: "这条路线反复回到同一个步骤，已经不像正常的剧情推进了。",
        detail: `烟测在 ${steps} 步内重复命中同一位置超过 ${PREVIEW_REGRESSION_MAX_REPEAT} 次，可先检查跳转、条件判断或循环分支。`,
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: anchorSnapshot?.sceneId ?? seed.sceneId,
        anchorBlockId: anchorSnapshot?.blockId ?? null,
      };
      result.actions = buildPreviewRegressionCaseActions(result);
      return result;
    }

    if (snapshot.completed) {
      const terminalMeta = getPreviewRegressionTerminalMeta(snapshot, previousSnapshot, steps);
      const result = {
        id: `${seed.sceneId}:${terminalMeta.status}:${steps}`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: terminalMeta.status,
        statusLabel:
          terminalMeta.status === "pass"
            ? "已走通"
            : terminalMeta.status === "warn"
              ? "需要复看"
              : "回归失败",
        reason: terminalMeta.title,
        detail: terminalMeta.detail,
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: terminalMeta.anchorSnapshot?.sceneId ?? seed.sceneId,
        anchorBlockId: terminalMeta.anchorSnapshot?.blockId ?? null,
      };
      result.actions = buildPreviewRegressionCaseActions(result);
      return result;
    }

    if (snapshot.blockType === "choice") {
      if (!snapshot.choiceOptions.length) {
        const result = {
          id: `${seed.sceneId}:choice-empty`,
          seedSceneId: seed.sceneId,
          sceneName: seed.sceneName,
          chapterName: seed.chapterName,
          sourceLabel: seed.sourceLabel,
          status: "fail",
          statusLabel: "选项卡无可用选项",
          reason: "这张选项卡没有任何可走分支",
          detail: "玩家走到这里时没有任何选项可点，试玩会直接中断，可先补齐选项去向。",
          steps,
          visitedSceneCount: visitedSceneIds.size,
          choiceCount,
          selectedOptionTexts,
          anchorSceneId: snapshot.sceneId ?? seed.sceneId,
          anchorBlockId: snapshot.blockId ?? null,
        };
        result.actions = buildPreviewRegressionCaseActions(result);
        return result;
      }

      const selectedOption = snapshot.choiceOptions[0];
      choiceCount += 1;
      selectedOptionTexts.push(truncateText(selectedOption.text || `选项 ${choiceCount}`, 18));
      previousSnapshot = snapshot;
      choosePreviewRegressionOption(session, selectedOption.id);
      steps += 1;
      continue;
    }

    previousSnapshot = snapshot;
    const nextSnapshot = movePreviewRegressionForward(session);

    if (!nextSnapshot || nextSnapshot === snapshot) {
      const result = {
        id: `${seed.sceneId}:stalled`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: "fail",
        statusLabel: "推进中断",
        reason: "这条路线没有正常继续往下推进",
        detail: "烟测在这里没能继续前进，可检查这一张卡片是否缺少目标场景、选项或有效内容。",
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: snapshot.sceneId ?? seed.sceneId,
        anchorBlockId: snapshot.blockId ?? null,
      };
      result.actions = buildPreviewRegressionCaseActions(result);
      return result;
    }

    steps += 1;
  }

  const result = {
    id: `${seed.sceneId}:max-steps`,
    seedSceneId: seed.sceneId,
    sceneName: seed.sceneName,
    chapterName: seed.chapterName,
    sourceLabel: seed.sourceLabel,
    status: "fail",
    statusLabel: "超过最大步数",
    reason: "这条路线跑得太久了，像是没能正常收束",
    detail: `烟测已经推进超过 ${PREVIEW_REGRESSION_MAX_STEPS} 步，仍然没有走到结尾，可先检查是否存在循环跳转或条件阻塞。`,
    steps: PREVIEW_REGRESSION_MAX_STEPS,
    visitedSceneCount: visitedSceneIds.size,
    choiceCount,
    selectedOptionTexts,
    anchorSceneId: previousSnapshot?.sceneId ?? seed.sceneId,
    anchorBlockId: previousSnapshot?.blockId ?? null,
  };
  result.actions = buildPreviewRegressionCaseActions(result);
  return result;
}

function runPreviewRegressionSmokeTest(routeOverview = buildSceneRouteOverview()) {
  const seeds = buildPreviewRegressionSeeds(routeOverview);
  const cases = seeds.map((seed) => runPreviewRegressionCase(seed)).sort((left, right) => {
    const priorityMap = { fail: 0, warn: 1, pass: 2 };
    if (priorityMap[left.status] !== priorityMap[right.status]) {
      return priorityMap[left.status] - priorityMap[right.status];
    }
    return left.sceneName.localeCompare(right.sceneName, "zh-CN");
  });

  const summary = {
    total: cases.length,
    passCount: cases.filter((item) => item.status === "pass").length,
    warnCount: cases.filter((item) => item.status === "warn").length,
    failCount: cases.filter((item) => item.status === "fail").length,
  };

  return {
    ranAt: new Date().toISOString(),
    seeds,
    cases,
    summary,
  };
}

function getPreviewRegressionStatusToneClass(status) {
  if (status === "fail") {
    return "danger-text";
  }
  if (status === "warn") {
    return "warn-text";
  }
  return "good-text";
}

function renderPreviewRegressionCaseCard(caseResult) {
  return `
    <article class="preview-sprint-card is-${
      caseResult.status === "fail" ? "danger" : caseResult.status === "warn" ? "warn" : "good"
    }">
      <div class="preview-sprint-head">
        <strong>${escapeHtml(caseResult.sceneName)}</strong>
        <span class="issue-tag ${getPreviewRegressionStatusToneClass(caseResult.status)}">
          ${escapeHtml(caseResult.statusLabel)}
        </span>
      </div>
      <div class="detail-meta">
        ${escapeHtml(
          `${caseResult.chapterName} · ${caseResult.sourceLabel} · 走了 ${caseResult.steps} 步 · 到过 ${caseResult.visitedSceneCount} 个场景`
        )}
      </div>
      <p>${escapeHtml(caseResult.reason)}</p>
      <div class="helper-text">${escapeHtml(caseResult.detail)}</div>
      <div class="scene-card-tags">
        <span class="issue-tag">选择 ${caseResult.choiceCount} 次</span>
        ${
          caseResult.selectedOptionTexts.length > 0
            ? `<span class="issue-tag">${escapeHtml(`默认选项：${caseResult.selectedOptionTexts.slice(0, 2).join(" / ")}`)}${
                caseResult.selectedOptionTexts.length > 2 ? "…" : ""
              }</span>`
            : ""
        }
      </div>
      <div class="preview-sprint-actions">
        ${(caseResult.actions ?? []).map((action, index) => renderQuickActionButton(action, index === 0)).join("")}
      </div>
    </article>
  `;
}

function renderPreviewRegressionPanel(routeOverview) {
  const result = state.inspectionRegressionResult;
  const focusSceneNames = (result?.seeds ?? buildPreviewRegressionSeeds(routeOverview))
    .map((seed) => seed.sceneName)
    .slice(0, 4)
    .join(" / ");

  return `
    <article class="detail-card preview-sprint-panel">
      <div class="panel-heading">
        <h2>自动回归试玩路线测试</h2>
        <span class="badge badge-soft">关键路线烟测</span>
      </div>
      <p class="helper-text">这里会自动用试玩运行时把关键入口、章节起点和高分支场景先跑一遍，优先检查坏链、空场景和疑似死循环。</p>
      <div class="detail-actions">
        <button class="toolbar-button toolbar-button-primary" data-action="run-preview-regression">
          自动回归试玩路线测试
        </button>
        <button class="toolbar-button" data-action="export-inspection-report">
          导出带回归结果的巡检报告
        </button>
      </div>
      ${
        result
          ? `
              <div class="summary-grid">
                ${renderStatCard("已测试路线", `${result.summary.total} 条`)}
                ${renderStatCard("通过", `${result.summary.passCount} 条`)}
                ${renderStatCard("需要复看", `${result.summary.warnCount} 条`)}
                ${renderStatCard("失败", `${result.summary.failCount} 条`)}
              </div>
              <div class="detail-meta">上次回归时间：${escapeHtml(formatDate(result.ranAt))} · 本次重点覆盖 ${escapeHtml(
                focusSceneNames || "关键入口"
              )}${(result.seeds?.length ?? 0) > 4 ? " 等关键入口" : ""}</div>
              <div class="preview-sprint-grid">
                ${result.cases.map((caseResult) => renderPreviewRegressionCaseCard(caseResult)).join("")}
              </div>
            `
          : renderEmpty("还没有跑过自动回归试玩路线测试。点上面的按钮后，这里会列出关键路线的通过、提醒和失败结果。")
      }
    </article>
  `;
}

function getPreviewRegressionFixPriority(caseResult) {
  let score = caseResult.status === "fail" ? 100 : 60;

  if (caseResult.reason.includes("不存在的场景")) {
    score += 30;
  } else if (caseResult.reason.includes("空场景")) {
    score += 24;
  } else if (caseResult.reason.includes("死循环")) {
    score += 20;
  } else if (caseResult.reason.includes("无可用选项")) {
    score += 18;
  } else if (caseResult.reason.includes("推进中断")) {
    score += 14;
  } else if (caseResult.reason.includes("超过最大步数")) {
    score += 12;
  } else if (caseResult.reason.includes("结束得太快")) {
    score += 8;
  }

  score += Math.min(caseResult.visitedSceneCount ?? 0, 6);
  return score;
}

function getPreviewRegressionFixRecommendation(caseResult) {
  if (caseResult.reason.includes("不存在的场景")) {
    return "先把这条跳转补到真实存在的目标场景，再重新跑这一条烟测。";
  }

  if (caseResult.reason.includes("空场景")) {
    return "先给这个落点补至少一张可推进的剧情卡，避免玩家直接掉进空白场景。";
  }

  if (caseResult.reason.includes("死循环") || caseResult.reason.includes("超过最大步数")) {
    return "先检查这里前后的 jump / condition / choice 去向，看看是不是把路线绕回了自己。";
  }

  if (caseResult.reason.includes("无可用选项")) {
    return "先给这张选项卡补至少一个真正可走的去向，不然玩家会直接卡死。";
  }

  if (caseResult.reason.includes("推进中断")) {
    return "先检查这一张卡片是不是缺目标、缺正文，或者逻辑没有把下一步接上。";
  }

  if (caseResult.reason.includes("结束得太快")) {
    return "先确认这段是不是本来就该收尾；如果不是，补正文、分支承接或结尾跳转会更稳。";
  }

  return "这条路线适合优先复看一次，确认推进节奏和去向是否符合当前设计。";
}

function buildPreviewRegressionFixQueue() {
  const regressionResult = state.inspectionRegressionResult;

  if (!regressionResult) {
    return [];
  }

  return regressionResult.cases
    .filter((caseResult) => caseResult.status !== "pass")
    .map((caseResult) => ({
      ...caseResult,
      priorityScore: getPreviewRegressionFixPriority(caseResult),
      recommendation: getPreviewRegressionFixRecommendation(caseResult),
    }))
    .sort((left, right) => {
      if (right.priorityScore !== left.priorityScore) {
        return right.priorityScore - left.priorityScore;
      }
      return left.sceneName.localeCompare(right.sceneName, "zh-CN");
    });
}

function renderPreviewRegressionFixQueuePanel() {
  const queue = buildPreviewRegressionFixQueue();

  return `
    <article class="detail-card preview-sprint-panel">
      <div class="panel-heading">
        <h2>发布前回归修复优先队列</h2>
        <span class="badge badge-soft">先修这几条最省力</span>
      </div>
      <p class="helper-text">这里会把刚才回归里优先处理的失败路线和提醒路线排成队列，便于按顺序处理。</p>
      ${
        queue.length > 0
          ? `
              <div class="preview-sprint-grid">
                ${queue
                  .map(
                    (caseResult, index) => `
                      <article class="preview-sprint-card is-${
                        caseResult.status === "fail" ? "danger" : "warn"
                      }">
                        <div class="preview-sprint-head">
                          <strong>第 ${index + 1} 优先 · ${escapeHtml(caseResult.sceneName)}</strong>
                          <span class="issue-tag ${getPreviewRegressionStatusToneClass(caseResult.status)}">
                            ${escapeHtml(caseResult.statusLabel)}
                          </span>
                        </div>
                        <div class="detail-meta">
                          ${escapeHtml(
                            `${caseResult.chapterName} · ${caseResult.sourceLabel} · 优先分 ${caseResult.priorityScore}`
                          )}
                        </div>
                        <p>${escapeHtml(caseResult.reason)}</p>
                        <div class="helper-text">${escapeHtml(caseResult.recommendation)}</div>
                        <div class="preview-sprint-actions">
                          ${(caseResult.actions ?? []).map((action, actionIndex) => renderQuickActionButton(action, actionIndex === 0)).join("")}
                        </div>
                      </article>
                    `
                  )
                  .join("")}
              </div>
            `
          : renderEmpty(
              state.inspectionRegressionResult
                ? "这轮自动回归里暂时没有需要优先修的失败或提醒路线。"
                : "先跑一遍自动回归试玩路线测试，这里才会排出最值得先修的路线。"
            )
      }
    </article>
  `;
}

