function renderVoiceReplayOverviewPanel() {
  const scenes = state.data?.scenes ?? [];
  const assetList = state.data?.assetList ?? [];
  const assetsById = state.data?.assetsById ?? new Map();
  const voiceBlocks = [];

  scenes.forEach((scene) => {
    (scene.blocks ?? []).forEach((block, blockIndex) => {
      if ((block.type !== "dialogue" && block.type !== "narration") || !block.voiceAssetId) {
        return;
      }

      const asset = assetsById.get(block.voiceAssetId);
      if (!asset || asset.type !== "voice") {
        return;
      }

      voiceBlocks.push({
        sceneName: scene.name,
        chapterName: scene.chapterName,
        text: String(block.text ?? "").trim(),
        asset,
        blockIndex,
      });
    });
  });

  const readyVoiceBlocks = voiceBlocks.filter((entry) => entry.asset.fileExists);
  const missingVoiceBlocks = voiceBlocks.filter((entry) => !entry.asset.fileExists);
  const uniqueVoiceAssets = new Set(voiceBlocks.map((entry) => entry.asset.id)).size;
  const readyVoiceAssets = new Set(readyVoiceBlocks.map((entry) => entry.asset.id)).size;

  return `
    <article class="detail-card">
      <strong>语音回听 / 名台词回放馆</strong>
      <p class="helper-text">导出后的标题页会根据“已经绑了真实语音文件的台词”自动显示“语音回听”。玩家第一次推进到那句台词后，这句就会被收录进本机回听馆，之后能直接从标题页回放。</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(
          "可参与回听的台词",
          readyVoiceBlocks.length > 0 ? `${readyVoiceBlocks.length} 句` : "暂时没有",
          readyVoiceBlocks.length > 0
            ? "这些已经有真实语音文件的台词，导出后就能自动进入回听馆"
            : "至少先让几句台词绑上真实语音文件，标题页回听入口才会出现"
        )}
        ${renderRouteMetricCard(
          "语音条目",
          uniqueVoiceAssets > 0 ? `${readyVoiceAssets}/${uniqueVoiceAssets} 已就绪` : "还没有语音条目",
          uniqueVoiceAssets > 0
            ? missingVoiceBlocks.length > 0
              ? `还有 ${missingVoiceBlocks.length} 句绑了语音条目但还没真实文件`
              : "这批语音素材已经能支持标题页回听"
            : "去配音工作流里生成或上传语音"
        )}
        ${renderRouteMetricCard(
          "标题页入口",
          readyVoiceBlocks.length > 0 ? "会显示" : "暂不显示",
          readyVoiceBlocks.length > 0
            ? "只要项目里已经有至少一句“带真实语音文件”的台词，标题页就会出现“语音回听”按钮"
            : "当前没有可播放的语音台词，所以标题页不会显示回听入口"
        )}
        ${renderRouteMetricCard(
          "自动收录规则",
          "第一次推进到这句后收录",
          "玩家真的走到这句带语音的台词后，这句就会在自己的本机自动亮起"
        )}
      </div>
      <div class="detail-actions">
        <button class="toolbar-button" data-action="switch-screen" data-screen="script">
          去台词台本看语音
        </button>
        <button
          class="toolbar-button"
          data-action="focus-asset-gap"
          data-asset-filter-mode="missing_file"
          data-asset-type="voice"
        >
          去补待导入语音
        </button>
        <button class="toolbar-button" data-action="export-build" data-export-target="web">
          导一版试玩包确认
        </button>
      </div>
      <div class="detail-meta">${
        readyVoiceBlocks.length > 0
          ? `当前最适合先确认的回听台词：${escapeHtml(
              readyVoiceBlocks
                .slice(0, 3)
                .map((entry) => `${entry.chapterName} · ${entry.sceneName} · ${truncateText(entry.text || "这句台词没有正文。", 20)}`)
                .join(" / ")
            )}${readyVoiceBlocks.length > 3 ? ` 等 ${readyVoiceBlocks.length} 句` : ""}`
          : "现在还没有满足条件的语音台词，所以标题页不会出现语音回听入口。"
      }</div>
    </article>
  `;
}

function buildExtraModeOverview() {
  const assetList = state.data?.assetList ?? [];
  const cgAssets = assetList.filter((asset) => asset.type === "cg");
  const bgmAssets = assetList.filter((asset) => asset.type === "bgm");
  const readyCgCount = cgAssets.filter((asset) => asset.fileExists).length;
  const readyBgmCount = bgmAssets.filter((asset) => asset.fileExists).length;

  return {
    cg: {
      total: cgAssets.length,
      ready: readyCgCount,
      missing: Math.max(cgAssets.length - readyCgCount, 0),
    },
    bgm: {
      total: bgmAssets.length,
      ready: readyBgmCount,
      missing: Math.max(bgmAssets.length - readyBgmCount, 0),
    },
    hasAnyEntry: cgAssets.length > 0 || bgmAssets.length > 0,
  };
}

