async function moveScene(direction) {
  const { scene, chapter, sceneOrder, index } = getSelectedSceneOrderInfo();

  if (!scene || !chapter) {
    window.alert("先选中一个场景，再调整它的位置。");
    return;
  }

  const targetIndex = index + direction;

  if (index < 0 || targetIndex < 0 || targetIndex >= sceneOrder.length) {
    setSaveStatus(direction < 0 ? "这个场景已经在章节最前面了" : "这个场景已经在章节最后面了");
    return;
  }

  try {
    setSaveStatus("正在调整场景顺序...");
    await postJson(API_MOVE_SCENE, {
      chapterId: chapter.chapterId,
      sceneId: scene.id,
      direction,
    });

    await reloadProjectData({
      ...getCurrentUiState(),
      selectedSceneId: scene.id,
      previewSceneId: scene.id,
      previewStartSceneId: state.previewStartSceneId,
    });

    setSaveStatus(direction < 0 ? "场景已上移一位" : "场景已下移一位");
  } catch (error) {
    setSaveStatus("调整场景顺序失败", true);
    window.alert(`调整场景顺序没有成功：${error.message}`);
  }
}

