function toggleUnusedAssetsFilter(nextMode = null) {
  const unusedAssets = getUnusedAssets();
  const targetMode = getSafeAssetFilterMode(
    nextMode ?? (state.assetFilterMode === "unused" ? "all" : "unused")
  );

  if (targetMode === "unused" && unusedAssets.length === 0) {
    setSaveStatus("当前没有未使用素材");
    return;
  }

  state.assetFilterMode = targetMode;
  const visibleAssets = getVisibleAssets();
  const selectedAsset =
    visibleAssets.find((asset) => asset.id === state.selectedAssetId) ??
    visibleAssets.find((asset) => asset.type === state.selectedAssetType) ??
    visibleAssets[0] ??
    null;

  if (selectedAsset) {
    state.selectedAssetType = selectedAsset.type;
    state.selectedAssetId = selectedAsset.id;
  } else {
    state.selectedAssetId = null;
  }

  renderAssetsScreen();
  setSaveStatus(
    targetMode === "unused"
      ? `现在只显示${getAssetFilterModeStatusLabel(targetMode)}`
      : `已恢复显示${getAssetFilterModeStatusLabel("all")}`
  );
}

function focusUnusedAssets() {
  const unusedAssets = getUnusedAssets();

  if (unusedAssets.length === 0) {
    setSaveStatus("当前没有未使用素材");
    switchScreen("assets");
    renderAssetsScreen();
    return;
  }

  state.assetFilterMode = "unused";
  state.assetSearchQuery = "";
  state.assetTagFilter = "";
  state.assetFavoriteOnly = false;
  state.selectedAssetType = unusedAssets[0].type;
  state.selectedAssetId = unusedAssets[0].id;
  switchScreen("assets");
  renderAssetsScreen();
  setSaveStatus(`已定位到 ${unusedAssets.length} 个未使用素材`);
}

function focusAssetGap(filterMode, assetType = null) {
  const safeFilterMode = getSafeAssetFilterMode(filterMode);
  const safeType = Object.prototype.hasOwnProperty.call(ASSET_TYPE_LABELS, assetType ?? "")
    ? assetType
    : null;

  state.assetFilterMode = safeFilterMode;
  state.assetSearchQuery = "";
  state.assetTagFilter = "";
  state.assetFavoriteOnly = false;
  switchScreen("assets");

  const visibleAssets = getVisibleAssets();
  const matchingAssets = safeType
    ? visibleAssets.filter((asset) => asset.type === safeType)
    : visibleAssets;

  if (!matchingAssets.length) {
    if (safeType) {
      state.selectedAssetType = safeType;
    }
    state.selectedAssetId = null;
    renderAssetsScreen();
    const emptyMessage = safeType
      ? `${getAssetTypeLabel(safeType)}里暂时没有${getAssetFilterModeStatusLabel(safeFilterMode)}`
      : `当前没有${getAssetFilterModeStatusLabel(safeFilterMode)}`;
    setSaveStatus(emptyMessage);
    showToast(emptyMessage);
    return;
  }

  const nextSelectedAsset = matchingAssets[0];
  state.selectedAssetType = nextSelectedAsset.type;
  state.selectedAssetId = nextSelectedAsset.id;
  renderAssetsScreen();
  const successMessage = safeType
    ? `已定位到${getAssetTypeLabel(nextSelectedAsset.type)}里的${getAssetFilterModeStatusLabel(safeFilterMode)}`
    : `已定位到${getAssetFilterModeStatusLabel(safeFilterMode)}`;
  setSaveStatus(successMessage);
  showToast(successMessage);
}

async function saveProjectResolution(widthValue, heightValue) {
  const width = Number.parseInt(widthValue, 10);
  const height = Number.parseInt(heightValue, 10);
  const current = getProjectResolution();

  if (width === current.width && height === current.height) {
    setSaveStatus(`当前已经是 ${width} × ${height}`);
    showToast(`当前已经是 ${getResolutionLabel(width, height)}`);
    return;
  }

  try {
    setSaveStatus("正在切换项目分辨率...");
    const result = await postJson(API_SAVE_PROJECT_SETTINGS, {
      resolution: { width, height },
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
    });

    const resolution = result.project?.resolution ?? { width, height };
    setSaveStatus(`项目分辨率已切到 ${resolution.width} × ${resolution.height}`);
    showToast(`分辨率已切到 ${getResolutionLabel(resolution.width, resolution.height)}`);
  } catch (error) {
    setSaveStatus("切换分辨率失败", true);
    showToast("切换分辨率失败", "error");
    window.alert(`切换分辨率没有成功：${error.message}`);
  }
}

async function saveProjectEditorMode(mode) {
  const nextMode = getSafeEditorMode(mode);
  const currentMode = getProjectEditorMode();
  const previousScreen = state.currentScreen;

  if (nextMode === currentMode) {
    setSaveStatus(`当前已经是${getEditorModeLabel(currentMode)}`);
    showToast(`当前已经是${getEditorModeLabel(currentMode)}`);
    return;
  }

  try {
    setSaveStatus(`正在切到${getEditorModeLabel(nextMode)}...`);
    await postJson(API_SAVE_PROJECT_SETTINGS, {
      editorMode: nextMode,
    });

    state.projectCenter = await loadProjectCenter();
    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
    });

    const savedMode = getProjectEditorMode();
    if (savedMode === "beginner" && previousScreen === "script") {
      switchScreen("story");
    }
    setSaveStatus(`已切到${getEditorModeLabel(savedMode)}`);
    showToast(
      savedMode === "advanced"
        ? "高级模式已开启，完整工具栏已经展开"
        : previousScreen === "script"
          ? "新手模式已开启，台本页先收回到剧情页继续写"
          : "新手模式已开启，复杂入口已经收起"
    );
  } catch (error) {
    setSaveStatus("切换编辑模式失败", true);
    showToast("切换编辑模式失败", "error");
    window.alert(`切换编辑模式没有成功：${error.message}`);
  }
}

async function saveProjectReleaseVersion() {
  const input = document.getElementById("projectReleaseVersionInput");
  const nextReleaseVersion = String(input?.value ?? "").trim();
  const currentReleaseVersion = getProjectReleaseVersion();

  if (nextReleaseVersion === currentReleaseVersion) {
    setSaveStatus(`当前发布版本已经是 ${currentReleaseVersion}`);
    showToast(`当前发布版本已经是 ${currentReleaseVersion}`);
    return;
  }

  try {
    setSaveStatus("正在保存发布版本...");
    const result = await postJson(API_SAVE_PROJECT_SETTINGS, {
      releaseVersion: nextReleaseVersion,
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
    });

    const savedReleaseVersion = getProjectReleaseVersion(result.project ?? state.data?.project);
    setSaveStatus(`发布版本已更新为 ${savedReleaseVersion}`);
    showToast(`发布版本已更新为 ${savedReleaseVersion}`);
  } catch (error) {
    setSaveStatus("保存发布版本失败", true);
    showToast("保存发布版本失败", "error");
    window.alert(`保存发布版本没有成功：${error.message}`);
  }
}

function applyReleaseVersionPreset(preset) {
  const input = document.getElementById("projectReleaseVersionInput");
  if (!input) {
    return;
  }

  const nextReleaseVersion = buildReleaseVersionFromPreset(preset, String(input.value ?? "").trim());
  input.value = nextReleaseVersion;
  setSaveStatus(`已套用版本预设：${nextReleaseVersion}`);
  showToast(`已套用版本预设：${nextReleaseVersion}`);
}

function buildDialogBoxAssetSelectOptions(selectedAssetId = "") {
  const uiAssets = state.data.assetList.filter((asset) => asset.type === "ui");
  if (!uiAssets.length) {
    return `<option value="">当前还没有可用的 UI 素材</option>`;
  }
  return [
    `<option value="" ${!selectedAssetId ? "selected" : ""}>不叠图片图层</option>`,
    ...uiAssets.map(
      (asset) =>
        `<option value="${escapeHtml(asset.id)}" ${selectedAssetId === asset.id ? "selected" : ""}>${escapeHtml(
          asset.fileExists ? `${asset.name} · ${asset.path.split("/").pop()}` : `${asset.name} · 文件未导入`
        )}</option>`
    ),
  ].join("");
}

function buildGameUiAssetSelectOptions(selectedAssetId = "", allowedTypes = ["ui"], emptyLabel = "不绑定素材") {
  const allowedSet = new Set(allowedTypes);
  const assets = state.data.assetList.filter((asset) => allowedSet.has(asset.type));
  const selectedAsset = selectedAssetId ? state.data.assetsById?.get(selectedAssetId) : null;
  const options = [`<option value="" ${!selectedAssetId ? "selected" : ""}>${escapeHtml(emptyLabel)}</option>`];

  if (selectedAssetId && selectedAsset && !allowedSet.has(selectedAsset.type)) {
    options.push(
      `<option value="${escapeHtml(selectedAsset.id)}" selected>${escapeHtml(`${selectedAsset.name} · 当前绑定`)}</option>`
    );
  }

  if (!assets.length) {
    const typeHint = allowedTypes.map((type) => getAssetTypeLabel(type)).join(" / ") || "素材";
    options.push(`<option value="" disabled>当前还没有可用${escapeHtml(typeHint)}，可先去素材库导入</option>`);
    return options.join("");
  }

  options.push(
    ...assets.map(
      (asset) =>
        `<option value="${escapeHtml(asset.id)}" ${selectedAssetId === asset.id ? "selected" : ""}>${escapeHtml(
          asset.fileExists ? `${asset.name} · ${asset.path.split("/").pop()}` : `${asset.name} · 文件未导入`
        )}</option>`
    )
  );

  return options.join("");
}

function renderGameUiFrameSliceControls(idPrefix, title, slice) {
  const fields = [
    ["top", "上"],
    ["right", "右"],
    ["bottom", "下"],
    ["left", "左"],
  ];
  return `
    <div class="detail-card ui-frame-slice-card">
      <strong>${escapeHtml(title)}</strong>
      <p class="helper-text">九宫格边距会决定 UI 贴图四角不被拉伸，中间区域自动延展；适合按钮框、科幻边框、纸张卷轴等资源。</p>
      <div class="playback-setting-grid dialog-config-grid">
        ${fields
          .map(
            ([key, label]) => `
              <label class="playback-setting">
                <span>${label}边距</span>
                <input
                  id="${idPrefix}${key[0].toUpperCase()}${key.slice(1)}Input"
                  type="number"
                  min="0"
                  max="96"
                  step="1"
                  value="${slice[key]}"
                />
              </label>
            `
          )
          .join("")}
      </div>
    </div>
  `;
}

function getSafeProjectVariableType(type) {
  return ["number", "boolean", "string"].includes(type) ? type : "string";
}

function renderProjectVariableTypeOptions(selectedType) {
  const safeType = getSafeProjectVariableType(selectedType);
  return ["number", "boolean", "string"]
    .map(
      (type) => `
        <option value="${type}" ${type === safeType ? "selected" : ""}>
          ${escapeHtml(getVariableTypeLabel(type))}
        </option>
      `
    )
    .join("");
}

const PROJECT_VARIABLE_FILTER_LABELS = {
  all: "全部",
  referenced: "已引用",
  unused: "未引用",
  risky: "有风险",
  number: "数字",
  boolean: "开关",
  string: "文本",
  active: "使用中",
  reserved: "预留",
  deprecated: "废弃",
  draft: "有草稿",
};

function getSafeProjectVariableFilterMode(mode) {
  return Object.prototype.hasOwnProperty.call(PROJECT_VARIABLE_FILTER_LABELS, mode) ? mode : "all";
}

const PROJECT_VARIABLE_STATUS_LABELS = {
  active: "使用中",
  reserved: "预留",
  deprecated: "废弃",
};

function getSafeProjectVariableStatus(status) {
  return Object.prototype.hasOwnProperty.call(PROJECT_VARIABLE_STATUS_LABELS, status) ? status : "active";
}

function renderProjectVariableStatusOptions(selectedStatus) {
  const safeStatus = getSafeProjectVariableStatus(selectedStatus);
  return Object.entries(PROJECT_VARIABLE_STATUS_LABELS)
    .map(
      ([status, label]) => `
        <option value="${status}" ${status === safeStatus ? "selected" : ""}>
          ${escapeHtml(label)}
        </option>
      `
    )
    .join("");
}

function makeProjectVariableId(name, existingIds = []) {
  const base =
    String(name ?? "")
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9\u4e00-\u9fff]+/g, "_")
      .replace(/^_+|_+$/g, "") || "custom";
  const prefix = base.startsWith("var_") ? "" : "var_";
  const used = new Set(existingIds);
  let candidate = `${prefix}${base}`;
  let suffix = 2;
  while (used.has(candidate)) {
    candidate = `${prefix}${base}_${String(suffix).padStart(2, "0")}`;
    suffix += 1;
  }
  return candidate;
}

function isSafeProjectVariableId(variableId) {
  return /^[0-9A-Za-z_\-\u4e00-\u9fff]{1,64}$/.test(String(variableId ?? "").trim());
}

function getProjectVariableIdIssue(variableId, currentVariableId = "") {
  const safeVariableId = String(variableId ?? "").trim();
  if (!safeVariableId) {
    return "逻辑 ID 不能为空";
  }
  if (!isSafeProjectVariableId(safeVariableId)) {
    return "逻辑 ID 含有不可用于发布的字符";
  }
  if (state.data.variables.some((item) => item.id === safeVariableId && item.id !== currentVariableId)) {
    return "逻辑 ID 已被其他变量使用";
  }
  return "";
}

function buildDefaultProjectVariable(type = "number") {
  const safeType = getSafeProjectVariableType(type);
  const labels = {
    number: "新数字变量",
    boolean: "新开关变量",
    string: "新文本变量",
  };
  const existingIds = state.data.variables.map((variable) => variable.id);
  const id = makeProjectVariableId(labels[safeType], existingIds);
  const base = {
    id,
    name: labels[safeType],
    type: safeType,
    group: "默认",
    status: "active",
    description: "",
  };

  if (safeType === "number") {
    return {
      ...base,
      defaultValue: 0,
      min: 0,
      max: 100,
    };
  }

  if (safeType === "boolean") {
    return {
      ...base,
      defaultValue: false,
    };
  }

  return {
    ...base,
    defaultValue: "common",
  };
}

function getProjectVariableDefaultInputValue(variable) {
  if (variable.type === "boolean") {
    return variable.defaultValue === true ? "true" : "false";
  }
  return String(variable.defaultValue ?? "");
}

function buildProjectVariableUsageMap(data = state.data) {
  const usageMap = new Map(
    (data?.variables ?? []).map((variable) => [
      variable.id,
      {
        total: 0,
        setCount: 0,
        addCount: 0,
        conditionCount: 0,
        choiceEffectCount: 0,
        locations: [],
        references: [],
      },
    ])
  );

  const addUsage = (variableId, kind, label, reference = {}) => {
    const safeVariableId = String(variableId ?? "").trim();
    if (!safeVariableId || !usageMap.has(safeVariableId)) {
      return;
    }
    const usage = usageMap.get(safeVariableId);
    usage.total += 1;
    if (kind === "set") usage.setCount += 1;
    if (kind === "add") usage.addCount += 1;
    if (kind === "condition") usage.conditionCount += 1;
    if (kind === "choice") usage.choiceEffectCount += 1;
    if (usage.locations.length < 4) {
      usage.locations.push(label);
    }
    usage.references.push({
      kind,
      label,
      variableId: safeVariableId,
      ...reference,
    });
  };

  (data?.chapters ?? []).forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      const sceneLabel = `${chapter.name ?? "未命名章节"} / ${scene.name ?? scene.id}`;
      (scene.blocks ?? []).forEach((block, blockIndex) => {
        const blockLabel = `${sceneLabel} / 第 ${blockIndex + 1} 张`;
        if (block.type === "variable_set") {
          addUsage(block.variableId, "set", `${blockLabel}：设置变量`, {
            chapterId: chapter.chapterId,
            sceneId: scene.id,
            blockId: block.id,
            blockIndex,
          });
        }
        if (block.type === "variable_add") {
          addUsage(block.variableId, "add", `${blockLabel}：修改数值`, {
            chapterId: chapter.chapterId,
            sceneId: scene.id,
            blockId: block.id,
            blockIndex,
          });
        }
        if (block.type === "choice") {
          (block.options ?? []).forEach((option) => {
            (option.effects ?? []).forEach((effect, effectIndex) => {
              addUsage(effect.variableId, "choice", `${blockLabel}：选项「${option.text || option.id}」效果`, {
                chapterId: chapter.chapterId,
                sceneId: scene.id,
                blockId: block.id,
                blockIndex,
                optionId: option.id,
                effectIndex,
              });
            });
          });
        }
        if (block.type === "condition") {
          (block.branches ?? []).forEach((branch, branchIndex) => {
            (branch.when ?? []).forEach((rule, ruleIndex) => {
              addUsage(rule.variableId, "condition", `${blockLabel}：条件分支 ${branch.id ?? ""}`.trim(), {
                chapterId: chapter.chapterId,
                sceneId: scene.id,
                blockId: block.id,
                blockIndex,
                branchId: branch.id,
                branchIndex,
                ruleIndex,
              });
            });
          });
        }
      });
    });
  });

  return usageMap;
}

function getProjectVariableRangeIssues(variable) {
  if (variable.type !== "number") {
    return [];
  }

  const issues = [];
  const rawMin = variable.min ?? variable.minValue;
  const rawMax = variable.max ?? variable.maxValue;
  const [minValue, maxValue] = getVariableNumberBounds(variable);

  if (rawMin !== null && rawMin !== undefined && minValue === null) {
    issues.push("最小值不是有效数字");
  }
  if (rawMax !== null && rawMax !== undefined && maxValue === null) {
    issues.push("最大值不是有效数字");
  }
  if (minValue !== null && maxValue !== null && minValue > maxValue) {
    issues.push("范围上下限反了");
  }
  if (isRawVariableValueMatchingType(variable, variable.defaultValue)) {
    const defaultValue = Number.parseFloat(variable.defaultValue);
    if (
      (minValue !== null && defaultValue < minValue) ||
      (maxValue !== null && defaultValue > maxValue)
    ) {
      issues.push("默认值超出范围");
    }
  }

  return issues;
}

function getProjectVariableDraftSeed(variableId) {
  const variable = state.data?.variablesById?.get(variableId);
  if (!variable) {
    return null;
  }

  return {
    type: getSafeProjectVariableType(variable.type),
    idText: variable.id ?? "",
    name: variable.name ?? "",
    group: variable.group ?? "",
    status: getSafeProjectVariableStatus(variable.status),
    description: variable.description ?? "",
    defaultText: getProjectVariableDefaultInputValue(variable),
    minText: String(variable.min ?? variable.minValue ?? ""),
    maxText: String(variable.max ?? variable.maxValue ?? ""),
  };
}

function getProjectVariableDraft(variableId) {
  return state.projectVariableDrafts?.[variableId] ?? null;
}

function setProjectVariableDraft(variableId, draft) {
  if (!variableId || !draft) {
    return;
  }
  if (!state.projectVariableDrafts) {
    state.projectVariableDrafts = {};
  }
  state.projectVariableDrafts[variableId] = draft;
}

function clearProjectVariableDraft(variableId) {
  if (!state.projectVariableDrafts || !variableId) {
    return;
  }
  delete state.projectVariableDrafts[variableId];
}

function clearAllProjectVariableDrafts() {
  state.projectVariableDrafts = {};
}

function captureProjectVariableDraftField(target) {
  if (!target?.matches?.('[data-field^="project-variable-"]')) {
    return false;
  }

  const row = target.closest("[data-project-variable-row]");
  const variableId = row?.dataset.variableId;
  const seed = getProjectVariableDraftSeed(variableId);
  if (!row || !variableId || !seed) {
    return false;
  }

  const fieldName = target.dataset.field;
  const draft = {
    ...seed,
    ...(getProjectVariableDraft(variableId) ?? {}),
  };

  if (fieldName === "project-variable-name") {
    draft.name = target.value ?? "";
  } else if (fieldName === "project-variable-id") {
    draft.idText = target.value ?? "";
  } else if (fieldName === "project-variable-group") {
    draft.group = target.value ?? "";
  } else if (fieldName === "project-variable-status") {
    draft.status = getSafeProjectVariableStatus(target.value);
  } else if (fieldName === "project-variable-description") {
    draft.description = target.value ?? "";
  } else if (fieldName === "project-variable-type") {
    draft.type = getSafeProjectVariableType(target.value);
  } else if (fieldName === "project-variable-default") {
    draft.defaultText = target.value ?? "";
  } else if (fieldName === "project-variable-min") {
    draft.minText = target.value ?? "";
  } else if (fieldName === "project-variable-max") {
    draft.maxText = target.value ?? "";
  } else {
    return false;
  }

  setProjectVariableDraft(variableId, draft);
  return true;
}

function buildProjectVariableDraftModel(variable) {
  const draft = getProjectVariableDraft(variable.id);
  if (!draft) {
    return variable;
  }

  const type = getSafeProjectVariableType(draft.type);
  const nextVariable = {
    ...variable,
    id: draft.idText ?? variable.id,
    type,
    name: draft.name ?? variable.name,
    group: draft.group ?? variable.group ?? "",
    status: getSafeProjectVariableStatus(draft.status ?? variable.status),
    description: draft.description ?? variable.description ?? "",
    defaultValue: draft.defaultText ?? getProjectVariableDefaultInputValue(variable),
  };

  if (type === "number") {
    const parsedDefault = Number.parseFloat(draft.defaultText ?? variable.defaultValue);
    nextVariable.defaultValue = Number.isFinite(parsedDefault)
      ? parsedDefault
      : draft.defaultText ?? variable.defaultValue;
    if (draft.minText) {
      nextVariable.min = draft.minText;
    } else {
      delete nextVariable.min;
      delete nextVariable.minValue;
    }
    if (draft.maxText) {
      nextVariable.max = draft.maxText;
    } else {
      delete nextVariable.max;
      delete nextVariable.maxValue;
    }
  } else {
    delete nextVariable.min;
    delete nextVariable.max;
    delete nextVariable.minValue;
    delete nextVariable.maxValue;
  }

  return nextVariable;
}

function renderProjectVariableRiskTags(variable, usage, currentVariableId = variable.id) {
  const tags = [];
  const idIssue = getProjectVariableIdIssue(variable.id, currentVariableId);
  const status = getSafeProjectVariableStatus(variable.status);
  tags.push(`<span class="issue-tag">${escapeHtml(PROJECT_VARIABLE_STATUS_LABELS[status])}</span>`);
  if (usage.total > 0) {
    tags.push(`<span class="issue-tag good-text">被引用 ${usage.total} 次</span>`);
  } else {
    tags.push(`<span class="issue-tag warn-text">暂未引用</span>`);
  }
  if (idIssue) {
    tags.push(`<span class="issue-tag danger-text">${escapeHtml(idIssue)}</span>`);
  }
  if (status === "deprecated" && usage.total > 0) {
    tags.push(`<span class="issue-tag danger-text">废弃变量仍被引用</span>`);
  }
  if (status === "reserved" && usage.total === 0) {
    tags.push(`<span class="issue-tag good-text">清理保护</span>`);
  }
  getProjectVariableRangeIssues(variable).forEach((issue) => {
    tags.push(`<span class="issue-tag danger-text">${escapeHtml(issue)}</span>`);
  });
  return tags.join("");
}

function renderProjectVariableEditorRow(variable, usage) {
  const draft = getProjectVariableDraft(variable.id);
  const renderVariable = buildProjectVariableDraftModel(variable);
  const [minValue, maxValue] = getVariableNumberBounds(renderVariable);
  const rawMin = draft ? draft.minText ?? "" : variable.min ?? variable.minValue ?? "";
  const rawMax = draft ? draft.maxText ?? "" : variable.max ?? variable.maxValue ?? "";
  const inputIdBase = `projectVariable-${variable.id}`;
  const rangeHint =
    renderVariable.type === "number" && (minValue !== null || maxValue !== null)
      ? `运行时会夹在 ${minValue !== null ? minValue : "-∞"} ~ ${maxValue !== null ? maxValue : "+∞"}`
      : "非数字变量不会使用范围。";
  const locationPreview =
    usage.references.length > 0
      ? usage.references
          .slice(0, 5)
          .map(
            (reference) => `
              <div class="detail-row">
                <label>${escapeHtml(reference.label)}</label>
                <button
                  type="button"
                  class="toolbar-button"
                  data-action="jump-to-variable-reference"
                  data-scene-id="${escapeHtml(reference.sceneId ?? "")}"
                  data-block-id="${escapeHtml(reference.blockId ?? "")}"
                >
                  定位到卡片
                </button>
              </div>
            `
          )
          .join("")
      : `<div class="detail-meta">还没有剧情卡片引用它，可以放心改名或删除。</div>`;
  const hiddenReferenceCount = Math.max((usage.references?.length ?? 0) - 5, 0);

  return `
    <article class="detail-card" data-project-variable-row data-variable-id="${escapeHtml(variable.id)}">
      <div class="panel-heading">
        <div>
          <strong>${escapeHtml(renderVariable.name || variable.id)}</strong>
          <p class="helper-text">ID：<code>${escapeHtml(variable.id)}</code></p>
        </div>
        <span class="badge badge-soft">${escapeHtml(getVariableTypeLabel(renderVariable.type))}</span>
      </div>
      <div class="story-filter-chip-row">
        ${renderProjectVariableRiskTags(renderVariable, usage, variable.id)}
        ${
          draft?.idText && draft.idText !== variable.id
            ? `<span class="issue-tag warn-text">保存后会迁移 ID：${escapeHtml(variable.id)} → ${escapeHtml(draft.idText)}</span>`
            : ""
        }
      </div>
      <div class="playback-setting-grid dialog-config-grid">
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-name`)}">
          <span>变量名</span>
          <input id="${escapeHtml(`${inputIdBase}-name`)}" data-field="project-variable-name" type="text" maxlength="48" value="${escapeHtml(draft?.name ?? variable.name ?? "")}" autocomplete="off" spellcheck="false" />
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-id`)}">
          <span>逻辑 ID</span>
          <input id="${escapeHtml(`${inputIdBase}-id`)}" data-field="project-variable-id" type="text" maxlength="64" value="${escapeHtml(draft?.idText ?? variable.id ?? "")}" autocomplete="off" spellcheck="false" />
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-group`)}">
          <span>变量分组</span>
          <input id="${escapeHtml(`${inputIdBase}-group`)}" data-field="project-variable-group" type="text" maxlength="40" value="${escapeHtml(draft?.group ?? variable.group ?? "")}" placeholder="例如：主线 / 好感度 / 系统" autocomplete="off" spellcheck="false" />
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-status`)}">
          <span>维护状态</span>
          <select id="${escapeHtml(`${inputIdBase}-status`)}" data-field="project-variable-status">
            ${renderProjectVariableStatusOptions(draft?.status ?? variable.status)}
          </select>
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-type`)}">
          <span>变量类型</span>
          <select id="${escapeHtml(`${inputIdBase}-type`)}" data-field="project-variable-type">
            ${renderProjectVariableTypeOptions(draft?.type ?? variable.type)}
          </select>
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-default`)}">
          <span>默认值</span>
          <input
            id="${escapeHtml(`${inputIdBase}-default`)}"
            data-field="project-variable-default"
            type="text"
            value="${escapeHtml(draft?.defaultText ?? getProjectVariableDefaultInputValue(variable))}"
            placeholder="数字 / true false / 文本"
            autocomplete="off"
            spellcheck="false"
          />
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-min`)}">
          <span>最小值</span>
          <input id="${escapeHtml(`${inputIdBase}-min`)}" data-field="project-variable-min" type="text" value="${escapeHtml(String(rawMin))}" placeholder="仅数字变量使用" autocomplete="off" spellcheck="false" />
        </label>
        <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-max`)}">
          <span>最大值</span>
          <input id="${escapeHtml(`${inputIdBase}-max`)}" data-field="project-variable-max" type="text" value="${escapeHtml(String(rawMax))}" placeholder="仅数字变量使用" autocomplete="off" spellcheck="false" />
        </label>
      </div>
      <label class="playback-setting" for="${escapeHtml(`${inputIdBase}-description`)}">
        <span>用途说明</span>
        <textarea id="${escapeHtml(`${inputIdBase}-description`)}" data-field="project-variable-description" rows="2" maxlength="220" placeholder="写清楚这个变量控制什么、什么时候可以删除。">${escapeHtml(draft?.description ?? variable.description ?? "")}</textarea>
      </label>
      <div class="detail-meta">${escapeHtml(rangeHint)}</div>
      <div class="detail-stack">
        ${locationPreview}
        ${hiddenReferenceCount > 0 ? `<div class="detail-meta">另有 ${hiddenReferenceCount} 处引用，搜索变量名或打开巡检可继续定位。</div>` : ""}
      </div>
      <div class="detail-actions">
        <button class="toolbar-button toolbar-button-primary" data-action="save-project-variable" data-variable-id="${escapeHtml(variable.id)}">
          保存变量
        </button>
        <button class="toolbar-button" data-action="suggest-project-variable-id" data-variable-id="${escapeHtml(variable.id)}">
          根据变量名生成 ID
        </button>
        <button class="toolbar-button" data-action="duplicate-project-variable" data-variable-id="${escapeHtml(variable.id)}">
          复制一份
        </button>
        <button class="toolbar-button" data-action="delete-project-variable" data-variable-id="${escapeHtml(variable.id)}">
          删除变量
        </button>
      </div>
    </article>
  `;
}

function getProjectVariableGovernanceItems(variables, usageMap) {
  return variables.map((variable) => {
    const draft = getProjectVariableDraft(variable.id);
    const renderVariable = buildProjectVariableDraftModel(variable);
  const usage = usageMap.get(variable.id) ?? { total: 0, references: [] };
  const rangeIssues = getProjectVariableRangeIssues(renderVariable);
  const idIssue = getProjectVariableIdIssue(renderVariable.id, variable.id);
  const status = getSafeProjectVariableStatus(renderVariable.status);
  const issues = [...rangeIssues];
  if (idIssue) {
    issues.push(idIssue);
  }
  if (status === "deprecated" && usage.total > 0) {
    issues.push("废弃变量仍被引用");
  }
  return {
    variable,
    renderVariable,
    usage,
    issues,
    status,
    hasDraft: Boolean(draft),
  };
});
}

function isProjectVariableMatchingFilter(item, filterMode) {
  if (filterMode === "referenced") {
    return item.usage.total > 0;
  }
  if (filterMode === "unused") {
    return item.usage.total === 0;
  }
  if (filterMode === "risky") {
    return item.issues.length > 0;
  }
  if (filterMode === "draft") {
    return item.hasDraft;
  }
  if (["active", "reserved", "deprecated"].includes(filterMode)) {
    return item.status === filterMode;
  }
  if (["number", "boolean", "string"].includes(filterMode)) {
    return item.renderVariable.type === filterMode;
  }
  return true;
}

function getProjectVariableGovernanceScore(items) {
  if (items.length === 0) {
    return 100;
  }
  const riskCount = items.filter((item) => item.issues.length > 0).length;
  const unusedCount = items.filter((item) => item.usage.total === 0 && item.status !== "reserved").length;
  const draftCount = items.filter((item) => item.hasDraft).length;
  const penalty = riskCount * 18 + unusedCount * 4 + draftCount * 2;
  return clamp(100 - penalty, 0, 100);
}

function renderProjectVariableGovernancePanel(items) {
  const totalCount = items.length;
  const referencedCount = items.filter((item) => item.usage.total > 0).length;
  const unusedCount = items.filter((item) => item.usage.total === 0).length;
  const riskItems = items.filter((item) => item.issues.length > 0);
  const draftCount = items.filter((item) => item.hasDraft).length;
  const reservedCount = items.filter((item) => item.status === "reserved").length;
  const deprecatedCount = items.filter((item) => item.status === "deprecated").length;
  const score = getProjectVariableGovernanceScore(items);
  const hotItems = items
    .filter((item) => item.usage.total > 0)
    .sort((a, b) => b.usage.total - a.usage.total)
    .slice(0, 3);
  const unusedPreview = items
    .filter((item) => item.usage.total === 0)
    .slice(0, 4);

  return `
    <section class="detail-card">
      <div class="panel-heading">
        <div>
          <strong>变量治理雷达</strong>
          <p class="helper-text">用项目级视角看变量健康度：风险越少、废弃变量越少，后期做分支和导出就越稳。</p>
        </div>
        <span class="badge badge-soft">Health ${score}</span>
      </div>
      <div class="route-summary-strip beginner-guide-metrics">
        ${renderRouteMetricCard("健康分", score, "范围风险、草稿和未引用变量越少越高")}
        ${renderRouteMetricCard("引用覆盖", `${referencedCount} / ${totalCount}`, "至少被一张剧情卡片使用")}
        ${renderRouteMetricCard("未引用", unusedCount, "可清理，也可能是预留变量")}
        ${renderRouteMetricCard("风险变量", riskItems.length, "ID、范围或默认值需要处理")}
        ${renderRouteMetricCard("草稿中", draftCount, "已修改但还没保存")}
        ${renderRouteMetricCard("预留 / 废弃", `${reservedCount} / ${deprecatedCount}`, "预留不会被自动清理；废弃仍引用会报风险")}
      </div>
      <div class="playback-setting-grid dialog-config-grid">
        <article class="detail-card">
          <strong>热点变量</strong>
          <div class="detail-stack">
            ${
              hotItems.length > 0
                ? hotItems
                    .map(
                      (item) => `
                        <div class="detail-row">
                          <label>${escapeHtml(item.renderVariable.name || item.variable.id)}</label>
                          <div class="value">${item.usage.total} 处引用</div>
                        </div>
                      `
                    )
                    .join("")
                : renderEmpty("还没有变量被剧情卡片引用。")
            }
          </div>
        </article>
        <article class="detail-card">
          <strong>优先处理</strong>
          <div class="detail-stack">
            ${
              riskItems.length > 0
                ? riskItems
                    .slice(0, 4)
                    .map(
                      (item) => `
                        <div class="detail-row">
                          <label>${escapeHtml(item.renderVariable.name || item.variable.id)}</label>
                          <div class="value">${escapeHtml(item.issues.join("、"))}</div>
                        </div>
                      `
                    )
                    .join("")
                : renderEmpty("变量 ID、默认值和范围目前没有明显风险。")
            }
          </div>
        </article>
        <article class="detail-card">
          <strong>未引用预览</strong>
          <div class="detail-stack">
            ${
              unusedPreview.length > 0
                ? unusedPreview
                    .map(
                      (item) => `
                        <div class="detail-row">
                          <label>${escapeHtml(item.renderVariable.name || item.variable.id)}</label>
                          <div class="value">${escapeHtml(getVariableTypeLabel(item.renderVariable.type))}</div>
                        </div>
                      `
                    )
                    .join("")
                : renderEmpty("没有未引用变量，逻辑库很干净。")
            }
          </div>
        </article>
      </div>
    </section>
  `;
}

function renderProjectVariableFilterButtons(items) {
  const filterMode = getSafeProjectVariableFilterMode(state.projectVariableFilterMode);
  return Object.entries(PROJECT_VARIABLE_FILTER_LABELS)
    .map(([mode, label]) => {
      const count = items.filter((item) => isProjectVariableMatchingFilter(item, mode)).length;
      return `
        <button
          type="button"
          class="toolbar-button ${filterMode === mode ? "toolbar-button-primary" : ""}"
          data-action="set-project-variable-filter"
          data-variable-filter-mode="${mode}"
        >
          ${escapeHtml(label)} · ${count}
        </button>
      `;
    })
    .join("");
}

function renderProjectVariableLibraryPanel() {
  const variables = state.data.variables ?? [];
  const query = String(state.projectVariableSearchQuery ?? "").trim().toLowerCase();
  const filterMode = getSafeProjectVariableFilterMode(state.projectVariableFilterMode);
  const usageMap = buildProjectVariableUsageMap();
  const governanceItems = getProjectVariableGovernanceItems(variables, usageMap);
  const filteredItems = governanceItems.filter((item) => {
    const { variable, renderVariable } = item;
    if (!isProjectVariableMatchingFilter(item, filterMode)) {
      return false;
    }
    if (!query) {
      return true;
    }
    return [
      renderVariable.id,
      renderVariable.name,
      renderVariable.group,
      renderVariable.description,
      variable.id,
      variable.name,
      getVariableTypeLabel(renderVariable.type),
      PROJECT_VARIABLE_STATUS_LABELS[getSafeProjectVariableStatus(renderVariable.status)],
    ]
      .some((value) => String(value ?? "").toLowerCase().includes(query));
  });
  const referencedCount = variables.filter((variable) => (usageMap.get(variable.id)?.total ?? 0) > 0).length;
  const unusedCount = Math.max(variables.length - referencedCount, 0);
  const riskCount = variables.filter((variable) => getProjectVariableRangeIssues(variable).length > 0).length;
  const typeCount = (type) => variables.filter((variable) => variable.type === type).length;

  return `
    <section class="detail-card dialog-config-card" id="projectVariableLibraryPanel">
      <div class="panel-heading">
        <div>
          <strong>变量库管理台</strong>
          <p class="helper-text">集中管理好感度、路线标记、开关和计数器。这里保存后，剧情条件、选项效果、网页包和原生 Runtime 会一起使用同一套变量定义。</p>
        </div>
        <span class="badge badge-soft">Logic Core</span>
      </div>
      <div class="route-summary-strip beginner-guide-metrics">
        ${renderRouteMetricCard("变量总数", variables.length, "项目可用的逻辑状态")}
        ${renderRouteMetricCard("数字变量", typeCount("number"), "好感度、分数和进度")}
        ${renderRouteMetricCard("已引用", referencedCount, "被剧情卡片实际使用")}
        ${renderRouteMetricCard("未引用", unusedCount, "可能是废弃变量或预留变量")}
        ${renderRouteMetricCard("待整理", riskCount, "范围或默认值需要注意")}
      </div>
      ${renderProjectVariableGovernancePanel(governanceItems)}
      <div class="asset-search-row story-tree-filter-row">
        <label class="asset-search-field">
          <span class="sr-only">搜索变量</span>
          <input
            id="projectVariableSearchInput"
            type="search"
            value="${escapeHtml(state.projectVariableSearchQuery)}"
            placeholder="搜变量名、ID 或类型"
          />
        </label>
        <button class="toolbar-button" data-action="add-project-variable" data-variable-type="number">新增数字</button>
        <button class="toolbar-button" data-action="add-project-variable" data-variable-type="boolean">新增开关</button>
        <button class="toolbar-button" data-action="add-project-variable" data-variable-type="string">新增文本</button>
        <button class="toolbar-button" data-action="repair-project-variable-ranges">一键整理范围</button>
        <button class="toolbar-button" data-action="delete-unused-project-variables">清理未引用</button>
        <button class="toolbar-button" data-action="export-project-variable-report">导出治理报告</button>
        <button class="toolbar-button" data-action="create-starter-variables">补齐基础变量包</button>
      </div>
      <div class="story-filter-chip-row">
        ${renderProjectVariableFilterButtons(governanceItems)}
      </div>
      <div class="detail-stack">
        ${
          filteredItems.length > 0
            ? filteredItems
                .map(({ variable }) =>
                  renderProjectVariableEditorRow(
                    variable,
                    usageMap.get(variable.id) ?? {
                      total: 0,
                      setCount: 0,
                      addCount: 0,
                      conditionCount: 0,
                      choiceEffectCount: 0,
                      locations: [],
                      references: [],
                    }
                  )
                )
                .join("")
            : renderEmpty(
                variables.length > 0
                  ? `当前「${PROJECT_VARIABLE_FILTER_LABELS[filterMode]}」视图没有命中变量。`
                  : "这个项目还没有变量，可以先新增一个数字变量或补齐基础变量包。"
              )
        }
      </div>
    </section>
  `;
}

function rerenderProjectVariableLibraryPanel() {
  const host = document.getElementById("projectVariableLibraryPanelHost");
  if (host) {
    host.innerHTML = renderProjectVariableLibraryPanel();
  }
}

function setProjectVariableFilterMode(mode) {
  state.projectVariableFilterMode = getSafeProjectVariableFilterMode(mode);
  rerenderProjectVariableLibraryPanel();
  setSaveStatus(`变量库视图：${PROJECT_VARIABLE_FILTER_LABELS[state.projectVariableFilterMode]}`);
}

function buildProjectVariableAuditReportContent(items) {
  const projectTitle = state.data?.project?.title ?? "未命名项目";
  const score = getProjectVariableGovernanceScore(items);
  const referencedCount = items.filter((item) => item.usage.total > 0).length;
  const unusedItems = items.filter((item) => item.usage.total === 0);
  const riskItems = items.filter((item) => item.issues.length > 0);
  const draftItems = items.filter((item) => item.hasDraft);
  const hotItems = [...items]
    .filter((item) => item.usage.total > 0)
    .sort((a, b) => b.usage.total - a.usage.total);
  const lines = [
    "Tony Na Engine 变量治理报告",
    `项目：${projectTitle}`,
    `生成时间：${new Date().toLocaleString()}`,
    "",
    "一、总体概览",
    `- 健康分：${score}`,
    `- 变量总数：${items.length}`,
    `- 已引用变量：${referencedCount}`,
    `- 未引用变量：${unusedItems.length}`,
    `- 风险变量：${riskItems.length}`,
    `- 草稿变量：${draftItems.length}`,
    "",
    "二、热点变量",
  ];

  if (hotItems.length > 0) {
    hotItems.slice(0, 12).forEach((item, index) => {
      lines.push(
        `${index + 1}. ${item.renderVariable.name || item.variable.id} (${item.variable.id})：${item.usage.total} 处引用`
      );
    });
  } else {
    lines.push("暂无变量被剧情卡片引用。");
  }

  lines.push("", "三、优先处理风险");
  if (riskItems.length > 0) {
    riskItems.forEach((item, index) => {
      lines.push(
        `${index + 1}. ${item.renderVariable.name || item.variable.id} (${item.variable.id})：${item.issues.join("、")}`
      );
    });
  } else {
    lines.push("未发现变量 ID、默认值或范围风险。");
  }

  lines.push("", "四、未引用变量");
  if (unusedItems.length > 0) {
    unusedItems.forEach((item, index) => {
      lines.push(
        `${index + 1}. ${item.renderVariable.name || item.variable.id} (${item.variable.id}) · ${getVariableTypeLabel(item.renderVariable.type)}`
      );
    });
  } else {
    lines.push("没有未引用变量。");
  }

  lines.push("", "五、变量明细");
  items.forEach((item, index) => {
    lines.push(
      `${index + 1}. ${item.renderVariable.name || item.variable.id}`,
      `   ID：${item.variable.id}`,
      `   类型：${getVariableTypeLabel(item.renderVariable.type)}`,
      `   分组：${item.renderVariable.group || "未分组"}`,
      `   状态：${PROJECT_VARIABLE_STATUS_LABELS[item.status]}`,
      `   说明：${item.renderVariable.description || "未填写"}`,
      `   默认值：${getProjectVariableDefaultInputValue(item.renderVariable)}`,
      `   引用数：${item.usage.total}`,
      `   风险：${item.issues.length > 0 ? item.issues.join("、") : "无"}`
    );
    if (item.usage.references.length > 0) {
      item.usage.references.slice(0, 8).forEach((reference) => {
        lines.push(`   - ${reference.label}`);
      });
      if (item.usage.references.length > 8) {
        lines.push(`   - 另有 ${item.usage.references.length - 8} 处引用`);
      }
    }
  });

  return `\uFEFF${lines.join("\n")}`;
}

function exportProjectVariableAuditReport() {
  const usageMap = buildProjectVariableUsageMap();
  const items = getProjectVariableGovernanceItems(state.data.variables ?? [], usageMap);
  const safeProjectTitle = sanitizeFileName(state.data?.project?.title ?? "project") || "project";
  const fileName = `${safeProjectTitle}_variable_audit.txt`;
  downloadTextFile(fileName, buildProjectVariableAuditReportContent(items), "text/plain;charset=utf-8");
  setSaveStatus(`已导出变量治理报告：${fileName}`);
  showToast(`变量治理报告已导出：${fileName}`);
}

