function formatGroupedAssetCounts(groupedCounts = {}) {
  return Object.entries(groupedCounts)
    .filter(([, count]) => Number(count) > 0)
    .map(([type, count]) => `${getAssetTypeLabel(type)} ${count} 个`)
    .join(" / ");
}

async function importAssets(files, options = {}) {
  if (!files.length) {
    return;
  }

  try {
    const modeLabel = options.smartImport ? "智能导入" : "导入";
    setSaveStatus(`正在${modeLabel} ${files.length} 个素材...`);
    const payloadFiles = await Promise.all(files.map(readFileAsBase64Payload));
    const result = await postJson(API_IMPORT_ASSETS, {
      assetType: options.smartImport ? "auto" : state.selectedAssetType,
      fallbackAssetType: state.selectedAssetType,
      files: payloadFiles,
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: result.assetType ?? result.assets?.[0]?.type ?? state.selectedAssetType,
      selectedAssetId: result.assets?.[0]?.id ?? state.selectedAssetId,
      assetFilterMode: "all",
    });

    const groupedLabel = formatGroupedAssetCounts(result.groupedCounts);
    const message = groupedLabel
      ? `已导入 ${result.importedCount} 个素材：${groupedLabel}`
      : `已导入 ${result.importedCount} 个素材`;
    setSaveStatus(message);
    showToast(message);
  } catch (error) {
    setSaveStatus("导入素材失败", true);
    showToast("导入素材失败", "error");
    window.alert(`导入素材没有成功：${error.message}`);
  }
}

async function replaceSelectedAssetFile(file) {
  const asset = getSelectedAsset();
  if (!asset || !file) {
    return;
  }

  try {
    setSaveStatus(`正在替换素材文件：${asset.name}`);
    if (state.activeAssetAudioId === asset.id) {
      stopAssetAudioPreview({ rerender: false });
    }

    const result = await postJson(API_REPLACE_ASSET, {
      assetId: asset.id,
      file: await readFileAsBase64Payload(file),
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: asset.id,
      assetFilterMode: "all",
    });

    const nextAsset = result.asset ?? asset;
    setSaveStatus(`已替换素材文件：${nextAsset.name}`);
    showToast(`已替换素材文件：${nextAsset.name}`);
  } catch (error) {
    setSaveStatus("替换素材失败", true);
    showToast("替换素材失败", "error");
    window.alert(`替换素材没有成功：${error.message}`);
  }
}

async function deleteSelectedAsset() {
  const asset = getSelectedAsset();
  if (!asset) {
    setSaveStatus("先选中一个素材");
    return;
  }

  const usageCount = getAssetUsageCount(asset.id);
  if (usageCount > 0) {
    const usages = state.data.assetUsage.get(asset.id) ?? [];
    window.alert(
      `这个素材还在被 ${usageCount} 个位置使用，暂时不能删除。\n\n先解除这些引用后再删：\n${usages
        .slice(0, 6)
        .join("\n")}`
    );
    setSaveStatus("这个素材还在被使用，不能直接删除", true);
    showToast("这个素材还在被使用，先解除引用", "error");
    return;
  }

  const confirmed = window.confirm(`确定要删掉素材「${asset.name}」吗？这个动作不能撤回。`);
  if (!confirmed) {
    return;
  }

  try {
    setSaveStatus(`正在删除素材：${asset.name}`);
    if (state.activeAssetAudioId === asset.id) {
      stopAssetAudioPreview({ rerender: false });
    }

    await postJson(API_DELETE_ASSET, {
      assetId: asset.id,
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: null,
      assetFilterMode: "all",
    });

    setSaveStatus(`已删除素材：${asset.name}`);
    showToast(`已删除素材：${asset.name}`);
  } catch (error) {
    setSaveStatus("删除素材失败", true);
    showToast("删除素材失败", "error");
    window.alert(`删除素材没有成功：${error.message}`);
  }
}

function selectAllVisibleAssets() {
  const visibleAssets = getCurrentFilteredAssetsOfSelectedType();
  if (!visibleAssets.length) {
    setSaveStatus("当前列表里没有可勾选的素材", true);
    return;
  }

  const nextCheckedIds = new Set(getCheckedAssetIds());
  visibleAssets.forEach((asset) => nextCheckedIds.add(asset.id));
  state.assetCheckedIds = Array.from(nextCheckedIds);
  renderAssetsScreen();
  setSaveStatus(`已勾选当前列表 ${visibleAssets.length} 个素材`);
  showToast(`已勾选当前列表 ${visibleAssets.length} 个素材`);
}

function clearAssetSelection() {
  const checkedCount = getCheckedAssetIds().length;
  state.assetCheckedIds = [];
  renderAssetsScreen();
  setSaveStatus(
    checkedCount > 0 ? `已清空多选：${checkedCount} 个素材` : "当前没有勾选中的素材"
  );
}

async function deleteSelectedUnusedAssets() {
  const checkedAssets = getCurrentCheckedAssetsOfSelectedType();
  if (!checkedAssets.length) {
    setSaveStatus("先勾选当前列表里要处理的素材", true);
    showToast("先勾选素材，再批量删除", "error");
    return;
  }

  const unusedAssets = checkedAssets.filter((asset) => isAssetUnused(asset.id));
  const usedAssets = checkedAssets.filter((asset) => !isAssetUnused(asset.id));

  if (!unusedAssets.length) {
    const usageLines = usedAssets
      .slice(0, 6)
      .map((asset) => `${asset.name} · 已使用 ${getAssetUsageCount(asset.id)} 处`)
      .join("\n");
    window.alert(
      `当前勾选的 ${checkedAssets.length} 个素材都还在被使用，暂时不能批量删除。\n\n${usageLines}`
    );
    setSaveStatus("勾选项里没有可删除的未使用素材", true);
    showToast("勾选项都还在被使用", "error");
    return;
  }

  const confirmed = window.confirm(
    `确定要批量删除当前勾选里的未使用素材吗？\n\n可删除：${unusedAssets.length} 个\n${
      usedAssets.length > 0 ? `会自动跳过：${usedAssets.length} 个仍在使用的素材` : "没有检测到正在使用的勾选项"
    }`
  );
  if (!confirmed) {
    return;
  }

  try {
    setSaveStatus(`正在批量删除 ${unusedAssets.length} 个未使用素材...`);
    const result = await postJson(API_BULK_DELETE_ASSETS, {
      assetIds: checkedAssets.map((asset) => asset.id),
    });

    const deletedIds = new Set(result.deletedAssetIds ?? []);
    if (state.activeAssetAudioId && deletedIds.has(state.activeAssetAudioId)) {
      stopAssetAudioPreview({ rerender: false });
    }

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: state.selectedAssetType,
      selectedAssetId: deletedIds.has(state.selectedAssetId) ? null : state.selectedAssetId,
    });

    const message =
      result.deletedCount > 0
        ? `已删除 ${result.deletedCount} 个未使用素材${
            result.skippedUsedCount > 0 ? `，跳过 ${result.skippedUsedCount} 个正在使用的素材` : ""
          }`
        : "这次没有删除到素材";
    setSaveStatus(message, result.deletedCount === 0);
    showToast(message, result.deletedCount === 0 ? "error" : "soft");
  } catch (error) {
    setSaveStatus("批量删除素材失败", true);
    showToast("批量删除素材失败", "error");
    window.alert(`批量删除素材没有成功：${error.message}`);
  }
}

async function exportBuild(target = "web") {
  const exportTarget =
    target === "native_runtime"
      ? "native_runtime"
      : target === "windows_nwjs"
      ? "windows_nwjs"
      : target === "macos_nwjs"
        ? "macos_nwjs"
        : target === "linux_nwjs"
          ? "linux_nwjs"
      : target === "editor_desktop"
        ? "editor_desktop"
        : target === "editor_desktop_suite"
          ? "editor_desktop_suite"
          : "web";
  const targetLabel =
    exportTarget === "native_runtime"
      ? "原生 Runtime 包"
      : exportTarget === "windows_nwjs"
      ? "Windows 桌面包"
      : exportTarget === "macos_nwjs"
        ? "macOS 桌面包"
        : exportTarget === "linux_nwjs"
          ? "Linux 桌面包"
      : exportTarget === "editor_desktop"
        ? "编辑器桌面包"
        : exportTarget === "editor_desktop_suite"
          ? "三系统编辑器套装"
        : "试玩包";
  try {
    setSaveStatus(`正在导出${targetLabel}...`);
    const result = await postJson(API_EXPORT_BUILD, { target: exportTarget });
    state.lastExportResult = result;
    renderPreviewScreen();

    if (result.missingAssets > 0) {
      setSaveStatus(`${result.targetLabel ?? targetLabel}已导出，但还有 ${result.missingAssets} 个素材文件没找到`);
      showToast(`${result.targetLabel ?? targetLabel}已导出，缺失 ${result.missingAssets} 个素材`, "error");
      return;
    }

    if (exportTarget === "native_runtime") {
      setSaveStatus("原生 Runtime 包已经导出，里面已包含继续打成独立 App 的脚本");
      showToast("原生 Runtime 包已经导出");
      return;
    }

    if (exportTarget === "windows_nwjs") {
      setSaveStatus("Windows 桌面包已经导出，可以打包发给别人了");
      showToast("Windows 桌面包已经导出");
      return;
    }

    if (exportTarget === "macos_nwjs") {
      setSaveStatus("macOS 桌面包已经导出，可以打包发给别人了");
      showToast("macOS 桌面包已经导出");
      return;
    }

    if (exportTarget === "linux_nwjs") {
      setSaveStatus("Linux 桌面包已经导出，可以打包发给别人了");
      showToast("Linux 桌面包已经导出");
      return;
    }

    if (exportTarget === "editor_desktop") {
      setSaveStatus("编辑器桌面包已经导出，可以把整包发给别的创作者了");
      showToast("编辑器桌面包已经导出");
      return;
    }

    if (exportTarget === "editor_desktop_suite") {
      setSaveStatus("三系统编辑器套装已经导出，可以按平台分别分发了");
      showToast("三系统编辑器套装已经导出");
      return;
    }

    setSaveStatus("试玩包已经导出，可以直接打开");
    showToast("试玩包已经导出，可以直接打开");
  } catch (error) {
    setSaveStatus(`导出${targetLabel}失败`, true);
    showToast(`导出${targetLabel}失败`, "error");
    window.alert(`导出${targetLabel}没有成功：${error.message}`);
  }
}

async function readFileAsBase64Payload(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error(`读取文件失败：${file.name}`));
    reader.onload = () => {
      const result = String(reader.result ?? "");
      const dataBase64 = result.includes(",") ? result.split(",").pop() : result;
      resolve({
        name: file.name,
        dataBase64,
      });
    };
    reader.readAsDataURL(file);
  });
}

async function saveSelectedScenePlanner() {
  const scene = getSelectedScene();

  if (!scene) {
    setSaveStatus("先选中一个场景，再保存场景规划", true);
    return false;
  }

  const updatedScene = cloneScene(scene);
  updatedScene.status = getSafeSceneStatus(document.getElementById("storySceneStatusSelect")?.value);
  updatedScene.priority = getSafeScenePriority(document.getElementById("storyScenePrioritySelect")?.value);
  updatedScene.notes = String(document.getElementById("storySceneNotesInput")?.value ?? "").trim();

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: state.selectedBlockId,
    previewSceneId: state.previewSceneId ?? updatedScene.id,
    previewStartSceneId: state.previewStartSceneId,
    previewBlockIndex: state.previewBlockIndex,
    successMessage: `已保存场景规划：${updatedScene.name}`,
  });

  if (success) {
    showToast(`场景规划已保存：${updatedScene.name}`);
  }

  return success;
}

async function updateScenePlanning(sceneId, updates = {}, options = {}) {
  const scene = state.data?.scenesById.get(sceneId);

  if (!scene) {
    setSaveStatus("没有找到要更新的场景", true);
    return false;
  }

  const updatedScene = cloneScene(scene);

  if (Object.prototype.hasOwnProperty.call(updates, "status")) {
    updatedScene.status = getSafeSceneStatus(updates.status);
  }

  if (Object.prototype.hasOwnProperty.call(updates, "priority")) {
    updatedScene.priority = getSafeScenePriority(updates.priority);
  }

  if (Object.prototype.hasOwnProperty.call(updates, "notes")) {
    updatedScene.notes = String(updates.notes ?? "").trim();
  }

  const success = await persistScene(updatedScene, {
    selectedSceneId: state.selectedSceneId,
    selectedBlockId: state.selectedBlockId,
    previewSceneId: state.previewSceneId,
    previewStartSceneId: state.previewStartSceneId,
    previewBlockIndex: state.previewBlockIndex,
    successMessage: options.successMessage ?? `已更新场景规划：${updatedScene.name}`,
  });

  if (success) {
    showToast(options.toastMessage ?? `场景规划已更新：${updatedScene.name}`);
  }

  return success;
}

async function toggleScenePriority(sceneId, priorityValue) {
  const scene = state.data?.scenesById.get(sceneId);
  if (!scene) {
    return false;
  }

  const safePriority = getSafeScenePriority(priorityValue);
  const nextPriority = getSafeScenePriority(scene.priority) === safePriority ? "normal" : safePriority;

  return updateScenePlanning(
    sceneId,
    { priority: nextPriority },
    {
      successMessage: `${scene.name} 的优先级已切到：${getScenePriorityLabel(nextPriority)}`,
      toastMessage: `${scene.name} · ${getScenePriorityLabel(nextPriority)}`,
    }
  );
}

async function toggleSceneStatus(sceneId, statusValue) {
  const scene = state.data?.scenesById.get(sceneId);
  if (!scene) {
    return false;
  }

  const safeStatus = getSafeSceneStatus(statusValue);
  const nextStatus = getSafeSceneStatus(scene.status) === safeStatus ? "drafting" : safeStatus;

  return updateScenePlanning(
    sceneId,
    { status: nextStatus },
    {
      successMessage: `${scene.name} 的制作状态已切到：${getSceneStatusLabel(nextStatus)}`,
      toastMessage: `${scene.name} · ${getSceneStatusLabel(nextStatus)}`,
    }
  );
}

async function saveSelectedBlock(options = {}) {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return false;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);

  if (blockIndex < 0) {
    return false;
  }

  updatedScene.blocks[blockIndex] = collectEditedBlock(block);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: block.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: blockIndex,
    successMessage: options.successMessage ?? "这张卡片已经保存",
    reloadAfterSave: !options.autoSave,
    skipAlertOnError: Boolean(options.autoSave),
  });

  if (success) {
    if (options.autoSave) {
      if (options.saveVersion === storyChangeVersion) {
        clearPendingStoryChanges();
      } else {
        queuePendingAutoSave(280);
      }
    } else {
      clearPendingStoryChanges();
    }
  }

  return success;
}

function getReadableTextMetrics(text) {
  const safeText = String(text ?? "").trim();
  return {
    length: safeText.length,
    lineCount: safeText ? safeText.split(/\r?\n/).length : 0,
  };
}

function buildReadableTextSummary(metrics) {
  const safeMetrics =
    metrics && typeof metrics === "object"
      ? metrics
      : {
          length: 0,
          lineCount: 0,
        };
  return `当前 ${safeMetrics.length} 字 / ${safeMetrics.lineCount} 行，超过 ${VN_TEXT_SPLIT_TARGET_LENGTH} 字会启用拆分；超过 ${VN_TEXT_LONG_WARNING_LENGTH} 字或 ${VN_TEXT_LONG_WARNING_LINES} 行时建议拆卡。`;
}

function getChoiceTextQualityState(text) {
  const length = String(text ?? "").trim().length;
  const isLong = length > VN_CHOICE_LONG_WARNING_LENGTH;

  return {
    length,
    isLong,
    statusText: isLong ? "文案偏长" : "按钮舒适",
    toneClass: isLong ? "warn-text" : "good-text",
  };
}

function buildChoiceTextSummary(length) {
  return `当前 ${length} 字，建议不超过 ${VN_CHOICE_LONG_WARNING_LENGTH} 字；解释性内容最好放到前一句台词或旁白里。`;
}

function renderChoiceTextQualityTools(text) {
  const toolState = getChoiceTextQualityState(text);

  return `
    <div class="choice-text-tools ${toolState.isLong ? "is-warning" : ""}" data-choice-text-tools>
      <span class="helper-text" data-choice-text-summary>${escapeHtml(buildChoiceTextSummary(toolState.length))}</span>
      <span class="issue-tag ${toolState.toneClass}" data-choice-text-status>${toolState.statusText}</span>
    </div>
  `;
}

function buildChoiceCountSummary(optionCount) {
  return `当前 ${optionCount} 个选项，超过 ${VN_CHOICE_MANY_OPTIONS} 个时按钮区可能拥挤；复杂分支建议拆成二级选择。`;
}

function updateChoiceCountQualityTools(container = document.getElementById("choiceOptionsEditor")) {
  const countTools = document.querySelector("[data-choice-count-tools]");
  const optionCount = container?.querySelectorAll("[data-choice-option]").length ?? 0;
  const isCrowded = optionCount > VN_CHOICE_MANY_OPTIONS;

  if (!countTools) {
    return;
  }

  countTools.classList.toggle("is-warning", isCrowded);
  const summary = countTools.querySelector("[data-choice-count-summary]");
  const status = countTools.querySelector("[data-choice-count-status]");
  if (summary) {
    summary.textContent = buildChoiceCountSummary(optionCount);
  }
  if (status) {
    status.textContent = isCrowded ? "按钮偏多" : "数量舒适";
    status.className = `issue-tag ${isCrowded ? "warn-text" : "good-text"}`;
  }
}

function updateChoiceTextQualityToolsFromInput(input) {
  if (!(input instanceof HTMLInputElement)) {
    return;
  }

  const tools = input.closest(".detail-row")?.querySelector("[data-choice-text-tools]");
  if (!tools) {
    return;
  }

  const toolState = getChoiceTextQualityState(input.value);
  const summary = tools.querySelector("[data-choice-text-summary]");
  const status = tools.querySelector("[data-choice-text-status]");

  tools.classList.toggle("is-warning", toolState.isLong);
  if (summary) {
    summary.textContent = buildChoiceTextSummary(toolState.length);
  }
  if (status) {
    status.textContent = toolState.statusText;
    status.className = `issue-tag ${toolState.toneClass}`;
  }
}

function isReadableTextLong(text) {
  const metrics = getReadableTextMetrics(text);
  return metrics.length > VN_TEXT_LONG_WARNING_LENGTH || metrics.lineCount > VN_TEXT_LONG_WARNING_LINES;
}

function getReadableTextToolState(text) {
  const metrics = getReadableTextMetrics(text);
  const isLong = isReadableTextLong(text);
  const canSplit = splitReadableTextIntoChunks(text).length > 1;

  return {
    metrics,
    isLong,
    canSplit,
    statusText: isLong ? "建议拆卡" : canSplit ? "可拆卡" : "长度舒适",
    toneClass: isLong ? "warn-text" : "good-text",
  };
}

function updateReadableTextQualityToolsFromInput(input) {
  if (!(input instanceof HTMLTextAreaElement)) {
    return;
  }

  const tools = input.closest(".detail-row")?.querySelector("[data-readable-text-tools]");
  if (!tools) {
    return;
  }

  const toolState = getReadableTextToolState(input.value);
  const status = tools.querySelector("[data-readable-status]");
  const summary = tools.querySelector("[data-readable-summary]");
  const splitButton = tools.querySelector("[data-readable-split-button]");

  tools.classList.toggle("is-warning", toolState.isLong);
  if (summary) {
    summary.textContent = buildReadableTextSummary(toolState.metrics);
  }
  if (status) {
    status.textContent = toolState.statusText;
    status.className = `issue-tag ${toolState.toneClass}`;
  }
  if (splitButton) {
    splitButton.disabled = !toolState.canSplit;
  }
}

function findReadableSplitIndex(text, limit) {
  const safeLimit = Math.max(1, Number(limit) || VN_TEXT_SPLIT_TARGET_LENGTH);
  const searchWindow = text.slice(0, safeLimit + 1);
  const minUsefulIndex = Math.floor(safeLimit * 0.45);
  const punctuationPattern = /[。！？!?；;，,、：:]/g;
  let match = null;
  let splitIndex = -1;

  while ((match = punctuationPattern.exec(searchWindow)) !== null) {
    const candidateIndex = match.index + 1;
    if (candidateIndex >= minUsefulIndex) {
      splitIndex = candidateIndex;
    }
  }

  if (splitIndex > 0) {
    return splitIndex;
  }

  const spaceIndex = searchWindow.lastIndexOf(" ");
  if (spaceIndex >= minUsefulIndex) {
    return spaceIndex + 1;
  }

  return safeLimit;
}

function splitLongReadableSegment(segment, limit) {
  const chunks = [];
  let remaining = String(segment ?? "").trim();

  while (remaining.length > limit) {
    const splitIndex = findReadableSplitIndex(remaining, limit);
    const head = remaining.slice(0, splitIndex).trim();
    if (head) {
      chunks.push(head);
    }
    remaining = remaining.slice(splitIndex).trim();
  }

  if (remaining) {
    chunks.push(remaining);
  }

  return chunks;
}

function shouldJoinReadableSegmentsWithSpace(left, right) {
  return /[A-Za-z0-9)]$/.test(left) && /^[A-Za-z0-9(]/.test(right);
}

function splitReadableTextIntoChunks(text, limit = VN_TEXT_SPLIT_TARGET_LENGTH) {
  const safeLimit = Math.max(20, Number(limit) || VN_TEXT_SPLIT_TARGET_LENGTH);
  const normalizedText = String(text ?? "").replace(/\r\n/g, "\n").trim();
  if (!normalizedText) {
    return [];
  }

  const rawSegments = normalizedText
    .split(/\n+/)
    .flatMap((line) => line.match(/[^。！？!?；;…]+[。！？!?；;…]*/g) ?? [line])
    .map((segment) => segment.trim())
    .filter(Boolean);
  const sentenceSegments = rawSegments.flatMap((segment) =>
    segment.length > safeLimit ? splitLongReadableSegment(segment, safeLimit) : [segment]
  );
  const chunks = [];
  let currentChunk = "";

  sentenceSegments.forEach((segment) => {
    if (!currentChunk) {
      currentChunk = segment;
      return;
    }

    const separator = shouldJoinReadableSegmentsWithSpace(currentChunk, segment) ? " " : "";
    const merged = `${currentChunk}${separator}${segment}`;
    if (merged.length <= safeLimit) {
      currentChunk = merged;
      return;
    }

    chunks.push(currentChunk);
    currentChunk = segment;
  });

  if (currentChunk) {
    chunks.push(currentChunk);
  }

  return chunks;
}

function createBlockIdAllocator(scene) {
  const existing = new Set((scene.blocks ?? []).map((block) => block.id));
  return () => {
    let number = 1;
    let blockId = "";
    do {
      blockId = `block_${String(number).padStart(3, "0")}`;
      number += 1;
    } while (existing.has(blockId));
    existing.add(blockId);
    return blockId;
  };
}

async function splitSelectedReadableBlock() {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return false;
  }

  if (block.type !== "dialogue" && block.type !== "narration") {
    setSaveStatus("只有台词和旁白卡片可以自动拆分", true);
    showToast("只有台词和旁白卡片可以自动拆分", "error");
    return false;
  }

  const editedBlock = collectEditedBlock(block);
  const chunks = splitReadableTextIntoChunks(editedBlock.text);

  if (chunks.length < 2) {
    setSaveStatus("当前文本还不需要拆成多张卡片");
    showToast("当前文本长度还适合放在一张卡片里");
    return false;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);

  if (blockIndex < 0) {
    return false;
  }

  const allocateBlockId = createBlockIdAllocator(updatedScene);
  const splitBlocks = chunks.map((chunk, index) => {
    const nextBlock = JSON.parse(JSON.stringify(editedBlock));
    nextBlock.id = index === 0 ? block.id : allocateBlockId();
    nextBlock.text = chunk;

    if (index > 0 && nextBlock.type === "dialogue") {
      delete nextBlock.voiceAssetId;
    }

    return nextBlock;
  });

  updatedScene.blocks.splice(blockIndex, 1, ...splitBlocks);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: splitBlocks[0].id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: blockIndex,
    successMessage: `已拆分为 ${splitBlocks.length} 张卡片`,
  });

  if (success) {
    clearPendingStoryChanges();
    showToast(`已拆分为 ${splitBlocks.length} 张卡片`);
  }

  return success;
}

function collectEditedBlock(block) {
  if (block.type === "dialogue") {
    const speakerId = getSafeCharacterId(document.getElementById("editorSpeakerId")?.value);
    const expressionId = getSafeExpressionId(
      speakerId,
      document.getElementById("editorExpressionId")?.value
    );
    const voiceAssetId = document.getElementById("editorVoiceAssetId")?.value ?? "";
    const text = document.getElementById("editorDialogueText")?.value ?? "";
    const nextBlock = {
      ...block,
      speakerId,
      expressionId,
      text,
    };

    if (voiceAssetId) {
      nextBlock.voiceAssetId = voiceAssetId;
    } else {
      delete nextBlock.voiceAssetId;
    }

    return nextBlock;
  }

  if (block.type === "narration") {
    return {
      ...block,
      text: document.getElementById("editorNarrationText")?.value ?? "",
    };
  }

  if (block.type === "choice") {
    const optionEditors = Array.from(document.querySelectorAll("[data-choice-option]"));
    const options = optionEditors.map((editor, index) => {
      const optionId = editor.getAttribute("data-option-id") || createChoiceOptionId(block.id, index);
      const existing = block.options?.find((option) => option.id === optionId);
      const text = editor.querySelector('[data-field="choice-text"]')?.value ?? "";
      const gotoSceneId =
        editor.querySelector('[data-field="choice-goto"]')?.value ?? state.selectedSceneId;
      const editableEffects = Array.from(editor.querySelectorAll("[data-choice-effect]")).map(
        (effectEditor) => {
          const effectType = getSafeChoiceEffectType(
            effectEditor.querySelector('[data-field="choice-effect-type"]')?.value
          );
          const variableId = getChoiceEffectVariableId(
            effectType,
            effectEditor.querySelector('[data-field="choice-effect-variable"]')?.value
          );

          return {
            type: effectType,
            variableId,
            value: readChoiceEffectValue(effectEditor, effectType, variableId),
          };
        }
      );
      const preservedEffects = (existing?.effects ?? []).filter(
        (effect) => !isEditableChoiceEffect(effect)
      );

      return {
        id: optionId,
        text,
        gotoSceneId,
        effects: [...editableEffects, ...preservedEffects],
      };
    });

    return {
      ...block,
      options,
    };
  }

  if (block.type === "background") {
    return {
      ...block,
      assetId:
        document.getElementById("editorBackgroundAssetId")?.value ??
        state.data.assetList.find((asset) => asset.type === "background" || asset.type === "scene3d")?.id ??
        "",
      transition: getSafeTransition(document.getElementById("editorTransition")?.value),
      scene3dPreview: getSafeScene3dPreviewConfig({
        yaw: document.getElementById("editorScene3dYaw")?.value,
        pitch: document.getElementById("editorScene3dPitch")?.value,
        zoom: document.getElementById("editorScene3dZoom")?.value,
        interactionEnabled: document.getElementById("editorScene3dInteractionEnabled")?.checked !== false,
      }),
    };
  }

  if (block.type === "character_show") {
    const characterId = getSafeCharacterId(document.getElementById("editorCharacterId")?.value);

    return {
      ...block,
      characterId,
      expressionId: getSafeExpressionId(
        characterId,
        document.getElementById("editorExpressionId")?.value
      ),
      position: getSafePosition(document.getElementById("editorCharacterPosition")?.value),
      transition: getSafeTransition(document.getElementById("editorTransition")?.value),
    };
  }

  if (block.type === "character_hide") {
    return {
      ...block,
      characterId: getSafeCharacterId(document.getElementById("editorCharacterId")?.value),
      transition: getSafeTransition(document.getElementById("editorTransition")?.value),
    };
  }

  if (block.type === "music_play") {
    return {
      ...block,
      assetId: getSafeAssetIdByType("bgm", document.getElementById("editorMusicAssetId")?.value),
      loop: document.getElementById("editorMusicLoop")?.value !== "false",
      fadeInMs: getSafeNonNegativeNumber(document.getElementById("editorFadeInMs")?.value, 600),
    };
  }

  if (block.type === "music_stop") {
    return {
      ...block,
      fadeOutMs: getSafeNonNegativeNumber(document.getElementById("editorFadeOutMs")?.value, 600),
    };
  }

  if (block.type === "sfx_play") {
    return {
      ...block,
      assetId: getSafeAssetIdByType("sfx", document.getElementById("editorSfxAssetId")?.value),
    };
  }

  if (block.type === "video_play") {
    const startTimeSeconds = getSafeNonNegativeNumber(document.getElementById("editorVideoStartTime")?.value, 0);
    const endTimeSeconds = getSafeNonNegativeNumber(document.getElementById("editorVideoEndTime")?.value, 0);

    return {
      ...block,
      assetId: getSafeAssetIdByType("video", document.getElementById("editorVideoAssetId")?.value),
      title: String(document.getElementById("editorVideoTitle")?.value ?? "").trim(),
      fit: getSafeVideoFit(document.getElementById("editorVideoFit")?.value),
      volume: getSafeVideoVolume(document.getElementById("editorVideoVolume")?.value),
      startTimeSeconds,
      endTimeSeconds: endTimeSeconds > startTimeSeconds ? endTimeSeconds : 0,
      skippable: document.getElementById("editorVideoSkippable")?.value !== "false",
    };
  }

  if (block.type === "credits_roll") {
    return {
      ...block,
      title: String(document.getElementById("editorCreditsTitle")?.value ?? "STAFF").trim() || "STAFF",
      subtitle: String(document.getElementById("editorCreditsSubtitle")?.value ?? "").trim(),
      lines: parseCreditsLines(document.getElementById("editorCreditsLines")?.value ?? ""),
      durationSeconds: getSafeCreditsDuration(document.getElementById("editorCreditsDuration")?.value),
      background: getSafeCreditsBackground(document.getElementById("editorCreditsBackground")?.value),
      skippable: document.getElementById("editorCreditsSkippable")?.value !== "false",
    };
  }

  if (block.type === "particle_effect") {
    const preset = getSafeParticlePreset(document.getElementById("editorParticlePreset")?.value);
    const defaults = getParticlePresetDefaults(preset);
    const advancedDefaults = getParticleAdvancedDefaults(preset);
    const customComboLayers = Array.from(document.querySelectorAll("[data-particle-custom-layer]")).map(
      (layerEditor, index) =>
        normalizeParticleCustomComboLayer(
          {
            enabled: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}Enabled`)?.value === "true",
            preset: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}Preset`)?.value,
            emissionMode: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}EmissionMode`)?.value,
            follow: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}Follow`)?.value,
            followAnchor: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}FollowAnchor`)?.value,
            densityMultiplier: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}DensityMultiplier`)?.value,
            sizeScale: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}SizeScale`)?.value,
            lifeScale: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}LifeScale`)?.value,
            opacityScale: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}OpacityScale`)?.value,
            colorMix: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}ColorMix`)?.value,
            blend: layerEditor.querySelector(`#editorParticleCustomLayer${index + 1}Blend`)?.value,
          },
          index === 0 ? "stardust" : "smoke"
        )
    );
    const [sizeMin, sizeMax] = normalizeParticleRange(
      document.getElementById("editorParticleSizeMin")?.value,
      document.getElementById("editorParticleSizeMax")?.value,
      defaults.sizeMin,
      defaults.sizeMax,
      1,
      160
    );
    const [lifeMin, lifeMax] = normalizeParticleRange(
      document.getElementById("editorParticleLifeMin")?.value,
      document.getElementById("editorParticleLifeMax")?.value,
      defaults.lifeMin,
      defaults.lifeMax,
      0.4,
      20
    );
    const [opacityMin, opacityMax] = normalizeParticleRange(
      document.getElementById("editorParticleOpacityMin")?.value,
      document.getElementById("editorParticleOpacityMax")?.value,
      defaults.opacityMin,
      defaults.opacityMax,
      0.04,
      1
    );
    const [rotationMin, rotationMax] = normalizeParticleRange(
      document.getElementById("editorParticleRotationMin")?.value,
      document.getElementById("editorParticleRotationMax")?.value,
      defaults.rotationMin,
      defaults.rotationMax,
      -360,
      360
    );

    return {
      ...block,
      action: getSafeParticleAction(document.getElementById("editorParticleAction")?.value),
      preset,
      assetId: getSafeParticleImageAssetId(document.getElementById("editorParticleAssetId")?.value),
      intensity: getSafeParticleIntensity(document.getElementById("editorParticleIntensity")?.value),
      speed: getSafeParticleSpeed(document.getElementById("editorParticleSpeed")?.value),
      wind: getSafeParticleWind(document.getElementById("editorParticleWind")?.value),
      area: getSafeParticleArea(document.getElementById("editorParticleArea")?.value),
      emissionMode: getSafeParticleEmissionMode(document.getElementById("editorParticleEmissionMode")?.value),
      emitterShape: getSafeParticleEmitterShape(document.getElementById("editorParticleEmitterShape")?.value),
      emitterX: getSafeParticleClampedNumber(
        document.getElementById("editorParticleEmitterX")?.value,
        advancedDefaults.emitterX,
        0,
        100
      ),
      emitterY: getSafeParticleClampedNumber(
        document.getElementById("editorParticleEmitterY")?.value,
        advancedDefaults.emitterY,
        -20,
        120
      ),
      emitterZ: getSafeParticleClampedNumber(
        document.getElementById("editorParticleEmitterZ")?.value,
        advancedDefaults.emitterZ,
        -100,
        100
      ),
      attractionX: getSafeParticleClampedNumber(
        document.getElementById("editorParticleAttractionX")?.value,
        advancedDefaults.attractionX,
        -160,
        160
      ),
      attractionY: getSafeParticleClampedNumber(
        document.getElementById("editorParticleAttractionY")?.value,
        advancedDefaults.attractionY,
        -160,
        160
      ),
      vortex: getSafeParticleClampedNumber(
        document.getElementById("editorParticleVortex")?.value,
        advancedDefaults.vortex,
        -240,
        240
      ),
      follow: getSafeParticleFollowTarget(document.getElementById("editorParticleFollow")?.value),
      followAnchor: getSafeParticleFollowAnchor(document.getElementById("editorParticleFollowAnchor")?.value),
      comboPreset: getSafeParticleComboPreset(document.getElementById("editorParticleComboPreset")?.value),
      customComboLayers,
      layerCount: getSafeParticleLayerCount(document.getElementById("editorParticleLayerCount")?.value),
      forceField: getSafeParticleForceField(document.getElementById("editorParticleForceField")?.value),
      fieldX: getSafeParticleClampedNumber(
        document.getElementById("editorParticleFieldX")?.value,
        advancedDefaults.fieldX,
        0,
        100
      ),
      fieldY: getSafeParticleClampedNumber(
        document.getElementById("editorParticleFieldY")?.value,
        advancedDefaults.fieldY,
        -20,
        120
      ),
      sizeCurve: getSafeParticleSizeCurve(document.getElementById("editorParticleSizeCurve")?.value),
      opacityCurve: getSafeParticleOpacityCurve(document.getElementById("editorParticleOpacityCurve")?.value),
      colorCurve: getSafeParticleColorCurve(document.getElementById("editorParticleColorCurve")?.value),
      density: Math.round(
        getSafeParticleClampedNumber(
          document.getElementById("editorParticleDensity")?.value,
          defaults.density,
          4,
          240
        )
      ),
      sizeMin,
      sizeMax,
      lifeMin,
      lifeMax,
      gravityX: getSafeParticleClampedNumber(
        document.getElementById("editorParticleGravityX")?.value,
        defaults.gravityX,
        -180,
        180
      ),
      gravityY: getSafeParticleClampedNumber(
        document.getElementById("editorParticleGravityY")?.value,
        defaults.gravityY,
        -160,
        280
      ),
      gravityZ: getSafeParticleClampedNumber(
        document.getElementById("editorParticleGravityZ")?.value,
        defaults.gravityZ,
        -120,
        120
      ),
      spreadX: getSafeParticleClampedNumber(
        document.getElementById("editorParticleSpreadX")?.value,
        defaults.spreadX,
        4,
        100
      ),
      spreadY: getSafeParticleClampedNumber(
        document.getElementById("editorParticleSpreadY")?.value,
        defaults.spreadY,
        0,
        100
      ),
      spreadZ: getSafeParticleClampedNumber(
        document.getElementById("editorParticleSpreadZ")?.value,
        defaults.spreadZ,
        0,
        100
      ),
      opacityMin,
      opacityMax,
      rotationMin,
      rotationMax,
      spin: getSafeParticleClampedNumber(
        document.getElementById("editorParticleSpin")?.value,
        defaults.spin,
        -1080,
        1080
      ),
      turbulence: getSafeParticleClampedNumber(
        document.getElementById("editorParticleTurbulence")?.value,
        defaults.turbulence,
        0,
        120
      ),
      color: getSafeParticleColor(document.getElementById("editorParticleColor")?.value, defaults.color),
      colorAccent: getSafeParticleColor(
        document.getElementById("editorParticleColorAccent")?.value,
        defaults.colorAccent
      ),
      colorEnd: getSafeParticleColor(
        document.getElementById("editorParticleColorEnd")?.value,
        document.getElementById("editorParticleColorAccent")?.value ?? defaults.colorAccent
      ),
      blend: getSafeParticleBlendMode(document.getElementById("editorParticleBlend")?.value),
    };
  }

  if (block.type === "screen_shake") {
    return {
      ...block,
      intensity: getSafeShakeIntensity(document.getElementById("editorShakeIntensity")?.value),
      duration: getSafeEffectDuration(document.getElementById("editorShakeDuration")?.value),
    };
  }

  if (block.type === "screen_flash") {
    return {
      ...block,
      color: getSafeFlashColor(document.getElementById("editorFlashColor")?.value),
      intensity: getSafeFlashIntensity(document.getElementById("editorFlashIntensity")?.value),
      duration: getSafeEffectDuration(document.getElementById("editorFlashDuration")?.value),
    };
  }

  if (block.type === "screen_fade") {
    return {
      ...block,
      action: getSafeFadeAction(document.getElementById("editorFadeAction")?.value),
      color: getSafeFadeColor(document.getElementById("editorFadeColor")?.value),
      duration: getSafeEffectDuration(document.getElementById("editorFadeDuration")?.value),
    };
  }

  if (block.type === "camera_zoom") {
    return {
      ...block,
      action: getSafeCameraZoomAction(document.getElementById("editorCameraZoomAction")?.value),
      strength: getSafeCameraZoomStrength(document.getElementById("editorCameraZoomStrength")?.value),
      focus: getSafeCameraZoomFocus(document.getElementById("editorCameraZoomFocus")?.value),
    };
  }

  if (block.type === "camera_pan") {
    return {
      ...block,
      target: getSafeCameraPanTarget(document.getElementById("editorCameraPanTarget")?.value),
      strength: getSafeCameraPanStrength(document.getElementById("editorCameraPanStrength")?.value),
    };
  }

  if (block.type === "screen_filter") {
    return {
      ...block,
      action: getSafeScreenFilterAction(document.getElementById("editorScreenFilterAction")?.value),
      preset: getSafeScreenFilterPreset(document.getElementById("editorScreenFilterPreset")?.value),
      strength: getSafeScreenFilterStrength(document.getElementById("editorScreenFilterStrength")?.value),
    };
  }

  if (block.type === "depth_blur") {
    return {
      ...block,
      action: getSafeDepthBlurAction(document.getElementById("editorDepthBlurAction")?.value),
      focus: getSafeDepthBlurFocus(document.getElementById("editorDepthBlurFocus")?.value),
      strength: getSafeDepthBlurStrength(document.getElementById("editorDepthBlurStrength")?.value),
    };
  }

  if (block.type === "jump") {
    return {
      ...block,
      targetSceneId: getSafeSceneId(
        document.getElementById("editorJumpTargetSceneId")?.value,
        getDefaultJumpTargetSceneId(state.selectedSceneId)
      ),
    };
  }

  if (block.type === "variable_set") {
    const variableId = getSafeVariableId(document.getElementById("editorVariableId")?.value);
    return {
      ...block,
      variableId,
      value: readVariableSetEditorValue(variableId),
    };
  }

  if (block.type === "variable_add") {
    return {
      ...block,
      variableId: getSafeVariableId(document.getElementById("editorVariableAddId")?.value, "number"),
      value: getSafeNumber(document.getElementById("editorVariableAddValue")?.value, 1),
    };
  }

  if (block.type === "condition") {
    const branchEditors = Array.from(document.querySelectorAll("[data-condition-branch]"));
    const branches = branchEditors.map((branchEditor, branchIndex) => {
      const branchId =
        branchEditor.getAttribute("data-branch-id") || createConditionBranchId(block.id, branchIndex);
      const gotoSceneId = getSafeSceneId(
        branchEditor.querySelector('[data-field="condition-goto"]')?.value,
        getDefaultJumpTargetSceneId(state.selectedSceneId)
      );
      const when = Array.from(branchEditor.querySelectorAll("[data-condition-rule]")).map(
        (ruleEditor) => {
          const variableId = getSafeVariableId(
            ruleEditor.querySelector('[data-field="condition-variable"]')?.value
          );

          return {
            variableId,
            operator: getSafeConditionOperator(
              variableId,
              ruleEditor.querySelector('[data-field="condition-operator"]')?.value
            ),
            value: readConditionRuleValue(ruleEditor, variableId),
          };
        }
      );

      return {
        id: branchId,
        when: when.length > 0 ? when : [createDefaultConditionRule()],
        gotoSceneId,
      };
    });

    return {
      ...block,
      branches: branches.length > 0 ? branches : createDefaultConditionBranches(block.id),
      elseGotoSceneId: getSafeSceneId(
        document.getElementById("editorConditionElseSceneId")?.value,
        getDefaultJumpTargetSceneId(state.selectedSceneId)
      ),
    };
  }

  return block;
}

function renderSceneStatusOptions(selectedStatus) {
  const safeSelected = getSafeSceneStatus(selectedStatus);
  return Object.entries(SCENE_STATUS_LABELS)
    .map(
      ([value, label]) => `
        <option value="${value}" ${value === safeSelected ? "selected" : ""}>${escapeHtml(label)}</option>
      `
    )
    .join("");
}

function renderScenePriorityOptions(selectedPriority) {
  const safeSelected = getSafeScenePriority(selectedPriority);
  return Object.entries(SCENE_PRIORITY_LABELS)
    .map(
      ([value, label]) => `
        <option value="${value}" ${value === safeSelected ? "selected" : ""}>${escapeHtml(label)}</option>
      `
    )
    .join("");
}

function getCurrentUiState() {
  return {
    selectedSceneId: state.selectedSceneId,
    selectedBlockId: state.selectedBlockId,
    previewSceneId: state.previewSceneId,
    previewStartSceneId: state.previewStartSceneId,
    previewBlockIndex: state.previewBlockIndex,
    assetFilterMode: state.assetFilterMode,
    assetSearchQuery: state.assetSearchQuery,
    assetTagFilter: state.assetTagFilter,
    assetSortMode: state.assetSortMode,
    assetFavoriteOnly: state.assetFavoriteOnly,
    assetCheckedIds: [...state.assetCheckedIds],
    selectedAssetType: state.selectedAssetType,
    selectedAssetId: state.selectedAssetId,
    selectedCharacterId: state.selectedCharacterId,
  };
}

function promptForText(message, defaultValue) {
  const promptValue =
    typeof window.prompt === "function" ? window.prompt(message, defaultValue) : defaultValue;

  if (promptValue === null) {
    return null;
  }

  const cleanValue = String(promptValue).trim();
  return cleanValue || defaultValue;
}

async function postJson(url, payload) {
  const response = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });
  const result = await response.json();

  if (!response.ok || !result.ok) {
    const requestError = new Error(result.error ?? "请求失败");
    requestError.recovery = result.recovery ?? null;
    requestError.history = result.history ?? null;
    throw requestError;
  }

  return result;
}

async function persistScene(updatedScene, options = {}) {
  try {
    setSaveStatus("正在保存...");
    await postJson(API_SAVE_SCENE, {
      chapterId: updatedScene.chapterId,
      sceneId: updatedScene.id,
      scene: stripSceneForSave(updatedScene),
    });

    if (options.reloadAfterSave === false) {
      applySceneToLocalState(updatedScene);
    } else {
      await reloadProjectData({
        ...getCurrentUiState(),
        selectedSceneId: options.selectedSceneId ?? updatedScene.id,
        selectedBlockId: options.selectedBlockId ?? null,
        previewSceneId: options.previewSceneId ?? updatedScene.id,
        previewStartSceneId: options.previewStartSceneId ?? state.previewStartSceneId,
        previewBlockIndex: options.previewBlockIndex ?? 0,
      });
    }

    setSaveStatus(options.successMessage ?? "保存完成");
    return true;
  } catch (error) {
    setSaveStatus("保存失败", true);

    if (options.skipAlertOnError) {
      showToast("自动保存失败，请稍后手动点一次保存", "error");
      return false;
    }

    window.alert(`保存没有成功：${error.message}`);
    return false;
  }
}

async function reloadProjectData(preserved = {}) {
  const data = await loadProjectData();
  state.data = data;
  state.projectHistory = data.history ?? null;
  state.projectSessionRecovery = data.sessionRecovery ?? null;
  state.validation = runValidation(data);
  updateErrorRecoveryState(null);

  const selectedScene =
    data.scenesById.get(preserved.selectedSceneId) ??
    data.scenesById.get(data.project.entrySceneId) ??
    data.scenes[0] ??
    null;

  state.selectedSceneId = selectedScene?.id ?? null;
  state.selectedBlockId =
    selectedScene?.blocks?.some((block) => block.id === preserved.selectedBlockId)
      ? preserved.selectedBlockId
      : selectedScene?.blocks?.[0]?.id ?? null;

  const previewScene =
    data.scenesById.get(preserved.previewSceneId) ??
    data.scenesById.get(state.selectedSceneId) ??
    selectedScene;

  state.previewStartSceneId =
    data.scenesById.get(preserved.previewStartSceneId)?.id ??
    data.scenesById.get(preserved.previewSceneId)?.id ??
    previewScene?.id ??
    selectedScene?.id ??
    null;
  state.previewSceneId = previewScene?.id ?? null;
  state.previewBlockIndex = clamp(
    preserved.previewBlockIndex ?? Math.max((previewScene?.blocks?.length ?? 1) - 1, 0),
    0,
    Math.max((previewScene?.blocks?.length ?? 1) - 1, 0)
  );

  state.assetFilterMode = getSafeAssetFilterMode(preserved.assetFilterMode ?? "all");
  state.assetSearchQuery = preserved.assetSearchQuery ?? "";
  state.assetTagFilter = preserved.assetTagFilter ?? "";
  state.assetSortMode = preserved.assetSortMode ?? "default";
  state.assetFavoriteOnly = preserved.assetFavoriteOnly ?? false;
  state.assetCheckedIds = pruneAssetCheckedIds(preserved.assetCheckedIds ?? state.assetCheckedIds, data);
  state.selectedAssetType = preserved.selectedAssetType ?? data.assetList[0]?.type ?? "background";
  const visibleAssets = getVisibleAssets(data, {
    filterMode: state.assetFilterMode,
    searchQuery: state.assetSearchQuery,
    tagFilter: state.assetTagFilter,
    sortMode: state.assetSortMode,
    favoriteOnly: state.assetFavoriteOnly,
  });
  const selectedAsset =
    visibleAssets.find((asset) => asset.id === preserved.selectedAssetId) ??
    visibleAssets.find((asset) => asset.type === state.selectedAssetType) ??
    visibleAssets[0] ??
    null;
  state.selectedAssetType = selectedAsset?.type ?? state.selectedAssetType;
  state.selectedAssetId = selectedAsset?.id ?? null;

  state.selectedCharacterId =
    data.charactersById.get(preserved.selectedCharacterId)?.id ?? data.characters[0]?.id ?? null;

  state.previewSession = createPreviewSession(state.previewStartSceneId ?? state.selectedSceneId);
  renderAll();
  void maybePromptProjectRecovery(data);
}

function applySceneToLocalState(updatedScene) {
  const scenePayload = stripSceneForSave(updatedScene);
  const chapter = state.data.chaptersById.get(updatedScene.chapterId);

  if (!chapter) {
    return;
  }

  const chapterSceneIndex = chapter.scenes.findIndex((scene) => scene.id === updatedScene.id);
  if (chapterSceneIndex >= 0) {
    chapter.scenes[chapterSceneIndex] = scenePayload;
  } else {
    chapter.scenes.push(scenePayload);
  }

  const fullScene = {
    ...scenePayload,
    chapterId: updatedScene.chapterId,
    chapterName: chapter.name,
  };
  const sceneIndex = state.data.scenes.findIndex((scene) => scene.id === updatedScene.id);

  if (sceneIndex >= 0) {
    state.data.scenes[sceneIndex] = fullScene;
  } else {
    state.data.scenes.push(fullScene);
  }

  state.data.scenesById.set(updatedScene.id, fullScene);
  state.data.assetUsage = buildAssetUsageMap({
    chapters: state.data.chapters,
    characters: state.data.characters,
    charactersById: state.data.charactersById,
  });
  state.validation = runValidation(state.data);
  updateTopbar();
}

function appendChoiceOptionEditor() {
  const block = getSelectedBlock();
  const container = document.getElementById("choiceOptionsEditor");

  if (!block || block.type !== "choice" || !container) {
    return;
  }

  const nextIndex = container.querySelectorAll("[data-choice-option]").length;
  const nextOption = {
    id: getNextChoiceOptionEditorId(block.id, container),
    text: `新选项 ${nextIndex + 1}`,
    gotoSceneId: state.selectedSceneId,
    effects: [],
  };

  container.insertAdjacentHTML("beforeend", renderChoiceOptionEditorRow(nextOption, nextIndex, nextIndex + 1));
  updateChoiceOptionEditorControls(container);
  updateChoiceCountQualityTools(container);
}

function getNextChoiceOptionEditorId(blockId, container) {
  const existingIds = new Set(
    Array.from(container.querySelectorAll("[data-choice-option]"))
      .map((editor) => editor.getAttribute("data-option-id"))
      .filter(Boolean)
  );
  let index = 0;
  let optionId = createChoiceOptionId(blockId, index);

  while (existingIds.has(optionId)) {
    index += 1;
    optionId = createChoiceOptionId(blockId, index);
  }

  return optionId;
}

function updateChoiceOptionEditorControls(container = document.getElementById("choiceOptionsEditor")) {
  const optionEditors = Array.from(container?.querySelectorAll("[data-choice-option]") ?? []);
  optionEditors.forEach((editor, index) => {
    const title = editor.querySelector("[data-choice-option-title]");
    if (title) {
      title.textContent = `选项 ${index + 1}`;
    }
    const moveUpButton = editor.querySelector('[data-action="move-choice-option-up"]');
    const moveDownButton = editor.querySelector('[data-action="move-choice-option-down"]');
    if (moveUpButton) {
      moveUpButton.disabled = index <= 0;
    }
    if (moveDownButton) {
      moveDownButton.disabled = index >= optionEditors.length - 1;
    }
  });
}

function removeChoiceOptionEditor(actionTarget) {
  const container = document.getElementById("choiceOptionsEditor");
  const optionEditor = actionTarget.closest("[data-choice-option]");

  if (!container || !optionEditor) {
    return false;
  }

  const optionCount = container.querySelectorAll("[data-choice-option]").length;
  if (optionCount <= 1) {
    setSaveStatus("至少保留一个选项", true);
    showToast("至少保留一个选项", "error");
    return false;
  }

  optionEditor.remove();
  updateChoiceOptionEditorControls(container);
  updateChoiceCountQualityTools(container);
  return true;
}

function moveChoiceOptionEditor(actionTarget, direction) {
  const container = document.getElementById("choiceOptionsEditor");
  const optionEditor = actionTarget.closest("[data-choice-option]");

  if (!container || !optionEditor) {
    return false;
  }

  const optionEditors = Array.from(container.querySelectorAll("[data-choice-option]"));
  const currentIndex = optionEditors.indexOf(optionEditor);
  const targetIndex = currentIndex + direction;

  if (currentIndex < 0 || targetIndex < 0 || targetIndex >= optionEditors.length) {
    return false;
  }

  if (direction < 0) {
    container.insertBefore(optionEditor, optionEditors[targetIndex]);
  } else {
    container.insertBefore(optionEditors[targetIndex], optionEditor);
  }

  updateChoiceOptionEditorControls(container);
  return true;
}

function appendChoiceEffectEditor(optionId) {
  const optionEditor = document.querySelector(`[data-choice-option][data-option-id="${optionId}"]`);
  const effectsContainer = optionEditor?.querySelector("[data-choice-effects]");

  if (!effectsContainer) {
    return;
  }

  effectsContainer.querySelector("[data-choice-effects-empty]")?.remove();
  const nextIndex = effectsContainer.querySelectorAll("[data-choice-effect]").length;
  effectsContainer.insertAdjacentHTML(
    "beforeend",
    renderChoiceEffectEditorRow(createDefaultChoiceEffect(), nextIndex, nextIndex + 1)
  );
  updateChoiceEffectEditorControls(effectsContainer);
}

function updateChoiceEffectEditorControls(effectsContainer) {
  const effectEditors = Array.from(effectsContainer?.querySelectorAll("[data-choice-effect]") ?? []);
  effectEditors.forEach((editor, index) => {
    const title = editor.querySelector("[data-choice-effect-title]");
    const moveUpButton = editor.querySelector('[data-action="move-choice-effect-up"]');
    const moveDownButton = editor.querySelector('[data-action="move-choice-effect-down"]');
    if (title) {
      title.textContent = `附加效果 ${index + 1}`;
    }
    if (moveUpButton) {
      moveUpButton.disabled = index <= 0;
    }
    if (moveDownButton) {
      moveDownButton.disabled = index >= effectEditors.length - 1;
    }
  });
}

function removeChoiceEffectEditor(actionTarget) {
  const effectEditor = actionTarget.closest("[data-choice-effect]");
  const effectsContainer = effectEditor?.parentElement;

  if (!effectEditor || !effectsContainer) {
    return false;
  }

  effectEditor.remove();

  if (effectsContainer.querySelectorAll("[data-choice-effect]").length === 0) {
    effectsContainer.innerHTML = renderChoiceEffectEmptyState();
  } else {
    updateChoiceEffectEditorControls(effectsContainer);
  }
  return true;
}

function moveChoiceEffectEditor(actionTarget, direction) {
  const effectEditor = actionTarget.closest("[data-choice-effect]");
  const effectsContainer = effectEditor?.parentElement;

  if (!effectEditor || !effectsContainer) {
    return false;
  }

  const effectEditors = Array.from(effectsContainer.querySelectorAll("[data-choice-effect]"));
  const currentIndex = effectEditors.indexOf(effectEditor);
  const targetIndex = currentIndex + direction;

  if (currentIndex < 0 || targetIndex < 0 || targetIndex >= effectEditors.length) {
    return false;
  }

  if (direction < 0) {
    effectsContainer.insertBefore(effectEditor, effectEditors[targetIndex]);
  } else {
    effectsContainer.insertBefore(effectEditors[targetIndex], effectEditor);
  }

  updateChoiceEffectEditorControls(effectsContainer);
  return true;
}

function applyParticleCustomLayersToEditor(layers = []) {
  normalizeParticleCustomComboLayers(layers).forEach((layer, index) => {
    const slotNumber = index + 1;
    const assignValue = (suffix, value) => {
      const field = document.getElementById(`editorParticleCustomLayer${slotNumber}${suffix}`);
      if (field && value != null) {
        field.value = String(value);
      }
    };

    assignValue("Enabled", layer.enabled ? "true" : "false");
    assignValue("Preset", layer.preset);
    assignValue("EmissionMode", layer.emissionMode);
    assignValue("Follow", layer.follow);
    assignValue("FollowAnchor", layer.followAnchor);
    assignValue("DensityMultiplier", formatParticleNumber(layer.densityMultiplier, 1));
    assignValue("SizeScale", formatParticleNumber(layer.sizeScale, 1));
    assignValue("LifeScale", formatParticleNumber(layer.lifeScale, 1));
    assignValue("OpacityScale", formatParticleNumber(layer.opacityScale, 1));
    assignValue("ColorMix", formatParticleNumber(layer.colorMix, 2));
    assignValue("Blend", layer.blend);
  });
}

